insert into public.lessons (id, unit_id, title, title_pt, icon, xp, questions, sort_order)
values
('l0a', 'u0', 'What is English?', 'O que é o Inglês?', '🌍', 10, '{"learn":{"explanation":{"en":"English is a language — a way that people use words to talk, write, and understand each other. It is spoken as a first or second language in more than 50 countries, including the USA, the UK, Australia and South Africa. Learning English helps you travel, study, work, and connect with people all over the world.","pt":"O inglês é uma língua — uma forma que as pessoas usam para falar, escrever e se entenderem. É falado como primeira ou segunda língua em mais de 50 países, incluindo os EUA, o Reino Unido, a Austrália e a África do Sul. Aprender inglês ajuda-te a viajar, estudar, trabalhar e comunicar com pessoas de todo o mundo."},"examples":[{"en":"English is a global language.","pt":"O inglês é uma língua global."},{"en":"Many people speak English as a second language.","pt":"Muitas pessoas falam inglês como segunda língua."},{"en":"I want to learn English.","pt":"Eu quero aprender inglês."}],"practice":[{"q":"How many countries speak English?","opts":["Only 2","Over 50","Exactly 10","None"],"ans":1,"exp":"English is spoken in over 50 countries around the world."},{"q":"Choose the TRUE sentence.","opts":["English is a colour.","English is a language.","English is a food.","English is an animal."],"ans":1,"exp":"\"English is a language\" — a way of communicating."}]},"qs":[{"q":"English is a ___.","opts":["language","animal","colour","food"],"ans":0,"exp":"\"English\" is a language — a way of communicating!"},{"q":"English is spoken in how many countries?","opts":["2","10","50","over 50"],"ans":3,"exp":"English is spoken in over 50 countries! It is truly a global language."},{"q":"Which country speaks English as its official language?","opts":["Brazil","Portugal","USA","Mozambique"],"ans":2,"exp":"The USA (United States of America) has English as its main language."},{"q":"Why learn English?","opts":["To forget Portuguese","To travel, work and communicate globally","It''s easy","To watch TV only"],"ans":1,"exp":"English opens doors: travel, jobs, university, internet and more!"},{"q":"The English alphabet has ___ letters.","opts":["20","24","26","30"],"ans":2,"exp":"The English alphabet has 26 letters: A to Z!"}]}'::jsonb, 0),
('l0b', 'u0', 'The Alphabet A-Z', 'O Alfabeto A-Z', '🔤', 15, '{"learn":{"explanation":{"en":"The English alphabet has 26 letters, from A to Z. Five of them are vowels: A, E, I, O, U. The rest are consonants. Knowing the alphabet helps you spell words, read, and use a dictionary.","pt":"O alfabeto inglês tem 26 letras, de A a Z. Cinco delas são vogais: A, E, I, O, U. As restantes são consoantes. Conhecer o alfabeto ajuda-te a soletrar palavras, ler e usar um dicionário."},"examples":[{"en":"A, B, C, D, E... Z.","pt":"A, B, C, D, E... Z."},{"en":"My name starts with the letter S.","pt":"O meu nome começa com a letra S."},{"en":"Can you spell your name, please?","pt":"Podes soletrar o teu nome, por favor?"}],"practice":[{"q":"Which letters are vowels?","opts":["B, C, D, F","A, E, I, O, U","X, Y, Z","M, N, P"],"ans":1,"exp":"The 5 vowels are A, E, I, O, U."},{"q":"What comes right after the letter J?","opts":["I","K","H","L"],"ans":1,"exp":"...I, J, K, L... K comes after J!"}]},"qs":[{"q":"Which comes FIRST in the alphabet?","opts":["B","A","C","D"],"ans":1,"exp":"A is the first letter: A, B, C, D, E, F, G..."},{"q":"How many vowels does English have?","opts":["3","5","7","10"],"ans":1,"exp":"English has 5 vowels: A, E, I, O, U"},{"q":"Which letter is a VOWEL?","opts":["B","C","E","T"],"ans":2,"exp":"E is a vowel. Vowels are: A, E, I, O, U"},{"q":"What comes after M in the alphabet?","opts":["L","K","N","P"],"ans":2,"exp":"...K, L, M, N, O, P... N comes after M!"},{"q":"Which word starts with the letter \"H\"?","opts":["Apple","Elephant","Hello","Dog"],"ans":2,"exp":"\"Hello\" starts with H. Hello! 👋"}]}'::jsonb, 1),
('l0c', 'u0', 'Greetings & Goodbyes', 'Saudações e Despedidas', '👋', 15, '{"learn":{"explanation":{"en":"Greetings are words we use to say hello and goodbye politely. \"Hello\" and \"Hi\" greet someone. \"Good morning\", \"Good afternoon\" and \"Good evening\" depend on the time of day. \"Goodbye\" or \"Bye\" are used when leaving.","pt":"As saudações são palavras que usamos para cumprimentar e despedir-nos educadamente. \"Hello\" e \"Hi\" cumprimentam alguém. \"Good morning\", \"Good afternoon\" e \"Good evening\" dependem da hora do dia. \"Goodbye\" ou \"Bye\" são usados ao sair."},"examples":[{"en":"Hello! How are you?","pt":"Olá! Como estás?"},{"en":"Good morning, teacher!","pt":"Bom dia, professor(a)!"},{"en":"Goodbye, see you tomorrow!","pt":"Adeus, até amanhã!"}],"practice":[{"q":"What do you say when you meet someone in the morning?","opts":["Good night","Good morning","Goodbye","Good food"],"ans":1,"exp":"\"Good morning\" is used in the morning."},{"q":"Which word means \"Adeus\"?","opts":["Hello","Please","Goodbye","Thanks"],"ans":2,"exp":"\"Goodbye\" = Adeus."}]},"qs":[{"q":"How do you say \"Olá\" in English?","opts":["Goodbye","Thank you","Hello","Please"],"ans":2,"exp":"\"Hello\" = Olá. You can also say \"Hi!\" (informal)"},{"q":"\"Good morning\" is used:","opts":["At night","In the morning","At lunchtime","Any time"],"ans":1,"exp":"\"Good morning\" = Bom dia. Used in the morning!"},{"q":"How do you say \"Até logo\" in English?","opts":["Hello","How are you?","Goodbye","Please"],"ans":2,"exp":"\"Goodbye\" = Até logo / Adeus. Also \"Bye!\" (informal)"},{"q":"\"How are you?\" is a ___.","opts":["command","greeting","number","colour"],"ans":1,"exp":"\"How are you?\" = Como estás? It''s a greeting!"},{"q":"The correct response to \"How are you?\" is:","opts":["My name is Ana","I am fine, thank you","Goodbye","Yes, please"],"ans":1,"exp":"\"I am fine, thank you\" = Estou bem, obrigado/a. The perfect reply!"}]}'::jsonb, 2),
('l0d', 'u0', 'Introducing Yourself', 'Apresentar-se', '🙋', 20, '{"learn":{"explanation":{"en":"To introduce yourself in English, use \"My name is...\" for your name, \"I am from...\" for your country, and \"I am ___ years old\" for your age. Always use \"am\" after \"I\".","pt":"Para te apresentares em inglês, usa \"My name is...\" para o teu nome, \"I am from...\" para o teu país, e \"I am ___ years old\" para a tua idade. Usa sempre \"am\" depois de \"I\"."},"examples":[{"en":"My name is Sebastian.","pt":"O meu nome é Sebastian."},{"en":"I am from Mozambique.","pt":"Eu sou de Moçambique."},{"en":"I am 20 years old.","pt":"Eu tenho 20 anos."},{"en":"Nice to meet you!","pt":"Muito prazer!"}],"practice":[{"q":"Complete: \"I ___ from Maputo.\"","opts":["is","am","are","be"],"ans":1,"exp":"Use \"am\" with \"I\"."},{"q":"Which sentence says your age correctly?","opts":["I am Ana.","I am 18 years old.","I from Mozambique.","I name is Ana."],"ans":1,"exp":"Age: \"I am ___ years old.\""}]},"qs":[{"q":"\"My name is ___.\" This sentence introduces:","opts":["your age","your name","your job","your city"],"ans":1,"exp":"\"My name is...\" = O meu nome é... Use it to introduce yourself!"},{"q":"Complete: \"I ___ from Mozambique.\"","opts":["is","am","are","be"],"ans":1,"exp":"\"I am from...\" Use \"am\" with \"I\". I am from Mozambique!"},{"q":"\"I am 25 years ___.\"","opts":["old","age","young","year"],"ans":0,"exp":"\"I am 25 years old.\" = Tenho 25 anos. Always use \"old\"!"},{"q":"Which sentence correctly introduces someone?","opts":["My name are Ana.","My name am Ana.","My name is Ana.","Me name is Ana."],"ans":2,"exp":"\"My name IS Ana.\" — use \"is\" for names!"},{"q":"\"Nice to meet you!\" means:","opts":["Goodbye!","I don''t know you.","Happy to meet you!","See you later!"],"ans":2,"exp":"\"Nice to meet you!\" = Muito prazer! Say this when meeting someone new."}]}'::jsonb, 3),
('l0e', 'u0', 'Numbers 1-20', 'Números 1-20', '🔢', 15, '{"learn":{"explanation":{"en":"Numbers in English go from one (1) to twenty (20) and beyond. Numbers 13-19 usually end in \"-teen\" (thirteen, fourteen...). Round tens like twenty and thirty end in \"-ty\".","pt":"Os números em inglês vão de one (1) a twenty (20) e além. Os números de 13 a 19 normalmente terminam em \"-teen\" (thirteen, fourteen...). As dezenas como twenty, thirty terminam em \"-ty\"."},"examples":[{"en":"One, two, three, four, five.","pt":"Um, dois, três, quatro, cinco."},{"en":"I have ten fingers.","pt":"Eu tenho dez dedos."},{"en":"She is fifteen years old.","pt":"Ela tem quinze anos."}],"practice":[{"q":"What number is \"twenty\"?","opts":["12","20","2","22"],"ans":1,"exp":"twenty = 20."},{"q":"Which is the correct counting order?","opts":["one, three, two","one, two, three","three, two, one","two, three, one"],"ans":1,"exp":"one, two, three — counting order!"}]},"qs":[{"q":"What is \"five\" in numbers?","opts":["3","4","5","6"],"ans":2,"exp":"five = 5. One, two, three, four, five!"},{"q":"How do you write 10 in words?","opts":["twelve","eight","ten","eleven"],"ans":2,"exp":"10 = ten. Count: one, two, three... ten!"},{"q":"\"Fifteen\" is:","opts":["13","14","15","16"],"ans":2,"exp":"fifteen = 15. Five + Ten = Fifteen!"},{"q":"What comes after \"nineteen\"?","opts":["eighteen","twenty","seventeen","thirteen"],"ans":1,"exp":"After nineteen (19) comes twenty (20)!"},{"q":"Which number is \"twelve\"?","opts":["10","11","12","13"],"ans":2,"exp":"twelve = 12. A dozen = twelve!"}]}'::jsonb, 4),
('l0f', 'u0', 'Colours', 'Cores', '🎨', 15, '{"learn":{"explanation":{"en":"Colours describe how things look. The main colours are red, blue, yellow, green, orange, purple, black, white, and brown. We use \"is/are\" with colours: \"The sky IS blue.\"","pt":"As cores descrevem como as coisas parecem. As principais cores são red, blue, yellow, green, orange, purple, black, white e brown. Usamos \"is/are\" com as cores: \"The sky IS blue.\""},"examples":[{"en":"The sky is blue.","pt":"O céu é azul."},{"en":"My favourite colour is green.","pt":"A minha cor favorita é verde."},{"en":"The flag has red, yellow, and black.","pt":"A bandeira tem vermelho, amarelo e preto."}],"practice":[{"q":"What colour is a banana?","opts":["blue","yellow","purple","black"],"ans":1,"exp":"Bananas are yellow."},{"q":"\"Vermelho\" in English is:","opts":["blue","green","red","white"],"ans":2,"exp":"red = vermelho."}]},"qs":[{"q":"What colour is the sky?","opts":["green","red","blue","yellow"],"ans":2,"exp":"The sky is BLUE! 🔵 \"The sky is blue.\""},{"q":"\"Red\" in Portuguese is:","opts":["Azul","Verde","Vermelho","Amarelo"],"ans":2,"exp":"red = vermelho. \"The rose is red.\" 🌹"},{"q":"What colour is grass?","opts":["blue","green","orange","purple"],"ans":1,"exp":"Grass is GREEN! 🌿 \"The grass is green.\""},{"q":"\"Yellow\" is the colour of:","opts":["the sea","the sun","the night","the soil"],"ans":1,"exp":"The sun is YELLOW! ☀️ \"The sun is yellow.\""},{"q":"Which colour is NOT in the rainbow?","opts":["red","brown","blue","green"],"ans":1,"exp":"Brown is NOT in the rainbow. Rainbow = red, orange, yellow, green, blue, indigo, violet."}]}'::jsonb, 5),
('l0g', 'u0', 'Family Members', 'Membros da Família', '👨‍👩‍👧‍👦', 20, '{"learn":{"explanation":{"en":"Family words describe the people in your family. \"Mother\" and \"father\" are your parents. \"Brother\" and \"sister\" are your siblings. \"Grandmother\" and \"grandfather\" are your grandparents.","pt":"As palavras de família descrevem as pessoas da tua família. \"Mother\" e \"father\" são os teus pais. \"Brother\" e \"sister\" são os teus irmãos. \"Grandmother\" e \"grandfather\" são os teus avós."},"examples":[{"en":"This is my mother.","pt":"Esta é a minha mãe."},{"en":"I have one brother and one sister.","pt":"Eu tenho um irmão e uma irmã."},{"en":"My grandfather is very kind.","pt":"O meu avô é muito gentil."}],"practice":[{"q":"Your father''s mother is your:","opts":["aunt","grandmother","sister","cousin"],"ans":1,"exp":"Father''s mother = grandmother."},{"q":"\"Irmã\" in English is:","opts":["brother","mother","sister","daughter"],"ans":2,"exp":"sister = irmã."}]},"qs":[{"q":"\"Mother\" means:","opts":["irmã","mãe","avó","tia"],"ans":1,"exp":"mother = mãe. \"My mother is kind.\""},{"q":"What is \"father\" in Portuguese?","opts":["irmão","tio","pai","avô"],"ans":2,"exp":"father = pai. \"My father is strong.\""},{"q":"\"Brother\" and \"sister\" are your:","opts":["parents","grandparents","siblings","children"],"ans":2,"exp":"Brother and sister = siblings (irmãos). Part of your immediate family!"},{"q":"What do you call your mother''s mother?","opts":["aunt","sister","grandmother","cousin"],"ans":2,"exp":"Your mother''s mother = grandmother (avó)!"},{"q":"\"I have two ___.\" (brother + sister)","opts":["parents","siblings","cousins","grandparents"],"ans":1,"exp":"Brother + sister = siblings. \"I have two siblings.\""}]}'::jsonb, 6),
('l0h', 'u0', 'My First Conversation', 'A Minha Primeira Conversa', '💬', 25, '{"learn":{"explanation":{"en":"Now let''s put it all together! A simple conversation starts with a greeting, asks a question or two, and ends politely. For example: \"Hello! What is your name? Where are you from? Nice to meet you! Goodbye!\"","pt":"Agora vamos juntar tudo! Uma conversa simples começa com uma saudação, faz uma ou duas perguntas e termina educadamente. Por exemplo: \"Hello! What is your name? Where are you from? Nice to meet you! Goodbye!\""},"examples":[{"en":"A: Hello! B: Hi! How are you?","pt":"A: Olá! B: Oi! Como estás?"},{"en":"A: What is your name? B: My name is Ana.","pt":"A: Qual é o teu nome? B: O meu nome é Ana."},{"en":"A: Where are you from? B: I am from Mozambique.","pt":"A: De onde és? B: Eu sou de Moçambique."}],"practice":[{"q":"What is a polite way to end a conversation?","opts":["What?","Goodbye! Have a nice day!","Nothing","My name is..."],"ans":1,"exp":"Always end politely: \"Goodbye! Have a nice day!\""},{"q":"Put these in the right conversation order:","opts":["Goodbye → Hello → Name?","Hello → Name? → Goodbye","Name? → Goodbye → Hello","Goodbye → Name? → Hello"],"ans":1,"exp":"Start with Hello, ask questions, then say Goodbye."}]},"qs":[{"q":"Put in order: \"___ am I. Sebastian name My.\"","opts":["My name I am Sebastian.","My name is Sebastian.","I Sebastian name am.","Sebastian my name."],"ans":1,"exp":"\"My name is Sebastian.\" — Subject + Verb + Object!"},{"q":"A: \"Hello!\" B: \"___\"","opts":["Goodbye!","Hello! How are you?","My name is Ana.","I am fine."],"ans":1,"exp":"\"Hello! How are you?\" — Reply to a greeting with a greeting!"},{"q":"A: \"Where are you from?\" B: \"___\"","opts":["I am 20 years old.","I am fine.","I am from Mozambique.","My name is Tom."],"ans":2,"exp":"\"I am from Mozambique.\" — Answer \"Where from?\" with \"I am from...\""},{"q":"How do you say \"thank you\" in English?","opts":["Please","Sorry","Thank you","Excuse me"],"ans":2,"exp":"\"Thank you\" = Obrigado/a. Always be polite!"},{"q":"To end a conversation politely you say:","opts":["Hello!","How are you?","Nice to meet you!","Goodbye! Have a nice day!"],"ans":3,"exp":"\"Goodbye! Have a nice day!\" = Até logo! Tenha um bom dia! 👋"}]}'::jsonb, 7),
('l0i', 'u0', 'Plural Nouns', 'Substantivos no Plural', '➕', 15, '{"learn":{"explanation":{"en":"Most English nouns become plural by adding -s: book → books. Nouns ending in -s, -x, -ch, -sh add -es: box → boxes. A few are irregular: man → men, child → children.","pt":"A maioria dos substantivos ingleses fica no plural ao adicionar -s: book → books. Substantivos terminados em -s, -x, -ch, -sh adicionam -es: box → boxes. Alguns são irregulares: man → men, child → children."},"examples":[{"en":"I have two dogs.","pt":"Eu tenho dois cães."},{"en":"She bought three boxes.","pt":"Ela comprou três caixas."},{"en":"There are many children in the park.","pt":"Há muitas crianças no parque."}],"practice":[{"q":"Plural of \"book\":","opts":["bookes","books","bookies","book"],"ans":1,"exp":"Just add -s: book → books."},{"q":"Plural of \"box\":","opts":["boxs","boxes","boxies","box"],"ans":1,"exp":"Words ending in -x add -es: box → boxes."}]},"qs":[{"q":"Plural of \"cat\":","opts":["cates","cats","catses","cat"],"ans":1,"exp":"Add -s: cat → cats."},{"q":"Plural of \"watch\":","opts":["watchs","watches","watchies","watch"],"ans":1,"exp":"Words ending in -ch add -es: watch → watches."},{"q":"Irregular plural of \"child\":","opts":["childs","childes","children","childen"],"ans":2,"exp":"\"Child\" is irregular: child → children."},{"q":"\"I have ___ sisters.\" (2)","opts":["a","two","one","no"],"ans":1,"exp":"\"Two sisters\" — plural noun needs a number bigger than one!"},{"q":"Which is the correct plural of \"man\"?","opts":["mans","men","mens","manes"],"ans":1,"exp":"\"Man\" is irregular: man → men."}]}'::jsonb, 8),
('l0j', 'u0', 'Question Words', 'Palavras Interrogativas', '❓', 20, '{"learn":{"explanation":{"en":"Question words start most English questions: What (thing), Where (place), Who (person), When (time), Why (reason), and How (manner). They go at the beginning of the sentence.","pt":"As palavras interrogativas começam a maioria das perguntas em inglês: What (coisa), Where (lugar), Who (pessoa), When (tempo), Why (razão), e How (modo). Vêm no início da frase."},"examples":[{"en":"What is your name?","pt":"Qual é o teu nome?"},{"en":"Where do you live?","pt":"Onde vives?"},{"en":"Why are you happy?","pt":"Porque estás feliz?"}],"practice":[{"q":"Which question word asks about a PLACE?","opts":["What","Where","Who","Why"],"ans":1,"exp":"\"Where\" asks about a place."},{"q":"Which question word asks about a PERSON?","opts":["What","When","Who","How"],"ans":2,"exp":"\"Who\" asks about a person."}]},"qs":[{"q":"\"___ is your favourite colour?\"","opts":["Who","What","Where","When"],"ans":1,"exp":"\"What\" asks about a thing — like a colour."},{"q":"\"___ is your birthday?\" (asking about time)","opts":["Where","What","When","Who"],"ans":2,"exp":"\"When\" asks about time."},{"q":"\"___ are you sad?\" (asking for a reason)","opts":["Why","How","What","Where"],"ans":0,"exp":"\"Why\" asks for a reason."},{"q":"\"___ do you spell your name?\" (asking about manner)","opts":["What","How","Who","Why"],"ans":1,"exp":"\"How\" asks about manner or method."},{"q":"\"___ is your teacher?\" (asking about a person)","opts":["What","Where","Who","When"],"ans":2,"exp":"\"Who\" asks about a person."}]}'::jsonb, 9),
('l0k', 'u0b', 'Vowel Sounds', 'Sons das Vogais', '🔤', 15, '{"learn":{"explanation":{"en":"English has 5 vowels: A, E, I, O, U. But each vowel can make more than one sound! In short words, A sounds like in \"cat\", E like in \"bed\", I like in \"sit\", O like in \"hot\", U like in \"cup\". Listen and repeat each one slowly.","pt":"O inglês tem 5 vogais: A, E, I, O, U. Mas cada vogal pode fazer mais de um som! Em palavras curtas, A soa como em \"cat\" (gato), E como em \"bed\" (cama), I como em \"sit\" (sentar), O como em \"hot\" (quente), U como em \"cup\" (chávena). Ouve e repete cada uma devagar."},"examples":[{"en":"A — cat, man, bag","pt":"A — gato, homem, saco"},{"en":"E — bed, ten, pet","pt":"E — cama, dez, animal de estimação"},{"en":"I — sit, big, fish","pt":"I — sentar, grande, peixe"},{"en":"O — hot, dog, box","pt":"O — quente, cão, caixa"},{"en":"U — cup, bus, sun","pt":"U — chávena, autocarro, sol"}],"practice":[{"q":"Which vowel sound is in the word \"bed\"?","opts":["A","E","I","O"],"ans":1,"exp":"\"Bed\" uses the short E sound — like in \"ten\" or \"pet\"."},{"q":"Which word has the short U sound?","opts":["cake","bone","cup","feet"],"ans":2,"exp":"\"Cup\" has the short U sound — like \"bus\" or \"sun\"."}]},"qs":[{"q":"Which vowel is in \"cat\"?","opts":["A","E","I","U"],"ans":0,"exp":"\"Cat\" has the short A sound. A, E, I, O, U — A is the first vowel!"},{"q":"Which word rhymes with \"bed\"?","opts":["bad","red","bid","mud"],"ans":1,"exp":"\"Red\" rhymes with \"bed\" — both have the short E sound!"},{"q":"The word \"sit\" has which short vowel?","opts":["A","E","I","O"],"ans":2,"exp":"\"Sit\" has the short I sound — like \"big\" and \"fish\"."},{"q":"\"Dog\" has the same vowel sound as:","opts":["bag","bed","box","bug"],"ans":2,"exp":"\"Dog\" and \"box\" both have the short O sound!"},{"q":"Which word has the short U sound?","opts":["bone","bake","bus","beat"],"ans":2,"exp":"\"Bus\" has the short U sound — like \"cup\" and \"sun\"."},{"q":"How many vowels does English have?","opts":["3","4","5","6"],"ans":2,"exp":"English has 5 vowels: A, E, I, O, U!"}]}'::jsonb, 0),
('l0l', 'u0b', 'Consonant Sounds', 'Sons das Consoantes', '📣', 15, '{"learn":{"explanation":{"en":"Consonants are all letters that are NOT vowels. English has 21 consonants. Some sound the same as in Portuguese (B, D, F, M, N), but others are different! For example: W sounds like in \"water\" — there is no W sound in Portuguese.","pt":"As consoantes são todas as letras que NÃO são vogais. O inglês tem 21 consoantes. Algumas soam igual ao português (B, D, F, M, N), mas outras são diferentes! Por exemplo: o W soa como em \"water\" — não existe este som no português."},"examples":[{"en":"B — ball, book, bus","pt":"B — bola, livro, autocarro"},{"en":"D — dog, door, day","pt":"D — cão, porta, dia"},{"en":"W — water, window, work","pt":"W — água, janela, trabalho"},{"en":"TH — this, that, the","pt":"TH — este, aquele, o/a (artigo)"},{"en":"SH — shop, shoe, she","pt":"SH — loja, sapato, ela"}],"practice":[{"q":"Which letter makes the \"sh\" sound?","opts":["S alone","SH together","CH","TH"],"ans":1,"exp":"SH together makes the \"sh\" sound — like in \"shop\" and \"shoe\"."},{"q":"The word \"this\" starts with which sound?","opts":["S","T","TH","D"],"ans":2,"exp":"\"This\" starts with the TH sound — put your tongue between your teeth!"}]},"qs":[{"q":"Which TWO letters together make the sound in \"shop\"?","opts":["SS","ST","SH","SK"],"ans":2,"exp":"SH makes the sound in \"shop\", \"shoe\", \"she\"!"},{"q":"\"The\" starts with which sound?","opts":["D","T","TH","S"],"ans":2,"exp":"\"The\" starts with TH — a unique English sound!"},{"q":"Which letter makes a \"w\" sound?","opts":["V","U","W","WH"],"ans":2,"exp":"W makes the \"w\" sound in \"water\", \"work\", \"window\"!"},{"q":"B, D, F, M, N — these are:","opts":["vowels","consonants","numbers","colours"],"ans":1,"exp":"These are consonants — all letters that are NOT A, E, I, O, U!"},{"q":"How many consonants does English have?","opts":["5","15","21","26"],"ans":2,"exp":"English has 21 consonants and 5 vowels = 26 letters total!"},{"q":"Which word contains the TH sound?","opts":["shop","chin","this","fish"],"ans":2,"exp":"\"This\" has the TH sound — tongue between teeth!"}]}'::jsonb, 1),
('l0m', 'u0b', 'Spelling Your Name', 'Soletrar o Teu Nome', '✏️', 20, '{"learn":{"explanation":{"en":"Spelling means saying each letter of a word one by one. In English, when someone asks \"How do you spell that?\", you say each letter. For example, the name \"ANA\" is spelled: A-N-A. At a hotel or airport, people always ask you to spell your name.","pt":"Soletrar significa dizer cada letra de uma palavra uma a uma. Em inglês, quando alguém pergunta \"How do you spell that?\", dizes cada letra. Por exemplo, o nome \"ANA\" é soletrado: A-N-A. Num hotel ou aeroporto, as pessoas pedem sempre que soletres o teu nome."},"examples":[{"en":"A: How do you spell your name? B: S-E-B-A-S-T-I-A-N.","pt":"A: Como soletras o teu nome? B: S-E-B-A-S-T-I-A-N."},{"en":"Can you spell that for me, please?","pt":"Podes soletrar isso para mim, por favor?"},{"en":"My surname is Moiane — M-O-I-A-N-E.","pt":"O meu apelido é Moiane — M-O-I-A-N-E."}],"practice":[{"q":"How do you spell \"cat\"?","opts":["K-A-T","C-A-T","S-A-T","C-E-T"],"ans":1,"exp":"\"Cat\" is spelled C-A-T."},{"q":"What does \"How do you spell that?\" mean?","opts":["How do you say that?","Say each letter please","What is your name?","Write it down"],"ans":1,"exp":"\"How do you spell that?\" = Please say each letter!"}]},"qs":[{"q":"\"Dog\" is spelled:","opts":["D-O-G","D-U-G","D-A-G","T-O-G"],"ans":0,"exp":"D-O-G spells \"dog\"!"},{"q":"When do people ask you to spell your name?","opts":["At home eating dinner","At a hotel or airport","At the market","When playing football"],"ans":1,"exp":"At hotels, airports, offices — they ask you to spell your name!"},{"q":"\"Book\" is spelled:","opts":["B-O-K","B-U-K","B-O-O-K","P-O-O-K"],"ans":2,"exp":"B-O-O-K spells \"book\"!"},{"q":"How do you ask someone to spell a word?","opts":["How do you spell that?","What is that?","Who wrote that?","Where is that?"],"ans":0,"exp":"\"How do you spell that?\" — always helpful to ask!"},{"q":"\"Sun\" is spelled:","opts":["S-O-N","S-U-N","S-A-N","C-U-N"],"ans":1,"exp":"S-U-N spells \"sun\"! ☀️"},{"q":"Spelling means:","opts":["writing a story","saying each letter","reading fast","counting words"],"ans":1,"exp":"Spelling = saying each letter of a word one by one!"}]}'::jsonb, 2),
('l0n', 'u0b', 'Word Stress', 'Ênfase nas Palavras', '🎵', 15, '{"learn":{"explanation":{"en":"In English, one syllable in a word is always said LOUDER and LONGER than the others. This is called stress. For example: \"HEL-lo\" — the first part is stronger. \"to-DAY\" — the second part is stronger. Wrong stress can make it hard to understand you!","pt":"Em inglês, uma sílaba numa palavra é sempre dita MAIS ALTO e MAIS LONGO que as outras. Isso chama-se ênfase. Por exemplo: \"HEL-lo\" — a primeira parte é mais forte. \"to-DAY\" — a segunda parte é mais forte. A ênfase errada pode dificultar a compreensão!"},"examples":[{"en":"HEL-lo (stress on HEL)","pt":"HEL-lo (ênfase em HEL)"},{"en":"to-DAY (stress on DAY)","pt":"to-DAY (ênfase em DAY)"},{"en":"ENG-lish (stress on ENG)","pt":"ENG-lish (ênfase em ENG)"},{"en":"stu-DENT (stress on STU... wait: STU-dent!)","pt":"STU-dent (ênfase em STU)"},{"en":"a-GAIN (stress on GAIN)","pt":"a-GAIN (ênfase em GAIN)"}],"practice":[{"q":"In \"hello\", which part is stressed?","opts":["HEL","lo","both equally","neither"],"ans":0,"exp":"\"HEL-lo\" — the first syllable HEL is stressed!"},{"q":"In \"today\", which part is stressed?","opts":["TO","DAY","both","neither"],"ans":1,"exp":"\"to-DAY\" — the second syllable DAY is stressed!"}]},"qs":[{"q":"Word stress means:","opts":["speaking quietly","one syllable is louder","spelling correctly","writing neatly"],"ans":1,"exp":"Word stress = one syllable said LOUDER and LONGER!"},{"q":"In \"English\", the stress is on:","opts":["ENG","lish","both","neither"],"ans":0,"exp":"\"ENG-lish\" — ENG is stressed!"},{"q":"In \"again\", the stress is on:","opts":["A","GAIN","both","neither"],"ans":1,"exp":"\"a-GAIN\" — GAIN is stressed!"},{"q":"Wrong word stress can make people:","opts":["understand you better","not understand you","laugh at you","enjoy your English"],"ans":1,"exp":"Wrong stress = hard to understand! Practice the right stress!"},{"q":"In \"water\", the stress is on:","opts":["WA","ter","both","neither"],"ans":0,"exp":"\"WA-ter\" — WA is stressed! English words usually stress the first syllable."},{"q":"Which word has stress on the SECOND syllable?","opts":["English","water","today","morning"],"ans":2,"exp":"\"to-DAY\" has stress on the second syllable DAY!"}]}'::jsonb, 3),
('l0o', 'u0b', 'Common Pronunciation Mistakes', 'Erros Comuns de Pronúncia', '⚠️', 20, '{"learn":{"explanation":{"en":"Portuguese speakers often make the same mistakes in English pronunciation. The most common ones: (1) Adding \"ee\" sound before words starting with S+consonant — say \"school\" NOT \"eschool\". (2) The letter H is always pronounced — say \"hello\" NOT \"ello\". (3) The TH sound needs your tongue between your teeth!","pt":"Os falantes de português cometem frequentemente os mesmos erros na pronúncia inglesa. Os mais comuns: (1) Adicionar o som \"i\" antes de palavras com S+consoante — diz \"school\" NÃO \"escola\". (2) A letra H é sempre pronunciada — diz \"hello\" NÃO \"elo\". (3) O som TH precisa da tua língua entre os dentes!"},"examples":[{"en":"WRONG: \"eschool\" ✗   RIGHT: \"school\" ✓","pt":"ERRADO: \"escola\" ✗   CERTO: \"school\" ✓"},{"en":"WRONG: \"ello\" ✗   RIGHT: \"hello\" ✓","pt":"ERRADO: \"elo\" ✗   CERTO: \"hello\" ✓"},{"en":"WRONG: \"dis\" ✗   RIGHT: \"this\" ✓ (tongue between teeth!)","pt":"ERRADO: \"dis\" ✗   CERTO: \"this\" ✓ (língua entre os dentes!)"},{"en":"WRONG: \"tree\" for \"three\" ✗   RIGHT: \"three\" ✓","pt":"ERRADO: \"tree\" for \"three\" ✗   CERTO: \"three\" ✓"},{"en":"WRONG: \"wery\" ✗   RIGHT: \"very\" ✓","pt":"ERRADO: \"wery\" ✗   CERTO: \"very\" ✓"}],"practice":[{"q":"How do Portuguese speakers often mispronounce \"school\"?","opts":["skool","eschool","skhool","chool"],"ans":1,"exp":"Adding \"e\" before S+consonant is a common mistake. Just say \"school\"!"},{"q":"The H in \"hello\" is:","opts":["silent","pronounced","optional","written but not said"],"ans":1,"exp":"In English, H is always pronounced! Say \"hello\" with a clear H sound."}]},"qs":[{"q":"How should you pronounce \"hello\"?","opts":["ello","jello","HELL-o","chello"],"ans":2,"exp":"Say the H clearly! \"HELL-o\" — H is never silent in common words!"},{"q":"\"School\" — which is correct?","opts":["eschool","ischool","school","sschool"],"ans":2,"exp":"Just \"school\"! No extra vowel at the start!"},{"q":"For the TH sound, your tongue goes:","opts":["to the roof of your mouth","between your teeth","behind your teeth","to the back of your throat"],"ans":1,"exp":"Tongue between teeth! TH is unique to English!"},{"q":"\"This\" is often mispronounced as:","opts":["tis","dis","sis","zis"],"ans":1,"exp":"Portuguese speakers often say \"dis\" — remember the TH sound!"},{"q":"\"Very\" is mispronounced as:","opts":["wery","bery","fery","dery"],"ans":0,"exp":"\"Wery\" is a common mistake — V and W sound different in English!"},{"q":"The most important tip for English pronunciation is:","opts":["speak very fast","listen and repeat often","read silently","memorise rules"],"ans":1,"exp":"Listen and repeat! Your mouth needs practice — just like sport!"}]}'::jsonb, 4),
('l0p', 'u0c', 'Numbers 21-100', 'Números 21-100', '💯', 20, '{"learn":{"explanation":{"en":"After twenty (20), English numbers are built by combining tens and units: twenty-one (21), twenty-two (22)... thirty (30), forty (40), fifty (50), sixty (60), seventy (70), eighty (80), ninety (90), one hundred (100). Notice: forty has NO \"u\" — not \"fourty\"!","pt":"Depois de twenty (20), os números ingleses são construídos combinando dezenas e unidades: twenty-one (21), twenty-two (22)... thirty (30), forty (40), fifty (50), sixty (60), seventy (70), eighty (80), ninety (90), one hundred (100). Atenção: forty não tem \"u\" — não é \"fourty\"!"},"examples":[{"en":"21 — twenty-one","pt":"21 — vinte e um"},{"en":"35 — thirty-five","pt":"35 — trinta e cinco"},{"en":"50 — fifty","pt":"50 — cinquenta"},{"en":"77 — seventy-seven","pt":"77 — setenta e sete"},{"en":"100 — one hundred","pt":"100 — cem"}],"practice":[{"q":"How do you write 42 in English?","opts":["fourty-two","forty-two","forty two","fourtytwo"],"ans":1,"exp":"42 = forty-two. Remember: no \"u\" in forty!"},{"q":"What number is \"sixty-eight\"?","opts":["58","68","78","86"],"ans":1,"exp":"sixty = 60, eight = 8. So sixty-eight = 68!"}]},"qs":[{"q":"How do you say 30 in English?","opts":["thirthy","thirty","therty","thirsy"],"ans":1,"exp":"30 = thirty! Not \"thirthy\" — no extra H!"},{"q":"\"Forty\" is which number?","opts":["14","24","40","44"],"ans":2,"exp":"forty = 40. Remember: no \"u\" — not \"fourty\"!"},{"q":"How do you say 55?","opts":["fifty-five","fiftyfive","fifteen-five","fifty five"],"ans":0,"exp":"55 = fifty-five. Use a hyphen for two-digit numbers!"},{"q":"What number is \"ninety-nine\"?","opts":["90","99","91","89"],"ans":1,"exp":"ninety = 90, nine = 9. So ninety-nine = 99!"},{"q":"One hundred = ","opts":["10","100","1000","110"],"ans":1,"exp":"one hundred = 100! 💯"},{"q":"Which is WRONG?","opts":["twenty-one","thirty-five","fourty","sixty"],"ans":2,"exp":"\"Fourty\" is wrong! The correct spelling is FORTY — no \"u\"!"},{"q":"How do you say 73?","opts":["seventy-three","sixty-three","seventy-thirteen","seven-three"],"ans":0,"exp":"73 = seventy-three!"}]}'::jsonb, 0),
('l0q', 'u0c', 'Ordinal Numbers', 'Números Ordinais', '🥇', 15, '{"learn":{"explanation":{"en":"Ordinal numbers show position or order: 1st (first), 2nd (second), 3rd (third), 4th (fourth)... Most ordinals add -th to the number. But the first three are irregular: first, second, third. We use them for dates: \"My birthday is on the 15th of June.\"","pt":"Os números ordinais mostram posição ou ordem: 1st (first), 2nd (second), 3rd (third), 4th (fourth)... A maioria dos ordinais adiciona -th ao número. Mas os três primeiros são irregulares: first, second, third. Usamo-los para datas: \"O meu aniversário é no dia 15 de junho.\""},"examples":[{"en":"1st — first (primeiro)","pt":"1st — first (primeiro)"},{"en":"2nd — second (segundo)","pt":"2nd — second (segundo)"},{"en":"3rd — third (terceiro)","pt":"3rd — third (terceiro)"},{"en":"4th — fourth (quarto)","pt":"4th — fourth (quarto)"},{"en":"Today is the 1st of January.","pt":"Hoje é o dia 1 de Janeiro."}],"practice":[{"q":"What is the ordinal of 1?","opts":["oneth","firstly","first","oned"],"ans":2,"exp":"1st = first. It''s irregular — not \"oneth\"!"},{"q":"What is the ordinal of 5?","opts":["fiveth","fifth","fived","five"],"ans":1,"exp":"5th = fifth. Some ordinals change spelling slightly!"}]},"qs":[{"q":"1st in English is:","opts":["onest","first","firstone","premier"],"ans":1,"exp":"1st = first! Irregular ordinal."},{"q":"\"Second\" is which number?","opts":["1st","2nd","3rd","4th"],"ans":1,"exp":"second = 2nd!"},{"q":"What is the ordinal for 3?","opts":["threeth","thirteenth","third","threest"],"ans":2,"exp":"3rd = third! Another irregular ordinal."},{"q":"\"The 4th of July\" — what does 4th mean?","opts":["four","fourth","forty","fourteen"],"ans":1,"exp":"4th = fourth. Most ordinals from 4 onwards add -th!"},{"q":"Which is CORRECT?","opts":["the onest day","the firstth day","the first day","the day first"],"ans":2,"exp":"\"The first day\" — ordinals go BEFORE the noun!"},{"q":"\"My birthday is on the ___ of March.\" (10)","opts":["tenth","ten","tenth","tenith"],"ans":0,"exp":"10th = tenth!"}]}'::jsonb, 1),
('l0r', 'u0c', 'Telling the Time — Advanced', 'Dizer as Horas — Avançado', '⏰', 20, '{"learn":{"explanation":{"en":"You already know \"o''clock\", \"half past\" and \"quarter past/to\". Now let''s add more! For exact minutes, say the hour then the minutes: \"It''s 7:20 — seven twenty.\" For AM/PM: AM is morning (before noon), PM is afternoon/evening (after noon).","pt":"Já conheces \"o''clock\", \"half past\" e \"quarter past/to\". Agora vamos adicionar mais! Para minutos exactos, diz a hora e depois os minutos: \"É 7:20 — seven twenty.\" Para AM/PM: AM é de manhã (antes do meio-dia), PM é de tarde/noite (depois do meio-dia)."},"examples":[{"en":"7:20 — It''s seven twenty.","pt":"7:20 — São sete e vinte."},{"en":"3:45 — It''s three forty-five.","pt":"3:45 — São três e quarenta e cinco."},{"en":"8:00 AM — eight o''clock in the morning","pt":"8:00 AM — oito horas da manhã"},{"en":"6:00 PM — six o''clock in the evening","pt":"6:00 PM — seis horas da tarde"},{"en":"My class starts at 9 AM.","pt":"A minha aula começa às 9 da manhã."}],"practice":[{"q":"\"It''s 4:30\" — How do you say this?","opts":["four thirty","half three","four and half","thirty four"],"ans":0,"exp":"4:30 = \"four thirty\" OR \"half past four\". Both are correct!"},{"q":"AM means:","opts":["afternoon/evening","any moment","morning","after midnight only"],"ans":2,"exp":"AM = morning (from midnight to noon). PM = afternoon/evening."}]},"qs":[{"q":"\"It''s 9:15\" — How do you say this?","opts":["nine fifteen","quarter nine","nine quarter","fifteen nine"],"ans":0,"exp":"9:15 = nine fifteen OR quarter past nine!"},{"q":"\"It''s 2:50\" — How do you say this?","opts":["two fifty","fifty two","two and fifty","ten to three"],"ans":0,"exp":"2:50 = two fifty. (You can also say \"ten to three\"!)"},{"q":"What does PM stand for?","opts":["past midnight","post morning","afternoon/evening hours","prior morning"],"ans":2,"exp":"PM = afternoon and evening (noon to midnight)!"},{"q":"\"My work starts at 8 AM.\" This means:","opts":["8 in the evening","8 at night","8 in the morning","8 at noon"],"ans":2,"exp":"AM = morning! Work starts at 8 in the morning."},{"q":"\"It''s 12:00 PM.\" This is:","opts":["midnight","midday/noon","morning","evening"],"ans":1,"exp":"12:00 PM = midday/noon = meio-dia!"},{"q":"How do you say 11:45?","opts":["eleven forty-five","eleven and three-quarter","forty-five eleven","quarter eleven"],"ans":0,"exp":"11:45 = eleven forty-five!"}]}'::jsonb, 2),
('l0s', 'u0c', 'Days of the Week', 'Dias da Semana', '📆', 15, '{"learn":{"explanation":{"en":"The seven days of the week in English are: Monday, Tuesday, Wednesday, Thursday, Friday, Saturday, Sunday. Monday to Friday are \"weekdays\" (dias de semana). Saturday and Sunday are the \"weekend\" (fim de semana). In English, days are always written with a CAPITAL letter.","pt":"Os sete dias da semana em inglês são: Monday, Tuesday, Wednesday, Thursday, Friday, Saturday, Sunday. Monday a Friday são \"weekdays\" (dias de semana). Saturday e Sunday são o \"weekend\" (fim de semana). Em inglês, os dias são sempre escritos com LETRA MAIÚSCULA."},"examples":[{"en":"Monday — segunda-feira","pt":"Monday — segunda-feira"},{"en":"Wednesday — quarta-feira","pt":"Wednesday — quarta-feira"},{"en":"Friday — sexta-feira","pt":"Friday — sexta-feira"},{"en":"I go to school Monday to Friday.","pt":"Vou à escola de segunda a sexta."},{"en":"The weekend is Saturday and Sunday.","pt":"O fim de semana é sábado e domingo."}],"practice":[{"q":"What comes after Wednesday?","opts":["Tuesday","Thursday","Friday","Monday"],"ans":1,"exp":"Mon, Tue, WED, THU — Thursday comes after Wednesday!"},{"q":"\"Weekdays\" are:","opts":["only Saturday and Sunday","Monday to Friday","Wednesday only","all 7 days"],"ans":1,"exp":"Weekdays = Monday to Friday — the working/school days!"}]},"qs":[{"q":"\"Segunda-feira\" in English is:","opts":["Sunday","Monday","Tuesday","Saturday"],"ans":1,"exp":"Monday = Segunda-feira! Start of the week!"},{"q":"Which day comes after Tuesday?","opts":["Monday","Thursday","Wednesday","Friday"],"ans":2,"exp":"Mon, Tue, WED — Wednesday comes after Tuesday!"},{"q":"\"Sexta-feira\" in English is:","opts":["Thursday","Saturday","Sunday","Friday"],"ans":3,"exp":"Friday = Sexta-feira! End of the school week!"},{"q":"Saturday and Sunday are called:","opts":["weekdays","workdays","weekend","midweek"],"ans":2,"exp":"Saturday + Sunday = the weekend!"},{"q":"Days of the week are written with:","opts":["all lowercase","a capital letter","all uppercase","no specific rule"],"ans":1,"exp":"In English, days ALWAYS start with a capital letter: Monday, Tuesday..."},{"q":"How many weekdays are there?","opts":["2","5","7","10"],"ans":1,"exp":"5 weekdays: Monday, Tuesday, Wednesday, Thursday, Friday!"},{"q":"\"Domingo\" in English is:","opts":["Saturday","Monday","Sunday","Friday"],"ans":2,"exp":"Sunday = Domingo! The last day of the week!"}]}'::jsonb, 3),
('l0t', 'u0c', 'Months & Seasons', 'Meses e Estações', '🌸', 20, '{"learn":{"explanation":{"en":"The 12 months of the year: January, February, March, April, May, June, July, August, September, October, November, December. The 4 seasons are: spring (primavera), summer (verão), autumn/fall (outono), winter (inverno). In Mozambique, we have a rainy season (época das chuvas) and a dry season (época seca)!","pt":"Os 12 meses do ano: January, February, March, April, May, June, July, August, September, October, November, December. As 4 estações são: spring (primavera), summer (verão), autumn/fall (outono), winter (inverno). Em Moçambique, temos a época das chuvas e a época seca!"},"examples":[{"en":"January is the first month.","pt":"Janeiro é o primeiro mês."},{"en":"My birthday is in March.","pt":"O meu aniversário é em Março."},{"en":"Summer is hot. Winter is cold.","pt":"O verão é quente. O inverno é frio."},{"en":"The rainy season in Mozambique is from November to April.","pt":"A época das chuvas em Moçambique é de Novembro a Abril."},{"en":"December is the last month of the year.","pt":"Dezembro é o último mês do ano."}],"practice":[{"q":"Which month comes after March?","opts":["February","May","April","June"],"ans":2,"exp":"January, February, March, APRIL — April comes after March!"},{"q":"How many months are in a year?","opts":["10","11","12","13"],"ans":2,"exp":"There are 12 months in a year!"}]},"qs":[{"q":"\"Agosto\" in English is:","opts":["June","July","August","September"],"ans":2,"exp":"August = Agosto! ☀️"},{"q":"Which month comes after October?","opts":["September","December","November","August"],"ans":2,"exp":"...October, NOVEMBER, December — November comes after October!"},{"q":"\"Janeiro\" in English is:","opts":["June","January","July","February"],"ans":1,"exp":"January = Janeiro! The first month of the year!"},{"q":"How many seasons are there?","opts":["2","3","4","12"],"ans":2,"exp":"4 seasons: spring, summer, autumn, winter!"},{"q":"\"Summer\" in Portuguese is:","opts":["inverno","primavera","outono","verão"],"ans":3,"exp":"Summer = Verão! The hottest season!"},{"q":"Which is the last month of the year?","opts":["November","October","December","January"],"ans":2,"exp":"December is the 12th and last month! 🎄"},{"q":"\"February\" in Portuguese is:","opts":["Janeiro","Fevereiro","Março","Abril"],"ans":1,"exp":"February = Fevereiro! The shortest month."}]}'::jsonb, 4),
('l0u', 'u0d', 'Friends & People', 'Amigos e Pessoas', '👫', 15, '{"learn":{"explanation":{"en":"Beyond family, we talk about the people around us every day. A \"friend\" is someone you like and spend time with. A \"classmate\" is someone in your class. A \"neighbour\" is someone who lives near you. A \"colleague\" or \"workmate\" is someone you work with.","pt":"Para além da família, falamos das pessoas à nossa volta todos os dias. Um \"friend\" é alguém de quem gostas e com quem passas tempo. Um \"classmate\" é alguém da tua turma. Um \"neighbour\" é alguém que vive perto de ti. Um \"colleague\" ou \"workmate\" é alguém com quem trabalhas."},"examples":[{"en":"This is my best friend, Carlos.","pt":"Este é o meu melhor amigo, Carlos."},{"en":"My classmate is very funny.","pt":"O meu colega de turma é muito engraçado."},{"en":"My neighbour helps me sometimes.","pt":"O meu vizinho ajuda-me às vezes."},{"en":"She is my colleague at work.","pt":"Ela é minha colega de trabalho."},{"en":"I have many friends at school.","pt":"Tenho muitos amigos na escola."}],"practice":[{"q":"A \"classmate\" is:","opts":["a friend from childhood","someone in your class","a family member","a neighbour"],"ans":1,"exp":"Classmate = someone in your class at school!"},{"q":"A \"neighbour\" is:","opts":["someone at work","someone in your family","someone who lives near you","your best friend"],"ans":2,"exp":"Neighbour = someone who lives near you!"}]},"qs":[{"q":"\"Friend\" in Portuguese is:","opts":["vizinho","família","amigo","colega de trabalho"],"ans":2,"exp":"Friend = amigo/a!"},{"q":"A \"classmate\" is someone who:","opts":["works with you","lives near you","is in your class","is in your family"],"ans":2,"exp":"Classmate = colega de turma!"},{"q":"What do you call someone who lives next door to you?","opts":["classmate","colleague","friend","neighbour"],"ans":3,"exp":"Neighbour = vizinho/a!"},{"q":"\"Colleague\" means:","opts":["a family member","a workmate","a classmate","a neighbour"],"ans":1,"exp":"Colleague = colega de trabalho!"},{"q":"\"My best friend\" means:","opts":["my only friend","my most special friend","a new friend","a classmate"],"ans":1,"exp":"\"Best friend\" = melhor amigo — the most special one!"},{"q":"How do you introduce a friend?","opts":["\"This is my friend, Ana.\"","\"Ana is my classmate.\"","\"She neighbour me.\"","\"Ana friend I.\""],"ans":0,"exp":"\"This is my friend, Ana.\" — the perfect introduction!"}]}'::jsonb, 0),
('l0v', 'u0d', 'School & Classroom Objects', 'Escola e Objectos da Sala de Aula', '🏫', 20, '{"learn":{"explanation":{"en":"School vocabulary helps you talk about your daily learning environment. Key objects: book (livro), pen (caneta), pencil (lápis), notebook (caderno), bag (mochila), board (quadro), desk (secretária), chair (cadeira), ruler (régua), rubber/eraser (borracha).","pt":"O vocabulário escolar ajuda-te a falar sobre o teu ambiente de aprendizagem diário. Objectos importantes: book (livro), pen (caneta), pencil (lápis), notebook (caderno), bag (mochila), board (quadro), desk (secretária), chair (cadeira), ruler (régua), rubber/eraser (borracha)."},"examples":[{"en":"Open your book on page 10.","pt":"Abre o teu livro na página 10."},{"en":"I need a pen and a notebook.","pt":"Preciso de uma caneta e um caderno."},{"en":"The board is very useful in class.","pt":"O quadro é muito útil na aula."},{"en":"Put your bag under your desk.","pt":"Põe a tua mochila debaixo da secretária."},{"en":"Can I borrow your eraser?","pt":"Posso pedir emprestada a tua borracha?"}],"practice":[{"q":"What is a \"pencil\"?","opts":["caneta","lápis","régua","caderno"],"ans":1,"exp":"Pencil = lápis! A pen uses ink; a pencil uses graphite."},{"q":"What is a \"notebook\"?","opts":["livro","pasta","caderno","mochila"],"ans":2,"exp":"Notebook = caderno! Where you write your notes."}]},"qs":[{"q":"\"Mochila\" in English is:","opts":["book","bag","box","board"],"ans":1,"exp":"Bag (or schoolbag/backpack) = mochila!"},{"q":"What do you use to write on paper?","opts":["ruler","eraser","pen or pencil","board"],"ans":2,"exp":"Pen or pencil — you use these to write!"},{"q":"\"Quadro\" in English is:","opts":["book","desk","board","chair"],"ans":2,"exp":"Board = quadro! Where the teacher writes."},{"q":"What is an \"eraser\"?","opts":["lápis","borracha","régua","caderno"],"ans":1,"exp":"Eraser (or rubber) = borracha! Used to erase pencil marks."},{"q":"\"Ruler\" in Portuguese is:","opts":["caneta","régua","borracha","lápis"],"ans":1,"exp":"Ruler = régua! Used to draw straight lines and measure."},{"q":"Where do you sit in class?","opts":["on the board","at the desk/chair","in the bag","on the ruler"],"ans":1,"exp":"You sit at a desk on a chair!"},{"q":"\"Can I borrow your ___?\" (you need to write)","opts":["board","pen","desk","chair"],"ans":1,"exp":"\"Can I borrow your pen?\" — when you need to write!"}]}'::jsonb, 1),
('l0w', 'u0d', 'House & Rooms', 'Casa e Divisões', '🏡', 20, '{"learn":{"explanation":{"en":"A house has several rooms (divisões). The main ones are: bedroom (quarto), bathroom (casa de banho), kitchen (cozinha), living room (sala de estar), dining room (sala de jantar), and garden (jardim). We use \"in the\" to say where we are: \"I am in the kitchen.\"","pt":"Uma casa tem várias divisões. As principais são: bedroom (quarto), bathroom (casa de banho), kitchen (cozinha), living room (sala de estar), dining room (sala de jantar) e garden (jardim). Usamos \"in the\" para dizer onde estamos: \"I am in the kitchen.\""},"examples":[{"en":"I sleep in the bedroom.","pt":"Durmo no quarto."},{"en":"We eat in the dining room.","pt":"Comemos na sala de jantar."},{"en":"The TV is in the living room.","pt":"A televisão está na sala de estar."},{"en":"She is cooking in the kitchen.","pt":"Ela está a cozinhar na cozinha."},{"en":"The children play in the garden.","pt":"As crianças brincam no jardim."}],"practice":[{"q":"Where do you sleep?","opts":["kitchen","living room","bedroom","bathroom"],"ans":2,"exp":"Bedroom = quarto! Where you sleep."},{"q":"\"Cozinha\" in English is:","opts":["bathroom","bedroom","kitchen","living room"],"ans":2,"exp":"Kitchen = cozinha! Where you cook."}]},"qs":[{"q":"\"Quarto\" (where you sleep) in English is:","opts":["bathroom","kitchen","bedroom","living room"],"ans":2,"exp":"Bedroom = quarto! Where you sleep at night."},{"q":"Where do you cook food?","opts":["bedroom","kitchen","bathroom","garden"],"ans":1,"exp":"Kitchen = cozinha! Where you cook!"},{"q":"\"Living room\" in Portuguese is:","opts":["quarto","cozinha","sala de estar","casa de banho"],"ans":2,"exp":"Living room = sala de estar!"},{"q":"\"I am in the ___.\" (you are washing your hands)","opts":["bedroom","kitchen","bathroom","garden"],"ans":2,"exp":"Bathroom = casa de banho! Where you wash and shower."},{"q":"Where does the family eat together?","opts":["bedroom","garden","bathroom","dining room"],"ans":3,"exp":"Dining room = sala de jantar!"},{"q":"\"The children play outside.\" Outside means:","opts":["in the bedroom","in the bathroom","in the garden/outside","in the kitchen"],"ans":2,"exp":"Outside = garden or any outdoor area!"},{"q":"How do you say you are in a room?","opts":["I am at bedroom","I am in the bedroom","I am on the bedroom","I am of the bedroom"],"ans":1,"exp":"\"I am IN THE bedroom.\" — use \"in the\" for rooms!"}]}'::jsonb, 2),
('l0x', 'u0d', 'Furniture & Home Objects', 'Mobília e Objectos da Casa', '🛋️', 20, '{"learn":{"explanation":{"en":"Inside each room, there is furniture and objects. Key words: bed (cama), sofa (sofá), table (mesa), chair (cadeira), wardrobe (guarda-roupa), fridge (frigorífico), TV (televisão), lamp (candeeiro), mirror (espelho), window (janela), door (porta).","pt":"Dentro de cada divisão, há mobília e objectos. Palavras-chave: bed (cama), sofa (sofá), table (mesa), chair (cadeira), wardrobe (guarda-roupa), fridge (frigorífico), TV (televisão), lamp (candeeiro), mirror (espelho), window (janela), door (porta)."},"examples":[{"en":"The bed is big and comfortable.","pt":"A cama é grande e confortável."},{"en":"We sit on the sofa to watch TV.","pt":"Sentamo-nos no sofá para ver televisão."},{"en":"Open the window — it''s hot!","pt":"Abre a janela — está calor!"},{"en":"The food is in the fridge.","pt":"A comida está no frigorífico."},{"en":"I hang my clothes in the wardrobe.","pt":"Penduro as minhas roupas no guarda-roupa."}],"practice":[{"q":"What is a \"fridge\"?","opts":["fogão","frigorífico","forno","mesa"],"ans":1,"exp":"Fridge = frigorífico! Keeps your food cold."},{"q":"\"Cama\" in English is:","opts":["sofa","chair","desk","bed"],"ans":3,"exp":"Bed = cama! Where you sleep."}]},"qs":[{"q":"\"Cama\" in English is:","opts":["sofa","chair","table","bed"],"ans":3,"exp":"Bed = cama!"},{"q":"Where do you keep your clothes?","opts":["fridge","wardrobe","lamp","sofa"],"ans":1,"exp":"Wardrobe (guarda-roupa) = where you keep clothes!"},{"q":"\"Mesa\" in English is:","opts":["chair","table","lamp","door"],"ans":1,"exp":"Table = mesa!"},{"q":"What gives light in a room?","opts":["mirror","fridge","lamp","window"],"ans":2,"exp":"Lamp = candeeiro! Gives light in a room."},{"q":"You look at yourself in a:","opts":["window","fridge","mirror","door"],"ans":2,"exp":"Mirror = espelho! You see your reflection!"},{"q":"\"The food is in the ___.\"","opts":["wardrobe","fridge","mirror","lamp"],"ans":1,"exp":"Food goes in the fridge to stay cold!"},{"q":"\"Porta\" in English is:","opts":["window","wall","floor","door"],"ans":3,"exp":"Door = porta!"}]}'::jsonb, 3),
('l0y', 'u0d', 'Jobs & Occupations', 'Profissões e Ocupações', '👷', 20, '{"learn":{"explanation":{"en":"To talk about someone''s job, use \"He/She is a ___\" or \"I am a ___\". Key jobs: teacher (professor/a), doctor (médico), nurse (enfermeiro/a), engineer (engenheiro/a), driver (motorista), farmer (agricultor), student (estudante), manager (gerente), police officer (polícia), chef (cozinheiro/a).","pt":"Para falar sobre o trabalho de alguém, usa \"He/She is a ___\" ou \"I am a ___\". Profissões importantes: teacher (professor/a), doctor (médico), nurse (enfermeiro/a), engineer (engenheiro/a), driver (motorista), farmer (agricultor), student (estudante), manager (gerente), police officer (polícia), chef (cozinheiro/a)."},"examples":[{"en":"My mother is a nurse.","pt":"A minha mãe é enfermeira."},{"en":"He is a doctor at the hospital.","pt":"Ele é médico no hospital."},{"en":"I am a student.","pt":"Eu sou estudante."},{"en":"My father is a driver.","pt":"O meu pai é motorista."},{"en":"She is a teacher at our school.","pt":"Ela é professora na nossa escola."}],"practice":[{"q":"How do you say \"Eu sou estudante\"?","opts":["I is student","I am student","I am a student","I be student"],"ans":2,"exp":"\"I am a student.\" — Use \"a\" before job names!"},{"q":"\"Médico\" in English is:","opts":["nurse","driver","doctor","engineer"],"ans":2,"exp":"Doctor = médico!"}]},"qs":[{"q":"\"Teacher\" in Portuguese is:","opts":["médico","engenheiro","professor/a","motorista"],"ans":2,"exp":"Teacher = professor/a!"},{"q":"\"My mother is a ___.\" (enfermeira)","opts":["driver","nurse","farmer","manager"],"ans":1,"exp":"Nurse = enfermeiro/a!"},{"q":"How do you say \"Ela é médica\"?","opts":["She is doctor","She am a doctor","She is a doctor","She be doctor"],"ans":2,"exp":"\"She IS A doctor.\" — is + a + job!"},{"q":"\"Agricultor\" in English is:","opts":["driver","teacher","engineer","farmer"],"ans":3,"exp":"Farmer = agricultor!"},{"q":"A \"police officer\" is a:","opts":["motorista","polícia","cozinheiro","engenheiro"],"ans":1,"exp":"Police officer = polícia!"},{"q":"\"Student\" in Portuguese is:","opts":["professor","médico","estudante","gerente"],"ans":2,"exp":"Student = estudante!"},{"q":"\"He is ___ engineer.\" (fill in the blank)","opts":["a","an","the","is"],"ans":1,"exp":"\"He is AN engineer.\" — use \"an\" before words starting with a vowel sound!"}]}'::jsonb, 4),
('l0z', 'u0e', 'Food Vocabulary', 'Vocabulário de Comida', '🍕', 20, '{"learn":{"explanation":{"en":"Food is one of the most useful vocabulary topics! Key food words: rice (arroz), bread (pão), meat (carne), chicken (frango), fish (peixe), egg (ovo), vegetable (legume), fruit (fruta), soup (sopa), salad (salada). We say \"I like ___\" or \"I don''t like ___\" to talk about food preferences.","pt":"A comida é um dos temas de vocabulário mais úteis! Palavras de comida importantes: rice (arroz), bread (pão), meat (carne), chicken (frango), fish (peixe), egg (ovo), vegetable (legume), fruit (fruta), soup (sopa), salad (salada). Dizemos \"I like ___\" ou \"I don''t like ___\" para falar de preferências alimentares."},"examples":[{"en":"I like rice and chicken.","pt":"Eu gosto de arroz e frango."},{"en":"She doesn''t eat meat. She eats fish.","pt":"Ela não come carne. Come peixe."},{"en":"Fruits and vegetables are healthy.","pt":"As frutas e os legumes são saudáveis."},{"en":"Can I have some bread, please?","pt":"Posso ter um pouco de pão, por favor?"},{"en":"This soup is delicious!","pt":"Esta sopa é deliciosa!"}],"practice":[{"q":"\"Frango\" in English is:","opts":["fish","meat","chicken","egg"],"ans":2,"exp":"Chicken = frango!"},{"q":"\"I like ___\" — what comes after?","opts":["a verb","a noun (food)","a question","a number"],"ans":1,"exp":"\"I like rice.\" — \"like\" is followed by a noun!"}]},"qs":[{"q":"\"Arroz\" in English is:","opts":["bread","rice","meat","soup"],"ans":1,"exp":"Rice = arroz! 🍚"},{"q":"\"Peixe\" in English is:","opts":["chicken","beef","fish","pork"],"ans":2,"exp":"Fish = peixe! 🐟"},{"q":"\"I ___ like vegetables.\" (negative)","opts":["no","not","don''t","doesn''t"],"ans":2,"exp":"\"I don''t like vegetables.\" — use don''t for negative with I/you/we/they!"},{"q":"\"Pão\" in English is:","opts":["cake","bread","rice","egg"],"ans":1,"exp":"Bread = pão! 🍞"},{"q":"Which is a FRUIT?","opts":["carrot","onion","banana","potato"],"ans":2,"exp":"Banana is a fruit! 🍌"},{"q":"\"Ovo\" in English is:","opts":["oil","egg","ear","ice"],"ans":1,"exp":"Egg = ovo! 🥚"},{"q":"\"This soup is ___!\" (very good)","opts":["horrible","cold","delicious","raw"],"ans":2,"exp":"\"This soup is delicious!\" = Esta sopa é deliciosa!"}]}'::jsonb, 0),
('l0aa', 'u0e', 'Drinks & Beverages', 'Bebidas', '🥤', 15, '{"learn":{"explanation":{"en":"Key drink vocabulary: water (água), juice (sumo), milk (leite), tea (chá), coffee (café), soda/fizzy drink (refrigerante), beer (cerveja). To ask for a drink, say \"Can I have a ___?\" or \"I would like a ___.\" To ask what someone wants: \"What would you like to drink?\"","pt":"Vocabulário de bebidas importantes: water (água), juice (sumo), milk (leite), tea (chá), coffee (café), soda/fizzy drink (refrigerante), beer (cerveja). Para pedir uma bebida, diz \"Can I have a ___?\" ou \"I would like a ___.\" Para perguntar o que alguém quer: \"What would you like to drink?\""},"examples":[{"en":"Can I have a glass of water, please?","pt":"Posso ter um copo de água, por favor?"},{"en":"I drink coffee every morning.","pt":"Bebo café todas as manhãs."},{"en":"She prefers juice to soda.","pt":"Ela prefere sumo a refrigerante."},{"en":"What would you like to drink?","pt":"O que gostaria de beber?"},{"en":"I''d like a cold beer, please.","pt":"Queria uma cerveja fria, por favor."}],"practice":[{"q":"\"Água\" in English is:","opts":["juice","water","milk","beer"],"ans":1,"exp":"Water = água! The most important drink."},{"q":"How do you ask for a drink politely?","opts":["Give me water!","Water, now!","Can I have water, please?","I want water."],"ans":2,"exp":"\"Can I have water, please?\" — polite and correct!"}]},"qs":[{"q":"\"Leite\" in English is:","opts":["water","tea","milk","juice"],"ans":2,"exp":"Milk = leite! 🥛"},{"q":"\"Café\" in English is:","opts":["tea","coffee","juice","milk"],"ans":1,"exp":"Coffee = café! ☕"},{"q":"How do you ask what someone wants to drink?","opts":["What do you drink?","What would you like to drink?","You want drink?","Drink what?"],"ans":1,"exp":"\"What would you like to drink?\" — polite question!"},{"q":"\"Refrigerante\" in English is:","opts":["water","soda/fizzy drink","beer","tea"],"ans":1,"exp":"Soda or fizzy drink = refrigerante!"},{"q":"\"Can I have a glass of ___?\" (asking for water)","opts":["beer","milk","water","juice"],"ans":2,"exp":"\"Can I have a glass of water?\" — classic polite request!"},{"q":"\"Sumo\" in English is:","opts":["juice","water","milk","soda"],"ans":0,"exp":"Juice = sumo! 🍊"}]}'::jsonb, 1),
('l0bb', 'u0e', 'Clothes & Accessories', 'Roupas e Acessórios', '👗', 20, '{"learn":{"explanation":{"en":"Clothes vocabulary: shirt (camisa), t-shirt (t-shirt), trousers/pants (calças), dress (vestido), skirt (saia), shoes (sapatos), socks (meias), jacket (casaco), hat (chapéu), tie (gravata). To talk about clothes: \"She is wearing a red dress.\" \"I wear a uniform to school.\"","pt":"Vocabulário de roupas: shirt (camisa), t-shirt (t-shirt), trousers/pants (calças), dress (vestido), skirt (saia), shoes (sapatos), socks (meias), jacket (casaco), hat (chapéu), tie (gravata). Para falar de roupas: \"She is wearing a red dress.\" \"I wear a uniform to school.\""},"examples":[{"en":"He is wearing a blue shirt.","pt":"Ele está a usar uma camisa azul."},{"en":"I need new shoes.","pt":"Preciso de sapatos novos."},{"en":"She is wearing a beautiful dress.","pt":"Ela está a usar um vestido bonito."},{"en":"Don''t forget your jacket — it''s cold!","pt":"Não te esqueças do casaco — está frio!"},{"en":"I wear a school uniform every day.","pt":"Uso uniforme escolar todos os dias."}],"practice":[{"q":"\"Calças\" in English is:","opts":["dress","skirt","trousers","shirt"],"ans":2,"exp":"Trousers (or pants) = calças!"},{"q":"What do you wear on your feet?","opts":["hat","tie","socks and shoes","jacket"],"ans":2,"exp":"Socks and shoes go on your feet!"}]},"qs":[{"q":"\"Camisa\" in English is:","opts":["skirt","dress","shirt","jacket"],"ans":2,"exp":"Shirt = camisa!"},{"q":"\"She is ___ a dress.\" (wearing now)","opts":["wear","wore","wearing","wears"],"ans":2,"exp":"\"She IS WEARING a dress.\" — use is/am/are + wearing for now!"},{"q":"\"Sapatos\" in English is:","opts":["socks","shoes","sandals","boots"],"ans":1,"exp":"Shoes = sapatos! 👟"},{"q":"\"Chapéu\" in English is:","opts":["cap","tie","hat","scarf"],"ans":2,"exp":"Hat = chapéu! 🎩"},{"q":"What do you wear when it''s cold?","opts":["t-shirt","shorts","sandals","jacket"],"ans":3,"exp":"Jacket (casaco) keeps you warm when it''s cold!"},{"q":"\"Meias\" in English is:","opts":["shoes","socks","sandals","skirt"],"ans":1,"exp":"Socks = meias!"},{"q":"\"I ___ a uniform to school.\"","opts":["wears","is wearing","wear","wearing"],"ans":2,"exp":"\"I wear a uniform\" — simple habit uses Simple Present!"}]}'::jsonb, 2),
('l0cc', 'u0e', 'Transport & Getting Around', 'Transporte e Deslocação', '🚌', 20, '{"learn":{"explanation":{"en":"Transport vocabulary: bus (autocarro/machimbombo), car (carro), taxi (táxi), train (comboio), plane (avião), bicycle/bike (bicicleta), motorbike (moto), boat (barco), on foot (a pé). To say how you travel: \"I go to school BY bus.\" \"I travel BY plane.\" \"I go BY foot / on foot.\"","pt":"Vocabulário de transporte: bus (autocarro/machimbombo), car (carro), taxi (táxi), train (comboio), plane (avião), bicycle/bike (bicicleta), motorbike (moto), boat (barco), on foot (a pé). Para dizer como viaja: \"I go to school BY bus.\" \"I travel BY plane.\" \"I go BY foot / on foot.\""},"examples":[{"en":"I go to school by bus.","pt":"Vou à escola de autocarro."},{"en":"She travels to Beira by plane.","pt":"Ela viaja para a Beira de avião."},{"en":"He goes to the market on foot.","pt":"Ele vai ao mercado a pé."},{"en":"Can I get a taxi to the airport?","pt":"Posso apanhar um táxi para o aeroporto?"},{"en":"In Maputo, many people use chapas.","pt":"Em Maputo, muitas pessoas usam chapas."}],"practice":[{"q":"How do you say you travel by bus?","opts":["I go by bus","I go in bus","I travel bus","I use to bus"],"ans":0,"exp":"\"I go BY bus.\" — always use BY + transport!"},{"q":"\"Avião\" in English is:","opts":["boat","train","plane","bus"],"ans":2,"exp":"Plane = avião! ✈️"}]},"qs":[{"q":"\"Carro\" in English is:","opts":["bus","bike","car","taxi"],"ans":2,"exp":"Car = carro! 🚗"},{"q":"\"I go to work ___ bus.\"","opts":["in","at","by","on"],"ans":2,"exp":"\"By bus\" — always use BY with transport!"},{"q":"\"Bicicleta\" in English is:","opts":["motorbike","bicycle/bike","boat","car"],"ans":1,"exp":"Bicycle (or bike) = bicicleta! 🚲"},{"q":"\"She walks to school.\" This means she goes:","opts":["by car","by bus","on foot","by bike"],"ans":2,"exp":"Walks = on foot = a pé!"},{"q":"\"Avião\" in English is:","opts":["boat","train","plane","helicopter"],"ans":2,"exp":"Plane = avião! ✈️"},{"q":"\"Can I get a ___ to the airport?\"","opts":["bus","taxi","car","walk"],"ans":1,"exp":"\"Can I get a taxi?\" — taxis take you directly!"},{"q":"\"Barco\" in English is:","opts":["plane","train","boat","bus"],"ans":2,"exp":"Boat = barco! ⛵"}]}'::jsonb, 3),
('l0dd', 'u0e', 'Countries & Nationalities', 'Países e Nacionalidades', '🌍', 20, '{"learn":{"explanation":{"en":"To say where someone is from: \"I am FROM Mozambique.\" The nationality (adjectivo): \"I am Mozambican.\" Key countries and nationalities: Mozambique → Mozambican, Portugal → Portuguese, USA → American, UK → British, South Africa → South African, Brazil → Brazilian, China → Chinese, France → French.","pt":"Para dizer de onde alguém é: \"I am FROM Mozambique.\" A nacionalidade (adjectivo): \"I am Mozambican.\" Países e nacionalidades importantes: Mozambique → Mozambican, Portugal → Portuguese, USA → American, UK → British, South Africa → South African, Brazil → Brazilian, China → Chinese, France → French."},"examples":[{"en":"I am from Mozambique. I am Mozambican.","pt":"Eu sou de Moçambique. Eu sou moçambicano/a."},{"en":"She is from Portugal. She is Portuguese.","pt":"Ela é de Portugal. Ela é portuguesa."},{"en":"He is from Brazil. He is Brazilian.","pt":"Ele é do Brasil. Ele é brasileiro."},{"en":"Where are you from?","pt":"De onde és?"},{"en":"I am from the UK. I am British.","pt":"Sou do Reino Unido. Sou britânico/a."}],"practice":[{"q":"The nationality of someone from Brazil is:","opts":["Brazilish","Brazilor","Brazilian","Brazili"],"ans":2,"exp":"Brazil → Brazilian!"},{"q":"How do you ask where someone is from?","opts":["Where is you from?","Where are you from?","Where you from?","From where you?"],"ans":1,"exp":"\"Where ARE you from?\" — correct question form!"}]},"qs":[{"q":"The nationality from Portugal is:","opts":["Portugali","Portugese","Portuguese","Portugu"],"ans":2,"exp":"Portugal → Portuguese!"},{"q":"\"I am FROM ___.\" — What comes next?","opts":["a verb","a country","a number","a colour"],"ans":1,"exp":"\"I am from MOZAMBIQUE.\" — from + country name!"},{"q":"Someone from the USA is:","opts":["American","USAian","Unitedstater","Americano"],"ans":0,"exp":"USA → American!"},{"q":"\"Where are you ___?\"","opts":["of","at","from","by"],"ans":2,"exp":"\"Where are you FROM?\" — asking about someone''s country!"},{"q":"Someone from South Africa is:","opts":["African","Southie","South African","Afrikan"],"ans":2,"exp":"South Africa → South African!"},{"q":"\"He is from China.\" His nationality is:","opts":["Chineese","Chinese","Chinian","Chinish"],"ans":1,"exp":"China → Chinese!"},{"q":"Someone from France is:","opts":["Francese","Frenchman","French","Francian"],"ans":2,"exp":"France → French!"}]}'::jsonb, 4),
('l0ee', 'u0f', 'Common Action Verbs', 'Verbos de Acção Comuns', '🏃', 20, '{"learn":{"explanation":{"en":"Action verbs describe what people do. The most common ones: go (ir), come (vir), eat (comer), drink (beber), sleep (dormir), work (trabalhar), study (estudar), play (jogar/brincar), buy (comprar), sell (vender), walk (andar), run (correr), talk (falar), listen (ouvir), read (ler), write (escrever).","pt":"Os verbos de acção descrevem o que as pessoas fazem. Os mais comuns: go (ir), come (vir), eat (comer), drink (beber), sleep (dormir), work (trabalhar), study (estudar), play (jogar/brincar), buy (comprar), sell (vender), walk (andar), run (correr), talk (falar), listen (ouvir), read (ler), write (escrever)."},"examples":[{"en":"I go to school every day.","pt":"Vou à escola todos os dias."},{"en":"She studies English at night.","pt":"Ela estuda inglês à noite."},{"en":"They play football on Saturdays.","pt":"Eles jogam futebol aos sábados."},{"en":"He works at the hospital.","pt":"Ele trabalha no hospital."},{"en":"We buy food at the market.","pt":"Compramos comida no mercado."}],"practice":[{"q":"\"Estudar\" in English is:","opts":["sleep","study","work","play"],"ans":1,"exp":"Study = estudar!"},{"q":"\"They ___ football on weekends.\"","opts":["plays","playing","play","to play"],"ans":2,"exp":"\"They PLAY\" — They/We/I/You use the base verb!"}]},"qs":[{"q":"\"Dormir\" in English is:","opts":["eat","drink","sleep","rest"],"ans":2,"exp":"Sleep = dormir! 😴"},{"q":"\"Trabalhar\" in English is:","opts":["study","play","walk","work"],"ans":3,"exp":"Work = trabalhar!"},{"q":"\"She ___ at the market.\" (buying things)","opts":["buy","buys","buying","bought"],"ans":1,"exp":"\"She BUYS\" — she/he/it adds -s in Simple Present!"},{"q":"\"Correr\" in English is:","opts":["walk","swim","run","jump"],"ans":2,"exp":"Run = correr! 🏃"},{"q":"\"I ___ English every day.\"","opts":["studies","studying","study","to study"],"ans":2,"exp":"\"I STUDY English.\" — I always uses base verb!"},{"q":"\"Escrever\" in English is:","opts":["read","write","speak","listen"],"ans":1,"exp":"Write = escrever! ✍️"},{"q":"\"He ___ to school by bus.\"","opts":["go","goes","going","gone"],"ans":1,"exp":"\"He GOES\" — he/she/it adds -es or -s!"}]}'::jsonb, 0),
('l0ff', 'u0f', 'Yes/No Questions', 'Perguntas de Sim/Não', '❓', 20, '{"learn":{"explanation":{"en":"Yes/No questions in English use DO or DOES at the start. Use DO with I/you/we/they. Use DOES with he/she/it. The main verb stays in base form. \"Do you speak English?\" \"Does she live here?\" To answer: \"Yes, I do.\" / \"No, I don''t.\" \"Yes, she does.\" / \"No, she doesn''t.\"","pt":"As perguntas de Sim/Não em inglês usam DO ou DOES no início. Usa DO com I/you/we/they. Usa DOES com he/she/it. O verbo principal fica na forma base. \"Do you speak English?\" \"Does she live here?\" Para responder: \"Yes, I do.\" / \"No, I don''t.\" \"Yes, she does.\" / \"No, she doesn''t.\""},"examples":[{"en":"Do you speak English? Yes, I do.","pt":"Falas inglês? Sim, falo."},{"en":"Does he live in Maputo? No, he doesn''t.","pt":"Ele vive em Maputo? Não, não vive."},{"en":"Do they eat meat? No, they don''t.","pt":"Eles comem carne? Não, não comem."},{"en":"Does she work here? Yes, she does.","pt":"Ela trabalha aqui? Sim, trabalha."},{"en":"Do you like coffee? Yes, I do!","pt":"Gostas de café? Sim, gosto!"}],"practice":[{"q":"\"___ you speak English?\"","opts":["Is","Are","Do","Does"],"ans":2,"exp":"\"Do you speak?\" — use DO with I/you/we/they!"},{"q":"\"___ she like football?\"","opts":["Do","Is","Are","Does"],"ans":3,"exp":"\"Does she like?\" — use DOES with he/she/it!"}]},"qs":[{"q":"\"___ you live in Maputo?\"","opts":["Is","Are","Do","Does"],"ans":2,"exp":"\"Do you live?\" — use DO with you!"},{"q":"\"___ he work here?\"","opts":["Do","Is","Does","Are"],"ans":2,"exp":"\"Does he work?\" — use DOES with he!"},{"q":"\"Do you like fish?\" — Answer YES:","opts":["Yes, I like.","Yes, I does.","Yes, I do.","Yes, do I."],"ans":2,"exp":"\"Yes, I DO.\" — short positive answer!"},{"q":"\"Does she speak French?\" — Answer NO:","opts":["No, she don''t.","No, she doesn''t.","No, she not.","No, she isn''t."],"ans":1,"exp":"\"No, she doesn''t.\" — short negative answer!"},{"q":"\"Do they ___ English?\" (understand)","opts":["understands","understanding","understand","to understand"],"ans":2,"exp":"After DO/DOES, use the base verb: understand!"},{"q":"\"Does ___ have a car?\" (he)","opts":["he has","has he","he have","he"],"ans":2,"exp":"\"Does he HAVE a car?\" — base verb after does!"},{"q":"The correct yes/no question form is:","opts":["You do speak English?","Speak you English?","Do you speak English?","You speak English?"],"ans":2,"exp":"\"DO you SPEAK English?\" — DO first, then subject, then verb!"}]}'::jsonb, 1),
('l0gg', 'u0f', 'Simple Commands (Imperatives)', 'Comandos Simples (Imperativos)', '📢', 15, '{"learn":{"explanation":{"en":"Commands (imperatives) use the base verb directly — no subject needed! Positive: \"Open the window!\" \"Sit down!\" \"Please speak slowly.\" Negative commands use \"Don''t\": \"Don''t run!\" \"Don''t be late!\" \"Please don''t close the door.\" We add \"please\" to be polite.","pt":"Os comandos (imperativos) usam o verbo base directamente — sem sujeito! Positivo: \"Open the window!\" \"Sit down!\" \"Please speak slowly.\" Comandos negativos usam \"Don''t\": \"Don''t run!\" \"Don''t be late!\" \"Please don''t close the door.\" Adicionamos \"please\" para ser educado."},"examples":[{"en":"Open your books, please!","pt":"Abram os livros, por favor!"},{"en":"Don''t talk in class!","pt":"Não fales na aula!"},{"en":"Sit down and listen.","pt":"Senta-te e ouve."},{"en":"Please speak slowly — I''m learning!","pt":"Por favor fala devagar — estou a aprender!"},{"en":"Don''t be late for class!","pt":"Não chegues atrasado/a à aula!"}],"practice":[{"q":"Commands use:","opts":["the base verb","verb + ing","verb + ed","subject + verb"],"ans":0,"exp":"Commands use the BASE verb directly! \"Sit!\", \"Run!\", \"Open!\""},{"q":"To make a negative command, use:","opts":["No + verb","Not + verb","Don''t + verb","Doesn''t + verb"],"ans":2,"exp":"\"Don''t run!\" — Don''t + base verb for negative commands!"}]},"qs":[{"q":"\"Please ___ the door.\" (close it)","opts":["closes","closing","close","to close"],"ans":2,"exp":"\"Please CLOSE the door.\" — base verb in commands!"},{"q":"\"___ talk in class!\"","opts":["No","Not","Don''t","Doesn''t"],"ans":2,"exp":"\"DON''T talk in class!\" — Don''t + verb for negative commands!"},{"q":"Which is a CORRECT command?","opts":["You sit down!","Sits down!","Sit down!","Sitting down!"],"ans":2,"exp":"\"Sit down!\" — just the base verb, no subject!"},{"q":"\"Please speak ___.\" (asking for slower speech)","opts":["fast","quickly","slowly","loudly"],"ans":2,"exp":"\"Please speak SLOWLY.\" — slowly = devagar!"},{"q":"\"___ be late!\" (warning)","opts":["No","Not","Don''t","Doesn''t"],"ans":2,"exp":"\"DON''T be late!\" — a polite warning!"},{"q":"To make a command polite, add:","opts":["sorry","excuse","please","thank"],"ans":2,"exp":"Add PLEASE to make commands polite: \"Sit down, please!\""}]}'::jsonb, 2),
('l0hh', 'u0f', 'Daily Routine Vocabulary', 'Vocabulário de Rotina Diária', '🌅', 20, '{"learn":{"explanation":{"en":"Daily routine vocabulary describes what you do from morning to night. Key phrases: wake up (acordar), get up (levantar-se), have breakfast (tomar o pequeno-almoço), go to school/work (ir à escola/ao trabalho), have lunch (almoçar), come home (chegar a casa), have dinner (jantar), go to bed (ir dormir).","pt":"O vocabulário de rotina diária descreve o que fazes da manhã à noite. Frases-chave: wake up (acordar), get up (levantar-se), have breakfast (tomar o pequeno-almoço), go to school/work (ir à escola/ao trabalho), have lunch (almoçar), come home (chegar a casa), have dinner (jantar), go to bed (ir dormir)."},"examples":[{"en":"I wake up at 6 AM every day.","pt":"Acordo às 6 da manhã todos os dias."},{"en":"After breakfast, I go to school.","pt":"Depois do pequeno-almoço, vou à escola."},{"en":"We have lunch at 12:30.","pt":"Almoçamos às 12:30."},{"en":"I come home at 5 PM.","pt":"Chego a casa às 17h."},{"en":"I go to bed at 10 PM.","pt":"Vou dormir às 22h."}],"practice":[{"q":"\"Wake up\" means:","opts":["dormir","levantar-se da cama/acordar","jantar","ir trabalhar"],"ans":1,"exp":"Wake up = acordar/levantar-se!"},{"q":"\"Have dinner\" means:","opts":["ter o pequeno-almoço","almoçar","jantar","comer um lanche"],"ans":2,"exp":"Have dinner = jantar! The evening meal."}]},"qs":[{"q":"\"Get up\" means:","opts":["dormir","acordar e levantar-se","almoçar","ir para a cama"],"ans":1,"exp":"Get up = levantar-se da cama!"},{"q":"\"Have breakfast\" means:","opts":["jantar","almoçar","tomar o pequeno-almoço","lanchar"],"ans":2,"exp":"Have breakfast = tomar o pequeno-almoço! The first meal of the day."},{"q":"\"Go to bed\" means:","opts":["ir ao trabalho","ir à escola","ir dormir","levantar-se"],"ans":2,"exp":"Go to bed = ir dormir! 🛏️"},{"q":"\"I ___ up at 7 every morning.\"","opts":["goes","wake","wakes","going"],"ans":1,"exp":"\"I WAKE up\" — wake up is the phrase!"},{"q":"\"Have lunch\" in Portuguese is:","opts":["tomar o pequeno-almoço","lanchar","jantar","almoçar"],"ans":3,"exp":"Have lunch = almoçar!"},{"q":"What do you do FIRST in the morning?","opts":["go to bed","have dinner","wake up","come home"],"ans":2,"exp":"First you wake up, then get up, then have breakfast!"},{"q":"\"Come home\" means:","opts":["sair de casa","ir para a escola","chegar a casa","ir trabalhar"],"ans":2,"exp":"Come home = chegar a casa!"}]}'::jsonb, 3),
('l0ii', 'u0f', 'Weather & Nature Vocabulary', 'Vocabulário do Tempo e Natureza', '🌤️', 15, '{"learn":{"explanation":{"en":"Weather vocabulary helps you describe the day. Key words: sunny (ensolarado), cloudy (nublado), rainy (chuvoso), windy (ventoso), hot (quente), cold (frio), warm (morno/quente), cool (fresco), storm (tempestade), flood (inundação). In Mozambique: \"It''s hot and sunny in October.\" \"It rains a lot in January.\"","pt":"O vocabulário do tempo ajuda-te a descrever o dia. Palavras-chave: sunny (ensolarado), cloudy (nublado), rainy (chuvoso), windy (ventoso), hot (quente), cold (frio), warm (morno/quente), cool (fresco), storm (tempestade), flood (inundação). Em Moçambique: \"It''s hot and sunny in October.\" \"It rains a lot in January.\""},"examples":[{"en":"It''s hot and sunny today in Maputo.","pt":"Está quente e ensolarado hoje em Maputo."},{"en":"It rains a lot in January.","pt":"Chove muito em Janeiro."},{"en":"It''s very windy — close the windows!","pt":"Está muito ventoso — fecha as janelas!"},{"en":"Bring an umbrella — it''s cloudy!","pt":"Traz um guarda-chuva — está nublado!"},{"en":"There was a big storm last night.","pt":"Houve uma tempestade grande ontem à noite."}],"practice":[{"q":"\"Ensolarado\" in English is:","opts":["rainy","cloudy","sunny","windy"],"ans":2,"exp":"Sunny = ensolarado! ☀️"},{"q":"What do you use when it rains?","opts":["sunglasses","jacket","umbrella","hat"],"ans":2,"exp":"An umbrella keeps you dry in the rain!"}]},"qs":[{"q":"\"Chuvoso\" in English is:","opts":["sunny","cloudy","rainy","windy"],"ans":2,"exp":"Rainy = chuvoso! 🌧️"},{"q":"\"It''s ___ today.\" (the sun is shining)","opts":["rainy","cloudy","windy","sunny"],"ans":3,"exp":"\"It''s sunny today.\" ☀️"},{"q":"\"Frio\" in English is:","opts":["hot","warm","cold","cool"],"ans":2,"exp":"Cold = frio! ❄️"},{"q":"\"Tempestade\" in English is:","opts":["flood","storm","rain","wind"],"ans":1,"exp":"Storm = tempestade! ⛈️"},{"q":"\"Bring an umbrella — it''s ___!\"","opts":["hot","sunny","rainy","cool"],"ans":2,"exp":"\"It''s rainy!\" — you need an umbrella for rain!"},{"q":"\"It''s ___ in Maputo in October.\" (very warm)","opts":["cold","freezing","snowy","hot"],"ans":3,"exp":"\"It''s HOT in Maputo in October!\" 🌡️"}]}'::jsonb, 4),
('l0za', 'u0g', 'Countries & Nationalities', 'Países e Nacionalidades', '🌍', 20, '{"learn":{"explanation":{"en":"Every country has a name and a nationality. In English, both the country name and the nationality start with a CAPITAL letter. To say where you are from: \"I am from Mozambique. I am Mozambican.\" Some nationalities add -an, -ian, -ish, or -ese to the country name.","pt":"Cada país tem um nome e uma nacionalidade. Em inglês, tanto o nome do país como a nacionalidade começam com letra MAIÚSCULA. Para dizer de onde és: \"I am from Mozambique. I am Mozambican.\" Algumas nacionalidades adicionam -an, -ian, -ish ou -ese ao nome do país."},"examples":[{"en":"I am from Mozambique. I am Mozambican.","pt":"Eu sou de Moçambique. Eu sou moçambicano/a."},{"en":"She is from Portugal. She is Portuguese.","pt":"Ela é de Portugal. Ela é portuguesa."},{"en":"He is from Brazil. He is Brazilian.","pt":"Ele é do Brasil. Ele é brasileiro."},{"en":"They are from South Africa. They are South African.","pt":"Eles são da África do Sul. Eles são sul-africanos."},{"en":"Where are you from? — I am from Tanzania.","pt":"De onde és? — Eu sou da Tanzânia."}],"practice":[{"q":"A person from Brazil is called:","opts":["Brazilish","Brazilese","Brazilian","Brazilan"],"ans":2,"exp":"Brazil → Brazilian. Most countries ending in a consonant add -ian."},{"q":"Complete: \"She is ___ Portugal.\" (origin)","opts":["of","in","from","at"],"ans":2,"exp":"\"From\" tells us origin — where someone comes from."}]},"qs":[{"q":"A person from Mozambique is called:","opts":["Mozambican","Mozambiquese","Mozambish","Mozambiquian"],"ans":0,"exp":"Mozambique → Mozambican! 🇲🇿"},{"q":"\"Where are you from?\" asks about:","opts":["your age","your country","your job","your name"],"ans":1,"exp":"\"Where are you from?\" = De onde és? It asks about your country of origin!"},{"q":"Country names in English start with:","opts":["a small letter","a capital letter","a number","any letter"],"ans":1,"exp":"ALL country names start with a CAPITAL letter in English! Portugal, Brazil, Mozambique..."},{"q":"A person from Portugal is:","opts":["Portugu","Portugugese","Portuguese","Portugalian"],"ans":2,"exp":"Portugal → Portuguese! Notice the spelling change!"},{"q":"\"She is from Kenya.\" Kenya is:","opts":["a job","a city","a country","a language"],"ans":2,"exp":"Kenya is a country in East Africa! 🇰🇪"},{"q":"Complete: \"I am ___ Mozambique.\"","opts":["at","from","of","in"],"ans":1,"exp":"\"I am FROM Mozambique.\" = Eu sou de Moçambique!"},{"q":"A person from South Africa is:","opts":["South Africanish","South African","Southafrican","South Africanese"],"ans":1,"exp":"South Africa → South African! Two words, both capitalized!"}]}'::jsonb, 0),
('l0zb', 'u0g', 'Jobs & Professions', 'Trabalhos e Profissões', '👩‍⚕️', 20, '{"learn":{"explanation":{"en":"To talk about your job, say \"I am a...\" or \"I work as a...\". Jobs describe what a person does every day. In English, job titles usually do not change for men and women — a female doctor is still a \"doctor\", not a \"doctora\". Common exception: actor/actress.","pt":"Para falar do teu trabalho, diz \"I am a...\" ou \"I work as a...\". Os trabalhos descrevem o que uma pessoa faz todos os dias. Em inglês, os títulos de trabalho normalmente não mudam para homens e mulheres — uma médica é simplesmente \"doctor\", não \"doctora\". Excepção comum: actor/actress."},"examples":[{"en":"I am a teacher. I teach English.","pt":"Eu sou professor/a. Eu ensino inglês."},{"en":"She is a nurse. She works in a hospital.","pt":"Ela é enfermeira. Ela trabalha num hospital."},{"en":"He is a driver. He drives a bus.","pt":"Ele é motorista. Ele conduz um autocarro."},{"en":"What do you do? — I am a student.","pt":"O que fazes? — Eu sou estudante."},{"en":"My mother is a market seller.","pt":"A minha mãe é vendedeira no mercado."}],"practice":[{"q":"How do you say your job? \"I ___ a teacher.\"","opts":["have","do","am","work"],"ans":2,"exp":"\"I AM a teacher.\" Use \"am\" for identity/job!"},{"q":"\"What do you do?\" is asking about your:","opts":["age","nationality","job","family"],"ans":2,"exp":"\"What do you do?\" = Qual é a tua profissão? It asks about your job!"}]},"qs":[{"q":"To say your job you say: \"I ___ a doctor.\"","opts":["have","am","do","work"],"ans":1,"exp":"\"I AM a doctor.\" = Eu sou médico/a. Use \"am\" with \"I\"!"},{"q":"\"What do you do?\" asks about:","opts":["your name","your job","your age","your country"],"ans":1,"exp":"\"What do you do?\" = Qual é a tua profissão? Asking about your job!"},{"q":"A person who teaches is a:","opts":["driver","farmer","teacher","nurse"],"ans":2,"exp":"A TEACHER teaches! \"I am a teacher. I teach English.\""},{"q":"A person who helps sick people in a hospital is a:","opts":["teacher","driver","farmer","nurse"],"ans":3,"exp":"A NURSE (or doctor) helps sick people in a hospital!"},{"q":"\"She is a nurse. She ___ in a hospital.\"","opts":["teaches","works","drives","sells"],"ans":1,"exp":"\"She WORKS in a hospital.\" = Ela trabalha num hospital!"},{"q":"A person who grows food on land is a:","opts":["nurse","teacher","farmer","pilot"],"ans":2,"exp":"A FARMER grows food! Very common in Mozambique! 🌱"},{"q":"Which sentence is CORRECT?","opts":["I am teacher.","I am a teacher.","I is a teacher.","I am the teacher a."],"ans":1,"exp":"\"I am A teacher.\" — don''t forget the article \"a\"!"}]}'::jsonb, 1),
('l0zc', 'u0g', 'Getting Around — Transport', 'Meios de Transporte', '🚌', 20, '{"learn":{"explanation":{"en":"Transport words tell us HOW we travel. Use \"I go by...\" or \"I take the...\" for most transport. For walking: \"I go on foot\" or \"I walk.\" Common vehicles in Mozambique and the world: bus (chapa/autocarro), car, taxi, bicycle, motorcycle, train, plane, boat.","pt":"As palavras de transporte dizem-nos COMO viajamos. Usa \"I go by...\" ou \"I take the...\" para a maioria dos transportes. Para caminhar: \"I go on foot\" ou \"I walk.\" Veículos comuns em Moçambique e no mundo: bus (chapa/autocarro), car, taxi, bicycle, motorcycle, train, plane, boat."},"examples":[{"en":"I go to school by bus.","pt":"Eu vou para a escola de autocarro (chapa)."},{"en":"She takes a taxi to work.","pt":"Ela apanha um táxi para o trabalho."},{"en":"He rides a bicycle every day.","pt":"Ele anda de bicicleta todos os dias."},{"en":"We travel to Beira by plane.","pt":"Nós viajamos para a Beira de avião."},{"en":"I walk to the market — it''s not far.","pt":"Eu vou a pé ao mercado — não é longe."}],"practice":[{"q":"Complete: \"I go to work ___ bus.\"","opts":["in","on","by","at"],"ans":2,"exp":"\"BY bus/car/plane/train.\" — use BY for transport methods!"},{"q":"A large vehicle that carries many passengers is a:","opts":["bicycle","taxi","bus","motorcycle"],"ans":2,"exp":"A BUS carries many passengers. In Maputo — the chapa!"}]},"qs":[{"q":"\"I go to school ___ bus.\"","opts":["at","in","on","by"],"ans":3,"exp":"\"By bus\" = de autocarro. Always use BY with transport!"},{"q":"What do you use to fly between cities?","opts":["bicycle","boat","plane","train"],"ans":2,"exp":"A PLANE (avião) flies between cities! 🛩️"},{"q":"\"I walk to school\" means I go:","opts":["by car","on foot","by bus","by bicycle"],"ans":1,"exp":"\"Walk\" = go on foot = a pé! No vehicle!"},{"q":"In Mozambique, a popular local transport is the:","opts":["subway","tram","chapa/bus","helicopter"],"ans":2,"exp":"The chapa (minibus/bus) is the most common transport in Mozambique! 🚌"},{"q":"\"She ___ a taxi to work.\"","opts":["rides","drives","takes","flies"],"ans":2,"exp":"\"She TAKES a taxi.\" = Ela apanha um táxi!"},{"q":"A two-wheeled vehicle you pedal is a:","opts":["car","motorcycle","bicycle","boat"],"ans":2,"exp":"A BICYCLE (bicicleta) has two wheels and you pedal it! 🚲"},{"q":"\"We travel to Beira ___ plane.\"","opts":["on","by","in","with"],"ans":1,"exp":"\"By plane\" = de avião. Use BY for all transport methods!"}]}'::jsonb, 2),
('l0zd', 'u0g', 'Your Home — Rooms & Furniture', 'A Tua Casa — Divisões e Móveis', '🏠', 20, '{"learn":{"explanation":{"en":"Every home has different rooms (divisões). The most important rooms are: bedroom (quarto), bathroom (casa de banho), kitchen (cozinha), living room (sala de estar), and dining room (sala de jantar). In each room you find different furniture (móveis) — the things inside the room.","pt":"Cada casa tem divisões diferentes. As divisões mais importantes são: bedroom (quarto), bathroom (casa de banho), kitchen (cozinha), living room (sala de estar) e dining room (sala de jantar). Em cada divisão encontras móveis diferentes — as coisas dentro da divisão."},"examples":[{"en":"I sleep in the bedroom.","pt":"Eu durmo no quarto."},{"en":"We eat in the dining room.","pt":"Nós comemos na sala de jantar."},{"en":"The sofa is in the living room.","pt":"O sofá está na sala de estar."},{"en":"There is a fridge in the kitchen.","pt":"Há um frigorífico na cozinha."},{"en":"The toilet and the shower are in the bathroom.","pt":"A sanita e o chuveiro estão na casa de banho."}],"practice":[{"q":"Where do you sleep?","opts":["kitchen","bathroom","bedroom","living room"],"ans":2,"exp":"You sleep in the BEDROOM (quarto)!"},{"q":"Where do you cook food?","opts":["bedroom","bathroom","living room","kitchen"],"ans":3,"exp":"You cook in the KITCHEN (cozinha)!"}]},"qs":[{"q":"Where do you sleep?","opts":["kitchen","living room","bedroom","bathroom"],"ans":2,"exp":"You sleep in the BEDROOM = quarto!"},{"q":"Where do you wash yourself?","opts":["bedroom","bathroom","kitchen","dining room"],"ans":1,"exp":"You wash in the BATHROOM = casa de banho!"},{"q":"\"The sofa is in the ___.\"","opts":["kitchen","bathroom","bedroom","living room"],"ans":3,"exp":"The sofa is in the LIVING ROOM = sala de estar!"},{"q":"Where do you cook food?","opts":["dining room","bedroom","bathroom","kitchen"],"ans":3,"exp":"You cook in the KITCHEN = cozinha!"},{"q":"\"Fridge\" is found in the:","opts":["bedroom","bathroom","living room","kitchen"],"ans":3,"exp":"The FRIDGE (frigorífico) is in the kitchen!"},{"q":"\"We eat in the ___ room.\"","opts":["bed","living","dining","bath"],"ans":2,"exp":"\"Dining room\" = sala de jantar — where you eat meals!"},{"q":"A \"bed\" is a piece of:","opts":["food","transport","furniture","clothing"],"ans":2,"exp":"A BED is furniture (móvel) — things you find in a room!"}]}'::jsonb, 3),
('l0ze', 'u0g', 'Animals — Pets & Wild', 'Animais — Domésticos e Selvagens', '🦁', 20, '{"learn":{"explanation":{"en":"Animals can be pets (animals that live with people) or wild animals (animals in nature). Common pets: dog (cão), cat (gato), bird (pássaro), fish (peixe). Famous African wild animals: lion (leão), elephant (elefante), zebra, giraffe (girafa), crocodile (crocodilo). Each animal makes a different sound.","pt":"Os animais podem ser domésticos (animais que vivem com pessoas) ou selvagens (animais na natureza). Animais domésticos comuns: dog (cão), cat (gato), bird (pássaro), fish (peixe). Famosos animais selvagens africanos: lion (leão), elephant (elefante), zebra, giraffe (girafa), crocodile (crocodilo). Cada animal faz um som diferente."},"examples":[{"en":"My dog is called Rex. He is very friendly.","pt":"O meu cão chama-se Rex. Ele é muito amigável."},{"en":"Lions live in the savanna.","pt":"Os leões vivem na savana."},{"en":"Elephants are the biggest land animals.","pt":"Os elefantes são os maiores animais terrestres."},{"en":"A cat says \"meow\". A dog says \"woof\".","pt":"Um gato diz \"miau\". Um cão diz \"au au\"."},{"en":"Mozambique has crocodiles in its rivers.","pt":"Moçambique tem crocodilos nos seus rios."}],"practice":[{"q":"Which animal is a common pet?","opts":["lion","elephant","dog","crocodile"],"ans":2,"exp":"Dogs are common pets! Lions and elephants are wild animals."},{"q":"\"Lion\" in Portuguese is:","opts":["elefante","girafa","leão","zebra"],"ans":2,"exp":"Lion = leão! The king of the African savanna! 🦁"}]},"qs":[{"q":"Which animal is a pet?","opts":["lion","crocodile","cat","elephant"],"ans":2,"exp":"A CAT (gato) is a common pet! The others are wild animals."},{"q":"\"Elephant\" in Portuguese is:","opts":["leão","girafa","crocodilo","elefante"],"ans":3,"exp":"Elephant = elefante! The biggest land animal on Earth! 🐘"},{"q":"What sound does a cat make?","opts":["woof","moo","meow","roar"],"ans":2,"exp":"A cat says \"meow\"! (miau in Portuguese) 🐱"},{"q":"Wild animals live:","opts":["in houses","with families","in nature","in classrooms"],"ans":2,"exp":"Wild animals live IN NATURE — forests, rivers, savanna!"},{"q":"Which animal do you find in African rivers?","opts":["penguin","crocodile","polar bear","wolf"],"ans":1,"exp":"CROCODILES live in African rivers — including Mozambique''s rivers! 🐊"},{"q":"\"Giraffe\" in Portuguese is:","opts":["girafa","zebra","rinoceronte","hipopótamo"],"ans":0,"exp":"Giraffe = girafa! They have very long necks! 🦒"},{"q":"Which is a WILD animal?","opts":["dog","cat","lion","fish"],"ans":2,"exp":"LION is a wild animal — it lives in the savanna, not in houses!"}]}'::jsonb, 4),
('l0h1', 'u0h', 'Family Members', 'Membros da Família', '👨‍👩‍👧‍👦', 15, '{"learn":{"explanation":{"en":"Family vocabulary is essential in English. Core words: mother/mum, father/dad, brother, sister, son, daughter, grandfather/grandpa, grandmother/grandma, uncle, aunt, cousin, nephew, niece.","pt":"O vocabulário da família é essencial em inglês. Palavras-chave: mother/mum (mãe), father/dad (pai), brother (irmão), sister (irmã), son (filho), daughter (filha), grandfather/grandpa (avô), grandmother/grandma (avó), uncle (tio), aunt (tia), cousin (primo/a)."},"examples":[{"en":"My mother is a nurse.","pt":"A minha mãe é enfermeira."},{"en":"I have two brothers and one sister.","pt":"Eu tenho dois irmãos e uma irmã."},{"en":"My grandmother lives in Inhambane.","pt":"A minha avó vive em Inhambane."}],"practice":[{"q":"What does \"daughter\" mean?","opts":["filho","filha","irmã","prima"],"ans":1,"exp":"\"Daughter\" = filha. \"Son\" = filho."},{"q":"What is \"avó\" in English?","opts":["aunt","mother","grandmother","sister"],"ans":2,"exp":"\"Grandmother\" or \"grandma\" = avó."}]},"qs":[{"q":"What does \"brother\" mean?","opts":["irmã","primo","irmão","pai"],"ans":2,"exp":"\"Brother\" = irmão. \"Sister\" = irmã."},{"q":"\"Mum\" is an informal word for:","opts":["sister","aunt","grandmother","mother"],"ans":3,"exp":"\"Mum\" (British) / \"Mom\" (American) = mother = mãe."},{"q":"What is \"tio\" in English?","opts":["cousin","nephew","uncle","brother"],"ans":2,"exp":"\"Uncle\" = tio. \"Aunt\" = tia."},{"q":"\"I have one ___ and she is older than me.\"","opts":["son","brother","sister","uncle"],"ans":2,"exp":"\"Sister\" = irmã. She = female."},{"q":"What is \"neto/neta\" in English?","opts":["nephew","grandchild","cousin","son"],"ans":1,"exp":"\"Grandchild\" = neto/neta. Plural: grandchildren."}]}'::jsonb, 0),
('l0h2', 'u0h', 'Describing Your Family', 'Descrever a Tua Família', '🏠', 15, '{"learn":{"explanation":{"en":"To describe your family, use \"have got\" or \"have\": \"I have three brothers.\" Use \"My [family member] is/are...\" for descriptions. Ask \"Do you have any brothers or sisters?\" to learn about someone''s family.","pt":"Para descrever a tua família, usa \"have got\" ou \"have\": \"I have three brothers.\" Usa \"My [membro da família] is/are...\" para descrições. Pergunta \"Do you have any brothers or sisters?\" para saber sobre a família de alguém."},"examples":[{"en":"I have a big family.","pt":"Eu tenho uma família grande."},{"en":"My father is tall and kind.","pt":"O meu pai é alto e gentil."},{"en":"Do you have any siblings?","pt":"Tens irmãos ou irmãs?"}],"practice":[{"q":"\"Siblings\" means:","opts":["parents","brothers and/or sisters","cousins","grandparents"],"ans":1,"exp":"\"Siblings\" = brothers and sisters collectively."},{"q":"How do you ask about someone''s family?","opts":["Who is your family?","Do you have any siblings?","Are you a family?","What family?"],"ans":1,"exp":"\"Do you have any siblings?\" is the natural question."}]},"qs":[{"q":"\"I ___ two sisters and one brother.\"","opts":["am","have","do","be"],"ans":1,"exp":"\"I HAVE two sisters.\" — Use \"have\" for family members."},{"q":"\"My parents ___ both teachers.\"","opts":["is","am","are","be"],"ans":2,"exp":"\"My parents ARE both teachers.\" — plural → are."},{"q":"What does \"only child\" mean?","opts":["The youngest child","Having no brothers or sisters","The oldest child","Having one sibling"],"ans":1,"exp":"\"Only child\" = filho/a único/a — no brothers or sisters."},{"q":"\"Do you ___ any brothers?\"","opts":["are","have","be","do"],"ans":1,"exp":"\"Do you HAVE any brothers?\" — standard family question."},{"q":"\"My ___ is 65 years old and retired.\"","opts":["nephew","cousin","grandfather","sibling"],"ans":2,"exp":"\"Grandfather\" = avô. 65 years old, retired → likely a grandparent."}]}'::jsonb, 1),
('l0h3', 'u0h', 'Describing People''s Appearance', 'Descrever a Aparência das Pessoas', '👀', 20, '{"learn":{"explanation":{"en":"Describe appearance using \"She/He is...\" + adjective, or \"She/He has...\" + noun. Hair: long, short, curly, straight, dark, blonde. Eyes: brown, green, blue. Height: tall, short, medium height. Build: slim, heavy, muscular.","pt":"Descreve a aparência usando \"She/He is...\" + adjectivo, ou \"She/He has...\" + substantivo. Cabelo: long (comprido), short (curto), curly (encaracolado), straight (liso), dark (escuro), blonde (loiro). Olhos: brown, green, blue. Altura: tall, short, medium."},"examples":[{"en":"She has long dark hair and brown eyes.","pt":"Ela tem cabelo comprido e escuro e olhos castanhos."},{"en":"My father is tall and has a beard.","pt":"O meu pai é alto e tem barba."},{"en":"He is medium height with curly hair.","pt":"Ele é de altura média com cabelo encaracolado."}],"practice":[{"q":"\"Tall\" is used to describe:","opts":["hair colour","a person''s height","eye colour","weight"],"ans":1,"exp":"\"Tall\" = alto. Describes HEIGHT."},{"q":"\"She has curly hair\" describes:","opts":["eye colour","height","hair type","personality"],"ans":2,"exp":"\"Curly\" = encaracolado. Describes hair type."}]},"qs":[{"q":"\"He ___ blue eyes.\"","opts":["is","are","has","have"],"ans":2,"exp":"\"He HAS blue eyes.\" — Use \"has/have\" for features (eyes, hair, nose)."},{"q":"\"She ___ very tall.\"","opts":["has","have","is","are"],"ans":2,"exp":"\"She IS very tall.\" — Use \"is/are\" for adjectives (tall, short, slim)."},{"q":"What does \"curly\" describe?","opts":["height","eyes","hair","weight"],"ans":2,"exp":"\"Curly hair\" = cabelo encaracolado. It describes hair type."},{"q":"Opposite of \"tall\":","opts":["slim","heavy","short","young"],"ans":2,"exp":"\"Short\" = baixo/a. tall ↔ short."},{"q":"\"She has a ___ build.\" (very thin)","opts":["heavy","slim","tall","curly"],"ans":1,"exp":"\"Slim\" = magro/a. Describes body type."}]}'::jsonb, 2),
('l0h4', 'u0h', 'Personality & Character', 'Personalidade e Carácter', '😊', 20, '{"learn":{"explanation":{"en":"Personality adjectives describe HOW someone behaves. Positive: kind, friendly, funny, patient, generous, hardworking, honest. Negative: lazy, rude, selfish, impatient, shy. Use \"She is very...\" or \"He seems...\"","pt":"Os adjectivos de personalidade descrevem COMO alguém se comporta. Positivos: kind (gentil), friendly (simpático), funny (engraçado), patient (paciente), generous (generoso), hardworking (trabalhador), honest (honesto). Negativos: lazy (preguiçoso), rude (grosseiro), shy (tímido)."},"examples":[{"en":"My sister is very kind and generous.","pt":"A minha irmã é muito gentil e generosa."},{"en":"He is hardworking but a little shy.","pt":"Ele é trabalhador mas um pouco tímido."},{"en":"She seems friendly but I don''t know her well.","pt":"Ela parece simpática mas não a conheço bem."}],"practice":[{"q":"\"Shy\" means:","opts":["loud","nervous around people","very friendly","hardworking"],"ans":1,"exp":"\"Shy\" = tímido — uncomfortable or nervous around people."},{"q":"Opposite of \"lazy\":","opts":["rude","friendly","hardworking","selfish"],"ans":2,"exp":"\"Hardworking\" is the opposite of \"lazy\"."}]},"qs":[{"q":"\"Kind\" means:","opts":["rude","generous and caring","lazy","impatient"],"ans":1,"exp":"\"Kind\" = gentil e atencioso. She''s always kind to everyone."},{"q":"Which is a POSITIVE personality trait?","opts":["selfish","rude","lazy","generous"],"ans":3,"exp":"\"Generous\" = generoso. A positive quality! The others are negative."},{"q":"\"He never shares anything.\" He is:","opts":["generous","kind","selfish","patient"],"ans":2,"exp":"\"Selfish\" = egoísta — someone who never shares or thinks only of themselves."},{"q":"\"She always tells the truth.\" She is:","opts":["rude","honest","shy","lazy"],"ans":1,"exp":"\"Honest\" = honesto — always tells the truth."},{"q":"\"Funny\" means:","opts":["serious","sad","makes people laugh","shy"],"ans":2,"exp":"\"Funny\" = engraçado — someone who makes you laugh."}]}'::jsonb, 3),
('l0h5', 'u0h', 'Relationships & Social Life', 'Relações e Vida Social', '🤝', 20, '{"learn":{"explanation":{"en":"Relationship vocabulary: friend, best friend, classmate, colleague, neighbour, partner, boyfriend/girlfriend. Use \"We have been friends for...\" to describe duration. \"We met at school/work/church.\"","pt":"Vocabulário de relações: friend (amigo), best friend (melhor amigo), classmate (colega de turma), colleague (colega de trabalho), neighbour (vizinho), partner (parceiro), boyfriend/girlfriend (namorado/a). Usa \"We have been friends for...\" para descrever duração."},"examples":[{"en":"She is my best friend. We met at school.","pt":"Ela é a minha melhor amiga. Conhecemo-nos na escola."},{"en":"My neighbour is very friendly.","pt":"O meu vizinho é muito simpático."},{"en":"We have been colleagues for two years.","pt":"Somos colegas há dois anos."}],"practice":[{"q":"\"Neighbour\" means:","opts":["classmate","person who lives nearby","best friend","colleague"],"ans":1,"exp":"\"Neighbour\" = vizinho — person who lives near you."},{"q":"Where do you meet \"classmates\"?","opts":["at work","at church","at school","at the gym"],"ans":2,"exp":"\"Classmates\" = colegas de turma — people in your class at school."}]},"qs":[{"q":"\"Colleague\" means:","opts":["neighbour","best friend","someone you work with","family member"],"ans":2,"exp":"\"Colleague\" = colega de trabalho — someone you work with."},{"q":"\"We met at university.\" We are probably:","opts":["neighbours","classmates","colleagues","cousins"],"ans":1,"exp":"\"Classmates\" or course-mates — people who study together at the same institution."},{"q":"What is \"namorada\" in English?","opts":["friend","colleague","girlfriend","neighbour"],"ans":2,"exp":"\"Girlfriend\" = namorada. \"Boyfriend\" = namorado."},{"q":"\"We have been ___ for 10 years.\" (great friends)","opts":["classmates","best friends","neighbours","colleagues"],"ans":1,"exp":"\"Best friends\" = melhores amigos. A very close, long friendship."},{"q":"\"She lives next door.\" She is my:","opts":["colleague","classmate","neighbour","cousin"],"ans":2,"exp":"\"Neighbour\" = vizinho. \"Next door\" = ao lado."}]}'::jsonb, 4),
('l0h6', 'u0h', 'My Family Story', 'A Minha História de Família', '📖', 25, '{"learn":{"explanation":{"en":"Putting it together: describe your family using all the vocabulary you have learned. Use \"My [person] is...\" for descriptions, \"We live in...\" for location, and \"We always...\" for habits. Practice talking about your own family!","pt":"Juntar tudo: descreve a tua família usando todo o vocabulário que aprendeste. Usa \"My [person] is...\" para descrições, \"We live in...\" para localização, e \"We always...\" para hábitos. Pratica falar sobre a tua própria família!"},"examples":[{"en":"I come from a family of five.","pt":"Venho de uma família de cinco pessoas."},{"en":"We live in Maputo but my grandparents are from Gaza.","pt":"Vivemos em Maputo mas os meus avós são de Gaza."},{"en":"My family always eats together on Sundays.","pt":"A minha família come sempre junta aos domingos."}],"practice":[{"q":"\"I come from a family of five\" means:","opts":["I have 5 brothers","There are 5 people in my family","I am the 5th child","I have 5 cousins"],"ans":1,"exp":"\"A family of five\" = uma família de cinco membros."},{"q":"\"My grandparents are from Gaza\" means:","opts":["They live in Gaza now","They were born in Gaza","They work in Gaza","They visited Gaza"],"ans":1,"exp":"\"From\" = natural de, originally from that place."}]},"qs":[{"q":"\"I come from a ___ family.\" (many people)","opts":["small","only","large","single"],"ans":2,"exp":"\"Large family\" = família grande. Many members."},{"q":"\"We always ___ together on Sundays.\" (have a meal)","opts":["play","eat","work","study"],"ans":1,"exp":"\"We always EAT together on Sundays.\" — eat = comer."},{"q":"How do you say \"Somos de Nampula\"?","opts":["We are from Nampula.","We live to Nampula.","We go in Nampula.","We at Nampula."],"ans":0,"exp":"\"We are FROM Nampula.\" — use \"from\" for origin."},{"q":"\"My mother is a ___ woman.\" (very caring)","opts":["funny","kind","shy","rude"],"ans":1,"exp":"\"Kind\" = gentil. A caring person is kind."},{"q":"To describe your family in English, you use:","opts":["only \"is\"","only \"has\"","both \"is\" and \"has\"","only \"are\""],"ans":2,"exp":"Use \"is/are\" for adjectives (She is tall), \"has/have\" for features (She has long hair)."}]}'::jsonb, 5),
('l1', 'u1', 'Verb To Be', 'Verbo To Be', '🔵', 20, '{"learn":{"explanation":{"en":"The verb \"to be\" (am/is/are) is the most important verb in English. Use \"am\" with I, \"is\" with he/she/it, and \"are\" with you/we/they. It connects a subject to a description, name, or place.","pt":"O verbo \"to be\" (am/is/are) é o verbo mais importante do inglês. Usa \"am\" com I, \"is\" com he/she/it, e \"are\" com you/we/they. Ele liga o sujeito a uma descrição, nome ou lugar."},"examples":[{"en":"I am a student.","pt":"Eu sou estudante."},{"en":"She is happy.","pt":"Ela está feliz."},{"en":"They are from Maputo.","pt":"Eles são de Maputo."}],"practice":[{"q":"Complete: \"He ___ my friend.\"","opts":["am","is","are","be"],"ans":1,"exp":"He/She/It → IS."},{"q":"Which is correct?","opts":["You is tired.","You am tired.","You are tired.","You be tired."],"ans":2,"exp":"You → ARE."}]},"qs":[{"q":"\"She ___ a teacher.\"","opts":["am","is","are","be"],"ans":1,"exp":"\"She IS a teacher.\" — He/She/It = IS"},{"q":"\"We ___ from Mozambique.\"","opts":["am","is","are","be"],"ans":2,"exp":"\"We ARE from Mozambique.\" — We/You/They = ARE"},{"q":"Negative of \"I am happy\":","opts":["I is not happy.","I am not happy.","I are not happy.","I be not happy."],"ans":1,"exp":"\"I am not happy.\" — I + am. Negative = am not / I''m not"},{"q":"\"___ you a student?\"","opts":["Am","Is","Are","Be"],"ans":2,"exp":"\"ARE you a student?\" — You = ARE"},{"q":"\"They ___ not here.\"","opts":["am","is","are","was"],"ans":2,"exp":"\"They ARE not here.\" — They + are. Negative = are not / aren''t"}]}'::jsonb, 0),
('l2', 'u1', 'Subject Pronouns', 'Pronomes Pessoais', '👤', 15, '{"learn":{"explanation":{"en":"Subject pronouns (I, you, he, she, it, we, they) replace the name of a person, animal, or thing so we don''t repeat it. Use \"he\" for men, \"she\" for women, \"it\" for animals/objects, and \"they\" for two or more.","pt":"Os pronomes pessoais (I, you, he, she, it, we, they) substituem o nome de uma pessoa, animal ou coisa para não o repetirmos. Usa \"he\" para homens, \"she\" para mulheres, \"it\" para animais/objectos, e \"they\" para dois ou mais."},"examples":[{"en":"Maria is kind. She is kind.","pt":"A Maria é gentil. Ela é gentil."},{"en":"The cat is small. It is small.","pt":"O gato é pequeno. Ele é pequeno."},{"en":"Pedro and Ana are here. They are here.","pt":"O Pedro e a Ana estão aqui. Eles estão aqui."}],"practice":[{"q":"Which pronoun replaces \"João\"?","opts":["She","It","He","They"],"ans":2,"exp":"João is a man → HE."},{"q":"Which pronoun replaces \"the books\"?","opts":["It","He","They","She"],"ans":2,"exp":"Plural things → THEY."}]},"qs":[{"q":"What pronoun replaces \"Ana\"?","opts":["He","She","It","They"],"ans":1,"exp":"\"Ana\" is a woman → SHE. \"Ana is kind.\" = \"She is kind.\""},{"q":"\"The dog is hungry.\" Replace \"the dog\":","opts":["He","She","It","They"],"ans":2,"exp":"Animals and objects = IT. \"The dog is hungry.\" = \"It is hungry.\""},{"q":"\"Pedro and I are friends.\" Replace with one pronoun:","opts":["We","They","He","You"],"ans":0,"exp":"\"Pedro and I\" = WE. \"We are friends.\""},{"q":"What pronoun replaces \"Mr. Silva\"?","opts":["She","It","He","They"],"ans":2,"exp":"\"Mr. Silva\" is a man → HE. \"Mr. Silva works here.\" = \"He works here.\""},{"q":"\"Ana and Pedro are students.\" Replace:","opts":["We","He","She","They"],"ans":3,"exp":"\"Ana and Pedro\" = THEY. Two or more people = THEY."}]}'::jsonb, 1),
('l3', 'u1', 'Simple Present', 'Presente Simples', '⭕', 25, '{"learn":{"explanation":{"en":"We use Simple Present for habits, routines, and facts. Add -s or -es to the verb with he/she/it: \"She works.\" With I/you/we/they, use the base verb: \"I work.\" Signal words: always, usually, every day.","pt":"Usamos o Presente Simples para hábitos, rotinas e factos. Adiciona -s ou -es ao verbo com he/she/it: \"She works.\" Com I/you/we/they, usa o verbo base: \"I work.\" Palavras-sinal: always, usually, every day."},"examples":[{"en":"I study English every day.","pt":"Eu estudo inglês todos os dias."},{"en":"She works in a hospital.","pt":"Ela trabalha num hospital."},{"en":"We don''t eat meat.","pt":"Nós não comemos carne."}],"practice":[{"q":"Complete: \"He ___ TV every night.\"","opts":["watch","watchs","watches","watching"],"ans":2,"exp":"watch ends in -ch → add -es: watches."},{"q":"Which signals Simple Present?","opts":["right now","yesterday","usually","tomorrow"],"ans":2,"exp":"\"usually\" = repeated habit = Simple Present."}]},"qs":[{"q":"Which is correct?","opts":["She go to school.","She goes to school.","She is go.","She going."],"ans":1,"exp":"\"She GOES to school.\" — He/She/It adds -s or -es!"},{"q":"\"He ___ like coffee.\"","opts":["don''t","doesn''t","not","isn''t"],"ans":1,"exp":"\"He DOESN''T like coffee.\" — Negative: doesn''t + base verb."},{"q":"\"I ___ English every day.\"","opts":["studies","studying","study","to study"],"ans":2,"exp":"\"I STUDY English every day.\" — I/You/We/They: base form, no -s."},{"q":"Which word signals Simple Present?","opts":["yesterday","now","always","tomorrow"],"ans":2,"exp":"\"Always\", \"usually\", \"often\", \"every day\" = Simple Present signals!"},{"q":"\"___ she live in Maputo?\"","opts":["Do","Does","Is","Are"],"ans":1,"exp":"\"DOES she live in Maputo?\" — Questions with He/She/It use DOES."}]}'::jsonb, 2),
('l4', 'u1', 'Present Continuous', 'Presente Contínuo', '🔄', 25, '{"learn":{"explanation":{"en":"We use Present Continuous (am/is/are + verb-ing) for actions happening right now, or temporary situations. \"Look! She is dancing.\" Stative verbs like know, like, want usually don''t take -ing.","pt":"Usamos o Presente Contínuo (am/is/are + verbo-ing) para acções a acontecer agora, ou situações temporárias. \"Olha! Ela está a dançar.\" Verbos de estado como know, like, want normalmente não levam -ing."},"examples":[{"en":"I am studying right now.","pt":"Eu estou a estudar agora."},{"en":"They are playing football.","pt":"Eles estão a jogar futebol."},{"en":"It is raining outside.","pt":"Está a chover lá fora."}],"practice":[{"q":"Complete: \"We ___ lunch now.\"","opts":["eat","eats","are eating","ate"],"ans":2,"exp":"Right now = Present Continuous: are eating."},{"q":"Which verb usually does NOT take -ing?","opts":["run","know","play","write"],"ans":1,"exp":"\"Know\" is a stative verb — no -ing."}]},"qs":[{"q":"\"Look! It ___ (rain)\"","opts":["rains","rained","is raining","has rained"],"ans":2,"exp":"\"It IS RAINING.\" — Present Continuous = am/is/are + verb-ing."},{"q":"Which is WRONG?","opts":["I am eating.","She is running.","They are knowing.","We are waiting."],"ans":2,"exp":"\"Knowing\" is wrong! Stative verbs (know, like, want) cannot use -ing."},{"q":"\"They ___ playing football now.\"","opts":["is","am","are","be"],"ans":2,"exp":"\"They ARE playing.\" — They + are + verb-ing."},{"q":"What is \"write\" in Present Continuous?","opts":["writing","writeing","writting","wrotes"],"ans":0,"exp":"\"Writing\" — drop the silent \"e\" before adding -ing: write → writing."},{"q":"\"She is always ___ her keys.\" (lose)","opts":["lose","lost","losing","to lose"],"ans":2,"exp":"\"Losing\" — continuous = verb-ing. lose → losing!"}]}'::jsonb, 3),
('l5', 'u1', 'Present Perfect', 'Presente Perfeito', '✅', 30, '{"learn":{"explanation":{"en":"Present Perfect (have/has + past participle) connects the past to the present — for experiences or actions with no exact time. \"I have visited Paris.\" Use \"has\" with he/she/it, \"have\" with the rest.","pt":"O Present Perfect (have/has + particípio passado) liga o passado ao presente — para experiências ou acções sem hora exacta. \"I have visited Paris.\" Usa \"has\" com he/she/it, \"have\" com o resto."},"examples":[{"en":"I have finished my homework.","pt":"Eu já terminei o meu trabalho de casa."},{"en":"She has lived here for 5 years.","pt":"Ela vive aqui há 5 anos."},{"en":"Have you ever eaten sushi?","pt":"Já alguma vez comeste sushi?"}],"practice":[{"q":"Complete: \"She ___ already left.\"","opts":["have","has","had","is"],"ans":1,"exp":"He/She/It → HAS."},{"q":"Which signals Present Perfect?","opts":["yesterday","last week","already","tomorrow"],"ans":2,"exp":"\"already\" is a classic Present Perfect signal."}]},"qs":[{"q":"\"I ___ never been to Japan.\"","opts":["have","has","had","am"],"ans":0,"exp":"\"I HAVE never been.\" — I/You/We/They = HAVE."},{"q":"Which uses Present Perfect CORRECTLY?","opts":["She has went to Paris.","She went to Paris yesterday.","She has been to Paris.","She have been to Paris."],"ans":2,"exp":"\"She HAS BEEN to Paris.\" — No specific time = Present Perfect!"},{"q":"\"They ___ already finished.\"","opts":["have","has","had","did"],"ans":0,"exp":"\"They HAVE already finished.\" — \"already\" = big Present Perfect clue!"},{"q":"Which signal word goes with Present Perfect?","opts":["yesterday","last year","in 2010","just"],"ans":3,"exp":"\"Just\", \"already\", \"yet\", \"ever\", \"never\", \"since\", \"for\" = Perfect signals!"},{"q":"\"Have you ___ sushi?\" (eat)","opts":["eat","ate","eaten","eating"],"ans":2,"exp":"After have/has = past participle. eat → eaten. Irregular!"}]}'::jsonb, 4),
('l1a', 'u1', 'Can & Can''t', 'Can & Can''t (Poder)', '💪', 20, '{"learn":{"explanation":{"en":"\"Can\" expresses ability or permission. Use \"can\" + base verb for all subjects (no -s!): \"She can swim.\" The negative is \"cannot\" or \"can''t\": \"I can''t drive.\"","pt":"\"Can\" expressa capacidade ou permissão. Usa \"can\" + verbo base para todos os sujeitos (sem -s!): \"She can swim.\" A negativa é \"cannot\" ou \"can''t\": \"I can''t drive.\""},"examples":[{"en":"I can speak English.","pt":"Eu sei falar inglês."},{"en":"She can''t cook.","pt":"Ela não sabe cozinhar."},{"en":"Can you help me, please?","pt":"Podes ajudar-me, por favor?"}],"practice":[{"q":"Complete: \"He ___ swim very well.\"","opts":["cans","can","canning","to can"],"ans":1,"exp":"Can never adds -s: He CAN swim."},{"q":"Negative of \"They can dance\":","opts":["They cans not dance.","They don''t can dance.","They can''t dance.","They not can dance."],"ans":2,"exp":"Negative = can''t / cannot + base verb."}]},"qs":[{"q":"\"Can\" is followed by:","opts":["a base verb","a verb + ing","a verb + s","to + verb"],"ans":0,"exp":"After \"can\", always use the base verb: can swim, can run."},{"q":"\"She ___ play the piano.\"","opts":["can","cans","canning","is can"],"ans":0,"exp":"She CAN play — no -s with modal verbs!"},{"q":"Question form: \"___ you drive?\"","opts":["Do","Can","Are","Is"],"ans":1,"exp":"\"Can you drive?\" — Can goes before the subject in questions."},{"q":"\"I can''t swim\" means:","opts":["I am able to swim","I am not able to swim","I love swimming","I will swim"],"ans":1,"exp":"Can''t = cannot = NOT able to."},{"q":"Which is grammatically correct?","opts":["She can to dance.","She cans dance.","She can dance.","She can dances."],"ans":2,"exp":"\"Can + base verb\" — no \"to\", no -s."}]}'::jsonb, 5),
('l6', 'u2', 'Simple Past', 'Passado Simples', '⏮️', 25, '{"learn":{"explanation":{"en":"We use Simple Past for actions that finished at a specific time in the past. Regular verbs add -ed (worked, played). Many common verbs are irregular (go→went, buy→bought) and must be memorized.","pt":"Usamos o Passado Simples para acções que terminaram num momento específico do passado. Os verbos regulares adicionam -ed (worked, played). Muitos verbos comuns são irregulares (go→went, buy→bought) e têm de ser memorizados."},"examples":[{"en":"I visited my grandmother last week.","pt":"Eu visitei a minha avó na semana passada."},{"en":"She bought a new phone yesterday.","pt":"Ela comprou um telemóvel novo ontem."},{"en":"They didn''t go to the party.","pt":"Eles não foram à festa."}],"practice":[{"q":"Past of \"go\":","opts":["goed","went","gone","going"],"ans":1,"exp":"\"Go\" is irregular: go → went."},{"q":"Negative form uses:","opts":["don''t","doesn''t","didn''t","isn''t"],"ans":2,"exp":"Past negative = didn''t + base verb."}]},"qs":[{"q":"\"She ___ a letter yesterday.\" (write)","opts":["writes","write","wrote","written"],"ans":2,"exp":"\"Write\" is irregular: write → WROTE."},{"q":"\"They ___ not go to school last Monday.\"","opts":["did","do","does","have"],"ans":0,"exp":"Negative: DID + not + base verb. \"They did not go.\""},{"q":"What is the past of \"buy\"?","opts":["buyed","boughted","bought","buyt"],"ans":2,"exp":"\"Buy → Bought\" — irregular verb!"},{"q":"Which signals Simple Past?","opts":["just","since","already","three days ago"],"ans":3,"exp":"\"Three days ago\", \"yesterday\", \"last week\" = Simple Past signals."},{"q":"\"___ you see the match last night?\"","opts":["Did","Do","Does","Have"],"ans":0,"exp":"Past questions: DID + subject + base verb?"}]}'::jsonb, 0),
('l7', 'u2', 'Past Continuous', 'Passado Contínuo', '⏸️', 25, '{"learn":{"explanation":{"en":"Past Continuous (was/were + verb-ing) describes an action in progress at a specific past moment, often interrupted by another action. \"I was sleeping when the phone rang.\"","pt":"O Passado Contínuo (was/were + verbo-ing) descreve uma acção em curso num momento específico do passado, muitas vezes interrompida por outra acção. \"I was sleeping when the phone rang.\""},"examples":[{"en":"I was watching TV at 8pm.","pt":"Eu estava a ver TV às 8 da noite."},{"en":"They were playing football when it rained.","pt":"Eles estavam a jogar futebol quando começou a chover."},{"en":"What were you doing yesterday?","pt":"O que estavas a fazer ontem?"}],"practice":[{"q":"Past Continuous formula:","opts":["did + verb","was/were + verb-ing","have + verb-ed","will + verb"],"ans":1,"exp":"was/were + verb-ing."},{"q":"\"While I ___, she called.\"","opts":["cook","cooked","was cooking","cooking"],"ans":2,"exp":"Ongoing action interrupted = was cooking."}]},"qs":[{"q":"\"While I ___, the phone rang.\" (sleep)","opts":["sleep","slept","was sleeping","have slept"],"ans":2,"exp":"Past Continuous = was/were + -ing. Ongoing action interrupted!"},{"q":"\"They ___ football when it started raining.\"","opts":["played","were playing","have played","play"],"ans":1,"exp":"\"WERE PLAYING\" — ongoing action interrupted by rain."},{"q":"Choose the CORRECT sentence:","opts":["She was cry.","She was cried.","She were crying.","She was crying."],"ans":3,"exp":"\"She WAS CRYING.\" — was/were + -ing."},{"q":"\"What ___ you doing at 9pm last night?\"","opts":["did","were","have","are"],"ans":1,"exp":"\"WERE you doing?\" — Past Continuous question."},{"q":"Past Continuous describes:","opts":["Past habits","Finished actions","Ongoing past actions","Future plans"],"ans":2,"exp":"Past Continuous = actions IN PROGRESS at a specific past moment."}]}'::jsonb, 1),
('l8', 'u3', 'Future with Will', 'Futuro com Will', '🔮', 25, '{"learn":{"explanation":{"en":"\"Will\" + base verb expresses predictions, promises, and spontaneous decisions made at the moment of speaking. \"I think it will rain.\" \"I''ll help you!\"","pt":"\"Will\" + verbo base expressa previsões, promessas e decisões espontâneas tomadas no momento da fala. \"I think it will rain.\" \"I''ll help you!\""},"examples":[{"en":"I will call you tomorrow.","pt":"Eu vou ligar-te amanhã."},{"en":"She won''t be late.","pt":"Ela não vai chegar atrasada."},{"en":"Will you marry me?","pt":"Casas comigo?"}],"practice":[{"q":"\"Will\" is followed by:","opts":["a base verb","verb+ing","verb+ed","to+verb"],"ans":0,"exp":"will + base verb: will go, will help."},{"q":"Negative of \"will\":","opts":["willn''t","won''t","not will","will not have"],"ans":1,"exp":"will + not = won''t."}]},"qs":[{"q":"\"I think it ___ rain tomorrow.\"","opts":["is going to","will","rains","rained"],"ans":1,"exp":"\"Will\" for predictions based on opinion. \"I think\" = belief → will."},{"q":"\"I''m hungry.\" — \"___ get you something to eat.\"","opts":["I go","I will","I going to","I am going"],"ans":1,"exp":"Spontaneous decision = \"will\". No prior plan!"},{"q":"Negative of \"She will come\":","opts":["She won''t come.","She will not comes.","She doesn''t will come.","She will not coming."],"ans":0,"exp":"\"Won''t\" = will + not. She won''t come."},{"q":"\"Will you help me?\" — The correct answer is:","opts":["Yes, I will.","Yes, I do.","Yes, I am.","Yes, I shall."],"ans":0,"exp":"Will → will. \"Yes, I WILL.\" ✓"},{"q":"Which sentence uses \"will\" CORRECTLY?","opts":["They will goes.","She will is here.","We will arrive soon.","He will can help."],"ans":2,"exp":"\"Will + base verb\". \"arrive\" is base form. ✓"}]}'::jsonb, 0),
('l9', 'u3', 'Going To', 'Going To', '📅', 25, '{"learn":{"explanation":{"en":"\"Be going to\" + base verb expresses plans already made or predictions with visible evidence. \"I am going to study medicine.\" \"Look at those clouds — it''s going to rain!\"","pt":"\"Be going to\" + verbo base expressa planos já feitos ou previsões com evidência visível. \"I am going to study medicine.\" \"Look at those clouds — it''s going to rain!\""},"examples":[{"en":"We are going to travel next year.","pt":"Nós vamos viajar no próximo ano."},{"en":"She is going to buy a car.","pt":"Ela vai comprar um carro."},{"en":"Is he going to call you?","pt":"Ele vai ligar-te?"}],"practice":[{"q":"\"Going to\" is used for:","opts":["spontaneous decisions","plans already made","past habits","permanent facts"],"ans":1,"exp":"Going to = pre-planned future."},{"q":"\"She ___ going to study.\"","opts":["am","is","are","be"],"ans":1,"exp":"She + IS going to."}]},"qs":[{"q":"\"Look at those clouds! It ___ rain.\"","opts":["will","is going to","rains","might"],"ans":1,"exp":"\"Going to\" for predictions with visible evidence."},{"q":"\"We ___ visit grandma next weekend.\" (planned)","opts":["will","are going to","are going","going to"],"ans":1,"exp":"Pre-planned future = \"be going to\"."},{"q":"Correct form: \"She ___ study medicine.\"","opts":["is going to","are going to","is going","goes to"],"ans":0,"exp":"\"She IS GOING TO study\" — she + is + going to + base verb."},{"q":"What does \"going to\" express?","opts":["Spontaneous decisions","Prior plans and evidence","General facts","Habits"],"ans":1,"exp":"\"Going to\" = plans already made OR visible evidence of future event."},{"q":"\"I ___ start exercising.\" (already decided)","opts":["am going to","will","should","might"],"ans":0,"exp":"\"Going to\" for plans already decided."}]}'::jsonb, 1),
('l10', 'u4', 'Common Adjectives', 'Adjectivos Comuns', '🎨', 20, '{"learn":{"explanation":{"en":"Adjectives describe nouns — people, places, or things. They usually go before the noun (\"a big house\") or after \"to be\" (\"The house is big\"). Learning opposites (big/small, hot/cold) helps you remember faster.","pt":"Os adjectivos descrevem substantivos — pessoas, lugares ou coisas. Normalmente vêm antes do substantivo (\"a big house\") ou depois de \"to be\" (\"The house is big\"). Aprender opostos (big/small, hot/cold) ajuda-te a memorizar mais depressa."},"examples":[{"en":"This is a huge elephant.","pt":"Este é um elefante enorme."},{"en":"My sister is very kind.","pt":"A minha irmã é muito gentil."},{"en":"That phone is expensive.","pt":"Aquele telemóvel é caro."}],"practice":[{"q":"Opposite of \"cheap\":","opts":["small","expensive","kind","tiny"],"ans":1,"exp":"cheap ↔ expensive."},{"q":"\"The food is ___.\" (very tasty)","opts":["bland","disgusting","delicious","salty"],"ans":2,"exp":"delicious = very tasty."}]},"qs":[{"q":"Which word means \"very big\"?","opts":["tiny","huge","narrow","shallow"],"ans":1,"exp":"\"Huge\" = extremely large. Opposite: \"tiny\"."},{"q":"\"The weather is very ___. I need a jacket.\"","opts":["hot","warm","cold","boiling"],"ans":2,"exp":"If you need a jacket, it''s \"cold\"!"},{"q":"\"She is a ___ girl. She always helps others.\"","opts":["selfish","kind","rude","lazy"],"ans":1,"exp":"Someone who helps others is \"kind\"."},{"q":"What does \"expensive\" mean?","opts":["Cheap","Costing a lot","Free","Beautiful"],"ans":1,"exp":"\"Expensive\" = high price. Opposite: \"cheap\"."},{"q":"\"The soup tastes ___.\" (very good)","opts":["disgusting","delicious","bland","salty"],"ans":1,"exp":"\"Delicious\" = very tasty. 😋"}]}'::jsonb, 0),
('l11', 'u4', 'Everyday Actions', 'Acções do Dia-a-dia', '🏃', 20, '{"learn":{"explanation":{"en":"Action verbs describe what we do every day: eat, drink, read, sleep, watch, open, close. Pairing the right verb with the right noun (watch TV, read a book) sounds natural in English.","pt":"Os verbos de acção descrevem o que fazemos todos os dias: eat, drink, read, sleep, watch, open, close. Juntar o verbo certo ao substantivo certo (watch TV, read a book) soa natural em inglês."},"examples":[{"en":"I read a book before bed.","pt":"Eu leio um livro antes de dormir."},{"en":"We watch TV in the evening.","pt":"Nós vemos TV à noite."},{"en":"She opens the window every morning.","pt":"Ela abre a janela todas as manhãs."}],"practice":[{"q":"Which verb goes with \"a shower\"?","opts":["eat","take","read","watch"],"ans":1,"exp":"We TAKE a shower."},{"q":"\"I always ___ my teeth at night.\"","opts":["brush","watch","read","open"],"ans":0,"exp":"We BRUSH our teeth."}]},"qs":[{"q":"What do you do with a book?","opts":["eat","read","drive","cook"],"ans":1,"exp":"You \"read\" a book. 📖"},{"q":"\"I ___ breakfast every morning.\"","opts":["do","make","eat","drink"],"ans":2,"exp":"We \"eat\" breakfast."},{"q":"Where do you sleep?","opts":["In the kitchen","In the bathroom","In the garden","In the bedroom"],"ans":3,"exp":"You sleep in the bedroom!"},{"q":"\"Can you ___ the door, please? It''s hot.\"","opts":["close","open","lock","break"],"ans":1,"exp":"If it''s hot, you want to \"open\" the door!"},{"q":"Which verb goes with \"TV\"?","opts":["watch","see","look","hear"],"ans":0,"exp":"We \"watch\" TV. 📺"}]}'::jsonb, 1),
('l12', 'u4', 'Food & Cooking', 'Comida e Culinária', '🍳', 25, '{"learn":{"explanation":{"en":"Cooking vocabulary helps you talk about meals and recipes: boil, fry, bake, grill, wash, cut. Words like \"raw\", \"spicy\", and \"delicious\" describe how food tastes or looks.","pt":"O vocabulário de culinária ajuda-te a falar sobre refeições e receitas: boil, fry, bake, grill, wash, cut. Palavras como \"raw\", \"spicy\" e \"delicious\" descrevem o sabor ou aspecto da comida."},"examples":[{"en":"I like to fry onions first.","pt":"Eu gosto de fritar cebola primeiro."},{"en":"This soup is too spicy for me.","pt":"Esta sopa é demasiado picante para mim."},{"en":"Can you cut the tomatoes, please?","pt":"Podes cortar os tomates, por favor?"}],"practice":[{"q":"Which method uses an oven?","opts":["boil","bake","fry","wash"],"ans":1,"exp":"BAKE = cook in an oven."},{"q":"\"Raw\" food is:","opts":["well-cooked","not cooked","very sweet","very salty"],"ans":1,"exp":"Raw = not cooked yet."}]},"qs":[{"q":"What is the main ingredient in bread?","opts":["rice","flour","sugar","salt"],"ans":1,"exp":"Bread is made from \"flour\"."},{"q":"\"I need to ___ the vegetables before cooking.\"","opts":["wash","read","wear","build"],"ans":0,"exp":"You \"wash\" vegetables to clean them."},{"q":"Which cooking method uses water?","opts":["fry","bake","boil","grill"],"ans":2,"exp":"\"Boil\" = cooking in hot water."},{"q":"\"This steak is too ___. I ordered it well-done.\"","opts":["cooked","raw","sweet","salty"],"ans":1,"exp":"\"Raw\" = not cooked."},{"q":"What does \"spicy\" mean?","opts":["Sweet taste","Hot burning taste","No taste","Sour taste"],"ans":1,"exp":"\"Spicy\" = hot flavour from chili/pepper."}]}'::jsonb, 2),
('l13', 'u4', 'Body Parts', 'Partes do Corpo', '🦴', 20, '{"learn":{"explanation":{"en":"Body part vocabulary is essential for describing health, pain, and appearance: head, hand, eyes, ears, leg, arm. We say \"My ___ hurts\" to describe pain.","pt":"O vocabulário das partes do corpo é essencial para descrever saúde, dor e aparência: head, hand, eyes, ears, leg, arm. Dizemos \"My ___ hurts\" para descrever dor."},"examples":[{"en":"My head hurts.","pt":"Dói-me a cabeça."},{"en":"She has beautiful eyes.","pt":"Ela tem olhos bonitos."},{"en":"He broke his arm.","pt":"Ele partiu o braço."}],"practice":[{"q":"\"Hurts\" means:","opts":["feels good","causes pain","looks nice","smells bad"],"ans":1,"exp":"Hurts = causes pain."},{"q":"Which body part do you use to SMELL?","opts":["ears","eyes","nose","mouth"],"ans":2,"exp":"You smell with your NOSE."}]},"qs":[{"q":"\"Head\" means:","opts":["mão","pé","cabeça","nariz"],"ans":2,"exp":"head = cabeça. \"Use your head!\" means think!"},{"q":"What is \"hand\" in Portuguese?","opts":["pé","mão","braço","dedo"],"ans":1,"exp":"hand = mão. \"Give me your hand.\""},{"q":"Which body part do you use to SEE?","opts":["ears","nose","eyes","mouth"],"ans":2,"exp":"You see with your EYES! 👀"},{"q":"Which body part do you use to HEAR?","opts":["eyes","ears","nose","tongue"],"ans":1,"exp":"You hear with your EARS! 👂"},{"q":"\"My ___ hurts.\" (pointing to leg)","opts":["arm","head","leg","finger"],"ans":2,"exp":"leg = perna. \"My leg hurts.\""}]}'::jsonb, 3),
('l14', 'u4', 'Animals & Nature', 'Animais e Natureza', '🦁', 20, '{"learn":{"explanation":{"en":"Nature vocabulary covers animals, plants, and the environment. Each animal makes a different sound and lives in a different habitat — knowing these words helps with storytelling and descriptions.","pt":"O vocabulário da natureza cobre animais, plantas e o ambiente. Cada animal faz um som diferente e vive num habitat diferente — saber estas palavras ajuda a contar histórias e a descrever."},"examples":[{"en":"The lion is the king of the jungle.","pt":"O leão é o rei da selva."},{"en":"Fish live in water.","pt":"Os peixes vivem na água."},{"en":"Trees give us oxygen.","pt":"As árvores dão-nos oxigénio."}],"practice":[{"q":"Which animal says \"moo\"?","opts":["dog","cow","cat","lion"],"ans":1,"exp":"Cows say \"moo\"!"},{"q":"Where do birds usually live?","opts":["underground","in water","in trees","in caves"],"ans":2,"exp":"Birds usually live in trees / nests."}]},"qs":[{"q":"What sound does a dog make?","opts":["meow","woof","moo","roar"],"ans":1,"exp":"Dogs go \"woof\"! 🐕 Cats go \"meow\"."},{"q":"\"Lion\" in Portuguese is:","opts":["elefante","leão","girafa","crocodilo"],"ans":1,"exp":"lion = leão. Lions are symbols of Africa! 🦁"},{"q":"Where do fish live?","opts":["in trees","in water","underground","in the sky"],"ans":1,"exp":"Fish live in water — rivers, lakes, oceans!"},{"q":"Which animal is the biggest?","opts":["cat","dog","elephant","bird"],"ans":2,"exp":"The elephant is the biggest land animal on Earth!"},{"q":"\"Tree\" means:","opts":["flor","erva","árvore","pedra"],"ans":2,"exp":"tree = árvore. Trees give us oxygen!"}]}'::jsonb, 4),
('l4a', 'u4', 'Weather & Seasons', 'Tempo e Estações', '⛅', 20, '{"learn":{"explanation":{"en":"We talk about weather using \"It is...\": \"It is sunny\", \"It is raining\". The four seasons are spring, summer, autumn (fall), and winter. Each season has typical weather and activities.","pt":"Falamos sobre o tempo usando \"It is...\": \"It is sunny\", \"It is raining\". As quatro estações são spring, summer, autumn (fall) e winter. Cada estação tem um clima e actividades típicas."},"examples":[{"en":"It is sunny today.","pt":"Hoje está sol."},{"en":"It rains a lot in winter.","pt":"Chove muito no inverno."},{"en":"I love summer because it''s hot.","pt":"Eu adoro o verão porque é quente."}],"practice":[{"q":"\"It is raining\" describes the:","opts":["season","weather","time","colour"],"ans":1,"exp":"It describes WEATHER."},{"q":"Which season comes after spring?","opts":["winter","autumn","summer","none"],"ans":2,"exp":"Spring → Summer → Autumn → Winter."}]},"qs":[{"q":"\"It is ___ today. Bring an umbrella!\"","opts":["sunny","raining","cold","hot"],"ans":1,"exp":"You need an umbrella when it''s RAINING."},{"q":"How many seasons are there?","opts":["2","3","4","5"],"ans":2,"exp":"There are 4 seasons: spring, summer, autumn, winter."},{"q":"\"Hot\" is the opposite of:","opts":["warm","cold","sunny","windy"],"ans":1,"exp":"hot ↔ cold."},{"q":"Which season is the coldest?","opts":["summer","spring","winter","autumn"],"ans":2,"exp":"Winter is the coldest season."},{"q":"\"It''s very windy today\" means:","opts":["It is raining a lot","There is a lot of wind","It is very hot","It is snowing"],"ans":1,"exp":"Windy = lots of wind blowing."}]}'::jsonb, 5),
('l15', 'u5', 'Days & Months', 'Dias e Meses', '📅', 20, '{"learn":{"explanation":{"en":"The 7 days of the week and 12 months of the year are essential for making plans, telling stories, and talking about dates. In English, days and months always start with a capital letter.","pt":"Os 7 dias da semana e os 12 meses do ano são essenciais para fazer planos, contar histórias e falar sobre datas. Em inglês, os dias e meses começam sempre com letra maiúscula."},"examples":[{"en":"Today is Monday.","pt":"Hoje é segunda-feira."},{"en":"My birthday is in July.","pt":"O meu aniversário é em Julho."},{"en":"We have classes from Monday to Friday.","pt":"Temos aulas de segunda a sexta-feira."}],"practice":[{"q":"Which day comes after Friday?","opts":["Sunday","Thursday","Saturday","Monday"],"ans":2,"exp":"Friday → Saturday."},{"q":"How many months are in a year?","opts":["10","11","12","13"],"ans":2,"exp":"There are 12 months in a year."}]},"qs":[{"q":"What is the first day of the week in English?","opts":["Monday","Sunday","Saturday","Wednesday"],"ans":1,"exp":"In English-speaking countries, Sunday is traditionally the first day of the week."},{"q":"\"Segunda-feira\" in English is:","opts":["Sunday","Monday","Tuesday","Wednesday"],"ans":1,"exp":"Monday = Segunda-feira. The week starts with Monday for most people!"},{"q":"Which month comes after March?","opts":["February","May","April","June"],"ans":2,"exp":"March → April → May → June. April comes after March!"},{"q":"\"December\" is the ___ month of the year.","opts":["10th","11th","12th","9th"],"ans":2,"exp":"December is the 12th and last month of the year!"},{"q":"\"Agosto\" in English is:","opts":["June","July","August","September"],"ans":2,"exp":"August = Agosto. Summer month in Europe!"}]}'::jsonb, 0),
('l16', 'u5', 'Telling the Time', 'Dizer as Horas', '🕐', 20, '{"learn":{"explanation":{"en":"To tell the time, we use \"o''clock\" for exact hours, \"quarter past/to\" for 15 minutes, and \"half past\" for 30 minutes. \"What time is it?\" is the standard question.","pt":"Para dizer as horas, usamos \"o''clock\" para horas exactas, \"quarter past/to\" para 15 minutos, e \"half past\" para 30 minutos. \"What time is it?\" é a pergunta padrão."},"examples":[{"en":"It''s 7 o''clock.","pt":"São 7 horas."},{"en":"It''s half past three.","pt":"São três e meia."},{"en":"What time is it?","pt":"Que horas são?"}],"practice":[{"q":"\"Quarter to six\" means:","opts":["6:15","5:45","6:45","5:15"],"ans":1,"exp":"Quarter TO = 15 minutes BEFORE: 5:45."},{"q":"How do you ask the time?","opts":["What hour is now?","What time is it?","Which time?","How time is it?"],"ans":1,"exp":"\"What time is it?\" is correct."}]},"qs":[{"q":"\"It is 3 o''clock.\" This means:","opts":["3:15","3:00","3:30","2:45"],"ans":1,"exp":"\"O''clock\" = exact hour. 3 o''clock = 3:00."},{"q":"\"Quarter past five\" means:","opts":["5:05","5:10","5:15","5:45"],"ans":2,"exp":"\"Quarter past\" = 15 minutes after. Quarter past five = 5:15."},{"q":"\"Half past eight\" means:","opts":["8:00","8:15","8:30","8:45"],"ans":2,"exp":"\"Half past\" = 30 minutes. Half past eight = 8:30."},{"q":"How do you ask for the time?","opts":["Where is the time?","What is your time?","What time is it?","How much time?"],"ans":2,"exp":"\"What time is it?\" = Que horas são? The standard question!"},{"q":"\"It''s midnight.\" This means:","opts":["12:00 PM","12:00 AM","6:00 AM","6:00 PM"],"ans":1,"exp":"\"Midnight\" = 12:00 AM = meia-noite. \"Midday/noon\" = 12:00 PM."}]}'::jsonb, 1),
('l17', 'u5', 'Shopping & Money', 'Compras e Dinheiro', '🛍️', 25, '{"learn":{"explanation":{"en":"Shopping vocabulary helps you buy things confidently: price, expensive, cheap, change, receipt. \"How much does it cost?\" asks the price; the cashier might say \"Here''s your change.\"","pt":"O vocabulário de compras ajuda-te a comprar com confiança: price, expensive, cheap, change, receipt. \"How much does it cost?\" pergunta o preço; o caixa pode dizer \"Here''s your change.\""},"examples":[{"en":"How much does this cost?","pt":"Quanto custa isto?"},{"en":"That''s too expensive for me.","pt":"Isso é demasiado caro para mim."},{"en":"Here is your change.","pt":"Aqui está o seu troco."}],"practice":[{"q":"\"Change\" in a shop means:","opts":["a new product","money given back","a discount card","the shop owner"],"ans":1,"exp":"Change = money given back after paying."},{"q":"How do you ask the price?","opts":["How much does it cost?","How is it cost?","What price?","How many cost?"],"ans":0,"exp":"\"How much does it cost?\" is the standard question."}]},"qs":[{"q":"\"How much does it cost?\" This question is about:","opts":["size","colour","price","quality"],"ans":2,"exp":"\"How much does it cost?\" = Quanto custa? Asking about the price!"},{"q":"\"It''s too ___. I can''t afford it.\"","opts":["cheap","expensive","free","small"],"ans":1,"exp":"\"Expensive\" = muito caro. \"I can''t afford it\" = não consigo pagar."},{"q":"Where do you buy medicine?","opts":["supermarket","pharmacy","bakery","school"],"ans":1,"exp":"You buy medicine at a pharmacy (farmácia)!"},{"q":"\"Change\" in a shop means:","opts":["a new item","the money you get back","a discount","the receipt"],"ans":1,"exp":"\"Change\" = the money the cashier gives you back after paying!"},{"q":"\"Can I help you?\" is said by:","opts":["the customer","the security guard","the shop assistant","the manager"],"ans":2,"exp":"Shop assistants say \"Can I help you?\" when you enter a shop."}]}'::jsonb, 2),
('l18', 'u5', 'Directions & Places', 'Direcções e Lugares', '🗺️', 25, '{"learn":{"explanation":{"en":"Direction words (left, right, straight, next to, opposite) help you navigate a city and ask for help. \"Where is...?\" is the key question for asking locations.","pt":"As palavras de direcção (left, right, straight, next to, opposite) ajudam-te a navegar numa cidade e a pedir ajuda. \"Where is...?\" é a pergunta-chave para perguntar localizações."},"examples":[{"en":"Turn left at the corner.","pt":"Vira à esquerda na esquina."},{"en":"The bank is next to the pharmacy.","pt":"O banco fica ao lado da farmácia."},{"en":"Where is the nearest hospital?","pt":"Onde fica o hospital mais próximo?"}],"practice":[{"q":"\"Next to\" means:","opts":["far from","beside","inside","above"],"ans":1,"exp":"Next to = beside/near."},{"q":"How do you ask for a location?","opts":["Where is...?","What is...?","Who is...?","When is...?"],"ans":0,"exp":"Use \"Where\" for locations."}]},"qs":[{"q":"\"Turn left\" means:","opts":["go straight","turn right","turn left","go back"],"ans":2,"exp":"\"Turn left\" = vira à esquerda. Opposite: \"turn right\" = vira à direita."},{"q":"Where do you go to catch a plane?","opts":["harbour","station","airport","bus stop"],"ans":2,"exp":"You catch a plane at the AIRPORT (aeroporto)!"},{"q":"\"It''s next to the bank.\" This means:","opts":["far from","inside","beside/near","opposite"],"ans":2,"exp":"\"Next to\" = ao lado de. Beside/near the bank!"},{"q":"How do you ask for directions?","opts":["Where is the bank?","Who is the bank?","When is the bank?","Why is the bank?"],"ans":0,"exp":"\"Where is the bank?\" = Onde fica o banco? Use \"where\" for location!"},{"q":"\"The hospital is ___ the park.\" (in front)","opts":["next to","behind","opposite","above"],"ans":2,"exp":"\"Opposite\" = in front of, facing. The hospital faces the park."}]}'::jsonb, 3),
('l5a', 'u5', 'There Is / There Are', 'There Is / There Are (Há)', '📍', 20, '{"learn":{"explanation":{"en":"We use \"there is\" for one thing (singular) and \"there are\" for more than one (plural) to say something exists. \"There is a bank near here.\" \"There are two chairs in the room.\"","pt":"Usamos \"there is\" para uma coisa (singular) e \"there are\" para mais do que uma (plural) para dizer que algo existe. \"There is a bank near here.\" \"There are two chairs in the room.\""},"examples":[{"en":"There is a school near my house.","pt":"Há uma escola perto da minha casa."},{"en":"There are many shops in the city.","pt":"Há muitas lojas na cidade."},{"en":"Is there a pharmacy here?","pt":"Há uma farmácia aqui?"}],"practice":[{"q":"Complete: \"___ a cat in the garden.\"","opts":["There is","There are","Is there","They are"],"ans":0,"exp":"One cat (singular) → There IS."},{"q":"Complete: \"___ three books on the table.\"","opts":["There is","There are","Is there","It is"],"ans":1,"exp":"Three books (plural) → There ARE."}]},"qs":[{"q":"\"There ___ a hospital near here.\"","opts":["is","are","be","am"],"ans":0,"exp":"Singular noun → \"is\"."},{"q":"\"There ___ many people at the party.\"","opts":["is","are","be","was"],"ans":1,"exp":"Plural noun → \"are\"."},{"q":"Question form: \"___ a bank nearby?\"","opts":["Is there","There is","Are there","There are"],"ans":0,"exp":"Question with singular: \"Is there...?\""},{"q":"\"There aren''t any apples\" means:","opts":["There are some apples","There are no apples","There is one apple","There were apples"],"ans":1,"exp":"aren''t = are not = none."},{"q":"Which is correct?","opts":["There is two dogs.","There are two dogs.","There two dogs are.","Two dogs there are."],"ans":1,"exp":"Plural (two dogs) → There ARE."}]}'::jsonb, 4),
('l1b1', 'u1b', 'Frequency Adverbs', 'Advérbios de Frequência', '🔁', 20, '{"learn":{"explanation":{"en":"Frequency adverbs tell us HOW OFTEN someone does something. Order from most to least: always (100%) → usually → often → sometimes → rarely → never (0%). These adverbs go BEFORE the main verb but AFTER the verb \"to be\". \"I always eat breakfast.\" \"She is never late.\"","pt":"Os advérbios de frequência dizem-nos COM QUE FREQUÊNCIA alguém faz algo. Ordem de mais para menos: always (100%) → usually → often → sometimes → rarely → never (0%). Estes advérbios vêm ANTES do verbo principal mas DEPOIS do verbo \"to be\". \"I always eat breakfast.\" \"She is never late.\""},"examples":[{"en":"I always wake up early. (every day)","pt":"Acordo sempre cedo. (todos os dias)"},{"en":"She usually takes the bus. (most days)","pt":"Ela normalmente apanha o autocarro. (a maioria dos dias)"},{"en":"We sometimes go to the beach.","pt":"Nós às vezes vamos à praia."},{"en":"He rarely eats fast food.","pt":"Ele raramente come fast food."},{"en":"They are never late for class.","pt":"Eles nunca chegam atrasados à aula."}],"practice":[{"q":"\"Always\" means:","opts":["sometimes","never","100% of the time","rarely"],"ans":2,"exp":"\"Always\" = 100% of the time — every single time!"},{"q":"Where does a frequency adverb go?","opts":["at the end","before the main verb","after the object","at the start only"],"ans":1,"exp":"Before the main verb: \"I ALWAYS eat.\" But after \"to be\": \"She IS never late.\""}]},"qs":[{"q":"Which adverb means 0% of the time?","opts":["always","usually","sometimes","never"],"ans":3,"exp":"\"Never\" = 0% — not even once!"},{"q":"\"I ___ brush my teeth before bed.\"","opts":["always","never","sometimes","usually"],"ans":0,"exp":"You should ALWAYS brush your teeth! 😁"},{"q":"Where does \"always\" go in: \"She ___ is late\"?","opts":["She always is late","She is always late","She is late always","Always she is late"],"ans":1,"exp":"\"She IS ALWAYS late.\" — after \"to be\"!"},{"q":"\"Sometimes\" means:","opts":["every day","never","now and then","always"],"ans":2,"exp":"\"Sometimes\" = occasionally, now and then — às vezes!"},{"q":"\"He ___ eats vegetables.\" (almost never)","opts":["always","usually","rarely","often"],"ans":2,"exp":"\"He RARELY eats vegetables.\" = Ele raramente come legumes!"},{"q":"Correct order:","opts":["I go usually to school early","I usually go to school early","Usually I go to school early","I go to usually school early"],"ans":1,"exp":"\"I USUALLY GO to school early.\" — adverb before main verb!"},{"q":"\"Often\" is closest in meaning to:","opts":["rarely","sometimes","usually","never"],"ans":2,"exp":"\"Often\" is close to \"usually\" — both mean frequently, but usually is a bit more!"}]}'::jsonb, 0),
('l1b2', 'u1b', 'Prepositions of Place', 'Preposições de Lugar', '📍', 20, '{"learn":{"explanation":{"en":"Prepositions of place describe WHERE something is. Key ones: in (dentro de), on (em cima de), under (debaixo de), next to (ao lado de), between (entre), in front of (em frente de), behind (atrás de), above (acima de), below (abaixo de). \"The cat is ON the table.\" \"My keys are IN the bag.\"","pt":"As preposições de lugar descrevem ONDE algo está. As principais: in (dentro de), on (em cima de), under (debaixo de), next to (ao lado de), between (entre), in front of (em frente de), behind (atrás de), above (acima de), below (abaixo de). \"The cat is ON the table.\" \"My keys are IN the bag.\""},"examples":[{"en":"The book is on the table.","pt":"O livro está em cima da mesa."},{"en":"The cat is under the bed.","pt":"O gato está debaixo da cama."},{"en":"My house is next to the school.","pt":"A minha casa está ao lado da escola."},{"en":"The park is in front of the hotel.","pt":"O parque fica em frente do hotel."},{"en":"The keys are in the bag.","pt":"As chaves estão na mochila."}],"practice":[{"q":"\"The cat is ___ the bed.\" (below it)","opts":["on","above","under","in front of"],"ans":2,"exp":"Under = below/debaixo! The cat is UNDER the bed."},{"q":"\"Next to\" means:","opts":["debaixo de","em cima de","ao lado de","em frente de"],"ans":2,"exp":"Next to = ao lado de! Beside something."}]},"qs":[{"q":"\"The keys are ___ the bag.\" (inside)","opts":["on","under","in","next to"],"ans":2,"exp":"\"In the bag\" = inside the bag!"},{"q":"\"The book is ___ the table.\" (on top)","opts":["under","in","behind","on"],"ans":3,"exp":"\"ON the table\" = em cima da mesa!"},{"q":"\"Between\" means:","opts":["ao lado de","debaixo de","entre","em frente de"],"ans":2,"exp":"\"Between\" = entre! \"The bank is between the school and the market.\""},{"q":"\"The school is ___ my house.\" (directly in front)","opts":["behind","in front of","under","above"],"ans":1,"exp":"\"In front of\" = em frente de!"},{"q":"\"The cat is ___ the sofa.\" (behind it)","opts":["in front of","above","next to","behind"],"ans":3,"exp":"\"Behind\" = atrás de!"},{"q":"\"Above\" means:","opts":["acima de","abaixo de","ao lado de","dentro de"],"ans":0,"exp":"\"Above\" = acima de! Higher than something."},{"q":"Which is correct?","opts":["The pen is in on the desk","The pen is on the desk","The pen is at on the desk","The pen on the desk is"],"ans":1,"exp":"\"The pen IS ON the desk.\" — simple and correct!"}]}'::jsonb, 1),
('l1b3', 'u1b', 'Prepositions of Time', 'Preposições de Tempo', '🕐', 20, '{"learn":{"explanation":{"en":"Time prepositions tell us WHEN something happens. The three main ones: IN = months, years, seasons, parts of day (\"in January\", \"in 2025\", \"in the morning\"). ON = days and dates (\"on Monday\", \"on 15th March\"). AT = exact times and fixed expressions (\"at 7 AM\", \"at night\", \"at Christmas\").","pt":"As preposições de tempo dizem-nos QUANDO algo acontece. As três principais: IN = meses, anos, estações, partes do dia (\"in January\", \"in 2025\", \"in the morning\"). ON = dias e datas (\"on Monday\", \"on 15th March\"). AT = horas exactas e expressões fixas (\"at 7 AM\", \"at night\", \"at Christmas\")."},"examples":[{"en":"I was born in March. (month)","pt":"Nasci em Março. (mês)"},{"en":"School starts on Monday. (day)","pt":"A escola começa na segunda-feira. (dia)"},{"en":"The class is at 9 AM. (time)","pt":"A aula é às 9h. (hora)"},{"en":"We rest in the afternoon. (part of day)","pt":"Descansamos de tarde. (parte do dia)"},{"en":"I visit family at Christmas. (fixed expression)","pt":"Visito a família no Natal. (expressão fixa)"}],"practice":[{"q":"\"The party is ___ Saturday.\"","opts":["in","at","on","by"],"ans":2,"exp":"\"ON Saturday\" — use ON for days of the week!"},{"q":"\"She was born ___ 1999.\"","opts":["on","at","in","by"],"ans":2,"exp":"\"IN 1999\" — use IN for years!"}]},"qs":[{"q":"\"The match is ___ 3 PM.\"","opts":["in","on","at","by"],"ans":2,"exp":"\"AT 3 PM\" — use AT for specific times!"},{"q":"\"My birthday is ___ April.\"","opts":["at","on","in","by"],"ans":2,"exp":"\"IN April\" — use IN for months!"},{"q":"\"The meeting is ___ Monday.\"","opts":["in","at","on","by"],"ans":2,"exp":"\"ON Monday\" — use ON for days!"},{"q":"\"She wakes up early ___ the morning.\"","opts":["at","on","in","by"],"ans":2,"exp":"\"IN the morning\" — use IN for parts of the day!"},{"q":"\"School finishes ___ June.\"","opts":["at","on","in","by"],"ans":2,"exp":"\"IN June\" — use IN for months!"},{"q":"\"I was born ___ 5th May.\"","opts":["in","at","on","by"],"ans":2,"exp":"\"ON 5th May\" — use ON for specific dates!"},{"q":"Which is CORRECT?","opts":["at Monday","on Monday","in Monday","by Monday"],"ans":1,"exp":"\"ON Monday\" — days of the week always use ON!"}]}'::jsonb, 2),
('l1b4', 'u1b', 'Comparatives', 'Comparativos', '⚖️', 25, '{"learn":{"explanation":{"en":"We use comparatives to compare two things. For SHORT adjectives: add -er + than. \"tall → taller than\", \"big → bigger than\", \"hot → hotter than\". For LONG adjectives (3+ syllables): use more + adj + than. \"beautiful → more beautiful than\". Irregular: good → better, bad → worse, far → farther.","pt":"Usamos os comparativos para comparar duas coisas. Para adjectivos CURTOS: adiciona -er + than. \"tall → taller than\", \"big → bigger than\", \"hot → hotter than\". Para adjectivos LONGOS (3+ sílabas): usa more + adj + than. \"beautiful → more beautiful than\". Irregulares: good → better, bad → worse, far → farther."},"examples":[{"en":"Maputo is bigger than Inhambane.","pt":"Maputo é maior do que Inhambane."},{"en":"English is easier than Chinese.","pt":"O inglês é mais fácil do que o chinês."},{"en":"This phone is more expensive than that one.","pt":"Este telemóvel é mais caro do que aquele."},{"en":"She is better at English than me.","pt":"Ela é melhor em inglês do que eu."},{"en":"Today is hotter than yesterday.","pt":"Hoje está mais quente do que ontem."}],"practice":[{"q":"Comparative of \"tall\":","opts":["tallest","more tall","taller","most tall"],"ans":2,"exp":"\"Tall\" is short → add -er: taller!"},{"q":"Comparative of \"beautiful\":","opts":["beautifuler","more beautiful","beautifuller","most beautiful"],"ans":1,"exp":"\"Beautiful\" is long → use more: more beautiful!"}]},"qs":[{"q":"Comparative of \"big\":","opts":["biger","bigger","more big","most big"],"ans":1,"exp":"\"Big\" → BIGGER (double the G before -er)!"},{"q":"Comparative of \"expensive\":","opts":["expensiver","more expensiver","more expensive","expensiveer"],"ans":2,"exp":"\"Expensive\" is long → MORE expensive!"},{"q":"\"Maputo is ___ than Xai-Xai.\" (bigger)","opts":["more big","biger","bigger","biggest"],"ans":2,"exp":"\"Maputo is BIGGER than Xai-Xai.\""},{"q":"Comparative of \"good\":","opts":["gooder","more good","better","goodest"],"ans":2,"exp":"\"Good\" is irregular! good → BETTER!"},{"q":"Comparative of \"bad\":","opts":["badder","more bad","worst","worse"],"ans":3,"exp":"\"Bad\" is irregular! bad → WORSE!"},{"q":"\"This road is ___ than the other one.\" (dangerous)","opts":["dangerouser","more dangerous","most dangerous","dangerousmore"],"ans":1,"exp":"\"More dangerous\" — long adjective uses MORE!"},{"q":"\"She runs ___ than me.\" (fast)","opts":["more fast","fastest","faster","fastly"],"ans":2,"exp":"\"Faster than me\" — short adjective + -er!"}]}'::jsonb, 3),
('l1b5', 'u1b', 'Superlatives', 'Superlativos', '🏆', 25, '{"learn":{"explanation":{"en":"Superlatives say something is the MOST or LEAST of all. For SHORT adjectives: the + adj + -est. \"tall → the tallest\". For LONG adjectives: the most + adj. \"the most beautiful\". Irregular: good → the best, bad → the worst, far → the farthest. We always use \"the\" before a superlative.","pt":"Os superlativos dizem que algo é o MAIS ou o MENOS de todos. Para adjectivos CURTOS: the + adj + -est. \"tall → the tallest\". Para adjectivos LONGOS: the most + adj. \"the most beautiful\". Irregulares: good → the best, bad → the worst, far → the farthest. Usamos sempre \"the\" antes de um superlativo."},"examples":[{"en":"Mount Everest is the highest mountain.","pt":"O Monte Everest é a montanha mais alta."},{"en":"This is the most beautiful beach in Mozambique.","pt":"Esta é a praia mais bonita de Moçambique."},{"en":"He is the best player on the team.","pt":"Ele é o melhor jogador da equipa."},{"en":"This is the worst film I have ever seen.","pt":"Este é o pior filme que já vi."},{"en":"She is the most intelligent student.","pt":"Ela é a estudante mais inteligente."}],"practice":[{"q":"Superlative of \"tall\":","opts":["most tall","tallest","the tallest","taller"],"ans":2,"exp":"\"The tallest\" — always use \"the\" with superlatives!"},{"q":"Superlative of \"good\":","opts":["the goodest","the most good","the better","the best"],"ans":3,"exp":"\"Good\" is irregular → THE BEST!"}]},"qs":[{"q":"Superlative of \"big\":","opts":["the most big","the biger","the biggest","biggest"],"ans":2,"exp":"\"Big\" → THE BIGGEST!"},{"q":"Superlative of \"bad\":","opts":["the baddest","the most bad","the worse","the worst"],"ans":3,"exp":"\"Bad\" is irregular → THE WORST!"},{"q":"\"Maputo is ___ city in Mozambique.\" (big)","opts":["bigger","more big","the biggest","most big"],"ans":2,"exp":"\"Maputo is THE BIGGEST city in Mozambique.\""},{"q":"Which is CORRECT?","opts":["She is most intelligent.","She is the most intelligent.","She is the intelligentst.","She is more intelligent."],"ans":1,"exp":"\"She is THE MOST intelligent.\" — always use THE!"},{"q":"Superlative of \"fast\":","opts":["fastest","the faster","the fastest","most fastest"],"ans":2,"exp":"\"The fastest\"! Short adjective → the + -est!"},{"q":"\"This is ___ day of my life!\" (happy)","opts":["the happiest","the most happiest","more happy","happiest"],"ans":0,"exp":"\"The happiest day of my life!\" 😊"},{"q":"\"The ___ is the best food.\" (your favourite!)","opts":["Depends on you!","same as comparative","always long adjective","always short adjective"],"ans":0,"exp":"Superlative describes the BEST/WORST of all — choose your favourite!"}]}'::jsonb, 4),
('l1c1', 'u1c', 'Countable & Uncountable Nouns', 'Substantivos Contáveis e Incontáveis', '🍎', 25, '{"learn":{"explanation":{"en":"Countable nouns are things you can count one by one: one apple, two apples, three books. They can be singular or plural. Uncountable nouns cannot be counted individually — they are substances, liquids, or abstract things: water, rice, milk, music, advice. You CANNOT say \"one water\" or \"two rices\". Instead say \"some water\" or \"a glass of water\".","pt":"Os substantivos contáveis são coisas que podes contar uma a uma: one apple, two apples, three books. Podem ser singular ou plural. Os substantivos incontáveis não podem ser contados individualmente — são substâncias, líquidos ou coisas abstractas: water, rice, milk, music, advice. NÃO podes dizer \"one water\" ou \"two rices\". Em vez disso diz \"some water\" ou \"a glass of water\"."},"examples":[{"en":"I have two apples. (countable)","pt":"Eu tenho duas maçãs. (contável)"},{"en":"I drink water every day. (uncountable)","pt":"Eu bebo água todos os dias. (incontável)"},{"en":"She bought three books. (countable)","pt":"Ela comprou três livros. (contável)"},{"en":"We need some milk. (uncountable)","pt":"Nós precisamos de algum leite. (incontável)"},{"en":"Can I have a cup of tea? (uncountable)","pt":"Posso ter uma chávena de chá? (incontável)"}],"practice":[{"q":"Which is an UNCOUNTABLE noun?","opts":["book","chair","water","dog"],"ans":2,"exp":"\"Water\" cannot be counted — you can''t say \"one water, two waters\". It''s uncountable!"},{"q":"Which is a COUNTABLE noun?","opts":["milk","rice","apple","sugar"],"ans":2,"exp":"\"Apple\" can be counted: one apple, two apples. It''s countable!"}]},"qs":[{"q":"Which noun is COUNTABLE?","opts":["water","milk","sugar","chair"],"ans":3,"exp":"\"Chair\" is countable — one chair, two chairs, three chairs!"},{"q":"Which noun is UNCOUNTABLE?","opts":["book","pen","rice","apple"],"ans":2,"exp":"\"Rice\" is uncountable — you can''t say \"one rice, two rices\"!"},{"q":"\"I need ___ water.\" (some amount)","opts":["a","two","some","many"],"ans":2,"exp":"\"Some water\" — uncountable nouns use \"some\", not \"a\" or a number!"},{"q":"Can you say \"two milks\"?","opts":["Yes, always","No, milk is uncountable","Yes, if you want","Sometimes"],"ans":1,"exp":"NO! \"Milk\" is uncountable. Say \"two glasses of milk\" instead!"},{"q":"\"She bought ___ books.\" (3)","opts":["some","any","three","much"],"ans":2,"exp":"Countable nouns use numbers: \"She bought THREE books\"!"},{"q":"Which CAN you count?","opts":["music","advice","coffee","student"],"ans":3,"exp":"\"Student\" is countable — one student, two students, many students!"},{"q":"To measure uncountable nouns, we use:","opts":["numbers only","a/an","containers/measures","plurals"],"ans":2,"exp":"Use containers: \"a cup of tea\", \"a glass of water\", \"a bag of rice\"!"}]}'::jsonb, 0),
('l1c2', 'u1c', 'Some & Any', 'Some & Any (Algum/Nenhum)', '🧂', 25, '{"learn":{"explanation":{"en":"\"Some\" and \"any\" are used with uncountable nouns and plural countable nouns. Use SOME in positive sentences and offers: \"I have some milk.\" \"Would you like some tea?\" Use ANY in negative sentences and questions: \"I don''t have any milk.\" \"Do you have any brothers?\" Exception: \"Would you like some...?\" is an offer so it uses SOME even though it''s a question.","pt":"\"Some\" e \"any\" são usados com substantivos incontáveis e substantivos contáveis no plural. Usa SOME em frases positivas e ofertas: \"I have some milk.\" \"Would you like some tea?\" Usa ANY em frases negativas e perguntas: \"I don''t have any milk.\" \"Do you have any brothers?\" Excepção: \"Would you like some...?\" é uma oferta por isso usa SOME mesmo sendo pergunta."},"examples":[{"en":"I have some rice at home. (positive)","pt":"Eu tenho algum arroz em casa. (positivo)"},{"en":"I don''t have any bread. (negative)","pt":"Eu não tenho nenhum pão. (negativo)"},{"en":"Do you have any questions? (question)","pt":"Tens alguma pergunta? (pergunta)"},{"en":"Would you like some water? (offer)","pt":"Gostarias de um pouco de água? (oferta)"},{"en":"She has some friends in Beira.","pt":"Ela tem alguns amigos em Beira."}],"practice":[{"q":"\"I don''t have ___ money.\"","opts":["some","any","a","the"],"ans":1,"exp":"\"Any\" in negative sentences — I don''t have ANY money."},{"q":"\"Would you like ___ coffee?\"","opts":["any","the","some","a"],"ans":2,"exp":"\"Some\" in offers — Would you like SOME coffee? (offering, not questioning)"}]},"qs":[{"q":"\"There is ___ water in the bottle.\" (positive)","opts":["any","no","some","the"],"ans":2,"exp":"\"SOME water\" — use some in positive sentences!"},{"q":"\"Do you have ___ sisters?\" (question)","opts":["some","any","a","the"],"ans":1,"exp":"\"ANY sisters?\" — use any in questions!"},{"q":"\"She doesn''t have ___ money.\" (negative)","opts":["some","any","a","much"],"ans":1,"exp":"\"ANY money\" — use any in negative sentences!"},{"q":"\"Would you like ___ tea?\" (offer)","opts":["any","a","the","some"],"ans":3,"exp":"\"SOME tea\" — offers use some, even though it''s a question!"},{"q":"\"I bought ___ apples at the market.\"","opts":["any","some","a","the"],"ans":1,"exp":"\"SOME apples\" — positive sentence, so use some!"},{"q":"\"Is there ___ milk left?\" (question)","opts":["some","many","any","much"],"ans":2,"exp":"\"ANY milk left?\" — questions use any!"},{"q":"Which is CORRECT?","opts":["I have some any friends.","I have any friends.","I don''t have some friends.","I don''t have any friends."],"ans":3,"exp":"\"I don''t have ANY friends.\" — negative sentence uses any!"}]}'::jsonb, 1),
('l1c3', 'u1c', 'Much, Many & A Lot Of', 'Much, Many & A Lot Of (Muito/Muitos)', '📦', 25, '{"learn":{"explanation":{"en":"\"Much\", \"many\" and \"a lot of\" all mean a large quantity. The rule: MANY = countable nouns (many books, many people). MUCH = uncountable nouns (much water, much time). A LOT OF = both! In positive sentences, \"a lot of\" is more natural than much/many. \"Much\" and \"many\" are most common in negatives and questions.","pt":"\"Much\", \"many\" e \"a lot of\" significam todos uma grande quantidade. A regra: MANY = substantivos contáveis (many books, many people). MUCH = substantivos incontáveis (much water, much time). A LOT OF = ambos! Em frases positivas, \"a lot of\" é mais natural do que much/many. \"Much\" e \"many\" são mais comuns em negativos e perguntas."},"examples":[{"en":"There are many students in my class.","pt":"Há muitos alunos na minha turma."},{"en":"I don''t have much time today.","pt":"Eu não tenho muito tempo hoje."},{"en":"She drinks a lot of water.","pt":"Ela bebe muita água."},{"en":"How many brothers do you have?","pt":"Quantos irmãos tens?"},{"en":"How much does this cost?","pt":"Quanto custa isto?"}],"practice":[{"q":"\"How ___ brothers do you have?\" (counting people)","opts":["much","many","lot","some"],"ans":1,"exp":"\"How MANY\" — brothers are countable, use many!"},{"q":"\"How ___ water do you drink?\" (liquid)","opts":["many","some","much","few"],"ans":2,"exp":"\"How MUCH water\" — water is uncountable, use much!"}]},"qs":[{"q":"\"There are ___ people at the market.\"","opts":["much","a lot of","few","less"],"ans":1,"exp":"\"A LOT OF people\" — people is countable and positive sentence!"},{"q":"\"I don''t have ___ money.\"","opts":["many","a lot of","much","few"],"ans":2,"exp":"\"MUCH money\" — money is uncountable!"},{"q":"\"How ___ apples do you want?\"","opts":["much","a lot of","many","some"],"ans":2,"exp":"\"How MANY apples?\" — apples are countable!"},{"q":"\"How ___ rice did you cook?\"","opts":["many","a lot of","much","some"],"ans":2,"exp":"\"How MUCH rice?\" — rice is uncountable!"},{"q":"\"She has ___ friends in Maputo.\"","opts":["much","a lot of","many much","less"],"ans":1,"exp":"\"A LOT OF friends\" — works with countable nouns in positive sentences!"},{"q":"\"There isn''t ___ sugar left.\"","opts":["many","a lot of","much","some"],"ans":2,"exp":"\"MUCH sugar\" — sugar is uncountable, negative sentence!"},{"q":"Which is CORRECT?","opts":["How much books?","How many books?","How many water?","How much people?"],"ans":1,"exp":"\"How MANY books?\" — books are countable!"}]}'::jsonb, 2),
('l1c4', 'u1c', 'A Few & A Little', 'A Few & A Little (Um Pouco)', '🤏', 20, '{"learn":{"explanation":{"en":"\"A few\" and \"a little\" both mean a small amount, and they are POSITIVE — they say there IS something. A FEW = small number + countable nouns: \"I have a few friends.\" A LITTLE = small amount + uncountable nouns: \"I have a little money.\" Compare with \"few\" (almost none, negative feeling) and \"little\" (almost none, negative feeling). In everyday speech, \"a few\" and \"a little\" are much more common.","pt":"\"A few\" e \"a little\" significam ambos uma pequena quantidade, e são POSITIVOS — dizem que HÁ algo. A FEW = número pequeno + substantivos contáveis: \"I have a few friends.\" A LITTLE = quantidade pequena + substantivos incontáveis: \"I have a little money.\" Compara com \"few\" (quase nenhum, sentido negativo) e \"little\" (quase nenhum, sentido negativo). No discurso do dia-a-dia, \"a few\" e \"a little\" são muito mais comuns."},"examples":[{"en":"I have a few coins in my pocket. (small number)","pt":"Eu tenho algumas moedas no bolso. (número pequeno)"},{"en":"Can I have a little sugar, please? (small amount)","pt":"Posso ter um pouco de açúcar, por favor? (quantidade pequena)"},{"en":"She speaks a little English.","pt":"Ela fala um pouco de inglês."},{"en":"We have a few minutes before class.","pt":"Temos alguns minutos antes da aula."},{"en":"There is a little milk left in the bottle.","pt":"Há um pouco de leite que sobrou na garrafa."}],"practice":[{"q":"\"I have ___ friends in this city.\" (small number, positive)","opts":["little","a little","a few","few"],"ans":2,"exp":"\"A few friends\" — countable noun (friends) + small positive number!"},{"q":"\"She speaks ___ English.\" (small amount, positive)","opts":["few","a few","little","a little"],"ans":3,"exp":"\"A little English\" — uncountable (a language) + small positive amount!"}]},"qs":[{"q":"\"I have ___ money — enough for lunch.\" (small positive amount)","opts":["a few","few","a little","little"],"ans":2,"exp":"\"A LITTLE money\" — money is uncountable + positive (enough for lunch)!"},{"q":"\"She has ___ books to read.\" (small positive number)","opts":["a little","little","much","a few"],"ans":3,"exp":"\"A FEW books\" — books are countable + positive!"},{"q":"\"Can I have ___ water?\" (a small amount)","opts":["a few","few","a little","many"],"ans":2,"exp":"\"A LITTLE water\" — water is uncountable!"},{"q":"\"We have ___ minutes before the bus.\" (small number)","opts":["a little","much","a few","little"],"ans":2,"exp":"\"A FEW minutes\" — minutes are countable!"},{"q":"\"A little\" is used with:","opts":["countable nouns","uncountable nouns","plurals only","questions only"],"ans":1,"exp":"\"A little\" = uncountable nouns! \"A little rice, a little water, a little time.\""},{"q":"\"A few\" is used with:","opts":["uncountable nouns","liquids","countable nouns","negative sentences"],"ans":2,"exp":"\"A few\" = countable nouns! \"A few friends, a few books, a few coins.\""},{"q":"Which is CORRECT?","opts":["a few water","a little friends","a few apples","a little books"],"ans":2,"exp":"\"A few APPLES\" — apples are countable!"}]}'::jsonb, 3),
('l1c5', 'u1c', 'Articles — A, An & The', 'Artigos — A, An e The', '📖', 25, '{"learn":{"explanation":{"en":"English has three articles: A, AN, and THE. A and AN are \"indefinite\" — we use them when talking about something for the first time or in general. A = before consonant sounds (a book, a car). AN = before vowel sounds (an apple, an elephant, an hour). THE is \"definite\" — we use it when both the speaker and listener know which specific thing we mean. \"I saw A dog. THE dog was black.\" — first mention: A, second mention: THE.","pt":"O inglês tem três artigos: A, AN e THE. A e AN são \"indefinidos\" — usamo-los quando falamos de algo pela primeira vez ou em geral. A = antes de sons de consoante (a book, a car). AN = antes de sons de vogal (an apple, an elephant, an hour). THE é \"definido\" — usamo-lo quando tanto o falante como o ouvinte sabem de que coisa específica estamos a falar. \"I saw A dog. THE dog was black.\" — primeira menção: A, segunda menção: THE."},"examples":[{"en":"I have a dog. The dog is brown.","pt":"Eu tenho um cão. O cão é castanho."},{"en":"She ate an apple and an orange.","pt":"Ela comeu uma maçã e uma laranja."},{"en":"The sun is very hot today.","pt":"O sol está muito quente hoje."},{"en":"Can you close the door, please?","pt":"Podes fechar a porta, por favor?"},{"en":"He is a student at a university.","pt":"Ele é estudante numa universidade."}],"practice":[{"q":"\"She is ___ teacher.\" (general)","opts":["the","an","a","—"],"ans":2,"exp":"\"A teacher\" — general job, consonant sound, use A!"},{"q":"\"I ate ___ orange for breakfast.\"","opts":["a","the","—","an"],"ans":3,"exp":"\"AN orange\" — orange starts with a vowel sound, use AN!"}]},"qs":[{"q":"\"He has ___ umbrella.\"","opts":["a","an","the","—"],"ans":1,"exp":"\"AN umbrella\" — umbrella starts with a vowel sound (U)!"},{"q":"\"___ sun rises in the east.\"","opts":["A","An","The","—"],"ans":2,"exp":"\"THE sun\" — there is only one sun, both speaker and listener know which one!"},{"q":"\"She is ___ engineer.\"","opts":["an","a","the","—"],"ans":0,"exp":"\"AN engineer\" — engineer starts with a vowel sound (E)!"},{"q":"\"I saw ___ cat. ___ cat was orange.\"","opts":["a/A","a/The","the/A","an/The"],"ans":1,"exp":"\"A cat\" (first mention) → \"The cat\" (both know which cat now)!"},{"q":"\"Can you open ___ window, please?\" (specific window)","opts":["a","an","the","—"],"ans":2,"exp":"\"THE window\" — the specific window in this room, both speakers know it!"},{"q":"\"I need ___ new pen.\" (any pen)","opts":["the","—","a","an"],"ans":2,"exp":"\"A new pen\" — any pen, first mention, consonant sound!"},{"q":"\"She is ___ honest person.\"","opts":["a","an","the","—"],"ans":1,"exp":"\"AN honest person\" — \"honest\" starts with a silent H, so the vowel sound O follows. Use AN!"}]}'::jsonb, 4),
('l1c6', 'u1c', 'Possessives — My, Your, His, Her', 'Possessivos — Meu, Teu, Seu', '🏷️', 20, '{"learn":{"explanation":{"en":"Possessive adjectives show who something belongs to. They always go BEFORE a noun. I → my, You → your, He → his, She → her, It → its, We → our, They → their. \"This is MY book.\" \"What is YOUR name?\" \"HER mother is a teacher.\" Do NOT confuse \"his\" (possessive) with \"he''s\" (he is), or \"their\" with \"they''re\" (they are) or \"there\".","pt":"Os adjectivos possessivos mostram a quem algo pertence. Vão sempre ANTES de um substantivo. I → my, You → your, He → his, She → her, It → its, We → our, They → their. \"This is MY book.\" \"What is YOUR name?\" \"HER mother is a teacher.\" NÃO confundas \"his\" (possessivo) com \"he''s\" (he is), ou \"their\" com \"they''re\" (they are) ou \"there\"."},"examples":[{"en":"My name is Sebastian. What is your name?","pt":"O meu nome é Sebastian. Qual é o teu nome?"},{"en":"His car is blue. Her bag is red.","pt":"O carro dele é azul. A mala dela é vermelha."},{"en":"Our school is near the market.","pt":"A nossa escola fica perto do mercado."},{"en":"Their children are very polite.","pt":"Os filhos deles são muito educados."},{"en":"The dog hurt its leg.","pt":"O cão magoou a pata."}],"practice":[{"q":"\"___ name is Maria.\" (talking about her)","opts":["My","Your","His","Her"],"ans":3,"exp":"\"HER name is Maria.\" — she/her, so possessive = her!"},{"q":"\"This is ___ phone.\" (it belongs to me)","opts":["my","your","his","its"],"ans":0,"exp":"\"MY phone\" — belongs to me = my!"}]},"qs":[{"q":"\"___ name is João.\" (he)","opts":["My","His","Her","Your"],"ans":1,"exp":"\"HIS name is João.\" — he → his!"},{"q":"\"___ mother is a nurse.\" (she)","opts":["His","My","Her","Their"],"ans":2,"exp":"\"HER mother is a nurse.\" — she → her!"},{"q":"\"We love ___ country.\" (belonging to us)","opts":["my","their","our","her"],"ans":2,"exp":"\"We love OUR country.\" — we → our!"},{"q":"\"The dog wagged ___ tail.\" (belonging to it)","opts":["his","her","its","their"],"ans":2,"exp":"\"The dog wagged ITS tail.\" — it → its!"},{"q":"\"___ parents live in Beira.\" (belonging to them)","opts":["their","our","his","your"],"ans":0,"exp":"\"THEIR parents\" — they → their!"},{"q":"\"What is ___ phone number?\" (asking you)","opts":["my","his","her","your"],"ans":3,"exp":"\"YOUR phone number\" — talking to you = your!"},{"q":"Which sentence uses a possessive correctly?","opts":["This is hers bag.","This is her bag.","This is she bag.","This is her''s bag."],"ans":1,"exp":"\"This is HER bag.\" — possessive adjectives go directly before nouns, no apostrophe!"}]}'::jsonb, 5),
('l1d1', 'u1d', 'Can & Can''t — Ability', 'Can & Can''t — Capacidade', '💪', 20, '{"learn":{"explanation":{"en":"\"Can\" expresses what you are ABLE to do right now. \"Can''t\" (cannot) is the negative. Important rule: \"can\" NEVER changes — no -s, no -ed, no -ing. Always use the BASE verb after \"can\": \"She can swim.\" (NOT \"she cans swim\" or \"she can swims\"). Questions: \"Can you...?\" Answers: \"Yes, I can.\" / \"No, I can''t.\"","pt":"\"Can\" expressa o que és CAPAZ de fazer agora. \"Can''t\" (cannot) é o negativo. Regra importante: \"can\" NUNCA muda — sem -s, sem -ed, sem -ing. Usa sempre o verbo BASE depois de \"can\": \"She can swim.\" (NÃO \"she cans swim\" ou \"she can swims\"). Perguntas: \"Can you...?\" Respostas: \"Yes, I can.\" / \"No, I can''t.\""},"examples":[{"en":"I can speak English and Portuguese.","pt":"Eu sei falar inglês e português."},{"en":"She can''t drive — she is only 15.","pt":"Ela não sabe conduzir — ela só tem 15 anos."},{"en":"Can you help me, please?","pt":"Podes ajudar-me, por favor?"},{"en":"Yes, I can! / No, I can''t.","pt":"Sim, posso! / Não, não posso."},{"en":"He can play football very well.","pt":"Ele joga futebol muito bem."}],"practice":[{"q":"\"She ___ play the guitar.\" (she has this skill)","opts":["cans","can","is able","to can"],"ans":1,"exp":"\"She CAN play the guitar.\" — can never adds -s!"},{"q":"\"Can you swim?\" — Best answer:","opts":["Yes, I am.","Yes, I do.","Yes, I can.","Yes, I could."],"ans":2,"exp":"\"Yes, I CAN.\" — answer can with can!"}]},"qs":[{"q":"\"He ___ ride a bicycle.\" (has the skill)","opts":["cans","can","is able to","to can"],"ans":1,"exp":"\"He CAN ride a bicycle.\" — can NEVER adds -s!"},{"q":"Negative of \"I can dance\":","opts":["I don''t can dance.","I can''t dance.","I not can dance.","I cannot to dance."],"ans":1,"exp":"\"I CAN''T dance.\" = I cannot dance. Can + not = can''t!"},{"q":"Question form of \"You can cook\":","opts":["Do you can cook?","Are you can cook?","Can you cook?","You can cook?"],"ans":2,"exp":"\"CAN you cook?\" — move can to the front!"},{"q":"\"She can swims.\" — Is this correct?","opts":["Yes, correct","No, should be: she can swim","No, should be: she cans swim","No, should be: she is can swim"],"ans":1,"exp":"WRONG! After \"can\" always use BASE verb: \"She can SWIM.\""},{"q":"\"___ you speak French?\" (asking ability)","opts":["Do","Are","Can","Have"],"ans":2,"exp":"\"CAN you speak French?\" — can for ability!"},{"q":"\"I can''t see the board.\" means:","opts":["I don''t want to see it","I am not able to see it","I am allowed to see it","I should see it"],"ans":1,"exp":"\"Can''t\" = am not able to. I cannot see the board!"},{"q":"Which is grammatically CORRECT?","opts":["She can to swim.","She can swims.","She cans swim.","She can swim."],"ans":3,"exp":"\"She CAN swim.\" — can + base verb, no to, no -s!"}]}'::jsonb, 0),
('l1d2', 'u1d', 'Could — Past Ability & Polite Requests', 'Could — Capacidade Passada e Pedidos Educados', '🙏', 20, '{"learn":{"explanation":{"en":"\"Could\" has two uses. (1) Past ability — what someone WAS able to do in the past: \"When I was young, I could run fast.\" (2) Polite requests — more formal and polite than \"can\": \"Could you help me, please?\" is more polite than \"Can you help me?\" \"Could I have a glass of water?\" Both uses follow the same rule: could + base verb, never changes.","pt":"\"Could\" tem dois usos. (1) Capacidade passada — o que alguém ERA capaz de fazer no passado: \"When I was young, I could run fast.\" (2) Pedidos educados — mais formal e educado do que \"can\": \"Could you help me, please?\" é mais educado do que \"Can you help me?\" \"Could I have a glass of water?\" Ambos os usos seguem a mesma regra: could + verbo base, nunca muda."},"examples":[{"en":"When I was young, I could climb trees.","pt":"Quando eu era jovem, eu conseguia trepar às árvores."},{"en":"She couldn''t walk until she was 18 months old.","pt":"Ela não conseguia andar até ter 18 meses."},{"en":"Could you repeat that, please? (polite)","pt":"Poderia repetir isso, por favor? (educado)"},{"en":"Could I use your phone? (asking permission politely)","pt":"Poderia usar o teu telemóvel? (pedir permissão educadamente)"},{"en":"He could speak three languages as a child.","pt":"Ele conseguia falar três línguas quando era criança."}],"practice":[{"q":"Which use of \"could\" is correct for past ability?","opts":["Could you open the door?","I could swim when I was five.","Could I leave early?","Could you pass the salt?"],"ans":1,"exp":"\"I could swim when I was five.\" = past ability — I WAS ABLE TO swim then."},{"q":"\"Could you pass the salt?\" is:","opts":["past ability","future plan","polite request","obligation"],"ans":2,"exp":"Polite request! \"Could you...?\" sounds more formal and polite than \"Can you...?\""}]},"qs":[{"q":"\"When I was a child, I ___ speak Changana fluently.\"","opts":["can","could","should","must"],"ans":1,"exp":"\"I COULD speak Changana.\" — past ability (I was able to then)!"},{"q":"\"___ you help me with this bag, please?\" (polite request)","opts":["Can","Could","Should","Must"],"ans":1,"exp":"\"COULD you help me?\" — more polite/formal than \"can\"!"},{"q":"\"She couldn''t walk until she was two.\" means:","opts":["She didn''t want to walk","She wasn''t able to walk","She wasn''t allowed to walk","She didn''t try to walk"],"ans":1,"exp":"\"Couldn''t\" = was not able to. She was NOT ABLE to walk at that time!"},{"q":"\"Could I sit here?\" is asking for:","opts":["ability","past action","polite permission","obligation"],"ans":2,"exp":"\"Could I...?\" = asking permission politely. \"Is it okay if I sit here?\""},{"q":"\"___ you speak English when you were ten?\" (past)","opts":["Can","Could","Do","Did"],"ans":1,"exp":"\"COULD you speak English when you were ten?\" = asking about past ability!"},{"q":"Which is more polite?","opts":["\"Can you help me?\"","\"Could you help me?\"","Both are the same","Neither is polite"],"ans":1,"exp":"\"COULD you help me?\" is more polite and formal than \"can\"!"},{"q":"\"I could run very fast when I was young.\" This is about:","opts":["future plans","present ability","past ability","advice"],"ans":2,"exp":"Past ability — when I was young (past time), I WAS ABLE TO run fast!"}]}'::jsonb, 1),
('l1d3', 'u1d', 'Must & Have To — Obligation', 'Must & Have To — Obrigação', '⚠️', 25, '{"learn":{"explanation":{"en":"\"Must\" and \"have to\" both express obligation — something that is necessary or required. MUST = strong obligation, often from the speaker''s own feeling: \"I must study tonight.\" (I feel I need to). HAVE TO = obligation from external rules or circumstances: \"I have to wear a uniform at school.\" (the school rule). Negative: \"mustn''t\" = prohibition (you are NOT allowed). \"Don''t have to\" = it''s NOT necessary (but you can if you want).","pt":"\"Must\" e \"have to\" expressam ambos obrigação — algo que é necessário ou exigido. MUST = obrigação forte, muitas vezes do sentimento do próprio falante: \"I must study tonight.\" (Sinto que preciso). HAVE TO = obrigação de regras externas ou circunstâncias: \"I have to wear a uniform at school.\" (a regra da escola). Negativo: \"mustn''t\" = proibição (NÃO tens permissão). \"Don''t have to\" = NÃO é necessário (mas podes se quiseres)."},"examples":[{"en":"I must finish this report today. (personal obligation)","pt":"Eu devo terminar este relatório hoje. (obrigação pessoal)"},{"en":"Students have to wear a uniform here. (rule)","pt":"Os alunos têm de usar farda aqui. (regra)"},{"en":"You mustn''t smoke in the hospital. (forbidden!)","pt":"Não podes fumar no hospital. (proibido!)"},{"en":"You don''t have to come — it''s optional.","pt":"Não tens de vir — é opcional."},{"en":"She has to wake up at 5am for work.","pt":"Ela tem de acordar às 5h para o trabalho."}],"practice":[{"q":"\"You ___ smoke here — it''s forbidden!\"","opts":["mustn''t","don''t have to","should","must"],"ans":0,"exp":"\"Mustn''t\" = NOT allowed! Prohibition! You are FORBIDDEN to smoke here."},{"q":"\"You ___ come to the meeting. It''s optional.\"","opts":["must","mustn''t","have to","don''t have to"],"ans":3,"exp":"\"Don''t have to\" = not necessary, but you can if you want. It''s optional."}]},"qs":[{"q":"\"You ___ eat vegetables. They''re good for you!\" (strong advice/obligation)","opts":["don''t have to","mustn''t","must","could"],"ans":2,"exp":"\"You MUST eat vegetables!\" — strong personal obligation/advice!"},{"q":"\"She ___ wear a helmet on the motorcycle.\" (rule/law)","opts":["must","has to","should","could"],"ans":1,"exp":"\"She HAS TO wear a helmet.\" — it''s a rule/law, external obligation!"},{"q":"\"You ___ touch the fire! It''s dangerous!\" (forbidden)","opts":["must","have to","mustn''t","don''t have to"],"ans":2,"exp":"\"You MUSTN''T touch the fire!\" — mustn''t = prohibition, NOT allowed!"},{"q":"\"You ___ pay for the bus. I have money.\" (not necessary)","opts":["must","have to","mustn''t","don''t have to"],"ans":3,"exp":"\"You DON''T HAVE TO pay.\" = It''s not necessary — I''ll pay!"},{"q":"\"I ___ go to the doctor today. I feel terrible.\" (personal need)","opts":["don''t have to","must","mustn''t","could"],"ans":1,"exp":"\"I MUST go to the doctor.\" — strong personal feeling of necessity!"},{"q":"What is the difference between \"mustn''t\" and \"don''t have to\"?","opts":["They mean the same thing","Mustn''t = forbidden; don''t have to = not necessary","Don''t have to = forbidden; mustn''t = not necessary","There is no difference"],"ans":1,"exp":"\"MUSTN''T\" = prohibited (not allowed). \"DON''T HAVE TO\" = not necessary (but OK if you want)."},{"q":"\"Students have to arrive on time.\" This means:","opts":["Students can arrive late","It is optional","It is a rule they must follow","Students should try to arrive on time"],"ans":2,"exp":"\"Have to\" = it is an external rule/obligation they must follow!"}]}'::jsonb, 2),
('l1d4', 'u1d', 'Should & Shouldn''t — Advice', 'Should & Shouldn''t — Conselho', '🎯', 20, '{"learn":{"explanation":{"en":"\"Should\" is used to give advice or make recommendations — it is LESS strong than must. \"Should\" = I think this is a good idea. \"Shouldn''t\" = I think this is a bad idea. \"You should drink more water.\" = good advice. \"You shouldn''t eat so much sugar.\" = advice against something. Questions with \"should\" ask for advice: \"Should I call the doctor?\" \"What should I do?\"","pt":"\"Should\" é usado para dar conselhos ou fazer recomendações — é MENOS forte do que must. \"Should\" = acho que isto é uma boa ideia. \"Shouldn''t\" = acho que isto é uma má ideia. \"You should drink more water.\" = bom conselho. \"You shouldn''t eat so much sugar.\" = conselho contra algo. Perguntas com \"should\" pedem conselho: \"Should I call the doctor?\" \"What should I do?\""},"examples":[{"en":"You should sleep early if you have an exam tomorrow.","pt":"Deves dormir cedo se tiveres exame amanhã."},{"en":"You shouldn''t eat so much junk food.","pt":"Não deves comer tanta comida lixo."},{"en":"Should I take an umbrella? It looks cloudy.","pt":"Devo levar um chapéu-de-chuva? Parece nublado."},{"en":"You should see a doctor — you look pale.","pt":"Devias ver um médico — estás pálido/a."},{"en":"We shouldn''t waste water.","pt":"Não devíamos desperdiçar água."}],"practice":[{"q":"My friend has a cold. What should I say?","opts":["You must drink water.","You should rest and drink fluids.","You have to see a doctor now.","You could not eat."],"ans":1,"exp":"\"You SHOULD rest and drink fluids.\" — should for advice, not forcing them."},{"q":"\"You shouldn''t be late.\" This means:","opts":["you must not come","it is a bad idea to be late","you are forbidden from being late","you don''t need to come"],"ans":1,"exp":"\"Shouldn''t\" = I think this is a bad idea / I advise against it."}]},"qs":[{"q":"\"You ___ study more — your exams are next week.\"","opts":["must","should","mustn''t","don''t have to"],"ans":1,"exp":"\"You SHOULD study more.\" — advice, recommendation!"},{"q":"\"You ___ drive so fast in the rain.\"","opts":["should","mustn''t","shouldn''t","have to"],"ans":2,"exp":"\"You SHOULDN''T drive so fast.\" — advice against something dangerous!"},{"q":"\"___ I take a jacket? It might be cold.\"","opts":["Must","Have to","Should","Can"],"ans":2,"exp":"\"SHOULD I take a jacket?\" — asking for advice!"},{"q":"\"What ___ I do? I''m lost!\" (asking for advice)","opts":["must","can","should","have to"],"ans":2,"exp":"\"What SHOULD I do?\" — asking someone for their recommendation!"},{"q":"\"You should drink more water.\" This is:","opts":["a rule","a prohibition","advice","past ability"],"ans":2,"exp":"\"Should\" gives advice — a recommendation, not a strict rule!"},{"q":"What is \"should\" used for?","opts":["past ability","polite requests","advice and recommendations","future plans"],"ans":2,"exp":"\"Should\" = advice and recommendations. Less strong than \"must\"!"},{"q":"Which is correct advice for someone who is tired?","opts":["You should to sleep.","You should sleeps.","You should sleep.","You should sleeping."],"ans":2,"exp":"\"You should SLEEP.\" — should + base verb, no to, no -s, no -ing!"}]}'::jsonb, 3),
('l1d5', 'u1d', 'May & Might — Possibility', 'May & Might — Possibilidade', '🎲', 20, '{"learn":{"explanation":{"en":"\"May\" and \"might\" both express possibility — something that is possible but not certain. \"It may rain tomorrow.\" = perhaps it will rain (50/50). \"It might rain tomorrow.\" = similar, but might suggests a little LESS certainty. Both use the base verb. \"May\" is also used for formal permission: \"May I come in?\" = Can I come in? (polite). In everyday speech, \"might\" is very common for possibility.","pt":"\"May\" e \"might\" expressam ambos possibilidade — algo que é possível mas não certo. \"It may rain tomorrow.\" = talvez chova (50/50). \"It might rain tomorrow.\" = semelhante, mas might sugere um pouco MENOS de certeza. Ambos usam o verbo base. \"May\" também é usado para permissão formal: \"May I come in?\" = Can I come in? (educado). Na fala do dia-a-dia, \"might\" é muito comum para possibilidade."},"examples":[{"en":"It may rain this afternoon — take an umbrella.","pt":"Pode chover esta tarde — leva um chapéu-de-chuva."},{"en":"I might go to the party, I''m not sure.","pt":"Posso ir à festa, não tenho a certeza."},{"en":"She may be late — there''s a lot of traffic.","pt":"Ela pode chegar atrasada — há muito trânsito."},{"en":"May I use the bathroom? (formal permission)","pt":"Posso usar a casa de banho? (permissão formal)"},{"en":"He might not come — he said he was tired.","pt":"Ele talvez não venha — ele disse que estava cansado."}],"practice":[{"q":"\"I''m not sure, but I ___ go to Beira next week.\"","opts":["must","should","might","have to"],"ans":2,"exp":"\"Might go\" — possibility, not certain. I''m not sure yet!"},{"q":"\"May I open the window?\" is asking for:","opts":["advice","possibility","formal permission","past ability"],"ans":2,"exp":"\"May I...?\" = formal way to ask for permission. More polite than \"Can I...?\""}]},"qs":[{"q":"\"It ___ rain later. Those clouds look dark.\"","opts":["must","should","might","has to"],"ans":2,"exp":"\"It MIGHT rain.\" — possible but not certain!"},{"q":"\"___ I ask you a question?\" (formal)","opts":["Should","Must","May","Have to"],"ans":2,"exp":"\"MAY I ask?\" — formal/polite request for permission!"},{"q":"\"She ___ be at home — try calling her.\"","opts":["must","might","has to","should"],"ans":1,"exp":"\"She MIGHT be at home.\" — she''s possibly there, but we''re not sure!"},{"q":"\"I might not come to class tomorrow.\" means:","opts":["I will definitely miss class","It''s possible I won''t come","I must miss class","I should miss class"],"ans":1,"exp":"\"Might not\" = it''s possible I won''t come — not certain either way!"},{"q":"\"May\" for possibility is similar to:","opts":["must","have to","might","should"],"ans":2,"exp":"\"May\" and \"might\" are both used for possibility — something possible but not certain!"},{"q":"Which sentence expresses possibility?","opts":["You must eat.","You should rest.","It might snow.","You have to leave."],"ans":2,"exp":"\"It MIGHT snow.\" — possible but not certain! 🌨️"},{"q":"\"May I sit here?\" This is:","opts":["a possibility","asking permission politely","giving advice","expressing obligation"],"ans":1,"exp":"\"May I...?\" = asking permission in a polite/formal way!"}]}'::jsonb, 4),
('l1d6', 'u1d', 'Modal Verbs — Summary & Practice', 'Verbos Modais — Resumo e Prática', '📋', 30, '{"learn":{"explanation":{"en":"Let''s review all modal verbs together! Can (ability now), Could (past ability / polite request), Must/Have to (obligation), Mustn''t (prohibition), Don''t have to (not necessary), Should (advice), May/Might (possibility). Key rule for ALL modals: always use the BASE verb after them — never add -s, -ed, or -ing. \"She can speak.\" ✓ \"She can speaks.\" ✗ \"She can speaking.\" ✗","pt":"Vamos rever todos os verbos modais juntos! Can (capacidade agora), Could (capacidade passada / pedido educado), Must/Have to (obrigação), Mustn''t (proibição), Don''t have to (não necessário), Should (conselho), May/Might (possibilidade). Regra fundamental para TODOS os modais: usa sempre o verbo BASE depois deles — nunca adiciones -s, -ed, ou -ing. \"She can speak.\" ✓ \"She can speaks.\" ✗ \"She can speaking.\" ✗"},"examples":[{"en":"I can swim. (ability)","pt":"Eu sei nadar. (capacidade)"},{"en":"You should rest. (advice)","pt":"Devias descansar. (conselho)"},{"en":"You must study. (strong obligation)","pt":"Deves estudar. (obrigação forte)"},{"en":"It might rain. (possibility)","pt":"Pode chover. (possibilidade)"},{"en":"You mustn''t smoke here. (prohibition)","pt":"Não podes fumar aqui. (proibição)"}],"practice":[{"q":"Which modal gives ADVICE?","opts":["must","can","should","might"],"ans":2,"exp":"\"Should\" = advice. \"You should study more.\""},{"q":"Which modal expresses PROHIBITION?","opts":["don''t have to","shouldn''t","might not","mustn''t"],"ans":3,"exp":"\"Mustn''t\" = you are NOT ALLOWED to do it. Stronger than shouldn''t!"}]},"qs":[{"q":"Which modal expresses ABILITY?","opts":["should","must","can","might"],"ans":2,"exp":"\"Can\" = ability. \"I CAN speak English.\""},{"q":"Which modal expresses POSSIBILITY (not certain)?","opts":["can","must","should","might"],"ans":3,"exp":"\"Might\" = possibility. \"It might rain.\" — not certain!"},{"q":"\"You ___ come if you don''t want to.\" (not necessary)","opts":["must","have to","mustn''t","don''t have to"],"ans":3,"exp":"\"DON''T HAVE TO\" = not necessary. You have a choice!"},{"q":"Which is grammatically CORRECT?","opts":["She should rests.","She should to rest.","She should rest.","She should resting."],"ans":2,"exp":"\"She should REST.\" — modal + base verb. No -s, no to, no -ing!"},{"q":"\"You ___ drink and drive!\" (it''s illegal)","opts":["shouldn''t","don''t have to","mustn''t","might not"],"ans":2,"exp":"\"You MUSTN''T drink and drive!\" — it''s forbidden by law!"},{"q":"\"Could you pass the sugar?\" is:","opts":["past ability","a polite request","strong obligation","advice"],"ans":1,"exp":"\"Could you...?\" = a polite/formal request! More polite than \"Can you...?\""},{"q":"\"I ___ be wrong — let me check.\" (uncertain)","opts":["must","should","might","have to"],"ans":2,"exp":"\"I MIGHT be wrong.\" — expressing uncertainty, possible but not sure!"}]}'::jsonb, 5),
('l1e1', 'u1e', 'Morning & Evening Routines', 'Rotinas Matinais e Nocturnas', '⏰', 20, '{"learn":{"explanation":{"en":"A routine is something you do regularly, usually at the same time every day. We use the Simple Present tense to describe routines. Signal words: every day, in the morning, at night, usually, always, first, then, after that, finally. \"First I wake up, then I brush my teeth, after that I have breakfast, and finally I go to school.\"","pt":"Uma rotina é algo que fazes regularmente, normalmente à mesma hora todos os dias. Usamos o Presente Simples para descrever rotinas. Palavras-sinal: every day, in the morning, at night, usually, always, first, then, after that, finally. \"First I wake up, then I brush my teeth, after that I have breakfast, and finally I go to school.\""},"examples":[{"en":"I wake up at 6am every day.","pt":"Acordo às 6h todos os dias."},{"en":"First, I brush my teeth. Then, I take a shower.","pt":"Primeiro, escovo os dentes. Depois, tomo duche."},{"en":"After that, I have breakfast.","pt":"A seguir, tomo o pequeno-almoço."},{"en":"I go to bed at 10pm.","pt":"Vou para a cama às 22h."},{"en":"She usually reads before sleeping.","pt":"Ela normalmente lê antes de dormir."}],"practice":[{"q":"Which signal word shows sequence (what comes next)?","opts":["yesterday","usually","then","always"],"ans":2,"exp":"\"Then\" shows sequence — first I do A, THEN I do B!"},{"q":"\"I wake up at 6am every day.\" Which tense?","opts":["Past Simple","Future","Present Continuous","Simple Present"],"ans":3,"exp":"Simple Present! \"Wake up\" — routine/habit!"}]},"qs":[{"q":"\"First I brush my teeth, ___ I have breakfast.\"","opts":["before","although","then","after"],"ans":2,"exp":"\"THEN I have breakfast.\" — then shows what comes next in a sequence!"},{"q":"\"I ___ up at 6am every day.\" (wake)","opts":["wake","wakes","waking","woke"],"ans":0,"exp":"\"I WAKE up.\" — Simple Present, first person, no -s!"},{"q":"\"She ___ to bed at 10pm.\" (go)","opts":["go","going","goes","went"],"ans":2,"exp":"\"She GOES to bed.\" — third person singular adds -s!"},{"q":"Which word describes a daily routine?","opts":["yesterday","last week","every day","right now"],"ans":2,"exp":"\"Every day\" signals a routine/habit — use Simple Present!"},{"q":"\"After that, I ___ to school.\" (go)","opts":["am going","goes","went","go"],"ans":3,"exp":"\"After that, I GO to school.\" — Simple Present for routines!"},{"q":"\"I wake up, ___ I brush my teeth, ___ I shower.\"","opts":["then/then","first/then","after/before","always/usually"],"ans":1,"exp":"\"First I wake up, THEN I brush my teeth, THEN I shower.\" Sequence!"},{"q":"What time do most Mozambican students wake up for school?","opts":["At midnight","At 2pm","Early morning around 5-6am","At 10am"],"ans":2,"exp":"Most students wake up early — around 5-6am — to get ready for school! 🌅"}]}'::jsonb, 0),
('l1e2', 'u1e', 'Describing Your Day', 'Descrever o Teu Dia', '📅', 20, '{"learn":{"explanation":{"en":"To describe your day, use time expressions: in the morning (de manhã), in the afternoon (de tarde), in the evening (à tarde/noite), at night (à noite), at noon (ao meio-dia). Use \"at\" with clock times: \"at 7am\". Use \"in\" with parts of the day. Use \"on\" with days: \"on Monday\". To connect events: first, then, next, after that, later, finally.","pt":"Para descrever o teu dia, usa expressões de tempo: in the morning (de manhã), in the afternoon (de tarde), in the evening (à tarde/noite), at night (à noite), at noon (ao meio-dia). Usa \"at\" com horas: \"at 7am\". Usa \"in\" com partes do dia. Usa \"on\" com dias: \"on Monday\". Para ligar eventos: first, then, next, after that, later, finally."},"examples":[{"en":"In the morning, I go to school.","pt":"De manhã, eu vou para a escola."},{"en":"At noon, I eat lunch with my friends.","pt":"Ao meio-dia, almoço com os meus amigos."},{"en":"In the afternoon, I study or play football.","pt":"À tarde, estudo ou jogo futebol."},{"en":"In the evening, my family watches TV.","pt":"À noite cedo, a minha família vê televisão."},{"en":"At night, I read and go to sleep.","pt":"À noite, leio e vou dormir."}],"practice":[{"q":"\"___ Monday I have English class.\"","opts":["In","At","On","By"],"ans":2,"exp":"\"ON Monday\" — use ON with specific days of the week!"},{"q":"\"I eat lunch ___ noon.\"","opts":["on","in","by","at"],"ans":3,"exp":"\"AT noon\" — use AT with clock times and \"noon\"!"}]},"qs":[{"q":"\"___ the morning, I exercise.\"","opts":["At","On","In","By"],"ans":2,"exp":"\"IN the morning\" — parts of the day use IN!"},{"q":"\"My class starts ___ 8am.\"","opts":["in","on","at","by"],"ans":2,"exp":"\"AT 8am\" — clock times use AT!"},{"q":"\"___ Saturdays, I go to the market.\"","opts":["At","In","On","By"],"ans":2,"exp":"\"ON Saturdays\" — days of the week use ON!"},{"q":"What do you do \"at noon\"?","opts":["sleep","eat breakfast","eat lunch","go to work"],"ans":2,"exp":"Noon = midday = 12pm. Most people eat LUNCH at noon! 🍽️"},{"q":"\"In the evening\" usually means:","opts":["very early morning","around midday","late afternoon/early night","midnight"],"ans":2,"exp":"\"In the evening\" = late afternoon/early night, roughly 6-9pm!"},{"q":"\"I study ___ the afternoon.\" (part of day)","opts":["at","on","in","by"],"ans":2,"exp":"\"IN the afternoon\" — parts of the day use IN!"},{"q":"Which sequence is CORRECT for a typical day?","opts":["Lunch → Breakfast → School → Dinner","Breakfast → School → Lunch → Dinner","Dinner → Lunch → Breakfast → School","School → Breakfast → Dinner → Lunch"],"ans":1,"exp":"Typical day: Breakfast → School → Lunch → Dinner. Morning first!"}]}'::jsonb, 1),
('l1e3', 'u1e', 'At the Doctor — Health Vocabulary', 'No Médico — Vocabulário de Saúde', '🏥', 25, '{"learn":{"explanation":{"en":"Health vocabulary helps you describe how you feel and communicate with a doctor or nurse. Common symptoms: headache (dor de cabeça), stomachache (dor de estômago), fever (febre), cough (tosse), sore throat (dor de garganta), cold (constipação). To say you have a symptom: \"I have a headache.\" \"I feel sick/dizzy/tired.\" \"My stomach hurts.\" \"I have a temperature.\"","pt":"O vocabulário de saúde ajuda-te a descrever como te sentes e a comunicar com um médico ou enfermeiro. Sintomas comuns: headache (dor de cabeça), stomachache (dor de estômago), fever (febre), cough (tosse), sore throat (dor de garganta), cold (constipação). Para dizer que tens um sintoma: \"I have a headache.\" \"I feel sick/dizzy/tired.\" \"My stomach hurts.\" \"I have a temperature.\""},"examples":[{"en":"I have a terrible headache.","pt":"Eu tenho uma dor de cabeça terrível."},{"en":"Doctor, I feel sick and I have a fever.","pt":"Doutor, sinto-me mal e tenho febre."},{"en":"My throat is very sore.","pt":"A minha garganta dói muito."},{"en":"How long have you had this cough?","pt":"Há quanto tempo tens esta tosse?"},{"en":"Take this medicine three times a day.","pt":"Tome este medicamento três vezes por dia."}],"practice":[{"q":"How do you say you have a headache?","opts":["My head hurts.","I am sick in my head.","I have a headache.","Both A and C."],"ans":3,"exp":"Both \"My head hurts\" and \"I have a headache\" are correct!"},{"q":"\"Fever\" means:","opts":["dor de cabeça","tosse","temperatura alta","dor de garganta"],"ans":2,"exp":"Fever = temperatura alta (febre). Your body temperature is above normal!"}]},"qs":[{"q":"How do you say you feel sick?","opts":["I am sick.","I feel sick.","I have sickness.","Both A and B."],"ans":3,"exp":"Both \"I AM sick\" and \"I FEEL sick\" are correct ways to say this!"},{"q":"\"Sore throat\" means:","opts":["dor de cabeça","dor de estômago","dor de garganta","tosse"],"ans":2,"exp":"\"Sore throat\" = dor de garganta. When your throat is painful!"},{"q":"\"I have a ___.\": Which completes a symptom?","opts":["hungry","headache","thirsty","tired"],"ans":1,"exp":"\"I have a HEADACHE.\" — headache is a noun/symptom. Hungry/thirsty/tired use \"I am/feel\"."},{"q":"\"Doctor, my stomach ___.\"","opts":["hurts","hurt","is hurting a lot","Both A and C"],"ans":3,"exp":"\"My stomach HURTS\" and \"my stomach IS HURTING\" are both correct!"},{"q":"What do you take when you are sick?","opts":["exercise","medicine","food","coffee"],"ans":1,"exp":"You take MEDICINE (medicamento) when you are sick!"},{"q":"\"Take this medicine three times a day.\" means you take it:","opts":["once","twice","three times","every hour"],"ans":2,"exp":"\"Three times a day\" = três vezes por dia — morning, afternoon, night!"},{"q":"\"I have a fever.\" Fever means your body:","opts":["is cold","is very hot","is normal","is shaking"],"ans":1,"exp":"Fever = your body temperature is very HOT, above normal (above 37.5°C)!"}]}'::jsonb, 2),
('l1e4', 'u1e', 'Feelings & Emotions', 'Sentimentos e Emoções', '😊', 20, '{"learn":{"explanation":{"en":"Describing how you feel is essential for communication. Use \"I feel...\" or \"I am...\" with adjectives. Common emotions: happy (feliz), sad (triste), angry (zangado/a), scared/afraid (com medo), tired (cansado/a), excited (entusiasmado/a), bored (aborrecido/a), nervous (nervoso/a), surprised (surpreendido/a), proud (orgulhoso/a). To ask: \"How do you feel?\" \"Are you okay?\"","pt":"Descrever como te sentes é essencial para a comunicação. Usa \"I feel...\" ou \"I am...\" com adjectivos. Emoções comuns: happy (feliz), sad (triste), angry (zangado/a), scared/afraid (com medo), tired (cansado/a), excited (entusiasmado/a), bored (aborrecido/a), nervous (nervoso/a), surprised (surpreendido/a), proud (orgulhoso/a). Para perguntar: \"How do you feel?\" \"Are you okay?\""},"examples":[{"en":"I feel very happy today!","pt":"Sinto-me muito feliz hoje!"},{"en":"She looks sad. What happened?","pt":"Ela parece triste. O que aconteceu?"},{"en":"I am nervous about the exam tomorrow.","pt":"Estou nervoso/a com o exame de amanhã."},{"en":"Are you okay? You look tired.","pt":"Estás bem? Pareces cansado/a."},{"en":"He was so excited before the football match.","pt":"Ele estava muito entusiasmado antes do jogo de futebol."}],"practice":[{"q":"\"Feliz\" in English is:","opts":["angry","tired","happy","sad"],"ans":2,"exp":"Feliz = HAPPY! \"I feel happy today.\" 😊"},{"q":"If you have an important exam, you might feel:","opts":["bored","happy","nervous","proud"],"ans":2,"exp":"Most people feel NERVOUS before an important exam!"}]},"qs":[{"q":"\"Triste\" in English is:","opts":["happy","angry","tired","sad"],"ans":3,"exp":"Triste = SAD. \"I feel sad today.\" 😢"},{"q":"\"I am ___ about the exam.\" (feeling nervous)","opts":["scared","nervous","excited","tired"],"ans":1,"exp":"\"I am NERVOUS about the exam.\" = Estou nervoso/a com o exame!"},{"q":"\"How do you ___?\" (asking about feelings)","opts":["do","look","feel","are"],"ans":2,"exp":"\"How do you FEEL?\" = Como te sentes? The standard question!"},{"q":"\"She is ___ because she won the prize!\" (very happy)","opts":["bored","sad","tired","excited"],"ans":3,"exp":"\"She is EXCITED!\" — very happy and enthusiastic about something great! 🎉"},{"q":"\"Are you okay? You ___ tired.\"","opts":["feel","look","am","have"],"ans":1,"exp":"\"You LOOK tired.\" — look = to appear/seem. She appears tired visually!"},{"q":"\"Zangado\" in English is:","opts":["tired","bored","happy","angry"],"ans":3,"exp":"Zangado = ANGRY. \"He is angry because he missed the bus.\""},{"q":"Which sentence is CORRECT?","opts":["I am feeling happy.","I feeling happy.","I feels happy.","I happy feeling."],"ans":0,"exp":"\"I AM FEELING happy.\" = I feel happy. Both \"I am happy\" and \"I am feeling happy\" are correct!"}]}'::jsonb, 3),
('l1e5', 'u1e', 'At the Pharmacy', 'Na Farmácia', '💊', 20, '{"learn":{"explanation":{"en":"At a pharmacy (farmácia) in Mozambique or anywhere, you need to describe your symptoms and understand the pharmacist''s advice. Key phrases: \"I need something for...\" (Preciso de algo para...). \"Do you have anything for a headache?\" Types of medicine: tablets/pills (comprimidos), syrup (xarope), cream (creme), drops (gotas). Instruction words: take (tomar), apply (aplicar), twice a day (duas vezes por dia).","pt":"Numa farmácia em Moçambique ou em qualquer lugar, precisas de descrever os teus sintomas e entender o conselho do farmacêutico. Frases-chave: \"I need something for...\" (Preciso de algo para...). \"Do you have anything for a headache?\" Tipos de medicamento: tablets/pills (comprimidos), syrup (xarope), cream (creme), drops (gotas). Palavras de instrução: take (tomar), apply (aplicar), twice a day (duas vezes por dia)."},"examples":[{"en":"I need something for a headache.","pt":"Preciso de algo para uma dor de cabeça."},{"en":"Do you have any cough syrup?","pt":"Tem algum xarope para a tosse?"},{"en":"Take two tablets three times a day.","pt":"Tome dois comprimidos três vezes por dia."},{"en":"Apply this cream to the wound twice a day.","pt":"Aplique esta creme na ferida duas vezes por dia."},{"en":"Is this medicine available without a prescription?","pt":"Este medicamento está disponível sem receita?"}],"practice":[{"q":"How do you ask for medicine at a pharmacy?","opts":["Give me medicine.","I need something for a headache.","Medicine please.","Buy me pills."],"ans":1,"exp":"\"I need something for a headache.\" — polite and clear!"},{"q":"\"Twice a day\" means:","opts":["one time","two times","three times","every hour"],"ans":1,"exp":"\"Twice a day\" = two times per day — morning and night!"}]},"qs":[{"q":"\"I need something ___ a cough.\"","opts":["about","with","for","from"],"ans":2,"exp":"\"I need something FOR a cough.\" — \"for\" shows the purpose!"},{"q":"\"Twice a day\" means taking medicine:","opts":["once","two times","three times","four times"],"ans":1,"exp":"\"Twice a day\" = TWO times a day! Twice = 2x."},{"q":"\"Comprimidos\" in English are:","opts":["syrup","tablets/pills","cream","drops"],"ans":1,"exp":"\"Comprimidos\" = tablets or pills — solid medicine you swallow!"},{"q":"\"Take three ___ per day.\" (solid medicine)","opts":["syrups","creams","drops","tablets"],"ans":3,"exp":"\"Take three TABLETS per day.\" = Tome três comprimidos por dia!"},{"q":"\"Apply this cream to your skin.\" means:","opts":["eat the cream","put the cream on your skin","take the cream orally","drink the cream"],"ans":1,"exp":"\"Apply\" = put on/spread on. You apply cream TO the skin, don''t eat it! 😄"},{"q":"Where do you buy medicine without going to a hospital?","opts":["supermarket","pharmacy","school","market"],"ans":1,"exp":"You buy medicine at a PHARMACY (farmácia)!"},{"q":"\"Do you have ___ aspirin?\" (asking if they sell it)","opts":["some","the","a","any"],"ans":3,"exp":"\"Do you have ANY aspirin?\" — questions about availability use \"any\"!"}]}'::jsonb, 4),
('l1e6', 'u1e', 'Healthy Habits & Advice', 'Hábitos Saudáveis e Conselhos', '🥗', 25, '{"learn":{"explanation":{"en":"Healthy habits help you live better. To give health advice, use should/shouldn''t. \"You should eat vegetables every day.\" \"You shouldn''t drink too much soda.\" Healthy activities: exercise regularly, sleep 8 hours, drink water, eat fruits and vegetables. Unhealthy habits: smoking, drinking too much alcohol, eating too much junk food, not sleeping enough. Use \"too much\" (demais) for negative excess.","pt":"Os hábitos saudáveis ajudam-te a viver melhor. Para dar conselhos de saúde, usa should/shouldn''t. \"You should eat vegetables every day.\" \"You shouldn''t drink too much soda.\" Actividades saudáveis: exercise regularly, sleep 8 hours, drink water, eat fruits and vegetables. Hábitos não saudáveis: smoking, drinking too much alcohol, eating too much junk food, not sleeping enough. Usa \"too much\" (demais) para excesso negativo."},"examples":[{"en":"You should drink at least 2 litres of water a day.","pt":"Deves beber pelo menos 2 litros de água por dia."},{"en":"You shouldn''t eat too much sugar.","pt":"Não deves comer demasiado açúcar."},{"en":"Exercise is important for a healthy body.","pt":"O exercício é importante para um corpo saudável."},{"en":"Try to sleep for 8 hours every night.","pt":"Tenta dormir 8 horas todas as noites."},{"en":"Eating fresh fruit and vegetables keeps you healthy.","pt":"Comer fruta e legumes frescos mantém-te saudável."}],"practice":[{"q":"\"You ___ eat more vegetables.\" (advice)","opts":["must","should","mustn''t","might"],"ans":1,"exp":"\"You SHOULD eat more vegetables.\" — advice with should!"},{"q":"\"You ___ smoke — it''s very bad for you.\" (strong advice against)","opts":["should","might","shouldn''t","could"],"ans":2,"exp":"\"You SHOULDN''T smoke.\" — advice against something harmful!"}]},"qs":[{"q":"\"You ___ exercise regularly.\" (it''s a good idea)","opts":["must","should","mustn''t","might"],"ans":1,"exp":"\"You SHOULD exercise regularly.\" — giving health advice!"},{"q":"\"You ___ eat too much junk food.\" (bad advice)","opts":["should","might","shouldn''t","could"],"ans":2,"exp":"\"You SHOULDN''T eat too much junk food.\" — advice against unhealthy habit!"},{"q":"How many hours of sleep do doctors recommend per night?","opts":["4 hours","6 hours","8 hours","12 hours"],"ans":2,"exp":"Doctors recommend 8 HOURS of sleep per night for adults! 😴"},{"q":"\"Too much\" before a noun means:","opts":["a good amount","a small amount","more than is good/healthy","the correct amount"],"ans":2,"exp":"\"Too much\" = MORE than is good. \"You eat too much sugar\" = you eat more than you should!"},{"q":"Which is a HEALTHY habit?","opts":["smoking every day","drinking 2 litres of water daily","eating junk food often","sleeping 4 hours only"],"ans":1,"exp":"Drinking 2 litres of water daily is a HEALTHY habit! Stay hydrated! 💧"},{"q":"\"___ is important for a healthy body.\"","opts":["Smoking","Not sleeping","Exercise","Junk food"],"ans":2,"exp":"\"EXERCISE is important for a healthy body.\" Stay active! 🏃"},{"q":"\"She should ___ more.\" (advice to sleep)","opts":["sleeps","sleeping","to sleep","sleep"],"ans":3,"exp":"\"She should SLEEP more.\" — should + base verb!"}]}'::jsonb, 5),
('l1f1', 'u1f', 'At the Airport', 'No Aeroporto', '✈️', 25, '{"learn":{"explanation":{"en":"At the airport, you need to check in, find your gate, and board your flight. Key vocabulary: passport (passaporte), ticket (bilhete), boarding pass (cartão de embarque), gate (porta de embarque), flight (voo), departure (partida), arrival (chegada), customs (alfândega), luggage/baggage (bagagem). Useful questions: \"Where is gate 5?\" \"Is this the queue for check-in?\" \"What time does my flight board?\"","pt":"No aeroporto, precisas de fazer check-in, encontrar o teu gate e embarcar no teu voo. Vocabulário-chave: passport (passaporte), ticket (bilhete), boarding pass (cartão de embarque), gate (porta de embarque), flight (voo), departure (partida), arrival (chegada), customs (alfândega), luggage/baggage (bagagem). Perguntas úteis: \"Where is gate 5?\" \"Is this the queue for check-in?\" \"What time does my flight board?\""},"examples":[{"en":"Can I see your passport, please?","pt":"Posso ver o seu passaporte, por favor?"},{"en":"Your flight departs from gate 12.","pt":"O seu voo parte do gate 12."},{"en":"Please have your boarding pass ready.","pt":"Por favor, tenha o seu cartão de embarque pronto."},{"en":"How many bags are you checking in?","pt":"Quantas malas está a despachar?"},{"en":"The flight to Beira is delayed by 30 minutes.","pt":"O voo para Beira está atrasado 30 minutos."}],"practice":[{"q":"What document do you need to travel internationally?","opts":["ID card","driving licence","passport","boarding pass"],"ans":2,"exp":"A PASSPORT is required for international travel!"},{"q":"\"Departure\" means:","opts":["chegada","espera","partida","atraso"],"ans":2,"exp":"\"Departure\" = partida — when you LEAVE somewhere. Opposite: arrival (chegada)!"}]},"qs":[{"q":"What do you show to board a plane?","opts":["ID card","library card","boarding pass","receipt"],"ans":2,"exp":"You show your BOARDING PASS (cartão de embarque) to board a plane!"},{"q":"\"Arrival\" means:","opts":["partida","atraso","check-in","chegada"],"ans":3,"exp":"\"Arrival\" = chegada — when you ARRIVE somewhere. Opposite: departure!"},{"q":"\"The flight is delayed.\" means:","opts":["the flight is on time","the flight is early","the flight is late","the flight is cancelled"],"ans":2,"exp":"\"Delayed\" = late — the flight will leave later than planned!"},{"q":"\"Where is ___ 12?\" (asking for the boarding area)","opts":["room","gate","floor","lane"],"ans":1,"exp":"\"Where is GATE 12?\" — a gate is a boarding area at the airport!"},{"q":"\"Can I see your ___?\" said by airport staff","opts":["phone","ticket only","passport","money"],"ans":2,"exp":"\"Can I see your PASSPORT?\" = the document for international travel!"},{"q":"\"Your luggage\" means:","opts":["your passport","your boarding pass","your bags/suitcases","your ticket"],"ans":2,"exp":"\"Luggage\" = your bags and suitcases that you travel with!"},{"q":"\"The flight departs at 8am.\" \"Departs\" means:","opts":["arrives","leaves","lands","boards"],"ans":1,"exp":"\"Departs\" = LEAVES. The plane leaves at 8am!"}]}'::jsonb, 0),
('l1f2', 'u1f', 'Hotel & Accommodation', 'Hotel e Alojamento', '🏨', 25, '{"learn":{"explanation":{"en":"When staying at a hotel, you check in at reception. Key phrases: \"I have a reservation.\" (Tenho uma reserva.) \"Do you have any rooms available?\" \"I''d like a single/double room.\" \"What time is check-out?\" Key vocabulary: reception (recepção), reservation/booking (reserva), single room (quarto individual), double room (quarto duplo), key (chave), floor (andar), lift/elevator (elevador), room service (serviço de quarto).","pt":"Quando ficas num hotel, fazes check-in na recepção. Frases-chave: \"I have a reservation.\" (Tenho uma reserva.) \"Do you have any rooms available?\" \"I''d like a single/double room.\" \"What time is check-out?\" Vocabulário-chave: reception (recepção), reservation/booking (reserva), single room (quarto individual), double room (quarto duplo), key (chave), floor (andar), lift/elevator (elevador), room service (serviço de quarto)."},"examples":[{"en":"Good evening. I have a reservation under \"Sebastian\".","pt":"Boa noite. Tenho uma reserva em nome de \"Sebastian\"."},{"en":"I''d like a double room for two nights, please.","pt":"Gostaria de um quarto duplo por duas noites, por favor."},{"en":"What time is check-out?","pt":"A que horas é o check-out?"},{"en":"Can I have the key for room 304?","pt":"Posso ter a chave do quarto 304?"},{"en":"Is breakfast included in the price?","pt":"O pequeno-almoço está incluído no preço?"}],"practice":[{"q":"\"I have a ___ under Smith.\" (pre-booked)","opts":["room","key","reservation","floor"],"ans":2,"exp":"\"I have a RESERVATION.\" — a reservation means you booked in advance!"},{"q":"A \"double room\" has:","opts":["one bed for one person","two beds or one large bed","a kitchen","a pool"],"ans":1,"exp":"A DOUBLE ROOM has two beds or one large bed, for two people!"}]},"qs":[{"q":"\"I''d like a ___ room.\" (for one person only)","opts":["double","triple","single","family"],"ans":2,"exp":"\"Single room\" = quarto individual — for ONE person!"},{"q":"At what moment do you \"check in\" at a hotel?","opts":["when you leave","when you pay","when you arrive and get your key","when you eat breakfast"],"ans":2,"exp":"You CHECK IN when you ARRIVE at the hotel and receive your key!"},{"q":"\"Is breakfast included?\" means:","opts":["How much is breakfast?","Is breakfast free with the room?","Is there a restaurant?","What time is breakfast?"],"ans":1,"exp":"\"Included\" = it''s part of the price, you don''t pay extra for it!"},{"q":"\"What floor is my room on?\" \"Floor\" means:","opts":["price","andar","janela","serviço"],"ans":1,"exp":"\"Floor\" = andar. \"Your room is on the 3rd floor\" = no 3º andar!"},{"q":"\"Reservation\" means:","opts":["recepção","elevador","reserva","chave"],"ans":2,"exp":"\"Reservation\" = reserva — you booked the room in advance!"},{"q":"\"What time is check-out?\" means:","opts":["What time do I arrive?","What time must I leave the room?","What time is breakfast?","What time is dinner?"],"ans":1,"exp":"\"Check-out\" = when you must leave. You return the key and pay the bill!"},{"q":"\"Can I have an extra ___?\" (needing another blanket)","opts":["key","blanket","reservation","floor"],"ans":1,"exp":"\"Can I have an extra BLANKET?\" — a blanket (cobertor) keeps you warm in bed!"}]}'::jsonb, 1),
('l1f3', 'u1f', 'At a Restaurant', 'Num Restaurante', '🍽️', 25, '{"learn":{"explanation":{"en":"At a restaurant, there are specific phrases for ordering food. The waiter asks: \"Are you ready to order?\" \"What would you like?\" You say: \"I''d like the...\" \"Can I have...?\" \"I''ll have...\" The menu has: starter/appetiser (entrada), main course (prato principal), dessert (sobremesa), drinks (bebidas). To get the bill: \"Can I have the bill, please?\" (Pode trazer a conta, por favor?)","pt":"Num restaurante, há frases específicas para pedir comida. O empregado pergunta: \"Are you ready to order?\" \"What would you like?\" Tu dizes: \"I''d like the...\" \"Can I have...?\" \"I''ll have...\" O menu tem: starter/appetiser (entrada), main course (prato principal), dessert (sobremesa), drinks (bebidas). Para pedir a conta: \"Can I have the bill, please?\" (Pode trazer a conta, por favor?)"},"examples":[{"en":"Waiter: Are you ready to order?","pt":"Empregado: Estão prontos para pedir?"},{"en":"I''d like the grilled chicken, please.","pt":"Gostaria do frango grelhado, por favor."},{"en":"Can I have a glass of water?","pt":"Posso ter um copo de água?"},{"en":"What do you recommend?","pt":"O que é que recomenda?"},{"en":"Can I have the bill, please?","pt":"Pode trazer a conta, por favor?"}],"practice":[{"q":"\"Are you ready to order?\" is said by:","opts":["you to the waiter","the waiter to you","the chef","the manager"],"ans":1,"exp":"The WAITER asks \"Are you ready to order?\" — they want to take your order!"},{"q":"How do you ask for the bill?","opts":["Give me the money.","Can I have the bill, please?","Pay now!","How much?"],"ans":1,"exp":"\"Can I have the bill, please?\" = Pode trazer a conta, por favor? Always be polite!"}]},"qs":[{"q":"\"I''d like the fish, please.\" \"I''d like\" means:","opts":["I don''t want","I would like / I want","I have","I need"],"ans":1,"exp":"\"I''d like\" = I would like — a polite way to order in a restaurant!"},{"q":"The \"main course\" is:","opts":["the dessert","the drink","the first small dish","the main dish of the meal"],"ans":3,"exp":"\"Main course\" = the principal/main dish — the biggest part of the meal!"},{"q":"\"Can I have the bill?\" is said:","opts":["when you arrive","when you order","when you are ready to pay","when you want water"],"ans":2,"exp":"You ask for the bill (conta) when you are READY TO PAY and leave!"},{"q":"\"What do you recommend?\" means:","opts":["What is the price?","What is the menu?","What is the best dish here?","Is the food fresh?"],"ans":2,"exp":"\"What do you recommend?\" = What dish do you suggest? What is best?"},{"q":"\"Dessert\" comes:","opts":["before the main course","after the main course","instead of the main course","at the same time as the main course"],"ans":1,"exp":"\"Dessert\" (sobremesa) comes AFTER the main course — it''s sweet!"},{"q":"How do you politely order food?","opts":["Give me chicken!","Chicken, now!","I''d like the chicken, please.","Bring chicken."],"ans":2,"exp":"\"I''d like the chicken, please.\" — polite ordering with \"I''d like\" and \"please\"!"},{"q":"\"Are you ready to ___?\" (waiter asking)","opts":["pay","eat","leave","order"],"ans":3,"exp":"\"Are you ready to ORDER?\" — the waiter wants to take your food choices!"}]}'::jsonb, 2),
('l1f4', 'u1f', 'Shopping for Clothes', 'Comprar Roupa', '👗', 25, '{"learn":{"explanation":{"en":"When shopping for clothes, you need to know sizes, colours, and prices. Key phrases: \"Can I try this on?\" (Posso experimentar?) \"Do you have this in a bigger/smaller size?\" \"How much is this?\" \"It''s too expensive.\" \"I''ll take it.\" Sizes: small (S), medium (M), large (L), extra large (XL). Clothes vocabulary: shirt, trousers/pants, dress, skirt, jacket, shoes, socks, belt.","pt":"Quando compras roupa, precisas de saber tamanhos, cores e preços. Frases-chave: \"Can I try this on?\" (Posso experimentar?) \"Do you have this in a bigger/smaller size?\" \"How much is this?\" \"It''s too expensive.\" \"I''ll take it.\" Tamanhos: small (S), medium (M), large (L), extra large (XL). Vocabulário de roupa: shirt, trousers/pants, dress, skirt, jacket, shoes, socks, belt."},"examples":[{"en":"Excuse me, can I try this dress on?","pt":"Com licença, posso experimentar este vestido?"},{"en":"Do you have this in a medium?","pt":"Tem isto no tamanho M?"},{"en":"It''s a bit too tight. Do you have a larger size?","pt":"Está um pouco justo. Tem num tamanho maior?"},{"en":"How much is this shirt?","pt":"Quanto custa esta camisa?"},{"en":"It''s on sale — 20% off!","pt":"Está em saldo — 20% de desconto!"}],"practice":[{"q":"\"Can I try this on?\" means:","opts":["Can I buy this?","Can I wear this to test the fit?","Is this my size?","Can I see this?"],"ans":1,"exp":"\"Try on\" = experimentar — you put it on to see if it fits!"},{"q":"\"It''s too tight.\" means:","opts":["it''s too big","it''s the right size","it''s too small/narrow","it''s too loose"],"ans":2,"exp":"\"Too tight\" = too small/narrow — the clothes squeeze you!"}]},"qs":[{"q":"\"Can I try this ___ please?\" (test if it fits)","opts":["on","off","in","out"],"ans":0,"exp":"\"Can I try this ON?\" — try on = experimentar clothes!"},{"q":"\"Do you have this in a ___ size?\" (you need bigger)","opts":["smaller","larger","tighter","shorter"],"ans":1,"exp":"\"Do you have this in a LARGER size?\" = Tem num tamanho maior?"},{"q":"If clothes are \"on sale\", it means:","opts":["they are very expensive","they are discounted/cheaper","they are sold out","they are new"],"ans":1,"exp":"\"On sale\" = em saldo/promoção — the price is reduced!"},{"q":"\"How much is this?\" is asking for:","opts":["size","colour","price","material"],"ans":2,"exp":"\"How much is this?\" = Quanto custa? Asking the PRICE!"},{"q":"\"I''ll take it.\" means:","opts":["I''ll think about it","I don''t want it","I want to buy it","I''ll try it on"],"ans":2,"exp":"\"I''ll take it.\" = Vou levá-lo. You''ve decided to buy it!"},{"q":"What does \"M\" mean on a clothes label?","opts":["Massive","Mini","Medium","Modern"],"ans":2,"exp":"\"M\" = MEDIUM — the middle size between Small (S) and Large (L)!"},{"q":"\"These trousers are too ___.\" (they fall down)","opts":["tight","small","loose","short"],"ans":2,"exp":"\"Too LOOSE\" = too big, they don''t fit tightly. They might fall down!"}]}'::jsonb, 3),
('l1f5', 'u1f', 'Getting Around a City', 'Deslocar-se numa Cidade', '🗺️', 20, '{"learn":{"explanation":{"en":"When you''re in a city, you might need to ask for and give directions. Key phrases: \"Excuse me, where is...?\" \"Turn left/right.\" \"Go straight.\" \"It''s on your left/right.\" \"It''s about 5 minutes on foot.\" \"Take the bus number 3.\" Landmarks: roundabout (rotunda), traffic lights (semáforos), crossroads (cruzamento), bridge (ponte), corner (esquina).","pt":"Quando estás numa cidade, podes precisar de pedir e dar direcções. Frases-chave: \"Excuse me, where is...?\" \"Turn left/right.\" \"Go straight.\" \"It''s on your left/right.\" \"It''s about 5 minutes on foot.\" \"Take the bus number 3.\" Pontos de referência: roundabout (rotunda), traffic lights (semáforos), crossroads (cruzamento), bridge (ponte), corner (esquina)."},"examples":[{"en":"Excuse me, where is the nearest pharmacy?","pt":"Com licença, onde fica a farmácia mais próxima?"},{"en":"Go straight for two blocks, then turn left.","pt":"Vai em frente dois quarteirões, depois vira à esquerda."},{"en":"It''s on your right, next to the bank.","pt":"Está à tua direita, ao lado do banco."},{"en":"Take bus number 7 to the city centre.","pt":"Apanha o autocarro número 7 para o centro da cidade."},{"en":"It''s about a 10-minute walk.","pt":"É cerca de 10 minutos a pé."}],"practice":[{"q":"How do you politely ask for directions?","opts":["Where is the bank?","Excuse me, where is the bank?","Tell me where the bank is.","Bank, where?"],"ans":1,"exp":"\"Excuse me, where is the bank?\" — always start with \"Excuse me\" to be polite!"},{"q":"\"Go straight\" means:","opts":["turn right","turn left","don''t turn, continue forward","stop here"],"ans":2,"exp":"\"Go straight\" = continue forward without turning!"}]},"qs":[{"q":"\"Turn ___.\" (to go to the right)","opts":["left","right","around","back"],"ans":1,"exp":"\"Turn RIGHT.\" = Vira à direita!"},{"q":"\"It''s on your ___.\" (it''s to the left)","opts":["right","left","top","back"],"ans":1,"exp":"\"It''s on your LEFT.\" = Está à tua esquerda!"},{"q":"\"Go ___ for two blocks.\"","opts":["back","around","straight","left"],"ans":2,"exp":"\"Go STRAIGHT for two blocks.\" = Vai em frente dois quarteirões!"},{"q":"\"It''s about a 10-minute ___.\" (walking)","opts":["ride","drive","walk","flight"],"ans":2,"exp":"\"10-minute WALK\" = 10 minutos a pé — you walk there!"},{"q":"\"Semáforos\" in English are:","opts":["roundabout","bridge","traffic lights","crossroads"],"ans":2,"exp":"\"Semáforos\" = TRAFFIC LIGHTS — the red/yellow/green lights at junctions!"},{"q":"\"Excuse me\" at the start of a question shows:","opts":["confusion","politeness","anger","certainty"],"ans":1,"exp":"\"Excuse me\" = \"com licença\" — it''s polite to say this before asking a stranger!"},{"q":"\"The bank is at the corner of Av. 25 de Setembro and Rua da Missão.\" \"Corner\" means:","opts":["centro","ponte","esquina/cruzamento","rotunda"],"ans":2,"exp":"\"Corner\" = esquina — where two streets meet at an angle!"}]}'::jsonb, 4),
('l1f6', 'u1f', 'Talking About the Weather', 'Falar Sobre o Tempo', '🌦️', 20, '{"learn":{"explanation":{"en":"Talking about the weather is one of the most common topics in English conversation! In Mozambique, weather is very important — rainy season (época das chuvas) vs dry season (época seca). Weather vocabulary: sunny (com sol), cloudy (nublado), rainy (chuvoso), windy (com vento), hot (quente), humid (húmido), cool (fresco). \"It is...\" and \"It''s...\" are used for weather: \"It''s hot today.\" \"It''s been raining all week.\"","pt":"Falar sobre o tempo é um dos temas mais comuns numa conversa em inglês! Em Moçambique, o tempo é muito importante — época das chuvas vs época seca. Vocabulário do tempo: sunny (com sol), cloudy (nublado), rainy (chuvoso), windy (com vento), hot (quente), humid (húmido), cool (fresco). Usa \"It is...\" e \"It''s...\" para o tempo: \"It''s hot today.\" \"It''s been raining all week.\""},"examples":[{"en":"It''s so hot today! Must be 35 degrees.","pt":"Está tanto calor hoje! Devem ser 35 graus."},{"en":"Take an umbrella — it looks like it''s going to rain.","pt":"Leva um chapéu-de-chuva — parece que vai chover."},{"en":"In Mozambique, the rainy season starts in November.","pt":"Em Moçambique, a época das chuvas começa em Novembro."},{"en":"It was cloudy all day but it didn''t rain.","pt":"Esteve nublado o dia todo mas não choveu."},{"en":"What''s the weather like in Maputo in July?","pt":"Como é o tempo em Maputo em Julho?"}],"practice":[{"q":"\"It''s cloudy today.\" \"Cloudy\" means:","opts":["muito sol","nublado","chuvoso","quente"],"ans":1,"exp":"\"Cloudy\" = nublado — lots of clouds, no sun!"},{"q":"How do you ask about the weather?","opts":["What is weather?","How is weather?","What''s the weather like?","How much weather?"],"ans":2,"exp":"\"What''s the weather like?\" = Como está o tempo? Standard weather question!"}]},"qs":[{"q":"\"It''s ___.\" (no clouds, lots of sun)","opts":["cloudy","rainy","sunny","windy"],"ans":2,"exp":"\"It''s SUNNY.\" = Está sol. ☀️"},{"q":"\"What''s the weather ___ today?\"","opts":["doing","being","having","like"],"ans":3,"exp":"\"What''s the weather LIKE?\" = Como está o tempo? Standard question!"},{"q":"\"Humid\" describes weather that is:","opts":["very cold","very windy","very dry","warm and wet/sticky"],"ans":3,"exp":"\"Humid\" = húmido — warm AND with a lot of moisture in the air. Common in Maputo!"},{"q":"In Mozambique, the rainy season is approximately:","opts":["April to September","November to March","June to August","January to March only"],"ans":1,"exp":"In Mozambique, the rainy season (época das chuvas) is roughly November to March! 🌧️"},{"q":"\"Take an umbrella — it might ___.\"","opts":["snow","be sunny","rain","be cool"],"ans":2,"exp":"\"It might RAIN.\" — take an umbrella when rain is possible! ☂️"},{"q":"\"It was ___ all day.\" (lots of clouds, no sun)","opts":["sunny","cloudy","clear","bright"],"ans":1,"exp":"\"It was CLOUDY all day.\" = Esteve nublado o dia todo."},{"q":"\"Cool\" weather means it is:","opts":["very hot","very cold","pleasantly slightly cold","humid"],"ans":2,"exp":"\"Cool\" = pleasantly slightly cold — not too cold, not too hot. Nice weather! 😊"}]}'::jsonb, 5),
('l1g1', 'u1g', 'Using Technology', 'Usar Tecnologia', '📱', 20, '{"learn":{"explanation":{"en":"Technology vocabulary is essential for modern life! Key verbs with technology: turn on/off (ligar/desligar), charge (carregar), download (descarregar), upload (carregar), search (pesquisar), click (clicar), send (enviar), receive (receber), connect to wifi (conectar ao wifi). Devices: smartphone (telemóvel inteligente), laptop (computador portátil), tablet, headphones (auscultadores), charger (carregador).","pt":"O vocabulário de tecnologia é essencial para a vida moderna! Verbos-chave com tecnologia: turn on/off (ligar/desligar), charge (carregar), download (descarregar), upload (carregar), search (pesquisar), click (clicar), send (enviar), receive (receber), connect to wifi (conectar ao wifi). Dispositivos: smartphone (telemóvel inteligente), laptop (computador portátil), tablet, headphones (auscultadores), charger (carregador)."},"examples":[{"en":"Can you turn on the laptop, please?","pt":"Podes ligar o computador portátil, por favor?"},{"en":"My phone battery is dead — I need to charge it.","pt":"A bateria do meu telemóvel está a zero — preciso de carregá-lo."},{"en":"I''ll send you the file by email.","pt":"Vou enviar-te o ficheiro por email."},{"en":"Can you connect to the wifi here?","pt":"Consegues conectar-te ao wifi aqui?"},{"en":"She downloaded the app on her phone.","pt":"Ela descarregou a aplicação no telemóvel."}],"practice":[{"q":"\"Turn off\" the phone means:","opts":["charge it","connect it","stop using it/shut it down","restart it"],"ans":2,"exp":"\"Turn off\" = desligar — stop the device. \"Turn on\" = ligar!"},{"q":"If your phone battery is \"dead\" it means:","opts":["it''s broken","it has no charge/power","it''s turned off","it''s on silent"],"ans":1,"exp":"\"Dead\" battery = has no power left. You need to charge it!"}]},"qs":[{"q":"\"I need to ___ my phone — the battery is at 2%.\"","opts":["turn off","charge","download","search"],"ans":1,"exp":"\"Charge my phone.\" = Carregar o telemóvel. The battery is almost empty!"},{"q":"\"___ the app from the Play Store.\"","opts":["Upload","Turn on","Download","Click"],"ans":2,"exp":"\"Download the app.\" = Descarregar a aplicação from the internet to your device!"},{"q":"\"Can you ___ to the wifi?\" (connect)","opts":["turn on","search","connect","click"],"ans":2,"exp":"\"Connect to the wifi.\" = Conectar ao wifi!"},{"q":"\"Send me the ___.\" (a document via email)","opts":["app","wifi","file","battery"],"ans":2,"exp":"\"Send me the FILE.\" = Envia-me o ficheiro. A file = a document on a computer!"},{"q":"\"Headphones\" are used to:","opts":["charge your phone","connect to wifi","listen to audio privately","take photos"],"ans":2,"exp":"\"Headphones\" = auscultadores — you put them on your ears to listen privately!"},{"q":"\"The wifi is ___.\" (there is no internet signal)","opts":["connected","downloading","down/not working","charging"],"ans":2,"exp":"\"The wifi is DOWN.\" = O wifi não está a funcionar — no internet connection!"},{"q":"Which is a technology DEVICE?","opts":["charger","wifi","download","click"],"ans":0,"exp":"A CHARGER is a device (aparelho). Wifi, download, and click are not physical devices."}]}'::jsonb, 0),
('l1g2', 'u1g', 'Social Media & Communication', 'Redes Sociais e Comunicação', '📲', 20, '{"learn":{"explanation":{"en":"Social media has its own vocabulary! Key actions: post (publicar), like (dar gosto), share (partilhar), comment (comentar), follow (seguir), unfollow (deixar de seguir), tag (marcar), message (enviar mensagem). \"I posted a photo on Instagram.\" \"She has a lot of followers.\" \"Can you send me a message?\" In professional context, use LinkedIn. In casual context — WhatsApp, Facebook, Instagram, TikTok.","pt":"As redes sociais têm o seu próprio vocabulário! Acções-chave: post (publicar), like (dar gosto), share (partilhar), comment (comentar), follow (seguir), unfollow (deixar de seguir), tag (marcar), message (enviar mensagem). \"I posted a photo on Instagram.\" \"She has a lot of followers.\" \"Can you send me a message?\" Em contexto profissional, usa o LinkedIn. Em contexto casual — WhatsApp, Facebook, Instagram, TikTok."},"examples":[{"en":"I posted a photo on my Instagram story.","pt":"Eu publiquei uma foto no meu story do Instagram."},{"en":"Can you send me a message on WhatsApp?","pt":"Podes enviar-me uma mensagem no WhatsApp?"},{"en":"She tagged me in a funny video.","pt":"Ela marcou-me num vídeo engraçado."},{"en":"This video has 5 million views!","pt":"Este vídeo tem 5 milhões de visualizações!"},{"en":"I follow English With Sebastian on TikTok.","pt":"Eu sigo o English With Sebastian no TikTok."}],"practice":[{"q":"\"Like\" on social media means:","opts":["to dislike","to click the heart/thumbs up button","to comment","to share"],"ans":1,"exp":"\"Like\" = to press the heart/👍 button — showing you enjoy the content!"},{"q":"\"She has 10,000 followers.\" \"Followers\" are:","opts":["enemies","people who follow her account","her family only","her co-workers"],"ans":1,"exp":"\"Followers\" = people who subscribe to/follow your social media account!"}]},"qs":[{"q":"\"I ___ a photo on Instagram.\" (published)","opts":["liked","shared","posted","commented"],"ans":2,"exp":"\"I POSTED a photo.\" = Eu publiquei uma foto. Post = publish on social media!"},{"q":"To \"share\" someone''s post means to:","opts":["delete it","like it","repost it so others can see it","comment on it"],"ans":2,"exp":"\"Share\" = repost/partilhar — you spread the post to your followers!"},{"q":"\"Tag\" someone in a post means to:","opts":["like their photo","mention/link their profile in the post","unfollow them","delete their comment"],"ans":1,"exp":"\"Tag\" = marcar — you link their name/profile so they get notified!"},{"q":"\"Follow\" someone on social media means:","opts":["walk behind them","subscribe to their account to see their posts","send them a message","unfollow them"],"ans":1,"exp":"\"Follow\" = seguir — subscribe to see their posts in your feed!"},{"q":"\"This video has 2 million ___.\"","opts":["followers","likes","views","comments"],"ans":2,"exp":"\"2 million VIEWS\" = visualizações — 2 million people watched it!"},{"q":"Which platform is best for PROFESSIONAL networking?","opts":["TikTok","Instagram","LinkedIn","Snapchat"],"ans":2,"exp":"LinkedIn is for PROFESSIONAL networking — jobs, CV, business contacts!"},{"q":"\"Can you ___ me on WhatsApp?\" (send a text)","opts":["post","tag","message","follow"],"ans":2,"exp":"\"Can you MESSAGE me on WhatsApp?\" = Podes enviar-me uma mensagem no WhatsApp?"}]}'::jsonb, 1),
('l1g3', 'u1g', 'Applying for a Job', 'Candidatar-se a um Emprego', '💼', 30, '{"learn":{"explanation":{"en":"Looking for a job requires specific vocabulary. Key documents: CV/resume (currículo), cover letter (carta de apresentação). Key actions: apply for (candidatar-se a), interview (entrevista), hire (contratar), get the job (conseguir o emprego). At the interview: \"Tell me about yourself.\" \"Why do you want this job?\" \"What are your strengths?\" Strengths: hardworking (trabalhador/a), organized (organizado/a), punctual (pontual), team player (bom/boa em equipa).","pt":"À procura de emprego requer vocabulário específico. Documentos-chave: CV/resume (currículo), cover letter (carta de apresentação). Acções-chave: apply for (candidatar-se a), interview (entrevista), hire (contratar), get the job (conseguir o emprego). Na entrevista: \"Tell me about yourself.\" \"Why do you want this job?\" \"What are your strengths?\" Pontos fortes: hardworking (trabalhador/a), organized (organizado/a), punctual (pontual), team player (bom/boa em equipa)."},"examples":[{"en":"I''d like to apply for the teacher position.","pt":"Gostaria de me candidatar ao posto de professor/a."},{"en":"I have three years of experience in this field.","pt":"Tenho três anos de experiência nesta área."},{"en":"I am hardworking, punctual and a good team player.","pt":"Sou trabalhador/a, pontual e bom/boa em equipa."},{"en":"When can you start?","pt":"Quando pode começar?"},{"en":"Congratulations, you got the job!","pt":"Parabéns, conseguiste o emprego!"}],"practice":[{"q":"\"Apply for a job\" means:","opts":["reject a job","look for a job","submit your CV and ask to be hired","quit a job"],"ans":2,"exp":"\"Apply for\" = candidatar-se. You send your CV and ask for the position!"},{"q":"A \"CV\" is:","opts":["a cover letter","a document listing your education and experience","a job offer","an interview"],"ans":1,"exp":"A CV (currículo) lists your education, experience and skills!"}]},"qs":[{"q":"\"I''d like to ___ for the position.\" (submit application)","opts":["hire","apply","interview","get"],"ans":1,"exp":"\"Apply for the position.\" = Candidatar-me ao posto/vaga!"},{"q":"\"Hardworking\" means:","opts":["lazy","organized","always works hard/doesn''t avoid work","punctual"],"ans":2,"exp":"\"Hardworking\" = trabalhador/a — someone who works hard and doesn''t avoid work!"},{"q":"\"Tell me about yourself.\" is a typical ___ question.","opts":["exam","interview","shopping","travel"],"ans":1,"exp":"\"Tell me about yourself.\" is a classic JOB INTERVIEW question!"},{"q":"What do you need to apply for a job?","opts":["a ticket","a passport","a CV","a boarding pass"],"ans":2,"exp":"You need a CV (currículo) to apply for a job — it lists your education and experience!"},{"q":"\"Punctual\" means:","opts":["always late","always on time","very organized","very creative"],"ans":1,"exp":"\"Punctual\" = pontual — always arriving on time! Very valued by employers."},{"q":"\"Congratulations, you ___ the job!\"","opts":["applied for","lost","got","rejected"],"ans":2,"exp":"\"You GOT the job!\" = Conseguiste o emprego! Great news! 🎉"},{"q":"\"I have three years of ___.\" (work history)","opts":["experience","interview","degree","application"],"ans":0,"exp":"\"I have three years of EXPERIENCE.\" = Tenho três anos de experiência!"}]}'::jsonb, 2),
('l1g4', 'u1g', 'At School & University', 'Na Escola e Universidade', '🎓', 20, '{"learn":{"explanation":{"en":"Education vocabulary helps you talk about school life. Subjects: English, Maths, History, Science, Geography, Art, Physical Education. People: teacher, professor, student, classmate, headmaster/principal. Places: classroom, library, canteen, playground, office. Actions: study, revise, pass (an exam), fail (an exam), graduate, enrol. \"I study at Eduardo Mondlane University.\" \"I am in 10th grade.\"","pt":"O vocabulário de educação ajuda-te a falar sobre a vida escolar. Disciplinas: English, Maths, History, Science, Geography, Art, Physical Education. Pessoas: teacher, professor, student, classmate, headmaster/principal. Lugares: classroom, library, canteen, playground, office. Acções: study, revise, pass (an exam), fail (an exam), graduate, enrol. \"I study at Eduardo Mondlane University.\" \"I am in 10th grade.\""},"examples":[{"en":"My favourite subject is English.","pt":"A minha disciplina favorita é o inglês."},{"en":"I study at Eduardo Mondlane University.","pt":"Estudo na Universidade Eduardo Mondlane."},{"en":"I need to revise for my exam tomorrow.","pt":"Preciso de estudar para o meu exame de amanhã."},{"en":"She passed her exam with very good marks.","pt":"Ela passou no exame com muito boas notas."},{"en":"We have a library with thousands of books.","pt":"Temos uma biblioteca com milhares de livros."}],"practice":[{"q":"\"Revise\" means:","opts":["to study something for the first time","to forget","to review/study again before an exam","to pass an exam"],"ans":2,"exp":"\"Revise\" = estudar/rever — reviewing material before an exam!"},{"q":"\"Pass an exam\" means:","opts":["fail it","take it","do it successfully (get a good enough mark)","ignore it"],"ans":2,"exp":"\"Pass\" = get a good enough mark to succeed. Opposite: \"fail\"."}]},"qs":[{"q":"What do you do in a \"library\"?","opts":["eat lunch","play sport","study and read books","have classes"],"ans":2,"exp":"In a LIBRARY = biblioteca — you study, read books and do research!"},{"q":"\"I am in ___ grade.\" (Mozambique school system)","opts":["class","form","grade","year"],"ans":2,"exp":"In Mozambique and many countries, we say \"in 10th GRADE\" for year of study!"},{"q":"\"She failed the exam.\" means:","opts":["she passed successfully","she got a very good mark","she didn''t get a good enough mark","she didn''t take the exam"],"ans":2,"exp":"\"Failed\" = didn''t pass — her mark wasn''t good enough. Opposite: passed!"},{"q":"\"My favourite ___.\" (talking about a school subject)","opts":["subject","lesson only","teacher only","class only"],"ans":0,"exp":"\"My favourite SUBJECT\" = a minha disciplina favorita! English, Maths, etc."},{"q":"\"Classmate\" means:","opts":["a friend outside school","a teacher","a person who studies in the same class as you","the school director"],"ans":2,"exp":"\"Classmate\" = colega de turma — someone who studies in the SAME class as you!"},{"q":"\"Enrol\" at a university means:","opts":["graduate","fail","register/sign up as a student","study all night"],"ans":2,"exp":"\"Enrol\" = matricular-se — register as a student officially!"},{"q":"\"I need to ___ for my exam.\" (study again)","opts":["enrol","graduate","revise","fail"],"ans":2,"exp":"\"I need to REVISE for my exam.\" = Preciso de estudar/rever para o exame!"}]}'::jsonb, 3),
('l1g5', 'u1g', 'Making Phone Calls', 'Fazer Chamadas Telefónicas', '📞', 20, '{"learn":{"explanation":{"en":"Telephone conversations have their own vocabulary! Calling phrases: \"Hello, can I speak to...?\" \"This is [name] speaking.\" \"Hold on, please.\" \"I''ll put you through.\" \"The line is busy.\" \"Can you call back later?\" Receiving phrases: \"Who''s calling?\" \"Just a moment.\" \"I''m sorry, he''s not in.\" \"Can I take a message?\" \"I''ll let him/her know you called.\"","pt":"As conversas telefónicas têm o seu próprio vocabulário! Frases para ligar: \"Hello, can I speak to...?\" \"This is [name] speaking.\" \"Hold on, please.\" \"I''ll put you through.\" \"The line is busy.\" \"Can you call back later?\" Frases para receber: \"Who''s calling?\" \"Just a moment.\" \"I''m sorry, he''s not in.\" \"Can I take a message?\" \"I''ll let him/her know you called.\""},"examples":[{"en":"Hello, can I speak to Mr. Nhamuneque, please?","pt":"Olá, posso falar com o Sr. Nhamuneque, por favor?"},{"en":"This is Sebastian speaking.","pt":"É o Sebastian a falar."},{"en":"I''m sorry, she''s not available at the moment.","pt":"Lamento, ela não está disponível neste momento."},{"en":"Can I take a message?","pt":"Posso anotar um recado?"},{"en":"Could you call back in an hour?","pt":"Poderia ligar novamente daqui a uma hora?"}],"practice":[{"q":"\"The line is busy.\" means:","opts":["no one is there","the phone is ringing","someone is already using the line","the phone is turned off"],"ans":2,"exp":"\"The line is busy\" = a linha está ocupada — someone is already on the phone!"},{"q":"How do you identify yourself on the phone?","opts":["Hi!","It''s me.","This is [name] speaking.","Hello there."],"ans":2,"exp":"\"This is [name] speaking.\" = Sou o/a [nome] a falar. The standard phone introduction!"}]},"qs":[{"q":"\"Hello, can I ___ to Ana, please?\"","opts":["talk","say","speak","tell"],"ans":2,"exp":"\"Can I SPEAK to Ana?\" = Posso falar com a Ana? Standard phone request!"},{"q":"\"Hold on\" on the phone means:","opts":["hang up","wait a moment","speak louder","call back"],"ans":1,"exp":"\"Hold on\" = wait/espera — I''ll be back in a moment!"},{"q":"\"Can I take a message?\" means:","opts":["Can I write down what you want to say?","Can I speak to you?","Can you call back?","Can I help you?"],"ans":0,"exp":"\"Can I take a message?\" = Posso anotar um recado? You''ll write down what the caller wants to say!"},{"q":"\"She''s not in at the moment.\" means:","opts":["she''s busy","she''s not available/not here right now","she doesn''t want to talk","her phone is off"],"ans":1,"exp":"\"She''s not in\" = ela não está/não está disponível agora — she''s not there right now!"},{"q":"\"This is Sebastian ___.\" (identifying yourself)","opts":["calling","speaking","talking","phoning"],"ans":1,"exp":"\"This is Sebastian SPEAKING.\" = Sou o Sebastian a falar. The standard way!"},{"q":"\"Could you call ___ later?\" (phone again)","opts":["again","back","here","up"],"ans":1,"exp":"\"Could you call BACK later?\" = Poderia ligar novamente mais tarde?"},{"q":"What do you say when you pick up the phone?","opts":["Goodbye!","Speaking!","Hello?","Please hold."],"ans":2,"exp":"\"Hello?\" is the standard greeting when you pick up a phone call!"}]}'::jsonb, 4),
('l1g6', 'u1g', 'Writing Emails & Messages', 'Escrever Emails e Mensagens', '✉️', 25, '{"learn":{"explanation":{"en":"Email and message writing has formal and informal styles. Formal email: \"Dear Mr/Ms [name],\" ... \"Yours sincerely,\" / \"Kind regards,\". Informal email/message: \"Hi [name],\" ... \"Best wishes,\" / \"See you soon!\" Key phrases: \"I am writing to...\" \"Please find attached...\" \"I look forward to hearing from you.\" \"Could you please...?\" \"Thank you for your reply.\" In WhatsApp/SMS: much more casual — abbreviations, emojis are fine.","pt":"Escrever emails e mensagens tem estilos formais e informais. Email formal: \"Dear Mr/Ms [name],\" ... \"Yours sincerely,\" / \"Kind regards,\". Email/mensagem informal: \"Hi [name],\" ... \"Best wishes,\" / \"See you soon!\" Frases-chave: \"I am writing to...\" \"Please find attached...\" \"I look forward to hearing from you.\" \"Could you please...?\" \"Thank you for your reply.\" No WhatsApp/SMS: muito mais casual — abreviações, emojis são aceitáveis."},"examples":[{"en":"Dear Professor Silva, I am writing to ask about the exam.","pt":"Caro Professor Silva, Escrevo para perguntar sobre o exame."},{"en":"Please find attached my CV for your consideration.","pt":"Em anexo encontrará o meu CV para a sua apreciação."},{"en":"I look forward to hearing from you soon.","pt":"Aguardo com expectativa uma resposta sua em breve."},{"en":"Kind regards, Sebastian.","pt":"Com os melhores cumprimentos, Sebastian."},{"en":"Hi Ana! Are you coming to class tomorrow? 😊","pt":"Oi Ana! Vens à aula amanhã? 😊"}],"practice":[{"q":"A formal email starts with:","opts":["Hey!","Hi there,","Dear Mr/Ms [name],","Hello everyone,"],"ans":2,"exp":"\"Dear Mr/Ms [name],\" — formal email opening!"},{"q":"\"I look forward to hearing from you.\" means:","opts":["I don''t want your reply","I hope you will reply soon","This email is finished","Please don''t reply"],"ans":1,"exp":"\"I look forward to hearing from you.\" = Aguardo a sua resposta. Polite closing phrase!"}]},"qs":[{"q":"How do you start a FORMAL email?","opts":["Hey!","Yo!","Dear Mr/Ms Silva,","Hi there!"],"ans":2,"exp":"\"Dear Mr/Ms [name],\" is the formal way to start an email!"},{"q":"How do you END a formal email?","opts":["Bye!","See you soon!","Kind regards, [name]","Talk later"],"ans":2,"exp":"\"Kind regards,\" or \"Yours sincerely,\" are formal email endings!"},{"q":"\"Please find ___.\" (there''s a document attached)","opts":["enclosed","attached","inside","here"],"ans":1,"exp":"\"Please find ATTACHED.\" = Em anexo encontrará... Standard phrase for attachments!"},{"q":"\"I am writing ___ ask about the exam.\"","opts":["to","for","of","in"],"ans":0,"exp":"\"I am writing TO ask...\" = the purpose of writing. \"To\" + infinitive!"},{"q":"Which is appropriate for a WhatsApp message to a friend?","opts":["Dear Ana, I am writing to inquire...","Hi! Coming to class tomorrow? 😊","To whom it may concern","Yours sincerely"],"ans":1,"exp":"WhatsApp to a friend is casual — \"Hi! Coming to class tomorrow? 😊\" is perfect!"},{"q":"\"Kind regards\" is used:","opts":["to start a formal email","to end a formal email","to start an informal message","to end an informal message"],"ans":1,"exp":"\"Kind regards,\" ends a formal email — like \"Com os melhores cumprimentos\"!"},{"q":"\"Thank you for your ___.\" (responding to an email received)","opts":["write","reply","message only","attached"],"ans":1,"exp":"\"Thank you for your REPLY.\" = Obrigado/a pela sua resposta. Acknowledging their email!"}]}'::jsonb, 5),
('l1h1', 'u1h', 'Reported Speech — Statements', 'Discurso Indirecto — Afirmações', '💬', 30, '{"learn":{"explanation":{"en":"Reported speech tells what someone said WITHOUT using their exact words. The verb usually goes one tense back: \"I am tired\" → She said she WAS tired. \"I work here\" → He said he WORKED there. Pronouns and time expressions also change.","pt":"O discurso indirecto relata o que alguém disse SEM usar as palavras exactas. O verbo normalmente recua um tempo verbal: \"I am tired\" → She said she WAS tired. \"I work here\" → He said he WORKED there. Os pronomes e as expressões de tempo também mudam."},"examples":[{"en":"\"I am hungry.\" → She said she was hungry.","pt":"\"Estou com fome.\" → Ela disse que estava com fome."},{"en":"\"I live in Beira.\" → He said he lived in Beira.","pt":"\"Vivo em Beira.\" → Ele disse que vivia em Beira."},{"en":"\"We will come tomorrow.\" → They said they would come the next day.","pt":"\"Vamos vir amanhã.\" → Eles disseram que viriam no dia seguinte."}],"practice":[{"q":"\"I am happy.\" → She said she ___ happy.","opts":["is","was","will be","be"],"ans":1,"exp":"am/is/are → was/were in reported speech."},{"q":"\"I work in a hospital.\" → He said he ___ in a hospital.","opts":["works","worked","is working","will work"],"ans":1,"exp":"work (present) → worked (past) in reported speech."}]},"qs":[{"q":"\"I love football.\" → He said he ___ football.","opts":["loves","love","loved","is loving"],"ans":2,"exp":"\"Love\" (present simple) → \"loved\" (past simple) in reported speech."},{"q":"\"She is cooking.\" → He said she ___ cooking.","opts":["is","was","has been","will be"],"ans":1,"exp":"\"is cooking\" → \"was cooking\". Present continuous → past continuous."},{"q":"\"I have finished.\" → She said she ___ finished.","opts":["has","have","had","is"],"ans":2,"exp":"\"have finished\" → \"had finished\". Present perfect → past perfect."},{"q":"\"We will help you.\" → They said they ___ help me.","opts":["will","would","should","can"],"ans":1,"exp":"\"will\" → \"would\" in reported speech."},{"q":"In reported speech, \"today\" usually becomes:","opts":["tomorrow","yesterday","that day","this day"],"ans":2,"exp":"\"Today\" → \"that day\". Time expressions shift: today→that day, tomorrow→the next day."}]}'::jsonb, 0),
('l1h2', 'u1h', 'Reported Questions', 'Perguntas no Discurso Indirecto', '❓', 30, '{"learn":{"explanation":{"en":"To report YES/NO questions, use \"asked if/whether\": \"Are you tired?\" → She asked if I was tired. For WH- questions, use \"asked where/what/why...\": \"Where do you live?\" → He asked where I lived. NO question mark in reported questions!","pt":"Para reportar perguntas de SIM/NÃO, usa \"asked if/whether\": \"Are you tired?\" → She asked if I was tired. Para perguntas WH-, usa \"asked where/what/why...\": \"Where do you live?\" → He asked where I lived. SEM ponto de interrogação nas perguntas reportadas!"},"examples":[{"en":"\"Are you okay?\" → She asked if I was okay.","pt":"\"Estás bem?\" → Ela perguntou se eu estava bem."},{"en":"\"What is your name?\" → He asked what my name was.","pt":"\"Qual é o teu nome?\" → Ele perguntou qual era o meu nome."},{"en":"\"Where do you work?\" → She asked where I worked.","pt":"\"Onde trabalhas?\" → Ela perguntou onde eu trabalhava."}],"practice":[{"q":"Reported YES/NO questions use:","opts":["\"asked that\"","\"asked if/whether\"","\"asked what\"","\"said if\""],"ans":1,"exp":"\"Asked if/whether\" introduces reported yes/no questions."},{"q":"\"Do you speak English?\" → She asked ___ I spoke English.","opts":["that","what","if","where"],"ans":2,"exp":"Yes/No question → \"asked IF I spoke English.\""}]},"qs":[{"q":"\"Are you a teacher?\" → He asked ___ I was a teacher.","opts":["what","where","if","that"],"ans":2,"exp":"Yes/No question → \"asked IF...\" No question mark!"},{"q":"\"Where do you live?\" → She asked where I ___.","opts":["live","lives","lived","living"],"ans":2,"exp":"\"lived\" — verb goes back a tense. \"Where do you live?\" → asked where I LIVED."},{"q":"\"What time is it?\" → He asked what time ___.","opts":["is it","it was","was it","it is"],"ans":1,"exp":"Reported question uses statement word order: \"what time IT WAS\" not \"was it\"."},{"q":"In reported questions:","opts":["Use a question mark","Keep question word order","Use statement word order","Use \"said\""],"ans":2,"exp":"Reported questions use STATEMENT word order and NO question mark."},{"q":"\"Why did you leave?\" → She asked why I ___ left.","opts":["have","has","had","did"],"ans":2,"exp":"\"had left\" — past simple question → past perfect in reported speech."}]}'::jsonb, 1),
('l1h3', 'u1h', 'Reported Commands & Requests', 'Ordens e Pedidos no Discurso Indirecto', '📢', 25, '{"learn":{"explanation":{"en":"To report commands and requests, use TELL or ASK + object + TO + infinitive. \"Close the door!\" → He told me to close the door. \"Please help me.\" → She asked me to help her. Negative: \"Don''t run!\" → He told me NOT to run.","pt":"Para reportar ordens e pedidos, usa TELL ou ASK + objecto + TO + infinitivo. \"Close the door!\" → He told me to close the door. \"Please help me.\" → She asked me to help her. Negativo: \"Don''t run!\" → He told me NOT to run."},"examples":[{"en":"\"Sit down!\" → The teacher told us to sit down.","pt":"\"Sentai-vos!\" → O professor disse-nos para nos sentarmos."},{"en":"\"Please open the window.\" → She asked me to open the window.","pt":"\"Por favor abre a janela.\" → Ela pediu-me para abrir a janela."},{"en":"\"Don''t be late!\" → He told her not to be late.","pt":"\"Não chegues tarde!\" → Ele disse-lhe para não chegar tarde."}],"practice":[{"q":"Commands use \"told\" + object + ___:","opts":["that","if","to + verb","verb-ing"],"ans":2,"exp":"\"Told + object + TO + infinitive\": He told me TO go."},{"q":"\"Don''t speak!\" → She told him ___ speak.","opts":["not to","to not","don''t","not"],"ans":0,"exp":"Negative command: \"told him NOT TO speak.\""}]},"qs":[{"q":"\"Sit down!\" → The teacher told us ___ down.","opts":["sit","sitting","to sit","that sit"],"ans":2,"exp":"\"Told + object + TO + infinitive\". told us TO SIT down."},{"q":"\"Please help me.\" → She asked me ___ her.","opts":["help","helping","to help","that help"],"ans":2,"exp":"\"Asked + object + TO + infinitive\". asked me TO HELP her."},{"q":"\"Don''t touch that!\" → He told me ___ that.","opts":["not touch","to not touch","not to touch","don''t touch"],"ans":2,"exp":"Negative: \"told me NOT TO touch\". NOT TO + infinitive."},{"q":"Which word is used for POLITE reported requests?","opts":["told","said","asked","ordered"],"ans":2,"exp":"\"Asked\" for polite requests. \"Told\" for direct commands."},{"q":"\"Be quiet!\" → She told them ___ quiet.","opts":["being","be","to be","is"],"ans":2,"exp":"\"Told them TO BE quiet.\" — to + base verb."}]}'::jsonb, 2),
('l1h4', 'u1h', 'Telling Stories — Narrative Tenses', 'Contar Histórias — Tempos Narrativos', '📚', 30, '{"learn":{"explanation":{"en":"Good storytelling uses a mix of tenses: Past Simple for the main sequence of events (\"I arrived, I saw, I decided...\"), Past Continuous for background actions (\"It was raining...\"), and Past Perfect for events that happened before (\"I had already eaten...\").","pt":"Uma boa narrativa usa uma mistura de tempos verbais: Passado Simples para a sequência principal (\"I arrived, I saw...\"), Passado Contínuo para acções de fundo (\"It was raining...\"), e Passado Perfeito para eventos anteriores (\"I had already eaten...\")."},"examples":[{"en":"I was walking home when I heard a noise.","pt":"Eu estava a andar para casa quando ouvi um barulho."},{"en":"She had already left when I arrived.","pt":"Ela já tinha ido embora quando eu cheguei."},{"en":"It was a dark night and the streets were empty.","pt":"Era uma noite escura e as ruas estavam vazias."}],"practice":[{"q":"The background of a story uses:","opts":["Past Simple","Past Continuous","Present Simple","Future Simple"],"ans":1,"exp":"Past Continuous sets the SCENE/background: \"It was raining, people were walking...\""},{"q":"\"She had already left.\" This means:","opts":["She left at the same time","She left before","She will leave","She is leaving"],"ans":1,"exp":"Past Perfect = action that happened BEFORE another past event."}]},"qs":[{"q":"\"I ___ to music when the phone rang.\" (listen)","opts":["listen","was listening","listened","am listening"],"ans":1,"exp":"Background action interrupted = Past Continuous: \"was listening\"."},{"q":"Past Perfect is used for:","opts":["actions happening now","the main events of a story","actions before another past event","future plans"],"ans":2,"exp":"Past Perfect (had + pp) = an event that happened BEFORE the main past story."},{"q":"\"She was tired because she ___ all day.\" (work)","opts":["worked","has worked","had worked","works"],"ans":2,"exp":"\"Had worked\" — Past Perfect. The working happened before she became tired."},{"q":"Which sequence is correct for storytelling?","opts":["Future→Present→Past","Past Simple for events, Past Continuous for background","Only Past Simple","Present Tense for all"],"ans":1,"exp":"Best storytelling: Past Simple (events) + Past Continuous (background) + Past Perfect (earlier events)."},{"q":"\"While Ana ___, Pedro arrived.\" (cook)","opts":["cooked","was cooking","had cooked","is cooking"],"ans":1,"exp":"\"Was cooking\" — background/ongoing action at the time of arrival."}]}'::jsonb, 3),
('l1h5', 'u1h', 'Linking Words — Connectors', 'Palavras de Ligação — Conectores', '🔗', 25, '{"learn":{"explanation":{"en":"Connectors make your speech and writing flow naturally. Time: first, then, after that, finally, meanwhile, suddenly. Cause & Effect: because, so, as a result, therefore. Contrast: but, however, although, despite. Addition: also, in addition, moreover, besides.","pt":"Os conectores tornam o teu discurso e escrita mais fluentes. Tempo: first, then, after that, finally, meanwhile, suddenly. Causa e Efeito: because, so, as a result, therefore. Contraste: but, however, although, despite. Adição: also, in addition, moreover."},"examples":[{"en":"First I studied, then I went out.","pt":"Primeiro estudei, depois saí."},{"en":"Although it was late, she kept working.","pt":"Apesar de ser tarde, ela continuou a trabalhar."},{"en":"I was tired. However, I finished the task.","pt":"Estava cansado. No entanto, terminei a tarefa."}],"practice":[{"q":"\"However\" expresses:","opts":["addition","time","contrast","cause"],"ans":2,"exp":"\"However\" = no entanto. It introduces a CONTRAST or unexpected idea."},{"q":"Which word introduces a result?","opts":["although","therefore","meanwhile","first"],"ans":1,"exp":"\"Therefore\" = portanto — introduces a result or conclusion."}]},"qs":[{"q":"\"___ it was raining, we went out.\"","opts":["Because","So","Although","Therefore"],"ans":2,"exp":"\"Although\" = apesar de. Introduces a contrasting fact."},{"q":"\"I studied hard, ___ I passed the exam.\"","opts":["although","so","despite","meanwhile"],"ans":1,"exp":"\"So\" = portanto, então. It introduces a RESULT."},{"q":"Which word shows a sequence in time?","opts":["however","therefore","meanwhile","also"],"ans":2,"exp":"\"Meanwhile\" = entretanto. Something happening at the same time."},{"q":"\"___, let me explain the problem.\" (to begin)","opts":["Finally","Therefore","First of all","Meanwhile"],"ans":2,"exp":"\"First of all\" = em primeiro lugar. Used to start an explanation."},{"q":"\"She worked hard. ___, she was promoted.\"","opts":["Although","However","As a result","Despite"],"ans":2,"exp":"\"As a result\" = como resultado. Shows cause and effect."}]}'::jsonb, 4),
('l1h6', 'u1h', 'Reporting Verbs', 'Verbos de Relato', '📝', 25, '{"learn":{"explanation":{"en":"Instead of always saying \"said\", use reporting verbs for more precise meaning: claim (afirmar), admit (admitir), deny (negar), promise (prometer), suggest (sugerir), warn (avisar), explain (explicar), complain (queixar-se), announce (anunciar).","pt":"Em vez de usar sempre \"said\", usa verbos de relato para maior precisão: claim (afirmar), admit (admitir), deny (negar), promise (prometer), suggest (sugerir), warn (avisar), explain (explicar), complain (queixar-se), announce (anunciar)."},"examples":[{"en":"She admitted she had made a mistake.","pt":"Ela admitiu que tinha cometido um erro."},{"en":"He promised to help me the next day.","pt":"Ele prometeu ajudar-me no dia seguinte."},{"en":"They warned us not to go there at night.","pt":"Eles avisaram-nos para não irmos lá à noite."}],"practice":[{"q":"\"Deny\" means:","opts":["agree with something","say something is NOT true","ask a question","complain"],"ans":1,"exp":"\"Deny\" = negar. To say that something is not true."},{"q":"\"He promised to help.\" This means:","opts":["He said he might help","He refused to help","He gave his word he would help","He suggested helping"],"ans":2,"exp":"\"Promise\" = prometer. A commitment to do something."}]},"qs":[{"q":"\"She ___ that she hadn''t taken the money.\" (said it wasn''t true)","opts":["admitted","denied","promised","warned"],"ans":1,"exp":"\"Denied\" = negou. To say something is NOT true."},{"q":"\"He ___ making a mistake.\" (accepted it was true)","opts":["denied","warned","admitted","suggested"],"ans":2,"exp":"\"Admitted\" = admitiu. To accept that something is true."},{"q":"\"They ___ us not to swim in the river.\" (told us of danger)","opts":["suggested","promised","claimed","warned"],"ans":3,"exp":"\"Warned\" = avisou. To tell someone about a danger."},{"q":"\"She ___ going to the beach.\" (gave the idea)","opts":["denied","suggested","warned","complained"],"ans":1,"exp":"\"Suggested\" = sugeriu. To put forward an idea."},{"q":"\"He ___ to call me later.\" (gave his word)","opts":["warned","suggested","denied","promised"],"ans":3,"exp":"\"Promised\" = prometeu. To give your word you will do something."}]}'::jsonb, 5),
('l1i1', 'u1i', 'Zero Conditional — General Truths', 'Condicional Zero — Verdades Gerais', '🌍', 20, '{"learn":{"explanation":{"en":"Zero Conditional = IF + Present Simple + Present Simple. Used for facts, laws of nature, and things that are always true. \"If you heat water to 100°C, it boils.\" Both parts use Present Simple. Can also use WHEN instead of IF.","pt":"Condicional Zero = IF + Presente Simples + Presente Simples. Usado para factos, leis da natureza e coisas que são sempre verdade. \"If you heat water to 100°C, it boils.\" Ambas as partes usam Presente Simples. Podes também usar WHEN em vez de IF."},"examples":[{"en":"If you mix blue and yellow, you get green.","pt":"Se misturares azul e amarelo, obténs verde."},{"en":"Water freezes if the temperature goes below 0°C.","pt":"A água congela se a temperatura baixar dos 0°C."},{"en":"If it rains, the streets get wet.","pt":"Se chover, as ruas ficam molhadas."}],"practice":[{"q":"Zero Conditional uses:","opts":["Past + Would","Present + Present","Present + Future","Past + Past"],"ans":1,"exp":"IF + Present Simple, Present Simple. Both sides are present tense."},{"q":"\"If you don''t sleep, you ___ tired.\" ","opts":["feel","felt","would feel","will feel"],"ans":0,"exp":"Zero Conditional: \"feel\" — present simple on both sides."}]},"qs":[{"q":"Zero Conditional is for:","opts":["imaginary situations","past regrets","general truths and facts","future predictions"],"ans":2,"exp":"Zero Conditional = always true situations, facts, laws of nature."},{"q":"\"If you ___ iron, it melts.\" (heat enough)","opts":["heated","heat","would heat","will heat"],"ans":1,"exp":"Zero Conditional: IF + Present Simple. \"If you HEAT iron...\""},{"q":"\"Plants die if they ___ enough water.\"","opts":["don''t get","didn''t get","wouldn''t get","won''t get"],"ans":0,"exp":"\"don''t get\" — present simple negative in Zero Conditional."},{"q":"Can you use WHEN instead of IF in Zero Conditional?","opts":["Never","Sometimes","Always","Only in questions"],"ans":1,"exp":"Yes! \"When\" is often used instead of \"if\" for general truths."},{"q":"\"If you ___ in the sun too long, you get sunburned.\"","opts":["stayed","would stay","stay","will stay"],"ans":2,"exp":"\"stay\" — present simple. Zero Conditional: fact/truth."}]}'::jsonb, 0),
('l1i2', 'u1i', 'First Conditional — Real Future', 'Primeiro Condicional — Futuro Real', '🚀', 25, '{"learn":{"explanation":{"en":"First Conditional = IF + Present Simple + WILL + base verb. Used for REAL and POSSIBLE future situations. \"If it rains, I will stay home.\" The \"if\" clause uses present tense even though it refers to the future!","pt":"Primeiro Condicional = IF + Presente Simples + WILL + verbo base. Usado para situações futuras REAIS e POSSÍVEIS. \"If it rains, I will stay home.\" A oração com \"if\" usa o presente mesmo que se refira ao futuro!"},"examples":[{"en":"If I study hard, I will pass the exam.","pt":"Se estudar muito, vou passar no exame."},{"en":"She will call you if she has time.","pt":"Ela vai ligar-te se tiver tempo."},{"en":"If you help me, I won''t forget it.","pt":"Se me ajudares, não me esquecerei."}],"practice":[{"q":"First Conditional formula:","opts":["If + Past, would + verb","If + Present, will + verb","If + Past, will + verb","If + Present, would + verb"],"ans":1,"exp":"IF + Present Simple, WILL + base verb."},{"q":"\"If she ___ late, the boss will be angry.\"","opts":["is","was","will be","would be"],"ans":0,"exp":"IF clause: present simple. \"If she IS late...\""}]},"qs":[{"q":"\"If it rains, we ___ the picnic.\"","opts":["cancel","will cancel","cancelled","would cancel"],"ans":1,"exp":"First Conditional: If + Present → WILL + verb. \"will cancel.\""},{"q":"\"If you ___ hard, you will succeed.\"","opts":["work","worked","will work","would work"],"ans":0,"exp":"IF clause = present simple: \"If you WORK hard...\""},{"q":"First Conditional expresses:","opts":["imaginary situations","impossible past regrets","real/possible future situations","general truths"],"ans":2,"exp":"First Conditional = real and possible future: it might actually happen!"},{"q":"\"We won''t catch the bus if we ___.\"","opts":["don''t hurry","didn''t hurry","wouldn''t hurry","not hurry"],"ans":0,"exp":"\"don''t hurry\" — present simple negative in IF clause."},{"q":"Which sentence uses First Conditional correctly?","opts":["If I will study, I pass.","If I study, I will pass.","If I studied, I will pass.","If I study, I would pass."],"ans":1,"exp":"\"If I STUDY (present), I WILL pass (will + base).\" ✓"}]}'::jsonb, 1),
('l1i3', 'u1i', 'Second Conditional — Hypothetical', 'Segundo Condicional — Hipotético', '💭', 30, '{"learn":{"explanation":{"en":"Second Conditional = IF + Past Simple + WOULD + base verb. Used for IMAGINARY or UNLIKELY present/future situations. \"If I had a million dollars, I would travel the world.\" (I don''t have a million dollars.) Note: use WERE instead of WAS with \"if I/he/she/it\".","pt":"Segundo Condicional = IF + Passado Simples + WOULD + verbo base. Usado para situações imaginárias ou improváveis. \"If I had a million dollars, I would travel the world.\" (Não tenho um milhão de dólares.) Nota: usa WERE em vez de WAS com \"if I/he/she/it\"."},"examples":[{"en":"If I won the lottery, I would buy a house.","pt":"Se ganhasse na lotaria, compraria uma casa."},{"en":"She would be happier if she lived near the sea.","pt":"Ela seria mais feliz se vivesse perto do mar."},{"en":"If I were you, I would apologise.","pt":"Se eu fosse tu, pediria desculpa."}],"practice":[{"q":"Second Conditional expresses:","opts":["real future","general truths","imaginary/unlikely situations","past regrets"],"ans":2,"exp":"Second Conditional = HYPOTHETICAL — not real or unlikely to happen."},{"q":"\"If I ___ a bird, I would fly home.\"","opts":["am","was","were","will be"],"ans":2,"exp":"Use WERE (not was) in Second Conditional: \"If I WERE a bird...\""}]},"qs":[{"q":"\"If I ___ more money, I would travel more.\"","opts":["have","had","would have","will have"],"ans":1,"exp":"Second Conditional IF clause: Past Simple. \"If I HAD more money...\""},{"q":"\"She would learn faster if she ___ more.\"","opts":["practised","practises","will practise","has practised"],"ans":0,"exp":"\"practised\" — Past Simple in IF clause."},{"q":"\"If I were the president, I ___ build more schools.\"","opts":["will","would","should","could"],"ans":1,"exp":"\"WOULD build\" — WOULD + base verb in the result clause."},{"q":"\"If I were you\" is used to:","opts":["describe a past event","give advice about a hypothetical situation","make a prediction","ask a question"],"ans":1,"exp":"\"If I were you, I would...\" is a classic way to give ADVICE."},{"q":"Second Conditional uses ___ in the IF clause.","opts":["present simple","past simple","will","past perfect"],"ans":1,"exp":"Second Conditional: IF + PAST SIMPLE, would + base verb."}]}'::jsonb, 2),
('l1i4', 'u1i', 'Third Conditional — Past Regrets', 'Terceiro Condicional — Arrependimentos', '😔', 30, '{"learn":{"explanation":{"en":"Third Conditional = IF + Past Perfect + WOULD HAVE + past participle. Used for IMAGINARY situations in the PAST — things that didn''t happen. \"If I had studied harder, I would have passed.\" (But I didn''t study hard and I didn''t pass.)","pt":"Terceiro Condicional = IF + Passado Perfeito + WOULD HAVE + particípio passado. Usado para situações imaginárias NO PASSADO — coisas que não aconteceram. \"If I had studied harder, I would have passed.\" (Mas não estudei muito e não passei.)"},"examples":[{"en":"If I had left earlier, I wouldn''t have missed the bus.","pt":"Se tivesse saído mais cedo, não teria perdido o autocarro."},{"en":"She would have passed if she had studied.","pt":"Ela teria passado se tivesse estudado."},{"en":"If it hadn''t rained, we would have had a picnic.","pt":"Se não tivesse chovido, teríamos feito um piquenique."}],"practice":[{"q":"Third Conditional is about:","opts":["real future","imaginary past","general truths","hypothetical present"],"ans":1,"exp":"Third Conditional = IMAGINARY PAST — things that didn''t happen."},{"q":"\"If I had known, I ___ have told you.\"","opts":["will","would","should","could"],"ans":1,"exp":"\"WOULD have told\" — result clause in Third Conditional."}]},"qs":[{"q":"Third Conditional IF clause uses:","opts":["present simple","past simple","past perfect","would + verb"],"ans":2,"exp":"IF + Past Perfect (had + past participle)."},{"q":"\"If she had arrived on time, she ___ the beginning.\"","opts":["would see","would have seen","will see","sees"],"ans":1,"exp":"\"WOULD HAVE SEEN\" — result clause: would have + past participle."},{"q":"\"If I ___ the map, I wouldn''t have got lost.\"","opts":["checked","had checked","have checked","would check"],"ans":1,"exp":"\"had checked\" — Past Perfect in the IF clause."},{"q":"Third Conditional expresses:","opts":["general facts","possible future","unreal past situations","present habits"],"ans":2,"exp":"Third Conditional = something that DIDN''T happen in the past, and imagining a different outcome."},{"q":"\"If it hadn''t been so cold, we ___ swimming.\"","opts":["would go","went","would have gone","will go"],"ans":2,"exp":"\"would have gone\" — result in Third Conditional."}]}'::jsonb, 3),
('l1i5', 'u1i', 'Wish & If Only', 'Wish e If Only (Desejos)', '⭐', 25, '{"learn":{"explanation":{"en":"\"Wish\" and \"If only\" express regrets and desires. For present situations you want to be different, use \"wish/if only\" + Past Simple: \"I wish I spoke Spanish.\" For past regrets, use \"wish/if only\" + Past Perfect: \"I wish I had studied more.\"","pt":"\"Wish\" e \"If only\" expressam arrependimentos e desejos. Para situações presentes que queres que sejam diferentes, usa \"wish/if only\" + Passado Simples: \"I wish I spoke Spanish.\" Para arrependimentos passados, usa \"wish/if only\" + Passado Perfeito: \"I wish I had studied more.\""},"examples":[{"en":"I wish I could fly. (impossible dream)","pt":"Queria poder voar. (sonho impossível)"},{"en":"If only I had more time! (present desire)","pt":"Oxalá tivesse mais tempo! (desejo presente)"},{"en":"I wish I had listened to my teacher. (past regret)","pt":"Queria ter ouvido o meu professor. (arrependimento passado)"}],"practice":[{"q":"\"I wish I ___ taller.\" (I am short)","opts":["am","was/were","had been","will be"],"ans":1,"exp":"\"Wish\" + past simple for present desires: \"I wish I WERE taller.\""},{"q":"For PAST regrets with \"wish\", use:","opts":["past simple","past continuous","past perfect","present simple"],"ans":2,"exp":"\"Wish\" + past perfect for past regrets: \"I wish I HAD studied.\""}]},"qs":[{"q":"\"I wish I ___ more money.\" (right now)","opts":["have","had","have had","will have"],"ans":1,"exp":"\"Wish\" + past simple for present wishes: \"I wish I HAD more money.\""},{"q":"\"If only I ___ so rude to her!\" (past regret)","opts":["wasn''t","hadn''t been","am not","won''t be"],"ans":1,"exp":"\"hadn''t been\" — If only + past perfect for past regrets."},{"q":"\"I wish I ___ how to cook.\" (present)","opts":["know","knew","had known","would know"],"ans":1,"exp":"\"knew\" — past simple with \"wish\" for present situations."},{"q":"Which expresses a PAST regret?","opts":["I wish I lived near the beach.","I wish I had called her.","I wish it stopped raining.","If only I were taller."],"ans":1,"exp":"\"I wish I HAD called her.\" — Past perfect = past regret."},{"q":"\"If only I ___ harder at school!\" (regret)","opts":["studied","had studied","study","would study"],"ans":1,"exp":"\"had studied\" — Past Perfect. Regret about something in the past."}]}'::jsonb, 4),
('l1i6', 'u1i', 'Conditionals — Mixed Practice', 'Condicionais — Prática Mista', '🎯', 35, '{"learn":{"explanation":{"en":"Quick summary: Zero (If + Present, Present) = always true. First (If + Present, Will) = real future. Second (If + Past, Would) = imaginary present. Third (If + Past Perfect, Would Have) = imaginary past. Wish + Past = present desire. Wish + Past Perfect = past regret.","pt":"Resumo rápido: Zero (If + Presente, Presente) = sempre verdade. Primeiro (If + Presente, Will) = futuro real. Segundo (If + Passado, Would) = presente imaginário. Terceiro (If + Passado Perfeito, Would Have) = passado imaginário. Wish + Passado = desejo presente. Wish + Past Perfect = arrependimento passado."},"examples":[{"en":"Zero: If water reaches 100°C, it boils.","pt":"Zero: Se a água atingir 100°C, ferve."},{"en":"Second: If I were rich, I would help everyone.","pt":"Segundo: Se eu fosse rico, ajudaria toda a gente."},{"en":"Third: If she had studied, she would have passed.","pt":"Terceiro: Se ela tivesse estudado, teria passado."}],"practice":[{"q":"Which conditional: \"If I had money, I would travel\"?","opts":["Zero","First","Second","Third"],"ans":2,"exp":"If + Past Simple + Would = Second Conditional. HYPOTHETICAL present."},{"q":"Which conditional: \"If you heat ice, it melts\"?","opts":["Zero","First","Second","Third"],"ans":0,"exp":"If + Present + Present = Zero Conditional. GENERAL TRUTH."}]},"qs":[{"q":"Identify: \"If it rains tomorrow, we will cancel.\"","opts":["Zero","First","Second","Third"],"ans":1,"exp":"If + Present Simple, WILL = First Conditional. Real possible future."},{"q":"Identify: \"If I had studied, I would have passed.\"","opts":["Zero","First","Second","Third"],"ans":3,"exp":"If + Past Perfect, WOULD HAVE = Third Conditional. Imaginary past."},{"q":"Identify: \"If I were you, I would apologise.\"","opts":["Zero","First","Second","Third"],"ans":2,"exp":"If + Past Simple (were), WOULD = Second Conditional. Hypothetical."},{"q":"\"I wish I ___ the lottery.\" (imagining winning right now)","opts":["win","won","had won","would win"],"ans":1,"exp":"\"won\" — Wish + Past Simple for PRESENT desires."},{"q":"Complete: \"If she ___ harder, she would have got the job.\"","opts":["tried","tries","had tried","would try"],"ans":2,"exp":"Third Conditional: IF + Past Perfect: \"had tried.\""}]}'::jsonb, 5),
('l1j1', 'u1j', 'What is the Passive?', 'O que é a Voz Passiva?', '📖', 20, '{"learn":{"explanation":{"en":"Active: The subject DOES the action. \"Pedro built the house.\" Passive: The subject RECEIVES the action. \"The house was built (by Pedro).\" Formula: BE + Past Participle. Use passive when the doer is unknown, unimportant, or obvious.","pt":"Activa: O sujeito FAZ a acção. \"Pedro built the house.\" Passiva: O sujeito RECEBE a acção. \"The house was built (by Pedro).\" Fórmula: BE + Particípio Passado. Usa a passiva quando quem faz não é conhecido, é irrelevante ou é óbvio."},"examples":[{"en":"Active: The chef cooked the meal.","pt":"Activa: O cozinheiro preparou a refeição."},{"en":"Passive: The meal was cooked (by the chef).","pt":"Passiva: A refeição foi preparada (pelo cozinheiro)."},{"en":"English is spoken in many countries.","pt":"O inglês é falado em muitos países."}],"practice":[{"q":"Passive formula:","opts":["Subject + verb","BE + past participle","Have + past participle","Will + verb"],"ans":1,"exp":"Passive = BE (in the right tense) + Past Participle."},{"q":"\"The window was broken.\" This is:","opts":["active voice","future tense","passive voice","reported speech"],"ans":2,"exp":"\"Was broken\" = BE + PP. This is PASSIVE voice."}]},"qs":[{"q":"Passive voice focuses on:","opts":["who does the action","what happens to the subject","the future","a question"],"ans":1,"exp":"Passive focuses on the OBJECT/receiver of the action, not the doer."},{"q":"\"Coffee is grown in Ethiopia.\" This sentence is:","opts":["active","passive","a question","reported speech"],"ans":1,"exp":"\"is grown\" = BE + PP = PASSIVE."},{"q":"To make passive, you need:","opts":["have + past participle","be + past participle","will + infinitive","do + base verb"],"ans":1,"exp":"Passive = BE (is/was/will be etc.) + Past Participle."},{"q":"When do we prefer passive?","opts":["When the doer is important","When we want to emphasise the action/result","When talking about the future","When asking questions"],"ans":1,"exp":"Passive is preferred when the DOER is unknown, obvious, or unimportant."},{"q":"\"Somebody stole my phone.\" → Passive: \"___ my phone.\"","opts":["Someone has stolen","My phone was stolen","My phone is stolen","They stolen"],"ans":1,"exp":"\"My phone WAS STOLEN.\" — was + stolen (past participle)."}]}'::jsonb, 0),
('l1j2', 'u1j', 'Present Simple Passive', 'Passiva no Presente Simples', '⭕', 25, '{"learn":{"explanation":{"en":"Present Simple Passive = IS/ARE + Past Participle. Use \"is\" for singular, \"are\" for plural. \"Rice is eaten every day in Mozambique.\" \"Cars are made in factories.\" Negative: \"It is not allowed.\" Question: \"Is it sold here?\"","pt":"Passiva no Presente Simples = IS/ARE + Particípio Passado. Usa \"is\" para singular, \"are\" para plural. \"Rice is eaten every day in Mozambique.\" \"Cars are made in factories.\" Negativa: \"It is not allowed.\" Pergunta: \"Is it sold here?\""},"examples":[{"en":"English is taught in all schools here.","pt":"O inglês é ensinado em todas as escolas aqui."},{"en":"These products are exported to many countries.","pt":"Estes produtos são exportados para muitos países."},{"en":"Is the shop open on Sundays?","pt":"A loja está aberta aos domingos?"}],"practice":[{"q":"\"The letters ___ delivered every morning.\"","opts":["is","are","was","were"],"ans":1,"exp":"\"Letters\" is plural → ARE delivered."},{"q":"\"Portuguese ___ spoken in Mozambique.\"","opts":["are","were","is","be"],"ans":2,"exp":"\"Portuguese\" is singular → IS spoken."}]},"qs":[{"q":"\"Football ___ played all over the world.\"","opts":["are","is","was","be"],"ans":1,"exp":"\"Football\" is singular → IS played. Present Simple Passive."},{"q":"\"The reports ___ written every Friday.\"","opts":["is","was","are","were"],"ans":2,"exp":"\"Reports\" is plural → ARE written."},{"q":"Negative Present Simple Passive: \"It ___ allowed here.\"","opts":["is not","are not","was not","not is"],"ans":0,"exp":"\"Is not allowed\" — singular subject + is + not + past participle."},{"q":"Question form: \"___ Portuguese spoken in Brazil?\"","opts":["Do","Does","Is","Are"],"ans":2,"exp":"\"IS Portuguese spoken...?\" — IS comes first in questions."},{"q":"\"Cashew nuts ___ grown in northern Mozambique.\"","opts":["is","are","was","will"],"ans":1,"exp":"\"Cashew nuts\" = plural → ARE grown. Present Simple Passive."}]}'::jsonb, 1),
('l1j3', 'u1j', 'Past Simple Passive', 'Passiva no Passado Simples', '⏮️', 25, '{"learn":{"explanation":{"en":"Past Simple Passive = WAS/WERE + Past Participle. Use \"was\" for singular, \"were\" for plural. \"The bridge was built in 1955.\" \"Many houses were damaged in the flood.\" By + agent can be added to say WHO did it.","pt":"Passiva no Passado Simples = WAS/WERE + Particípio Passado. Usa \"was\" para singular, \"were\" para plural. \"The bridge was built in 1955.\" \"Many houses were damaged in the flood.\" Podes adicionar by + agente para dizer QUEM fez."},"examples":[{"en":"Mozambique was colonised by Portugal.","pt":"Moçambique foi colonizado por Portugal."},{"en":"The thieves were caught by the police.","pt":"Os ladrões foram apanhados pela polícia."},{"en":"When was the Maputo cathedral built?","pt":"Quando foi construída a catedral de Maputo?"}],"practice":[{"q":"\"The car ___ stolen last night.\"","opts":["is","are","was","were"],"ans":2,"exp":"\"The car\" is singular → WAS stolen."},{"q":"\"The windows ___ broken in the storm.\"","opts":["is","was","are","were"],"ans":3,"exp":"\"Windows\" is plural → WERE broken."}]},"qs":[{"q":"\"The letter ___ sent yesterday.\"","opts":["is","are","was","were"],"ans":2,"exp":"\"The letter\" is singular → WAS sent. Past Simple Passive."},{"q":"\"Many trees ___ cut down last year.\"","opts":["is","was","are","were"],"ans":3,"exp":"\"Trees\" is plural → WERE cut down."},{"q":"\"The school ___ built by the government.\"","opts":["is","was","are","were"],"ans":1,"exp":"\"The school\" is singular + past → WAS built. \"By the government\" tells us the agent."},{"q":"Question: \"___ the suspect arrested?\"","opts":["Is","Are","Was","Were"],"ans":2,"exp":"\"WAS the suspect arrested?\" — singular past passive question."},{"q":"\"We ___ not told about the meeting.\"","opts":["was","were","is","are"],"ans":1,"exp":"\"We were not told.\" — We + WERE + not + past participle."}]}'::jsonb, 2),
('l1j4', 'u1j', 'Future & Modal Passives', 'Passiva no Futuro e com Modais', '🔮', 25, '{"learn":{"explanation":{"en":"Future Passive = WILL BE + Past Participle: \"The exam will be held next week.\" Modal Passives = MODAL + BE + Past Participle: \"It must be done.\" \"It should be checked.\" \"It can be fixed.\" \"It might be cancelled.\"","pt":"Passiva no Futuro = WILL BE + Particípio Passado: \"The exam will be held next week.\" Passivas Modais = MODAL + BE + Particípio Passado: \"It must be done.\" \"It should be checked.\" \"It can be fixed.\" \"It might be cancelled.\""},"examples":[{"en":"The results will be announced tomorrow.","pt":"Os resultados serão anunciados amanhã."},{"en":"This problem must be solved immediately.","pt":"Este problema deve ser resolvido imediatamente."},{"en":"The package can be collected at reception.","pt":"A encomenda pode ser levantada na recepção."}],"practice":[{"q":"Future Passive formula:","opts":["will + past participle","will be + past participle","will have + past participle","be + past participle"],"ans":1,"exp":"\"Will BE + past participle\": The work will be DONE."},{"q":"\"It ___ be repaired.\" (it''s possible)","opts":["can","could","must","will"],"ans":0,"exp":"\"Can be repaired\" = it is possible to repair it."}]},"qs":[{"q":"\"The winners ___ announced next week.\"","opts":["are","will be","were","are being"],"ans":1,"exp":"\"Will BE announced\" — Future Passive."},{"q":"\"All forms ___ filled in before submission.\"","opts":["must be","will","should","are"],"ans":0,"exp":"\"Must be filled in\" — Modal Passive expressing obligation."},{"q":"\"This machine ___ fixed by the engineer.\"","opts":["will","can be","must","should"],"ans":1,"exp":"\"Can be fixed\" — Modal Passive expressing possibility."},{"q":"\"The meeting ___ cancelled due to bad weather.\"","opts":["might be","will","is","was"],"ans":0,"exp":"\"Might be cancelled\" — Modal Passive expressing possibility."},{"q":"\"Phones ___ not be used in the exam room.\"","opts":["must","can","should","might"],"ans":0,"exp":"\"Must not be used\" — prohibition using modal passive."}]}'::jsonb, 3),
('l1j5', 'u1j', 'Active vs Passive — When to Use', 'Activa vs Passiva — Quando Usar', '⚖️', 20, '{"learn":{"explanation":{"en":"Use ACTIVE when the subject (doer) is important and known: \"The teacher explained the lesson.\" Use PASSIVE when: 1) the doer is unknown (\"My wallet was stolen.\"), 2) obvious (\"He was arrested.\"), 3) when the result matters more (\"The road has been closed.\").","pt":"Usa a VOZ ACTIVA quando o sujeito (quem faz) é importante e conhecido: \"The teacher explained the lesson.\" Usa a VOZ PASSIVA quando: 1) quem faz é desconhecido (\"My wallet was stolen.\"), 2) óbvio (\"He was arrested.\"), 3) o resultado importa mais (\"The road has been closed.\")."},"examples":[{"en":"Passive: A new hospital has been built. (result matters)","pt":"Passiva: Um novo hospital foi construído. (o resultado importa)"},{"en":"Active: Dr. Silva performed the surgery. (doer important)","pt":"Activa: O Dr. Silva realizou a cirurgia. (quem fez é importante)"},{"en":"Passive: Three people were injured. (doer unknown/less important)","pt":"Passiva: Três pessoas ficaram feridas. (quem fez é desconhecido/menos importante)"}],"practice":[{"q":"Which is better in PASSIVE? \"Someone robbed the bank.\"","opts":["Active is better here","Passive: \"The bank was robbed.\"","Both are always equal","Neither is good"],"ans":1,"exp":"When \"someone\" is vague/unknown, passive is more natural and informative."},{"q":"News reports prefer passive because:","opts":["it''s shorter","they don''t know who did things","the action/result is the focus","it sounds more formal"],"ans":2,"exp":"News focuses on WHAT HAPPENED, not who did it. Passive suits this perfectly."}]},"qs":[{"q":"Best passive use: \"Nobody knows who wrote this.\"","opts":["\"Someone wrote this.\"","\"This was written by someone.\"","\"This was written.\" (no agent needed)","Active is better here"],"ans":2,"exp":"When the agent is unknown/unimportant, omit it in passive: \"This was written.\""},{"q":"\"The police arrested the suspect.\" Active is better because:","opts":["passive is impossible here","the police (doer) is important information","the sentence is too long","it is in the past"],"ans":1,"exp":"When the DOER (the police) is important information, active voice is preferred."},{"q":"In scientific writing, passive is common because:","opts":["scientists don''t like people","the PROCESS/result matters, not the researcher","it sounds more complicated","it is shorter"],"ans":1,"exp":"Science focuses on results and methods, not on individual researchers → passive is standard."},{"q":"Which is correctly passive?","opts":["\"The car fixed.\"","\"The car was fixed.\"","\"The car be fixed.\"","\"Fixed the car.\""],"ans":1,"exp":"\"The car WAS fixed.\" = BE + Past Participle ✓"},{"q":"\"Oil was discovered in 1940.\" This passive is used because:","opts":["who discovered it is the main point","the discovery (event) is more important","it is a question","it is in active voice"],"ans":1,"exp":"The DISCOVERY (event) is what matters — who found it is less important. Passive is perfect."}]}'::jsonb, 4),
('l1j6', 'u1j', 'Passive — Revision & Practice', 'Passiva — Revisão e Prática', '🏆', 30, '{"learn":{"explanation":{"en":"Full passive review: Present (is/are + PP), Past (was/were + PP), Future (will be + PP), Modals (can/must/should + be + PP). Transform: Active subject → passive \"by\" phrase (optional). Active object → passive subject.","pt":"Revisão completa da passiva: Presente (is/are + PP), Passado (was/were + PP), Futuro (will be + PP), Modais (can/must/should + be + PP). Transformação: Sujeito activo → frase \"by\" passiva (opcional). Objecto activo → sujeito passivo."},"examples":[{"en":"Active: They make cars in Germany. → Passive: Cars are made in Germany.","pt":"Activa: Eles fabricam carros na Alemanha. → Passiva: Os carros são fabricados na Alemanha."},{"en":"Active: The teacher has corrected the tests. → Passive: The tests have been corrected.","pt":"Activa: O professor corrigiu os testes. → Passiva: Os testes foram corrigidos."}],"practice":[{"q":"Transform: \"They built this bridge in 1960.\" →","opts":["\"This bridge built in 1960.\"","\"This bridge was built in 1960.\"","\"This bridge is built in 1960.\"","\"This bridge were built in 1960.\""],"ans":1,"exp":"\"This bridge WAS BUILT in 1960.\" Past simple passive."},{"q":"Transform: \"Someone has stolen my bag.\" →","opts":["\"My bag is stolen.\"","\"My bag was stolen.\"","\"My bag has been stolen.\"","\"My bag had been stolen.\""],"ans":2,"exp":"\"My bag HAS BEEN stolen.\" — present perfect passive."}]},"qs":[{"q":"\"They speak Portuguese in Brazil.\" → Passive:","opts":["\"Portuguese is spoken in Brazil.\"","\"Portuguese was spoken in Brazil.\"","\"Portuguese will be spoken in Brazil.\"","\"Portuguese spoke in Brazil.\""],"ans":0,"exp":"\"Portuguese IS SPOKEN in Brazil.\" — Present Simple Passive."},{"q":"\"She will deliver the report tomorrow.\" → Passive:","opts":["\"The report delivered tomorrow.\"","\"The report is delivered tomorrow.\"","\"The report will be delivered tomorrow.\"","\"The report was delivered tomorrow.\""],"ans":2,"exp":"\"The report WILL BE DELIVERED tomorrow.\" — Future Passive."},{"q":"\"They have repaired the road.\" → Passive:","opts":["\"The road is repaired.\"","\"The road was repaired.\"","\"The road has been repaired.\"","\"The road will be repaired.\""],"ans":2,"exp":"\"The road HAS BEEN repaired.\" — Present Perfect Passive."},{"q":"\"You must submit the form by Friday.\" → Passive:","opts":["\"The form must be submitted by Friday.\"","\"The form is submitted by Friday.\"","\"The form was submitted by Friday.\"","\"The form will be submitted by Friday.\""],"ans":0,"exp":"\"The form MUST BE SUBMITTED by Friday.\" — Modal Passive."},{"q":"\"Somebody stole the bicycle.\" → Passive:","opts":["\"The bicycle is stolen.\"","\"The bicycle was stolen.\"","\"The bicycle has stolen.\"","\"The bicycle were stolen.\""],"ans":1,"exp":"\"The bicycle WAS STOLEN.\" — Past Simple Passive. No agent needed."}]}'::jsonb, 5),
('l19', 'u6', 'Common Phrasal Verbs', 'Verbos Frasais Comuns', '💬', 30, '{"learn":{"explanation":{"en":"Phrasal verbs combine a verb with a preposition or particle to create a new meaning, often totally different from the original verb. \"Give up\" (verb: give) means to quit! Native speakers use them constantly.","pt":"Os phrasal verbs combinam um verbo com uma preposição ou partícula para criar um novo significado, muitas vezes totalmente diferente do verbo original. \"Give up\" (verbo: give) significa desistir! Os falantes nativos usam-nos constantemente."},"examples":[{"en":"Don''t give up on your dreams.","pt":"Não desistas dos teus sonhos."},{"en":"I ran into an old friend yesterday.","pt":"Encontrei um velho amigo ontem, por acaso."},{"en":"Can you look after my dog?","pt":"Podes cuidar do meu cão?"}],"practice":[{"q":"\"Give up\" means:","opts":["to donate","to quit","to grow","to wake up"],"ans":1,"exp":"Give up = quit/stop trying."},{"q":"\"Look after\" means:","opts":["to search for","to take care of","to admire","to ignore"],"ans":1,"exp":"Look after = take care of."}]},"qs":[{"q":"\"Give up\" means:","opts":["to donate","to stop trying","to increase effort","to hand over"],"ans":1,"exp":"\"Give up\" = quit/desistir. \"Don''t give up!\" 💪"},{"q":"\"She ran ___ her ex at the mall.\"","opts":["over","into","away","out"],"ans":1,"exp":"\"Run into\" = to meet unexpectedly. Awkward! 😬"},{"q":"\"Turn ___ the TV — I''m sleeping!\"","opts":["on","up","off","down"],"ans":2,"exp":"\"Turn off\" = stop a device."},{"q":"\"He needs to ___ up with a good idea.\"","opts":["come","give","bring","look"],"ans":0,"exp":"\"Come up with\" = to think of/invent."},{"q":"\"Can you ___ after my dog this weekend?\"","opts":["look","watch","take","see"],"ans":0,"exp":"\"Look after\" = to take care of."}]}'::jsonb, 0),
('l20', 'u7', 'Common Idioms', 'Expressões Comuns', '🗣️', 35, '{"learn":{"explanation":{"en":"Idioms are fixed expressions whose meaning isn''t literal — you can''t guess it just from the individual words. \"It''s raining cats and dogs\" doesn''t involve animals; it means it''s raining very heavily! Learning idioms helps you sound natural.","pt":"Os idiomas são expressões fixas cujo significado não é literal — não se consegue adivinhar apenas pelas palavras individuais. \"It''s raining cats and dogs\" não tem animais; significa que está a chover muito! Aprender idiomas ajuda-te a soar natural."},"examples":[{"en":"That exam was a piece of cake!","pt":"Aquele exame foi canja (muito fácil)!"},{"en":"Break a leg in your interview!","pt":"Boa sorte na tua entrevista!"},{"en":"He''s on the fence about the job offer.","pt":"Ele está indeciso sobre a proposta de trabalho."}],"practice":[{"q":"\"A piece of cake\" means:","opts":["delicious food","very easy","very hard","a dessert"],"ans":1,"exp":"A piece of cake = very easy."},{"q":"\"On the fence\" means:","opts":["sitting outside","undecided","very confident","angry"],"ans":1,"exp":"On the fence = undecided."}]},"qs":[{"q":"\"It''s raining cats and dogs.\" This means:","opts":["Animals are falling","It''s raining heavily","The weather is strange","Pets are outside"],"ans":1,"exp":"\"Raining cats and dogs\" = raining VERY heavily."},{"q":"\"Break a leg!\" means:","opts":["Be careful!","Good luck!","Hurry up!","Don''t be nervous!"],"ans":1,"exp":"\"Break a leg\" = good luck! Used in theatre."},{"q":"\"He''s on the fence about the decision.\" This means he is:","opts":["sitting down","undecided","very sure","wrong"],"ans":1,"exp":"\"On the fence\" = undecided/indeciso."},{"q":"\"That exam was a piece of cake.\" This means:","opts":["It was delicious","It was very hard","It was very easy","It was boring"],"ans":2,"exp":"\"A piece of cake\" = very easy. 🎂"},{"q":"\"Hit the nail on the head\" = to be:","opts":["violent","confused","exactly right","careless"],"ans":2,"exp":"\"Hit the nail on the head\" = exactly right/acertar em cheio."}]}'::jsonb, 0),
('l8a', 'u8', 'The Past Perfect', 'O Past Perfect', '⏪', 20, '{"learn":{"explanation":{"en":"Past Perfect (had + past participle) shows that one past action happened BEFORE another past action. It''s the \"past of the past\". \"When I arrived, she had already left\" — leaving happened first.","pt":"O Past Perfect (had + particípio passado) mostra que uma acção passada aconteceu ANTES de outra acção passada. É o \"passado do passado\". \"When I arrived, she had already left\" — sair aconteceu primeiro."},"examples":[{"en":"I had finished my homework before dinner.","pt":"Eu já tinha terminado o trabalho de casa antes do jantar."},{"en":"She had never seen snow before that trip.","pt":"Ela nunca tinha visto neve antes daquela viagem."},{"en":"By the time we arrived, the film had started.","pt":"Quando chegámos, o filme já tinha começado."}],"practice":[{"q":"Past Perfect formula:","opts":["have + past participle","had + past participle","was + verb-ing","did + base verb"],"ans":1,"exp":"had + past participle."},{"q":"Which action happened FIRST: \"I had eaten before you called\"?","opts":["Calling","Eating","Both together","Unclear"],"ans":1,"exp":"Eating happened first (Past Perfect), then calling (Past Simple)."}]},"qs":[{"q":"\"She ___ already eaten when I arrived.\"","opts":["has","had","have","was"],"ans":1,"exp":"\"She HAD already eaten...\" — Past Perfect = action completed before another past action."},{"q":"Past Perfect = ___ + Past Participle","opts":["has","had","have","was"],"ans":1,"exp":"Had + Past Participle. Example: \"I had finished my work before she came.\""},{"q":"\"When I got home, my brother ___ already left.\"","opts":["has","had","have","was"],"ans":1,"exp":"\"had already left\" — the leaving happened BEFORE I got home."},{"q":"Which sentence uses Past Perfect correctly?","opts":["I have seen the movie already.","I had seen the movie when you arrived.","I saw the movie before you arrived.","I have had seen the movie."],"ans":1,"exp":"\"I had seen the movie when you arrived\" = Past Perfect for the action that happened first."},{"q":"\"She said she ___ never ___ to Europe.\"","opts":["has, be","had, been","have, been","was, be"],"ans":1,"exp":"\"She said she HAD never BEEN to Europe.\" — Past Perfect in reported speech."}]}'::jsonb, 0),
('l8b', 'u8', 'Narrative Tenses Overview', 'Visão Geral dos Tempos Narrativos', '📝', 20, '{"learn":{"explanation":{"en":"Narrative tenses (Past Simple, Past Continuous, and Past Perfect) work together to tell a clear story, showing what happened, what was already happening, and what had happened earlier.","pt":"Os tempos narrativos (Past Simple, Past Continuous e Past Perfect) trabalham juntos para contar uma história clara, mostrando o que aconteceu, o que já estava a acontecer, e o que tinha acontecido antes."},"examples":[{"en":"I was walking home when it started to rain.","pt":"Eu estava a caminhar para casa quando começou a chover."},{"en":"She had already cooked dinner when he arrived.","pt":"Ela já tinha cozinhado o jantar quando ele chegou."},{"en":"We met, talked, and then said goodbye.","pt":"Nós encontrámo-nos, conversámos, e depois despedimo-nos."}],"practice":[{"q":"Which tense shows an ongoing background action?","opts":["Past Simple","Past Continuous","Past Perfect","Future"],"ans":1,"exp":"Past Continuous = background/ongoing action."},{"q":"Which tense shows the EARLIEST event in a story?","opts":["Past Simple","Past Continuous","Past Perfect","Present"],"ans":2,"exp":"Past Perfect = the action before the rest of the story."}]},"qs":[{"q":"Narrative tenses are used for:","opts":["Describing routines","Telling stories","Making predictions","Giving orders"],"ans":1,"exp":"Narrative tenses are used to tell stories about past events."},{"q":"Which tenses are considered narrative tenses?","opts":["Present Simple only","Past Simple, Past Continuous, Past Perfect","Future only","All tenses"],"ans":1,"exp":"Past Simple, Past Continuous, and Past Perfect are the main narrative tenses."},{"q":"\"I ___ dinner when the phone ___.\"","opts":["was having, rang","had, rang","have, rings","was having, was ringing"],"ans":0,"exp":"\"I WAS HAVING dinner when the phone RANG\" — Past Continuous (ongoing) + Past Simple (interruption)."},{"q":"\"After I ___ my homework, I watched TV.\"","opts":["finish","finished","had finished","was finishing"],"ans":2,"exp":"\"After I HAD FINISHED my homework...\" — Past Perfect for the action that happened first."},{"q":"What is the correct narrative sequence?","opts":["I arrived. I was eating. I had left.","I had arrived. I ate. I was leaving.","I arrived. I ate. I had already eaten.","I was arriving. I ate. I had left."],"ans":2,"exp":"The correct sequence shows chronological order with Past Perfect for the earliest action."}]}'::jsonb, 1),
('l8c', 'u8', 'Narrative Story: The Unexpected Journey', 'História Narrativa: A Viagem Inesperada', '✈️', 25, '{"learn":{"explanation":{"en":"In storytelling, Past Perfect signals \"this happened even earlier\". Watch for it in stories to understand the true order of events, not just the order they are mentioned in.","pt":"Ao contar histórias, o Past Perfect assinala \"isto aconteceu ainda mais cedo\". Repara nele nas histórias para entenderes a verdadeira ordem dos eventos, não apenas a ordem em que são mencionados."},"examples":[{"en":"I had packed my bags before the taxi arrived.","pt":"Eu já tinha feito as malas antes do táxi chegar."},{"en":"She told me she had lost her passport.","pt":"Ela disse-me que tinha perdido o passaporte."},{"en":"By the time the sun rose, we had already left.","pt":"Quando o sol nasceu, nós já tínhamos partido."}],"practice":[{"q":"In \"I had packed before the taxi arrived\", what happened first?","opts":["Taxi arriving","Packing","Both together","Unclear"],"ans":1,"exp":"Packing happened first (Past Perfect)."},{"q":"Past Perfect in stories usually signals:","opts":["the next event","an earlier event","a future event","a repeated habit"],"ans":1,"exp":"It points back to something that happened even earlier."}]},"qs":[{"q":"Read the story: \"I was walking home when I saw a strange light in the sky. I had never seen anything like it before.\" The first action was:","opts":["Walking","Seeing the light","The light appearing","Going home"],"ans":2,"exp":"The light appeared (implied), then the person saw it while walking. Past Perfect in the third sentence shows the light had appeared before seeing it."},{"q":"In the story \"I had already left the house when I remembered my keys\", what happened first?","opts":["Left the house","Remembered the keys","Went back","Forgot the keys"],"ans":0,"exp":"The person HAD LEFT (Past Perfect) before remembering (Past Simple)."},{"q":"Which sentence uses Past Perfect correctly in a narrative?","opts":["I was tired because I was working all day.","I was tired because I worked all day.","I was tired because I had worked all day.","I was tired because I have worked all day."],"ans":2,"exp":"\"I HAD WORKED all day\" — cause (work) happened before effect (being tired)."},{"q":"\"She ___ the book for years before it ___ published.\"","opts":["wrote, was","had written, was","has written, was","was writing, had been"],"ans":1,"exp":"\"She HAD WRITTEN the book for years before it WAS published.\""}]}'::jsonb, 2),
('l8d', 'u8', 'Sequence Words', 'Palavras de Sequência', '🔗', 20, '{"learn":{"explanation":{"en":"Sequence words (first, then, after, before, finally) show the order of events in a story without needing complicated grammar. \"Before\" points to the earlier action; \"after\" and \"then\" point forward.","pt":"As palavras de sequência (first, then, after, before, finally) mostram a ordem dos eventos numa história sem precisar de gramática complicada. \"Before\" aponta para a acção mais cedo; \"after\" e \"then\" apontam para a frente."},"examples":[{"en":"First, I woke up. Then, I had breakfast.","pt":"Primeiro, acordei. Depois, tomei o pequeno-almoço."},{"en":"Before leaving, I locked the door.","pt":"Antes de sair, tranquei a porta."},{"en":"Finally, we arrived home.","pt":"Finalmente, chegámos a casa."}],"practice":[{"q":"Which word points to the EARLIER action?","opts":["after","before","then","finally"],"ans":1,"exp":"\"Before\" = earlier."},{"q":"\"I ate breakfast. ___ I left for work.\"","opts":["Before","Then","While","Since"],"ans":1,"exp":"\"Then\" shows the next step."}]},"qs":[{"q":"\"First, ___ we went to the market, we bought vegetables.\"","opts":["then","before","after","finally"],"ans":0,"exp":"\"First, THEN we went...\" — sequence words order events."},{"q":"Which word signals the EARLIEST action?","opts":["after","before","then","finally"],"ans":1,"exp":"\"Before\" indicates the action that happened earlier. \"Before I ate, I washed my hands.\""},{"q":"\"I finished my homework. ___ I went to bed.\"","opts":["Before","After","Then","When"],"ans":2,"exp":"\"Then\" shows the next action in sequence."},{"q":"Which sequence is correct?","opts":["I woke up, then I brushed my teeth, after I had breakfast.","I had breakfast, before I woke up, then I brushed my teeth.","I woke up, then I had breakfast, after I brushed my teeth."],"ans":0,"exp":"Correct sequence: woke up → brushed teeth → had breakfast."},{"q":"\"___ I left the house, I locked the door.\"","opts":["After","Before","Then","Finally"],"ans":0,"exp":"\"AFTER I left the house, I locked the door.\" — First left, then locked."}]}'::jsonb, 3),
('l8e', 'u8', 'Using "Already", "Just" & "Never"', 'Usando "Already", "Just" e "Never"', '⌛', 20, '{"learn":{"explanation":{"en":"With Past Perfect, \"already\" shows something was completed earlier than expected, \"just\" shows it happened a moment before, and \"never\" shows no prior experience. They usually go between had and the past participle.","pt":"Com o Past Perfect, \"already\" mostra que algo foi concluído mais cedo do que o esperado, \"just\" mostra que aconteceu um instante antes, e \"never\" mostra ausência de experiência anterior. Normalmente ficam entre had e o particípio passado."},"examples":[{"en":"I had already left when you called.","pt":"Eu já tinha saído quando me ligaste."},{"en":"She had just arrived when the meeting started.","pt":"Ela tinha acabado de chegar quando a reunião começou."},{"en":"He had never tried sushi before that night.","pt":"Ele nunca tinha experimentado sushi antes daquela noite."}],"practice":[{"q":"\"I had ___ finished when she arrived.\" (a moment before)","opts":["already","never","just","yet"],"ans":2,"exp":"\"Just\" = a moment before."},{"q":"Where does \"already\" usually go?","opts":["before had","between had and participle","at the end only","before the subject"],"ans":1,"exp":"had + already + past participle."}]},"qs":[{"q":"\"I had ___ arrived when she called.\" (a moment before)","opts":["already","never","just","yet"],"ans":2,"exp":"\"I had JUST arrived\" = a very short time before."},{"q":"\"She ___ seen that movie, so we watched something else.\" (before)","opts":["had just","had already","had never","has already"],"ans":1,"exp":"\"She had ALREADY seen it\" — an action completed before another time."},{"q":"\"I ___ been to Italy, so I was excited to go.\" (not before)","opts":["had already","had just","had never","has never"],"ans":2,"exp":"\"I had NEVER been\" — no prior experience."},{"q":"\"We ___ finished eating ___ the waiter arrived.\"","opts":["had already, when","already had, while","had just, before","just had, after"],"ans":0,"exp":"\"We HAD ALREADY finished eating WHEN the waiter arrived.\""},{"q":"Which is correct?","opts":["I had never saw that before.","I had never seen that before.","I have never saw that before.","I never seen that before."],"ans":1,"exp":"\"I had never SEEN\" — Past Perfect requires Past Participle (seen, not saw)."}]}'::jsonb, 4),
('l8f', 'u8', 'Narrative Practice: Writing a Story', 'Prática Narrativa: Escrevendo uma História', '✍️', 25, '{"learn":{"explanation":{"en":"To write a good story, start most actions in Past Simple, use Past Continuous for background scenes, and Past Perfect for anything that happened before the main story timeline.","pt":"Para escrever uma boa história, começa a maioria das acções no Past Simple, usa o Past Continuous para cenários de fundo, e o Past Perfect para tudo o que aconteceu antes da linha temporal principal da história."},"examples":[{"en":"The sun was setting when she finally arrived.","pt":"O sol estava a pôr-se quando ela finalmente chegou."},{"en":"He had studied hard, so the exam felt easy.","pt":"Ele tinha estudado muito, por isso o exame pareceu fácil."},{"en":"I opened the door and walked inside.","pt":"Eu abri a porta e entrei."}],"practice":[{"q":"Which tense usually starts a story''s main events?","opts":["Past Perfect","Past Simple","Present Perfect","Future"],"ans":1,"exp":"Past Simple narrates the main sequence of events."},{"q":"Which tense explains WHY something happened earlier?","opts":["Past Continuous","Past Perfect","Present Simple","Future Perfect"],"ans":1,"exp":"Past Perfect gives the earlier cause/reason."}]},"qs":[{"q":"What tense is best to start a story?","opts":["Present Simple","Past Simple","Future","Present Perfect"],"ans":1,"exp":"Past Simple is the standard tense to start narrating a past event."},{"q":"What tense describes an action that was ongoing when something else happened?","opts":["Past Perfect","Past Continuous","Past Simple","Present Continuous"],"ans":1,"exp":"Past Continuous describes actions in progress at a specific past moment."},{"q":"\"I was walking to the store when I ___ my friend.\"","opts":["see","saw","was seeing","had seen"],"ans":1,"exp":"\"I WAS WALKING (ongoing) when I SAW (interruption) my friend.\""},{"q":"\"She ___ in that office for five years before she got promoted.\"","opts":["worked","was working","had worked","has worked"],"ans":2,"exp":"\"She HAD WORKED for five years\" — duration before a later event (promotion)."},{"q":"Finish the story correctly: \"I ___ the door and ___ inside.\"","opts":["opened, walked","opened, was walking","was opening, walked","had opened, walked"],"ans":0,"exp":"Simple Past is used for consecutive actions in a story."}]}'::jsonb, 5),
('l8g', 'u8', 'Time Expressions with Past Perfect', 'Expressões de Tempo com Past Perfect', '🕰️', 20, '{"learn":{"explanation":{"en":"\"By the time\", \"since\", and \"for\" often pair with Past Perfect. \"By the time\" marks a deadline in the past. \"Since\" marks a starting point; \"for\" marks a duration.","pt":"\"By the time\", \"since\" e \"for\" juntam-se frequentemente ao Past Perfect. \"By the time\" marca um prazo no passado. \"Since\" marca um ponto de partida; \"for\" marca uma duração."},"examples":[{"en":"By the time he called, I had already gone to bed.","pt":"Quando ele ligou, eu já tinha ido para a cama."},{"en":"She had worked there for ten years before retiring.","pt":"Ela tinha trabalhado lá durante dez anos antes de se reformar."},{"en":"They had been friends since childhood.","pt":"Eles eram amigos desde a infância."}],"practice":[{"q":"\"For\" is used with:","opts":["a point in time","a duration","a place","a reason"],"ans":1,"exp":"\"For\" + a period/duration: for 10 years."},{"q":"\"Since\" is used with:","opts":["a duration","a starting point","a place","a reason"],"ans":1,"exp":"\"Since\" + a specific starting point: since 2010."}]},"qs":[{"q":"\"By the time I arrived, they ___ already ___.\"","opts":["have, left","had, left","has, left","were, left"],"ans":1,"exp":"\"By the time\" + Past Perfect: \"they HAD already LEFT.\""},{"q":"\"I had been there ___ 2010.\"","opts":["for","since","from","ago"],"ans":1,"exp":"\"since 2010\" — specific point in time. Past Perfect requires \"since\" or \"for\"."},{"q":"\"She had been a teacher ___ 15 years before she retired.\"","opts":["for","since","during","from"],"ans":0,"exp":"\"for 15 years\" — duration. \"For\" + period, \"Since\" + point."},{"q":"\"___ the time I woke up, she had already left.\"","opts":["After","By","Before","During"],"ans":1,"exp":"\"BY the time\" indicates the deadline before which the action had already happened."},{"q":"Which expression does NOT work with Past Perfect?","opts":["by the time","before","after","tomorrow"],"ans":3,"exp":"\"tomorrow\" is future — cannot be used with Past Perfect."}]}'::jsonb, 6),
('l8h', 'u8', 'Review: Narrative Tenses', 'Revisão: Tempos Narrativos', '🎯', 25, '{"learn":{"explanation":{"en":"Let''s review: Past Simple for the main events, Past Continuous for ongoing background actions, and Past Perfect for anything that happened even earlier. Mixing all three correctly makes your stories sound natural and clear.","pt":"Vamos rever: Past Simple para os eventos principais, Past Continuous para acções de fundo em curso, e Past Perfect para tudo o que aconteceu ainda mais cedo. Combinar os três correctamente faz as tuas histórias soarem naturais e claras."},"examples":[{"en":"I was reading when the lights went out.","pt":"Eu estava a ler quando as luzes se apagaram."},{"en":"She had already left when I called.","pt":"Ela já tinha saído quando eu liguei."},{"en":"We arrived, unpacked, and went to sleep.","pt":"Nós chegámos, desfizemos as malas, e fomos dormir."}],"practice":[{"q":"Which combination shows an interrupted action?","opts":["Past Simple + Past Simple","Past Continuous + Past Simple","Past Perfect + Past Perfect","Future + Past"],"ans":1,"exp":"Past Continuous (ongoing) + Past Simple (interruption)."},{"q":"Which tense always shows the EARLIEST event?","opts":["Past Simple","Past Continuous","Past Perfect","Present Perfect"],"ans":2,"exp":"Past Perfect = always the earliest action in the sequence."}]},"qs":[{"q":"\"I was watching TV when the lights went out.\" The two tenses are:","opts":["Past Continuous + Past Simple","Past Simple + Past Perfect","Past Perfect + Past Simple","Past Continuous + Past Perfect"],"ans":0,"exp":"Past Continuous (was watching) + Past Simple (went out)."},{"q":"\"I had finished my work before I went home.\" The first action is:","opts":["Went home","Finished work","Started work","Both at the same time"],"ans":1,"exp":"Had finished (Past Perfect) happened before went home (Past Simple)."},{"q":"Which sentence correctly describes three past events in order?","opts":["I ate, I had arrived, I was sleeping.","I arrived, I ate, I slept.","I was arriving, I ate, I had slept.","I had arrived, I was eating, I slept."],"ans":1,"exp":"Arrived (Past Simple) → ate (Past Simple) → slept (Past Simple) shows clear sequence."},{"q":"\"She ___ never ___ sushi before she ___ to Japan.\"","opts":["had, eaten, went","has, ate, went","had, ate, went","has, eaten, was going"],"ans":0,"exp":"\"She HAD never EATEN sushi before she WENT to Japan.\""},{"q":"Narrative tenses are essential for:","opts":["Writing emails","Ordering food","Telling stories","Giving directions"],"ans":2,"exp":"Narrative tenses are primarily used for storytelling and describing past events."}]}'::jsonb, 7),
('l9a', 'u9', 'Future Continuous: Actions in Progress', 'Future Continuous: Acções em Progresso', '🔄', 20, '{"learn":{"explanation":{"en":"Future Continuous (will be + verb-ing) describes an action that will be in progress at a specific moment in the future. \"This time tomorrow, I will be sleeping.\" It''s like a snapshot of the future.","pt":"O Future Continuous (will be + verbo-ing) descreve uma acção que estará em curso num momento específico do futuro. \"This time tomorrow, I will be sleeping.\" É como uma fotografia do futuro."},"examples":[{"en":"This time next week, I will be flying to London.","pt":"A esta hora na semana que vem, estarei a voar para Londres."},{"en":"At 9pm, she will be watching the game.","pt":"Às 21h, ela estará a ver o jogo."},{"en":"Will you be using your car tomorrow?","pt":"Vais estar a usar o teu carro amanhã?"}],"practice":[{"q":"Future Continuous formula:","opts":["will + base verb","will + be + verb-ing","will + have + verb-ed","am/is/are + verb-ing"],"ans":1,"exp":"will + be + verb-ing."},{"q":"\"At midnight I ___ (sleep).\"","opts":["will sleep","will be sleeping","will have slept","sleep"],"ans":1,"exp":"Future Continuous: will be sleeping."}]},"qs":[{"q":"\"This time tomorrow, I ___ on the beach.\"","opts":["will lie","will be lying","am lying","will have lain"],"ans":1,"exp":"\"will be lying\" = action in progress at a specific future time."},{"q":"Future Continuous = will + ___ + verb-ing","opts":["be","have","do","being"],"ans":0,"exp":"Future Continuous = WILL + BE + verb-ing."},{"q":"\"At 10am tomorrow, we ___ a meeting.\"","opts":["will have","will be having","are having","had"],"ans":1,"exp":"\"will be having\" = ongoing action at a specific future time."},{"q":"Which is correct?","opts":["I will be study at 8pm.","I will be studying at 8pm.","I am studying at 8pm.","I will studying at 8pm."],"ans":1,"exp":"\"will be studying\" — correct form: will + be + -ing."}]}'::jsonb, 0),
('l9b', 'u9', 'Future Perfect: Completed Actions', 'Future Perfect: Acções Completadas', '✅', 20, '{"learn":{"explanation":{"en":"Future Perfect (will have + past participle) shows an action that will be completed before a specific point in the future. \"By Friday, I will have finished the report.\" Think of it as looking back from a future moment.","pt":"O Future Perfect (will have + particípio passado) mostra uma acção que estará concluída antes de um ponto específico no futuro. \"By Friday, I will have finished the report.\" Imagina que olhas para trás a partir de um momento futuro."},"examples":[{"en":"By 2030, she will have graduated.","pt":"Em 2030, ela já terá se formado."},{"en":"I will have cooked dinner by the time you arrive.","pt":"Eu já terei cozinhado o jantar quando chegares."},{"en":"Will you have finished by 6pm?","pt":"Já terás terminado até às 18h?"}],"practice":[{"q":"Future Perfect formula:","opts":["will + base verb","will + be + verb-ing","will + have + past participle","have + past participle"],"ans":2,"exp":"will + have + past participle."},{"q":"\"By next year, I ___ this course.\"","opts":["will finish","will be finishing","will have finished","finish"],"ans":2,"exp":"\"By\" + future point = Future Perfect: will have finished."}]},"qs":[{"q":"\"By 2025, I ___ graduated.\"","opts":["will have","have","will","am going to"],"ans":0,"exp":"\"will have graduated\" = will + have + past participle. The action will be complete by then."},{"q":"Future Perfect = will + ___ + past participle","opts":["be","have","has","had"],"ans":1,"exp":"Future Perfect = WILL + HAVE + past participle."},{"q":"\"___ you have finished by 6pm?\"","opts":["Will","Are","Do","Have"],"ans":0,"exp":"\"Will you have finished?\" = question using Future Perfect."},{"q":"Which sentence is correct?","opts":["By next year, I will finish my degree.","By next year, I will have finished my degree.","By next year, I have finished my degree.","By next year, I finished my degree."],"ans":1,"exp":"\"By next year, I will have finished\" = Future Perfect to show completion by a future time."},{"q":"\"They ___ already ___ the report by Friday.\"","opts":["will, finish","will have, finished","have, finished","will be, finishing"],"ans":1,"exp":"\"They will have already finished by Friday\" — Future Perfect."}]}'::jsonb, 1),
('l9c', 'u9', 'Using "By the time" with Future Perfect', 'Usando "By the time" com Future Perfect', '⌛', 20, '{"learn":{"explanation":{"en":"\"By the time\" introduces the future point by which something will be done. It always pairs with Future Perfect in the main clause: \"By the time he arrives, we will have eaten.\" The time clause uses Present Simple.","pt":"\"By the time\" introduz o ponto futuro pelo qual algo estará feito. Junta-se sempre ao Future Perfect na oração principal: \"By the time he arrives, we will have eaten.\" A oração temporal usa o Presente Simples."},"examples":[{"en":"By the time she calls, I will have left.","pt":"Quando ela ligar, eu já terei saído."},{"en":"By the time the film ends, it will have been 3 hours.","pt":"Quando o filme acabar, já terão passado 3 horas."},{"en":"I will have eaten by the time you arrive.","pt":"Eu já terei comido quando chegares."}],"practice":[{"q":"After \"by the time\", use:","opts":["will + base verb","Present Simple","Past Simple","Future Perfect"],"ans":1,"exp":"Time clause = Present Simple (not will)."},{"q":"\"By the time I arrive, she ___ (leave).\"","opts":["will leave","will have left","left","leaves"],"ans":1,"exp":"Future Perfect: will have left."}]},"qs":[{"q":"\"By the time you arrive, we ___ already ___ dinner.\"","opts":["will, have","will have, had","have, had","will be, having"],"ans":1,"exp":"\"By the time you arrive, we WILL HAVE ALREADY HAD dinner.\""},{"q":"\"By the time he gets here, I ___ for an hour.\"","opts":["will wait","will have waited","am waiting","waited"],"ans":1,"exp":"\"will have waited\" — Future Perfect to show duration before a future point."},{"q":"Which time expression is used with Future Perfect?","opts":["now","by the time","currently","for the moment"],"ans":1,"exp":"\"By the time\" is commonly used to introduce the future point before which the action is completed."},{"q":"\"She ___ her homework by 8pm.\"","opts":["will finish","will have finished","is finishing","finishes"],"ans":1,"exp":"\"will have finished\" = she will be finished by 8pm."},{"q":"What is the difference between Future Continuous and Future Perfect?","opts":["Future Continuous is for completed actions, Future Perfect for ongoing","Future Continuous is for ongoing actions, Future Perfect for completed","Both are for ongoing actions","Both are for completed actions"],"ans":1,"exp":"Future Continuous = ongoing at a future time. Future Perfect = completed by a future time."}]}'::jsonb, 2),
('l9d', 'u9', 'Future Perfect Continuous', 'Future Perfect Continuous', '⏳', 25, '{"learn":{"explanation":{"en":"Future Perfect Continuous (will have been + verb-ing) emphasises how long an action will have been going on by a future point. \"By 2030, I will have been studying English for 10 years.\"","pt":"O Future Perfect Continuous (will have been + verbo-ing) enfatiza há quanto tempo uma acção terá durado até um ponto futuro. \"By 2030, I will have been studying English for 10 years.\""},"examples":[{"en":"By next June, I will have been working here for 5 years.","pt":"No próximo Junho, já trabalharei aqui há 5 anos."},{"en":"She will have been waiting for two hours by then.","pt":"Ela já estará à espera há duas horas nessa altura."},{"en":"They will have been building the house for a year.","pt":"Eles já estarão a construir a casa há um ano."}],"practice":[{"q":"Future Perfect Continuous formula:","opts":["will + be + verb-ing","will + have + past participle","will + have + been + verb-ing","will + verb"],"ans":2,"exp":"will + have + been + verb-ing."},{"q":"It emphasises:","opts":["a single completed action","duration of an ongoing action up to a future point","a future plan","a present habit"],"ans":1,"exp":"Duration in progress up to a future point."}]},"qs":[{"q":"\"By 2026, I ___ English for 10 years.\"","opts":["will be learning","will have learned","will have been learning","am learning"],"ans":2,"exp":"\"will have been learning\" = Future Perfect Continuous: emphasising duration up to a future point."},{"q":"Future Perfect Continuous = will + have + been + ___","opts":["-ing","past participle","infinitive","base form"],"ans":0,"exp":"Future Perfect Continuous = WILL + HAVE + BEEN + verb-ing."},{"q":"\"They ___ here for 20 years by 2030.\"","opts":["will live","will have lived","will have been living","are living"],"ans":2,"exp":"\"will have been living\" emphasises the duration of the action."},{"q":"Which sentence shows duration up to a future point?","opts":["I will study tomorrow.","I will have studied for three hours by then.","I will be studying at 5pm.","I will study today."],"ans":1,"exp":"\"will have studied for three hours\" — Future Perfect (not Continuous) for duration before a future point."}]}'::jsonb, 3),
('l9e', 'u9', 'Future Time Clauses', 'Orações Temporais Futuras', '⏰', 20, '{"learn":{"explanation":{"en":"After time conjunctions (when, as soon as, until, before, after), we use Present Simple — NOT \"will\" — even when talking about the future. The \"will\" goes in the other part of the sentence only.","pt":"Depois de conjunções de tempo (when, as soon as, until, before, after), usamos o Presente Simples — NÃO \"will\" — mesmo quando falamos do futuro. O \"will\" vai apenas na outra parte da frase."},"examples":[{"en":"I will call you when I arrive. (NOT: when I will arrive)","pt":"Vou ligar-te quando chegar. (NÃO: when I will arrive)"},{"en":"As soon as she wakes up, she will eat.","pt":"Assim que ela acordar, ela vai comer."},{"en":"Wait until the rain stops.","pt":"Espera até a chuva parar."}],"practice":[{"q":"\"I will call you when I ___ home.\"","opts":["will get","get","am getting","got"],"ans":1,"exp":"Time clause = Present Simple: get (not will get)."},{"q":"\"As soon as she ___, we''ll leave.\"","opts":["will arrive","arrives","arrived","is arriving"],"ans":1,"exp":"As soon as + Present Simple."}]},"qs":[{"q":"\"When I ___ home, I will call you.\"","opts":["will get","get","am getting","got"],"ans":1,"exp":"Use Present Simple in time clauses (when, as soon as, until) after \"will\" in the main clause."},{"q":"\"As soon as she ___ here, we will start.\"","opts":["will arrive","arrives","arrived","is arriving"],"ans":1,"exp":"\"As soon as she arrives\" — Present Simple in the time clause."},{"q":"Which sentence uses the time clause correctly?","opts":["I will wait until you will come.","I will wait until you come.","I will wait until you are coming.","I wait until you will come."],"ans":1,"exp":"\"until you come\" — Present Simple after until in a future time clause."},{"q":"\"___ the time I finish, I will have completed 10 lessons.\"","opts":["When","After","Before","By"],"ans":3,"exp":"\"BY the time I finish\" — Future Perfect expresses the action completed by that future point."},{"q":"What is the rule for future time clauses?","opts":["Use will + infinitive","Use present tense (not will)","Use past tense","Use future continuous"],"ans":1,"exp":"In future time clauses (after when, as soon as, until, before, after, by the time), we use the present tense, not will."}]}'::jsonb, 4),
('l9f', 'u9', 'Predictions with Future Forms', 'Previsões com Formas do Futuro', '🔮', 20, '{"learn":{"explanation":{"en":"Use \"will\" for opinions and strong predictions (\"I think it will snow\"). Use \"going to\" for predictions with visible evidence (\"Look at those clouds — it''s going to rain!\"). \"Might/could\" express lower certainty.","pt":"Usa \"will\" para opiniões e previsões fortes (\"I think it will snow\"). Usa \"going to\" para previsões com evidência visível (\"Look at those clouds — it''s going to rain!\"). \"Might/could\" expressam menor certeza."},"examples":[{"en":"I think she will win the competition.","pt":"Eu acho que ela vai ganhar a competição."},{"en":"Look at the sky — it''s going to storm!","pt":"Olha para o céu — vai haver tempestade!"},{"en":"He might be late today.","pt":"Ele pode chegar atrasado hoje."}],"practice":[{"q":"Which shows the STRONGEST certainty?","opts":["might rain","could rain","will rain","may rain"],"ans":2,"exp":"\"Will\" = strongest certainty."},{"q":"\"Look out! You ___ fall!\" (visible evidence)","opts":["will","are going to","might","may"],"ans":1,"exp":"Visible evidence → \"going to\"."}]},"qs":[{"q":"\"I think she ___ the exam.\" (opinion)","opts":["will pass","is passing","passes","is going to pass"],"ans":0,"exp":"\"will pass\" — predictions based on opinion or belief use \"will\"."},{"q":"\"Look at those clouds! It ___ rain.\" (evidence)","opts":["will","is going to","may","might"],"ans":1,"exp":"\"is going to\" — predictions based on visible evidence."},{"q":"\"In 2050, people ___ live on Mars.\" (certain prediction)","opts":["will","are going to","may","might"],"ans":0,"exp":"\"will\" — strong prediction about the future."},{"q":"\"I ___ be a millionaire one day!\" (ambition)","opts":["will","am going to","might","may"],"ans":0,"exp":"\"will\" — expressing ambition or hope about the future."},{"q":"Which is the most certain prediction?","opts":["It will rain.","It might rain.","It could rain.","It may rain."],"ans":0,"exp":"\"will\" expresses the highest certainty; \"might/could/may\" express possibility."}]}'::jsonb, 5),
('l9g', 'u9', 'Review: Future Tenses', 'Revisão: Tempos Futuros', '🎯', 25, '{"learn":{"explanation":{"en":"Quick recap: Will = spontaneous decisions, promises, opinions. Going to = plans and visible evidence. Future Continuous = action in progress at a future moment. Future Perfect = action completed before a future point.","pt":"Revisão rápida: Will = decisões espontâneas, promessas, opiniões. Going to = planos e evidência visível. Future Continuous = acção em curso num momento futuro. Future Perfect = acção concluída antes de um ponto futuro."},"examples":[{"en":"This time next year, I will be living in London.","pt":"A esta hora no próximo ano, estarei a viver em Londres."},{"en":"By December, I will have passed my English exam.","pt":"Em Dezembro, já terei passado no meu exame de inglês."},{"en":"I''m going to start a new job next Monday.","pt":"Vou começar um novo emprego na próxima segunda-feira."}],"practice":[{"q":"\"By next month, I ___ 30 lessons.\" (completed)","opts":["will finish","will be finishing","will have finished","finish"],"ans":2,"exp":"Completed by future point = Future Perfect."},{"q":"\"At 5pm tomorrow, I ___ in a meeting.\" (in progress)","opts":["will have met","will be meeting","meet","will meet"],"ans":1,"exp":"In progress at a future moment = Future Continuous."}]},"qs":[{"q":"\"This time next week, I ___ in a hotel.\" (ongoing)","opts":["will stay","will be staying","will have stayed","am staying"],"ans":1,"exp":"\"will be staying\" = action in progress at a specific future time."},{"q":"\"By next month, I ___ all the lessons.\" (completed)","opts":["will finish","will have finished","am finishing","finish"],"ans":1,"exp":"\"will have finished\" = Future Perfect for completion by a future point."},{"q":"\"For 5 years by 2026, she ___ as a teacher.\" (duration)","opts":["will work","will have been working","will be working","works"],"ans":1,"exp":"\"will have been working\" — Future Perfect Continuous to emphasise duration."},{"q":"\"When you arrive, I ___ for you at the station.\"","opts":["will wait","will be waiting","will have waited","am waiting"],"ans":1,"exp":"\"will be waiting\" = I will already be waiting at the time you arrive."},{"q":"\"By the time we get there, the film ___ started.\"","opts":["will have","will","is going to","has"],"ans":0,"exp":"\"will have started\" — Future Perfect: completed before a future point."}]}'::jsonb, 6),
('l10a', 'u10', 'Third Conditional', 'Terceiro Condicional', '🔀', 25, '{"learn":{"explanation":{"en":"Third Conditional (If + Past Perfect, would have + past participle) describes UNREAL past situations. It expresses what would have happened if the past had been different. It''s often used for regret.","pt":"O Terceiro Condicional (If + Past Perfect, would have + particípio passado) descreve situações passadas IRREAIS. Expressa o que teria acontecido se o passado tivesse sido diferente. Usado para exprimir arrependimento."},"examples":[{"en":"If I had studied harder, I would have passed.","pt":"Se eu tivesse estudado mais, teria passado."},{"en":"She would have called if she had known.","pt":"Ela teria ligado se tivesse sabido."},{"en":"We wouldn''t have been late if we had left earlier.","pt":"Não teríamos chegado atrasados se tivéssemos saído mais cedo."}],"practice":[{"q":"Third Conditional formula:","opts":["If+Past Simple,would+verb","If+Past Perfect,would have+PP","If+Present,will+verb","If+were,would+verb"],"ans":1,"exp":"If + Past Perfect, would have + past participle."},{"q":"Complete: ''If I had known, I ___ helped you.''","opts":["will have","would have","had","should"],"ans":1,"exp":"would have + past participle."}]},"qs":[{"q":"\"If I had studied harder, I ___ the exam.\"","opts":["would pass","would have passed","will pass","passed"],"ans":1,"exp":"\"would have passed\" — Third Conditional: If + Past Perfect, Would have + PP. Unreal past condition."},{"q":"Third Conditional = If + ___ + Would have + ___","opts":["Past Simple, Past Participle","Past Perfect, Past Participle","Present Simple, Infinitive","Past Continuous, Infinitive"],"ans":1,"exp":"Third Conditional: If + PAST PERFECT, Would have + PAST PARTICIPLE."},{"q":"\"If she ___ to the party, she would have met him.\"","opts":["went","had gone","goes","was going"],"ans":1,"exp":"\"If she HAD GONE\" — Third Conditional for unreal past situations."},{"q":"\"I would have bought it if I ___ enough money.\"","opts":["have","had","had had","would have"],"ans":2,"exp":"\"if I HAD HAD enough money\" — Past Perfect of \"have\"."},{"q":"Which sentence expresses regret about the past?","opts":["If I am rich, I will travel.","If I were rich, I would travel.","If I had been rich, I would have traveled.","If I have been rich, I travel."],"ans":2,"exp":"Third Conditional expresses regret or wishes about the past."}]}'::jsonb, 0),
('l10b', 'u10', 'Mixed Conditionals', 'Condicionais Mistas', '🔄', 25, '{"learn":{"explanation":{"en":"Mixed Conditionals combine two different conditional types. Past condition + present result: ''If I had studied medicine, I would be a doctor now.'' Present condition + past result: ''If I were richer, I would have bought it.''","pt":"Os Condicionais Mistos combinam dois tipos diferentes. Condição passada + resultado presente: ''If I had studied medicine, I would be a doctor now.'' Condição presente + resultado passado: ''If I were richer, I would have bought it.''"},"examples":[{"en":"If I had taken that job, I would be in Paris now.","pt":"Se eu tivesse aceite esse emprego, estaria em Paris agora."},{"en":"If she were more careful, she wouldn''t have broken it.","pt":"Se ela fosse mais cuidadosa, não o teria partido."},{"en":"He would be healthier now if he had exercised more.","pt":"Ele estaria mais saudável agora se tivesse feito mais exercício."}],"practice":[{"q":"Past condition + present result uses:","opts":["If+Past Perfect,would have+PP","If+Past Perfect,would+verb","If+Present,will+verb","If+Past,would+verb"],"ans":1,"exp":"If + Past Perfect → would + infinitive (present result)."},{"q":"''If I were richer, I ___ bought that house.''","opts":["would buy","will buy","would have bought","had bought"],"ans":2,"exp":"Present condition + past result = would have bought."}]},"qs":[{"q":"\"If I had studied medicine, I ___ a doctor now.\" (past condition, present result)","opts":["would be","would have been","am","was"],"ans":0,"exp":"Mixed Conditional: If + Past Perfect, Would + infinitive. Past condition → Present result."},{"q":"\"If I were a millionaire, I ___ bought that house.\" (present condition, past result)","opts":["would have","would","will have","had"],"ans":0,"exp":"Mixed Conditional: If + Past Simple, Would have + PP. Present condition → Past result."},{"q":"\"If she had taken the job, she ___ in London now.\"","opts":["would be","would have been","is","was"],"ans":0,"exp":"If + Past Perfect (past condition), Would + infinitive (present result)."},{"q":"\"If I ___ English, I wouldn''t have gotten this job.\" (present ability, past consequence)","opts":["hadn''t studied","don''t study","didn''t study","wouldn''t study"],"ans":2,"exp":"\"If I DIDN''T study English\" (present condition) → \"wouldn''t have gotten\" (past result)."},{"q":"Which is an example of a mixed conditional?","opts":["If it rains, I will stay home.","If I studied, I would pass.","If I had studied, I would be a doctor now.","If I had studied, I would have passed."],"ans":2,"exp":"\"If I had studied\" (past condition) → \"I would be a doctor now\" (present result) is mixed."}]}'::jsonb, 1),
('l10c', 'u10', 'Unreal Past with "Wish"', 'Passado Irreal com "Wish"', '✨', 20, '{"learn":{"explanation":{"en":"Wish expresses unreal desires. Wish + Past Simple = unreal present desire: ''I wish I had more time.'' Wish + Past Perfect = past regret: ''I wish I had studied harder.'' Never use will directly after wish.","pt":"Wish expressa desejos irreais. Wish + Past Simple = desejo irreal presente: ''I wish I had more time.'' Wish + Past Perfect = arrependimento passado: ''I wish I had studied harder.'' Nunca uses will directamente depois de wish."},"examples":[{"en":"I wish I had saved more money.","pt":"Eu queria ter poupado mais dinheiro."},{"en":"She wishes she could speak French.","pt":"Ela queria poder falar francês."},{"en":"I wish I hadn''t eaten so much!","pt":"Eu queria não ter comido tanto!"}],"practice":[{"q":"''I wish I ___ to the party.'' (past regret)","opts":["went","go","had gone","would go"],"ans":2,"exp":"Past regret = wish + Past Perfect: had gone."},{"q":"''I wish I ___ more time now.'' (present wish)","opts":["have","had","had had","will have"],"ans":1,"exp":"Present wish = wish + Past Simple: had."}]},"qs":[{"q":"\"I wish I ___ you yesterday.\" (regret)","opts":["see","saw","had seen","have seen"],"ans":2,"exp":"\"I wish I HAD SEEN you\" — wish + Past Perfect expresses regret about the past."},{"q":"\"I wish I ___ more time to travel.\" (present wish)","opts":["have","had","had had","would have"],"ans":1,"exp":"\"I wish I HAD more time\" — wish + Past Simple for present unreal wishes."},{"q":"\"She wishes she ___ to the party.\" (past)","opts":["went","goes","had gone","would go"],"ans":2,"exp":"\"She wishes she HAD GONE\" — regret about the past."},{"q":"\"I wish ___ studying earlier.\" (regret)","opts":["I start","I started","I had started","I would start"],"ans":2,"exp":"\"I wish I HAD STARTED\" — regret about a past action."},{"q":"Which expresses a present wish?","opts":["I wish I had been there.","I wish I were there now.","I wish I went there yesterday.","I wish I am there."],"ans":1,"exp":"\"I wish I WERE there now\" — present unreal wish (were for all subjects)."}]}'::jsonb, 2),
('l10d', 'u10', 'Inverted Conditionals', 'Condicionais Invertidos', '↕️', 25, '{"learn":{"explanation":{"en":"Inverted conditionals are formal: drop ''if'' and swap subject and auxiliary. ''If I had known'' becomes ''Had I known''. ''If I were you'' becomes ''Were I you''. ''If you should need help'' becomes ''Should you need help''.","pt":"Os condicionais invertidos são formais: elimina ''if'' e troca sujeito e auxiliar. ''If I had known'' torna-se ''Had I known''. ''If I were you'' torna-se ''Were I you''. ''If you should need help'' torna-se ''Should you need help''."},"examples":[{"en":"Had I known you were coming, I would have cooked.","pt":"Se eu soubesse que estavas a vir, teria cozinhado."},{"en":"Were I you, I would accept the offer.","pt":"Se eu fosse tu, aceitaria a oferta."},{"en":"Should you need help, please call me.","pt":"Se precisares de ajuda, liga-me."}],"practice":[{"q":"''Had I known'' is the inversion of:","opts":["If I know","If I had known","If I would know","If I knew"],"ans":1,"exp":"Had I known = If I had known."},{"q":"''Were I you'' is the inversion of:","opts":["If I was you","If I had been you","If I were you","If I am you"],"ans":2,"exp":"Were I you = If I were you."}]},"qs":[{"q":"\"Had I known, I ___ you.\" = \"If I had known, I would have told you.\"","opts":["would tell","would have told","will tell","tell"],"ans":1,"exp":"\"Had I known\" = \"If I had known\". Inversion in Third Conditional."},{"q":"\"Were I you, I ___ that job.\" = \"If I were you, I would accept that job.\"","opts":["would accept","would have accepted","accept","accepted"],"ans":0,"exp":"\"Were I you\" = \"If I were you\". Inversion in Second Conditional."},{"q":"\"Should you need help, ___ me.\" = \"If you should need help, contact me.\"","opts":["contact","would contact","will contact","contacts"],"ans":0,"exp":"\"Should you need help\" = \"If you should need help\". Inversion with should."},{"q":"\"___ she known, she would have come.\" = \"If she had known, she would have come.\"","opts":["Did","Has","Had","Would"],"ans":2,"exp":"\"Had she known\" — inversion removes \"if\" and moves \"had\" to the front."},{"q":"What is the inversion for \"If I were you\"?","opts":["Were I you","Was I you","If were I you","I were you"],"ans":0,"exp":"\"Were I you\" is the correct inversion."}]}'::jsonb, 3),
('l10e', 'u10', 'Conditionals with "Unless", "Even if"', 'Condicionais com "Unless" e "Even if"', '🚫', 20, '{"learn":{"explanation":{"en":"Unless means ''if not'': ''I won''t go unless you come'' = ''I won''t go if you don''t come.'' Even if means the result happens regardless of the condition: ''I''ll go even if it rains.'' As long as means on the condition that.","pt":"Unless significa ''se não'': ''I won''t go unless you come'' = ''I won''t go if you don''t come.'' Even if significa que o resultado acontece independentemente: ''I''ll go even if it rains.'' As long as significa desde que."},"examples":[{"en":"I won''t leave unless you come with me.","pt":"Eu não vou sair a menos que venhas comigo."},{"en":"She''ll pass even if she doesn''t study much.","pt":"Ela vai passar mesmo que não estude muito."},{"en":"You can stay as long as you are quiet.","pt":"Podes ficar desde que estejas sossegado."}],"practice":[{"q":"''Unless'' means:","opts":["if also","if not","even if","as long as"],"ans":1,"exp":"Unless = if not."},{"q":"''Even if it rains, I will go.'' This means:","opts":["I only go if it does not rain","The rain will not stop me","I might go","I will not go"],"ans":1,"exp":"Even if = regardless of the condition."}]},"qs":[{"q":"\"I won''t go ___ you invite me.\" = \"I won''t go if you don''t invite me.\"","opts":["if","unless","even if","as long as"],"ans":1,"exp":"\"Unless\" means \"if not\". \"I won''t go unless you invite me.\""},{"q":"\"She will come ___ she is tired.\" = \"She will come even if she is tired.\"","opts":["unless","even if","as long as","provided that"],"ans":1,"exp":"\"Even if\" expresses that the result will happen regardless of the condition."},{"q":"\"You can go ___ you finish your homework.\" = \"You can go if you finish your homework.\"","opts":["unless","even if","as long as","if not"],"ans":2,"exp":"\"As long as\" means \"on the condition that\"."},{"q":"\"I will help you ___ you need me.\" = \"I will help you if you need me.\"","opts":["unless","provided that","even if","although"],"ans":1,"exp":"\"Provided that\" means \"if\" or \"on the condition that\"."},{"q":"Which sentence uses \"unless\" correctly?","opts":["Unless you study, you will pass.","Unless you study, you won''t pass.","Unless you will study, you won''t pass.","Unless you studied, you won''t pass."],"ans":1,"exp":"\"Unless you study, you won''t pass.\" = If you don''t study, you won''t pass."}]}'::jsonb, 4),
('l10f', 'u10', 'Review: All Conditionals', 'Revisão: Todos os Condicionais', '🎯', 25, '{"learn":{"explanation":{"en":"Summary: Zero Conditional = If+Present, Present (universal truth). First = If+Present, will+verb (real future). Second = If+Past Simple, would+verb (unreal present). Third = If+Past Perfect, would have+PP (unreal past).","pt":"Resumo: Zero = If+Present, Present (verdade universal). First = If+Present, will+verb (futuro real). Second = If+Past Simple, would+verb (irreal presente). Third = If+Past Perfect, would have+PP (irreal passado)."},"examples":[{"en":"If water reaches 100C, it boils. (Zero)","pt":"Se a água atingir 100C, ferve. (Zero)"},{"en":"If it rains, I will stay home. (First)","pt":"Se chover, ficarei em casa. (First)"},{"en":"If I had wings, I would fly. (Second)","pt":"Se eu tivesse asas, voaria. (Second)"}],"practice":[{"q":"Which conditional is for REAL future possibilities?","opts":["Zero","First","Second","Third"],"ans":1,"exp":"First Conditional = real future."},{"q":"Which conditional expresses PAST regret?","opts":["Zero","First","Second","Third"],"ans":3,"exp":"Third Conditional = unreal past regret."}]},"qs":[{"q":"Zero Conditional: If + Present, ___","opts":["Will + Infinitive","Present","Would + Infinitive","Would have + PP"],"ans":1,"exp":"Zero Conditional = If + Present, Present (universal truths)."},{"q":"First Conditional: If + Present, ___","opts":["Will + Infinitive","Present","Would + Infinitive","Would have + PP"],"ans":0,"exp":"First Conditional = If + Present, Will + Infinitive (real future possibility)."},{"q":"Second Conditional: If + Past, ___","opts":["Will + Infinitive","Present","Would + Infinitive","Would have + PP"],"ans":2,"exp":"Second Conditional = If + Past, Would + Infinitive (unreal present)."},{"q":"Third Conditional: If + Past Perfect, ___","opts":["Will + Infinitive","Present","Would + Infinitive","Would have + PP"],"ans":3,"exp":"Third Conditional = If + Past Perfect, Would have + PP (unreal past)."},{"q":"\"If I ___ you, I would have gone.\" (mixed)","opts":["am","were","had been","would be"],"ans":1,"exp":"\"If I WERE you\" (present condition) → \"would have gone\" (past result). Mixed conditional."}]}'::jsonb, 5),
('l10g', 'u10', 'Conditionals in Real Life', 'Condicionais na Vida Real', '💡', 20, '{"learn":{"explanation":{"en":"Conditionals appear in everyday life. Zero for facts and advice. First for real future plans. Second for dreams and hypotheticals. Third for regrets. Inverted forms (Had I, Were I) for formal writing.","pt":"Os condicionais aparecem no dia-a-dia. Zero para factos e conselhos. First para planos futuros reais. Second para sonhos e hipotéticos. Third para arrependimentos. Formas invertidas (Had I, Were I) para escrita formal."},"examples":[{"en":"If you are tired, you should rest. (advice)","pt":"Se estás cansado, deves descansar. (conselho)"},{"en":"If I win the lottery, I''ll buy a house. (First - real)","pt":"Se eu ganhar na lotaria, comprarei uma casa. (First - real)"},{"en":"If I were president, I would change things. (Second - dream)","pt":"Se eu fosse presidente, mudaria as coisas. (Second - sonho)"}],"practice":[{"q":"''Should you need anything, call me.'' This is:","opts":["First Conditional","Second Conditional","Inverted Conditional","Zero Conditional"],"ans":2,"exp":"Should you need = formal inversion of First Conditional."},{"q":"''If I had left earlier, I wouldn''t be late.'' Which type?","opts":["First","Second","Mixed/Third","Zero"],"ans":2,"exp":"Past condition + present result = Mixed Conditional."}]},"qs":[{"q":"\"If it rains tomorrow, we ___ the picnic.\" (real future)","opts":["cancel","will cancel","would cancel","would have cancelled"],"ans":1,"exp":"First Conditional: real possibility about the future."},{"q":"\"If I ___ more money, I would travel.\" (unreal present)","opts":["have","had","had had","will have"],"ans":1,"exp":"Second Conditional: unreal present situation."},{"q":"\"If I had known, I ___ differently.\" (unreal past)","opts":["act","would act","would have acted","will act"],"ans":2,"exp":"Third Conditional: expressing regret or different past outcome."},{"q":"\"___ you need assistance, don''t hesitate to ask.\" (polite)","opts":["If","Unless","Should","Were"],"ans":2,"exp":"\"Should you need assistance\" = formal inversion of First Conditional."},{"q":"Which conditional expresses a general truth?","opts":["If it snows, the roads are dangerous.","If it snows, I will stay home.","If it snowed, I would stay home.","If it had snowed, I would have stayed home."],"ans":0,"exp":"Zero Conditional = general truth: \"If it snows, the roads are dangerous.\""}]}'::jsonb, 6),
('l10h', 'u10', 'Advanced Conditional Practice', 'Prática Avançada de Condicionais', '✍️', 25, '{"learn":{"explanation":{"en":"Advanced practice: choose the right conditional by reading the full context. Is it real or unreal? Past, present, or future? Formal or informal? Keywords like ''had'', ''were'', ''should'' signal formal inversions.","pt":"Prática avançada: escolhe o condicional correcto lendo o contexto completo. É real ou irreal? Passado, presente ou futuro? Formal ou informal? Palavras-chave como ''had'', ''were'', ''should'' sinalizam inversões formais."},"examples":[{"en":"Had she arrived earlier, she would have gotten a seat.","pt":"Se ela tivesse chegado mais cedo, teria conseguido lugar."},{"en":"Unless you apologise, I won''t forgive you.","pt":"A menos que peças desculpa, não te perdoarei."},{"en":"Were it not for your help, I would have failed.","pt":"Se não fosse a tua ajuda, eu teria falhado."}],"practice":[{"q":"''Had we known the truth, we ___ differently.''","opts":["would act","will act","would have acted","had acted"],"ans":2,"exp":"Third Conditional inversion: would have acted."},{"q":"''___ I you, I would think twice before accepting.''","opts":["If","Had","Were","Should"],"ans":2,"exp":"Were I you = If I were you."}]},"qs":[{"q":"\"Had I known you were coming, I ___ dinner.\"","opts":["would prepare","would have prepared","will prepare","prepared"],"ans":1,"exp":"\"Had I known\" (Third Conditional) → \"would have prepared\"."},{"q":"\"Were she here, she ___ help us.\"","opts":["would have","would have had","would","will"],"ans":2,"exp":"\"Were she here\" (Second Conditional inversion) → \"would help\"."},{"q":"\"If I ___ you, I wouldn''t have done that.\"","opts":["were","had been","am","would be"],"ans":0,"exp":"Mixed conditional: present condition \"If I were you\" + past result \"wouldn''t have done\"."},{"q":"\"You won''t pass the exam ___ you study.\"","opts":["unless","if","as long as","provided that"],"ans":0,"exp":"\"Unless you study\" = if you don''t study."},{"q":"\"___ I were you, I would accept the offer.\"","opts":["If","Unless","Were","Had"],"ans":2,"exp":"\"Were I you\" = inversion of \"If I were you\"."}]}'::jsonb, 7),
('l11a', 'u11', 'Introduction to Reported Speech', 'Introdução ao Discurso Indireto', '📢', 20, '{"learn":{"explanation":{"en":"Reported speech tells what someone said without using their exact words. The main rule: move the tense one step back into the past. ''I am happy'' becomes She said she WAS happy.","pt":"O discurso indirecto diz o que alguém disse sem usar as suas palavras exactas. A regra principal: recua o tempo um passo para o passado. ''I am happy'' torna-se She said she WAS happy."},"examples":[{"en":"Direct: I love English. Reported: She said she loved English.","pt":"Directo: I love English. Indirecto: Ela disse que adorava inglês."},{"en":"Direct: I am tired. Reported: He said he was tired.","pt":"Directo: I am tired. Indirecto: Ele disse que estava cansado."},{"en":"Direct: I will call. Reported: She said she would call.","pt":"Directo: I will call. Indirecto: Ela disse que ligaria."}],"practice":[{"q":"In reported speech, Present Simple becomes:","opts":["Present Simple","Past Simple","Past Perfect","Future"],"ans":1,"exp":"Present Simple becomes Past Simple."},{"q":"''I am hungry.'' She said she ___ hungry.","opts":["am","is","was","has been"],"ans":2,"exp":"am becomes was in reported speech."}]},"qs":[{"q":"What is reported speech?","opts":["Direct quotes","Telling what someone said without quoting exactly","Future predictions","Past actions"],"ans":1,"exp":"Reported speech is when you report what someone said without using their exact words."},{"q":"\"I am happy.\" → She said she ___ happy.","opts":["am","is","was","were"],"ans":2,"exp":"\"She said she WAS happy\" — Present becomes Past in reported speech."},{"q":"What happens to the tense in reported speech?","opts":["Present becomes Past","Past becomes Present","No change","Future becomes Past"],"ans":0,"exp":"Present Simple → Past Simple, Present Continuous → Past Continuous, etc."},{"q":"\"I study English.\" → He said he ___ English.","opts":["studies","studied","study","is studying"],"ans":1,"exp":"\"He said he STUDIED English\" — Present Simple → Past Simple."},{"q":"Which is an example of reported speech?","opts":["She said, \"I am tired.\"","She said she was tired.","She said, \"I tired.\"","She said she is tired."],"ans":1,"exp":"\"She said she was tired\" = reported speech without quotes."}]}'::jsonb, 0),
('l11b', 'u11', 'Tense Changes in Reported Speech', 'Mudanças de Tempo no Discurso Indireto', '🔄', 25, '{"learn":{"explanation":{"en":"Each tense moves one step back: Present Simple to Past Simple. Present Continuous to Past Continuous. Present Perfect to Past Perfect. Past Simple to Past Perfect. Will to Would. Can to Could. Must to Had to.","pt":"Cada tempo recua um passo: Present Simple para Past Simple. Present Continuous para Past Continuous. Present Perfect para Past Perfect. Past Simple para Past Perfect. Will para Would. Can para Could. Must para Had to."},"examples":[{"en":"''I am eating.'' He said he was eating.","pt":"''I am eating.'' Ele disse que estava a comer."},{"en":"''I have finished.'' She said she had finished.","pt":"''I have finished.'' Ela disse que tinha terminado."},{"en":"''I can help.'' He said he could help.","pt":"''I can help.'' Ele disse que podia ajudar."}],"practice":[{"q":"''I will come.'' She said she ___ come.","opts":["will","would","can","could"],"ans":1,"exp":"Will becomes Would in reported speech."},{"q":"''I have been waiting.'' He said he ___ been waiting.","opts":["has","had","was","have"],"ans":1,"exp":"Present Perfect becomes Past Perfect: had been waiting."}]},"qs":[{"q":"Present Simple → ___ in reported speech","opts":["Present Perfect","Past Simple","Past Perfect","Future"],"ans":1,"exp":"Present Simple becomes Past Simple: \"I eat\" → \"He said he ate.\""},{"q":"Present Continuous → ___ in reported speech","opts":["Past Continuous","Past Simple","Past Perfect Continuous","Present"],"ans":0,"exp":"Present Continuous → Past Continuous: \"I am eating\" → \"He said he was eating.\""},{"q":"Present Perfect → ___ in reported speech","opts":["Past Perfect","Present Perfect","Past Simple","Past Continuous"],"ans":0,"exp":"Present Perfect → Past Perfect: \"I have eaten\" → \"He said he had eaten.\""},{"q":"\"I will call you.\" → He said he ___ me.","opts":["will call","called","would call","has called"],"ans":2,"exp":"Future \"will\" → \"would\" in reported speech."},{"q":"\"I have been waiting.\" → She said she ___ been waiting.","opts":["has","had","have","was"],"ans":1,"exp":"Present Perfect Continuous → Past Perfect Continuous: \"I have been waiting\" → \"had been waiting\"."}]}'::jsonb, 1),
('l11c', 'u11', 'Reporting Questions', 'Reportando Perguntas', '❓', 20, '{"learn":{"explanation":{"en":"Reported questions use statement word order (no inversion, no question mark). Yes/No questions use ''if'' or ''whether''. Wh- questions keep the question word: ''Where do you live?'' becomes He asked where I lived.","pt":"As perguntas reportadas usam a ordem de afirmação (sem inversão, sem ponto de interrogação). Perguntas Sim/Não usam ''if'' ou ''whether''. Perguntas Wh- mantêm a palavra interrogativa: ''Where do you live?'' torna-se He asked where I lived."},"examples":[{"en":"''Are you coming?'' She asked if I was coming.","pt":"''Are you coming?'' Ela perguntou se eu estava a vir."},{"en":"''Where do you live?'' He asked me where I lived.","pt":"''Where do you live?'' Ele perguntou-me onde eu vivia."},{"en":"''Did you see it?'' She asked whether I had seen it.","pt":"''Did you see it?'' Ela perguntou se eu o tinha visto."}],"practice":[{"q":"Yes/No reported questions use:","opts":["that","which","if or whether","what"],"ans":2,"exp":"Use if or whether for Yes/No reported questions."},{"q":"''What time is it?'' He asked me what time ___.","opts":["is it","it is","it was","was it"],"ans":2,"exp":"Statement order + tense backshift: it was."}]},"qs":[{"q":"\"Where do you live?\" → He asked me ___","opts":["where do I live","where I live","where I lived","where did I live"],"ans":2,"exp":"Reported question: \"where I lived\" — no question word order and tense backshift."},{"q":"\"Are you coming?\" → She asked ___","opts":["if I am coming","if I was coming","if was I coming","if I came"],"ans":1,"exp":"Yes/No question becomes \"if/whether\" + statement word order: \"if I was coming\"."},{"q":"\"What time is it?\" → He asked me ___","opts":["what time is it","what time it was","what time it is","what time was it"],"ans":1,"exp":"Reported question: \"what time it was\" — subject + verb order."},{"q":"\"Did you go?\" → She asked me ___ I went.","opts":["did","that","if","whether"],"ans":2,"exp":"\"if\" is used to report yes/no questions: \"She asked me IF I went.\""},{"q":"Which is correct?","opts":["He asked me where I am going.","He asked me where I was going.","He asked me where was I going.","He asked me where I go."],"ans":1,"exp":"\"where I was going\" — correct reported question."}]}'::jsonb, 2),
('l11d', 'u11', 'Reporting Commands and Requests', 'Reportando Ordens e Pedidos', '📋', 20, '{"learn":{"explanation":{"en":"Commands in reported speech use TELL + object + TO + infinitive. Requests use ASK + object + TO + infinitive. Negatives use NOT TO + infinitive. No tense backshift is needed for commands and requests.","pt":"Ordens no discurso indirecto usam TELL + objecto + TO + infinitivo. Pedidos usam ASK + objecto + TO + infinitivo. Negativos usam NOT TO + infinitivo. Não é necessária mudança de tempo para ordens e pedidos."},"examples":[{"en":"''Sit down!'' He told me to sit down.","pt":"''Sit down!'' Ele disse-me para me sentar."},{"en":"''Please help me.'' She asked me to help her.","pt":"''Please help me.'' Ela pediu-me para a ajudar."},{"en":"''Don''t be late!'' He warned me not to be late.","pt":"''Don''t be late!'' Ele avisou-me para não me atrasar."}],"practice":[{"q":"''Open the window!'' She told me ___ the window.","opts":["open","to open","opening","opened"],"ans":1,"exp":"Tell + object + TO + infinitive."},{"q":"''Don''t touch that!'' He warned me ___ that.","opts":["to touch","not to touch","touching","not touching"],"ans":1,"exp":"Negative command: not to touch."}]},"qs":[{"q":"\"Sit down!\" → He told me ___","opts":["to sit down","sit down","that I sit down","that I sat down"],"ans":0,"exp":"Commands use \"tell + object + to + infinitive\": \"He told me to sit down.\""},{"q":"\"Please help me.\" → She asked me ___ her.","opts":["to help","help","that I help","if I help"],"ans":0,"exp":"Requests use \"ask + to + infinitive\": \"She asked me to help her.\""},{"q":"\"Don''t be late!\" → He warned me ___","opts":["to be late","not to be late","don''t be late","that I am not late"],"ans":1,"exp":"Negative commands become \"not to\": \"not to be late\"."},{"q":"\"Could you wait?\" → She asked us ___","opts":["wait","to wait","if we wait","that we wait"],"ans":1,"exp":"\"She asked us to wait\" — reporting a polite request."},{"q":"Which reports a command correctly?","opts":["He told me to close the door.","He told me close the door.","He told me that close the door.","He told me to closed the door."],"ans":0,"exp":"\"He told me to close the door\" — tell + object + to + infinitive."}]}'::jsonb, 3),
('l11e', 'u11', 'Reporting Verbs', 'Verbos de Reporte', '📝', 20, '{"learn":{"explanation":{"en":"Use specific reporting verbs instead of always ''said'': PROMISE for commitments, APOLOGISE for sorry, ADVISE for suggestions, WARN for danger, OFFER for voluntary help, EXPLAIN for reasons. They make reported speech more precise.","pt":"Usa verbos de reporte específicos em vez de sempre ''said'': PROMISE para compromissos, APOLOGISE para desculpas, ADVISE para sugestões, WARN para perigo, OFFER para ajuda voluntária, EXPLAIN para razões. Tornam o discurso indirecto mais preciso."},"examples":[{"en":"''I am sorry I am late.'' She apologised for being late.","pt":"''I am sorry I am late.'' Ela pediu desculpa por ter chegado atrasada."},{"en":"''I will definitely be there.'' He promised to be there.","pt":"''I will definitely be there.'' Ele prometeu estar lá."},{"en":"''You should rest.'' The doctor advised me to rest.","pt":"''You should rest.'' O médico aconselhou-me a descansar."}],"practice":[{"q":"''I can help you.'' He ___ to help me.","opts":["said","promised","offered","apologised"],"ans":2,"exp":"Offered = voluntary help."},{"q":"''Be careful!'' She ___ me to be careful.","opts":["asked","told","warned","advised"],"ans":2,"exp":"Warned = about danger."}]},"qs":[{"q":"\"I''m sorry I''m late.\" → She ___ for being late.","opts":["apologised","said","told","explained"],"ans":0,"exp":"\"apologised\" is a reporting verb that shows the meaning of the original statement."},{"q":"\"I can help you.\" → He ___ to help me.","opts":["offered","said","told","apologised"],"ans":0,"exp":"\"offered\" = reporting verb for a voluntary action."},{"q":"\"I''ll definitely be there.\" → She ___ to be there.","opts":["said","told","promised","explained"],"ans":2,"exp":"\"promised\" — reporting a commitment."},{"q":"\"The train is delayed.\" → The announcement ___ that the train was delayed.","opts":["said","told","offered","promised"],"ans":0,"exp":"\"said\" — neutral reporting verb for information."},{"q":"Which reporting verb is used for advice?","opts":["said","told","advised","asked"],"ans":2,"exp":"\"advised\" — \"He advised me to study harder.\""}]}'::jsonb, 4),
('l11f', 'u11', 'Review: Reported Speech', 'Revisão: Discurso Indireto', '🎯', 25, '{"learn":{"explanation":{"en":"Review: tenses shift one step back. Yes/No questions use if or whether. Wh- questions keep the question word with statement order. Commands use tell or ask + to + infinitive. Specific verbs like warn, promise, advise add meaning.","pt":"Revisão: os tempos recuam um passo. Perguntas Sim/Não usam if ou whether. Perguntas Wh- mantêm a palavra interrogativa com ordem de afirmação. Ordens usam tell ou ask + to + infinitivo. Verbos específicos como warn, promise, advise adicionam significado."},"examples":[{"en":"''I have finished.'' She said she had finished.","pt":"''I have finished.'' Ela disse que tinha terminado."},{"en":"''Where are you going?'' He asked where I was going.","pt":"''Where are you going?'' Ele perguntou para onde eu ia."},{"en":"''Please don''t leave.'' She asked me not to leave.","pt":"''Please don''t leave.'' Ela pediu-me para não sair."}],"practice":[{"q":"''I went to the shop.'' He said he ___ to the shop.","opts":["went","goes","had gone","has gone"],"ans":2,"exp":"Past Simple becomes Past Perfect: had gone."},{"q":"''Will you help me?'' She asked if I ___ help her.","opts":["will","would","can","could"],"ans":1,"exp":"Will becomes Would in reported questions."}]},"qs":[{"q":"\"I am tired.\" → She said she ___ tired.","opts":["is","was","has been","had been"],"ans":1,"exp":"Present Simple → Past Simple: \"She said she was tired.\""},{"q":"\"I went to the store.\" → He said he ___ to the store.","opts":["goes","went","had gone","was going"],"ans":2,"exp":"Past Simple → Past Perfect: \"He said he had gone.\""},{"q":"\"Where is the station?\" → He asked me where the station ___","opts":["is","was","has been","had been"],"ans":1,"exp":"\"where the station was\" — reported question with tense backshift."},{"q":"\"Don''t touch that!\" → She warned me ___ that.","opts":["to touch","not to touch","don''t touch","that I don''t touch"],"ans":1,"exp":"\"not to touch\" — negative command in reported speech."},{"q":"\"I''ll help you tomorrow.\" → He promised ___ me the next day.","opts":["he helps","to help","he helped","that he help"],"ans":1,"exp":"\"He promised TO HELP me\" — reporting a promise with infinitive."}]}'::jsonb, 5),
('l12a', 'u12', 'Defining Relative Clauses', 'Orações Relativas Definidoras', '🔍', 20, '{"learn":{"explanation":{"en":"Defining relative clauses identify WHICH person or thing we mean. Without them, the sentence is incomplete. We use: WHO for people, WHICH for things, THAT for people or things (informal), WHERE for places.","pt":"As orações relativas definidoras identificam QUAL pessoa ou coisa pretendemos dizer. Sem elas, a frase fica incompleta. Usamos: WHO para pessoas, WHICH para coisas, THAT para pessoas ou coisas (informal), WHERE para lugares."},"examples":[{"en":"The man who called is my uncle.","pt":"O homem que ligou é o meu tio."},{"en":"The book that I read was amazing.","pt":"O livro que li foi incrível."},{"en":"The city where I grew up is small.","pt":"A cidade onde cresci é pequena."}],"practice":[{"q":"Which pronoun is used for PEOPLE?","opts":["which","where","who","whose"],"ans":2,"exp":"WHO for people."},{"q":"\"The car ___ I bought is red.\"","opts":["who","which","where","whose"],"ans":1,"exp":"WHICH for things."}]},"qs":[{"q":"\"The man ___ lives next door is a doctor.\" (subject)","opts":["who","whom","which","whose"],"ans":0,"exp":"\"who\" — relative pronoun for people in subject position."},{"q":"\"This is the book ___ I bought yesterday.\" (object)","opts":["who","whom","which","whose"],"ans":2,"exp":"\"which\" — relative pronoun for things in object position."},{"q":"\"The woman ___ car was stolen called the police.\"","opts":["who","whom","which","whose"],"ans":3,"exp":"\"whose\" — relative pronoun showing possession for people."},{"q":"\"The house ___ is red belongs to my uncle.\"","opts":["who","whom","which","whose"],"ans":2,"exp":"\"which\" — relative pronoun for things in subject position."},{"q":"Which relative pronoun is used for people?","opts":["which","who","that","both who and that"],"ans":3,"exp":"\"who\" and \"that\" can both be used for people."}]}'::jsonb, 0),
('l12b', 'u12', 'Non-Defining Relative Clauses', 'Orações Relativas Não-Definidoras', '📝', 20, '{"learn":{"explanation":{"en":"Non-defining clauses add EXTRA information — remove them and the sentence still makes complete sense. They always use commas and CANNOT use \"that\". Example: \"My brother, WHO lives in London, is a doctor.\"","pt":"As orações não-definidoras adicionam informação EXTRA — se as removermos, a frase ainda faz sentido completo. Usam sempre vírgulas e NÃO podem usar \"that\". Exemplo: \"My brother, WHO lives in London, is a doctor.\""},"examples":[{"en":"My mother, who is a nurse, works nights.","pt":"A minha mãe, que é enfermeira, trabalha de noite."},{"en":"Paris, which I visited last year, is beautiful.","pt":"Paris, que visitei no ano passado, é bonita."},{"en":"The Eiffel Tower, which was built in 1889, is iconic.","pt":"A Torre Eiffel, que foi construída em 1889, é icónica."}],"practice":[{"q":"Non-defining clauses are separated by:","opts":["full stops","commas","dashes","semicolons"],"ans":1,"exp":"Commas before and after the non-defining clause."},{"q":"Can \"that\" be used in a non-defining clause?","opts":["Yes, always","Yes, sometimes","No, never","Only in questions"],"ans":2,"exp":"No — non-defining clauses cannot use \"that\"."}]},"qs":[{"q":"\"My brother, ___ lives in London, is a chef.\" (extra info)","opts":["who","whom","which","whose"],"ans":0,"exp":"\"who\" — non-defining clause with commas, gives extra information about the subject."},{"q":"\"Paris, ___ is the capital of France, is beautiful.\"","opts":["who","whom","which","whose"],"ans":2,"exp":"\"which\" — non-defining clause for things."},{"q":"\"My car, ___ is blue, is very fast.\"","opts":["who","whom","which","whose"],"ans":2,"exp":"\"which\" — non-defining clause with commas."},{"q":"What punctuation is used with non-defining relative clauses?","opts":["No punctuation","Commas","Semicolons","Colons"],"ans":1,"exp":"Non-defining clauses are separated by commas."},{"q":"Which is a non-defining relative clause?","opts":["The man who lives here is my uncle.","My uncle, who lives here, is a doctor.","The woman that I saw was happy.","The house which I bought is big."],"ans":1,"exp":"\"My uncle, who lives here, is a doctor\" — extra information with commas."}]}'::jsonb, 1),
('l12c', 'u12', 'Relative Pronouns: Who, Whom, Whose', 'Pronomes Relativos: Who, Whom, Whose', '📖', 20, '{"learn":{"explanation":{"en":"WHO is subject form for people: \"The man WHO called.\" WHOM is object form (formal): \"The man WHOM I met.\" WHOSE shows possession: \"The student WHOSE phone was stolen.\" WHICH is for things.","pt":"WHO é a forma de sujeito para pessoas: \"The man WHO called.\" WHOM é a forma de objecto (formal): \"The man WHOM I met.\" WHOSE mostra posse: \"The student WHOSE phone was stolen.\" WHICH é para coisas."},"examples":[{"en":"The woman who called is my aunt.","pt":"A mulher que ligou é a minha tia."},{"en":"The student whose phone was stolen was upset.","pt":"O estudante cujo telemóvel foi roubado ficou chateado."},{"en":"To whom should I address the letter?","pt":"A quem devo dirigir a carta?"}],"practice":[{"q":"\"The man ___ car is broken is my boss.\" (possession)","opts":["who","whom","whose","which"],"ans":2,"exp":"WHOSE = possession."},{"q":"WHOM is used as:","opts":["subject form","object form (formal)","possessive","for things"],"ans":1,"exp":"WHOM = formal object pronoun for people."}]},"qs":[{"q":"\"The woman ___ you met is my sister.\" (object)","opts":["who","whom","whose","which"],"ans":0,"exp":"\"who\" can be used as an object pronoun, though \"whom\" is more formal."},{"q":"\"To ___ should I address the letter?\" (object of preposition)","opts":["who","whom","whose","which"],"ans":1,"exp":"\"whom\" — formal object pronoun used after prepositions."},{"q":"\"The student ___ phone was stolen reported it.\" (possession)","opts":["who","whom","whose","which"],"ans":2,"exp":"\"whose\" — relative pronoun showing possession."},{"q":"\"The company ___ you work for is expanding.\" (object)","opts":["who","whom","whose","which"],"ans":3,"exp":"\"which\" — relative pronoun for things as objects."},{"q":"When do we use \"whom\"?","opts":["As a subject","As an object (formal)","To show possession","For things"],"ans":1,"exp":"\"whom\" is the formal object form for people."}]}'::jsonb, 2),
('l12d', 'u12', 'Omitting the Relative Pronoun', 'Omitindo o Pronome Relativo', '✂️', 20, '{"learn":{"explanation":{"en":"We can omit (drop) the relative pronoun only when it is the OBJECT of the clause, not the subject. \"The book (that) I read was great.\" — \"that\" is the object, so we can drop it. \"The man WHO called\" — WHO is the subject, cannot be dropped.","pt":"Podemos omitir o pronome relativo apenas quando é o OBJECTO da oração, não o sujeito. \"The book (that) I read was great.\" — \"that\" é o objecto, podemos omiti-lo. \"The man WHO called\" — WHO é o sujeito, não pode ser omitido."},"examples":[{"en":"The film (that) I watched was boring.","pt":"O filme (que) vi era aborrecido."},{"en":"The man who lives next door is a doctor. (cannot omit)","pt":"O homem que vive ao lado é médico. (não se pode omitir)"},{"en":"This is the book (which) I told you about.","pt":"Este é o livro (do qual) te falei."}],"practice":[{"q":"When can you omit the relative pronoun?","opts":["Always","Never","When it is the object","When it is the subject"],"ans":2,"exp":"Only when it is the OBJECT."},{"q":"In \"The girl who won\", can you omit \"who\"?","opts":["Yes","No","Sometimes","Only in writing"],"ans":1,"exp":"No — \"who\" is the subject here."}]},"qs":[{"q":"\"The film ___ I watched was boring.\" (object, can omit)","opts":["which","that","who","whom"],"ans":0,"exp":"The relative pronoun can be omitted when it is the object of the clause: \"The film I watched...\""},{"q":"\"The man ___ lives next door is a doctor.\" (subject, cannot omit)","opts":["who","whom","which","that"],"ans":0,"exp":"The relative pronoun cannot be omitted when it is the subject of the clause."},{"q":"\"This is the book ___ I told you about.\" (object, can omit)","opts":["which","that","who","whom"],"ans":0,"exp":"The object pronoun can be omitted: \"This is the book I told you about.\""},{"q":"Which relative pronoun can be omitted?","opts":["Subject pronoun","Object pronoun","Possessive pronoun","All pronouns"],"ans":1,"exp":"Only object relative pronouns can be omitted."},{"q":"Which sentence has an omitted relative pronoun?","opts":["The man who called you is here.","The book you gave me is great.","The woman whose car was stolen is upset.","The house which I bought is old."],"ans":1,"exp":"\"The book (that) you gave me\" — \"that\" is omitted."}]}'::jsonb, 3),
('l12e', 'u12', 'Reduced Relative Clauses', 'Orações Relativas Reduzidas', '📉', 25, '{"learn":{"explanation":{"en":"Reduced relative clauses drop the pronoun and auxiliary verb, leaving just the verb. Active = verb-ing: \"The man STANDING by the door\" (= who is standing). Passive = past participle: \"The house BUILT in 1990\" (= which was built).","pt":"As orações relativas reduzidas eliminam o pronome e o auxiliar, deixando apenas o verbo. Activa = verbo-ing: \"The man STANDING by the door\" (= who is standing). Passiva = particípio passado: \"The house BUILT in 1990\" (= which was built)."},"examples":[{"en":"The man standing at the door is my uncle.","pt":"O homem que está à porta é o meu tio."},{"en":"The book lying on the table is mine.","pt":"O livro que está na mesa é meu."},{"en":"The house built in 1990 is beautiful.","pt":"A casa construída em 1990 é bonita."}],"practice":[{"q":"Active reduced clause uses:","opts":["past participle","verb-ing","to + verb","base verb"],"ans":1,"exp":"Active reduced = verb-ing: the girl singing."},{"q":"Passive reduced clause uses:","opts":["verb-ing","to + verb","past participle","will + verb"],"ans":2,"exp":"Passive reduced = past participle: the house built."}]},"qs":[{"q":"\"The man ___ at the door is my uncle.\" (reduced from \"who is standing\")","opts":["standing","stands","stand","to stand"],"ans":0,"exp":"Reduced relative clause: \"The man standing at the door...\" = \"who is standing\"."},{"q":"\"The book ___ on the table is mine.\" (reduced from \"which is lying\")","opts":["lying","lies","lay","to lie"],"ans":0,"exp":"\"The book lying on the table\" = \"which is lying\"."},{"q":"\"The house ___ in 1990 is beautiful.\" (passive, reduced from \"which was built\")","opts":["built","building","to build","builds"],"ans":0,"exp":"\"The house built in 1990\" = \"which was built\"."},{"q":"How do you reduce a relative clause?","opts":["Remove the pronoun and change the verb to -ing or PP","Add more words","Keep the pronoun","Change to future tense"],"ans":0,"exp":"Reduce by dropping the relative pronoun and changing the verb to -ing (active) or past participle (passive)."},{"q":"Which is a reduced relative clause?","opts":["The girl who sings well.","The girl singing well.","The girl sings well.","The girl, singing well, left."],"ans":1,"exp":"\"The girl singing well\" is reduced from \"who sings well\"."}]}'::jsonb, 4),
('l12f', 'u12', 'Review: Relative Clauses', 'Revisão: Orações Relativas', '🎯', 25, '{"learn":{"explanation":{"en":"Defining clauses = essential, no commas, \"that\" OK. Non-defining = extra info, commas, no \"that\". WHO = people. WHICH = things. WHOSE = possession. WHERE = places. WHEN = times. Pronoun can be omitted if object.","pt":"Definidoras = essenciais, sem vírgulas, \"that\" permitido. Não-definidoras = informação extra, vírgulas, sem \"that\". WHO = pessoas. WHICH = coisas. WHOSE = posse. WHERE = lugares. WHEN = momentos. Pronome pode ser omitido se for objecto."},"examples":[{"en":"That''s the school where I studied.","pt":"Essa é a escola onde estudei."},{"en":"My car, which is red, needs a service.","pt":"O meu carro, que é vermelho, precisa de revisão."},{"en":"The woman whose dog barked all night is my neighbour.","pt":"A mulher cujo cão ladrou a noite toda é minha vizinha."}],"practice":[{"q":"Commas are used in ___ relative clauses.","opts":["defining","non-defining","both","neither"],"ans":1,"exp":"Non-defining clauses use commas."},{"q":"\"The film ___ won the Oscar is brilliant.\"","opts":["who","whose","which","where"],"ans":2,"exp":"WHICH for things."}]},"qs":[{"q":"\"The woman ___ we met is famous.\" (object, can omit)","opts":["who","whom","which","whose"],"ans":0,"exp":"\"who\" as object — can be omitted in informal English."},{"q":"\"This is the house ___ has a red door.\" (subject)","opts":["who","whom","which","whose"],"ans":2,"exp":"\"which\" — relative pronoun for things as subject."},{"q":"\"My teacher, ___ is from England, speaks very clearly.\" (non-defining)","opts":["who","whom","which","whose"],"ans":0,"exp":"\"who\" — non-defining clause with commas for people."},{"q":"\"The car ___ I bought is red.\" (object, can omit)","opts":["which","that","who","whom"],"ans":0,"exp":"\"which\" as object — can be omitted in informal speech."},{"q":"Which sentence has a reduced relative clause?","opts":["The woman who lives here is kind.","The woman living here is kind.","The woman, who lives here, is kind.","The woman that lives here is kind."],"ans":1,"exp":"\"The woman living here\" is reduced from \"who lives here\"."}]}'::jsonb, 5),
('l12g', 'u12', 'Relative Clauses Practice', 'Prática de Orações Relativas', '✍️', 25, '{"learn":{"explanation":{"en":"Relative adverbs add location, time, and reason nuance: WHERE for places, WHEN for times, WHY for reasons. \"The city WHERE I was born.\" \"The year WHEN I graduated.\" \"The reason WHY I called.\"","pt":"Os advérbios relativos adicionam nuances de localização, tempo e razão: WHERE para lugares, WHEN para momentos, WHY para razões. \"The city WHERE I was born.\" \"The year WHEN I graduated.\" \"The reason WHY I called.\""},"examples":[{"en":"That is the town where I grew up.","pt":"Essa é a cidade onde cresci."},{"en":"I remember the year when we met.","pt":"Lembro-me do ano em que nos conhecemos."},{"en":"Tell me the reason why you were late.","pt":"Diz-me a razão pela qual chegaste atrasado."}],"practice":[{"q":"\"The city ___ I was born is in the north.\" (place)","opts":["when","which","where","whose"],"ans":2,"exp":"WHERE for places."},{"q":"\"The reason ___ she left is unknown.\" (reason)","opts":["where","when","why","whose"],"ans":2,"exp":"WHY for reasons."}]},"qs":[{"q":"\"The restaurant ___ we ate is expensive.\" (object, can omit)","opts":["where","which","who","whose"],"ans":1,"exp":"\"which\" — object relative pronoun for things."},{"q":"\"This is the city ___ I was born.\" (place)","opts":["where","which","who","whose"],"ans":0,"exp":"\"where\" — relative adverb for places."},{"q":"\"The reason ___ I called is urgent.\" (reason)","opts":["where","which","why","whose"],"ans":2,"exp":"\"why\" — relative adverb for reasons."},{"q":"\"That was the day ___ we met.\" (time)","opts":["where","which","why","when"],"ans":3,"exp":"\"when\" — relative adverb for time."},{"q":"Which is correct?","opts":["The house where I bought is big.","The house which I bought is big.","The house who I bought is big.","The house when I bought is big."],"ans":1,"exp":"\"which\" is the correct relative pronoun for things."}]}'::jsonb, 6),
('l13a', 'u13', 'Gerund: Verb + -ing', 'Gerúndio: Verbo + -ing', '🔵', 20, '{"learn":{"explanation":{"en":"A gerund is a verb used as a noun by adding -ing: Swimming is fun. Gerunds can be the subject, the object of a verb, or the object of a preposition.","pt":"Um gerúndio é um verbo usado como substantivo ao adicionar -ing: Swimming is fun. Os gerúndios podem ser o sujeito, o objecto de um verbo ou o objecto de uma preposição."},"examples":[{"en":"Swimming every day keeps you healthy.","pt":"Nadar todos os dias mantém-te saudável."},{"en":"I love cooking Italian food.","pt":"Eu adoro cozinhar comida italiana."},{"en":"She is good at playing the guitar.","pt":"Ela é boa a tocar guitarra."}],"practice":[{"q":"''___ is my favourite hobby.'' (gerund as subject)","opts":["Swim","To swim","Swimming","Swims"],"ans":2,"exp":"Gerund as subject: Swimming."},{"q":"Which verb takes a gerund?","opts":["want","decide","enjoy","agree"],"ans":2,"exp":"enjoy + gerund: enjoy doing."}]},"qs":[{"q":"Gerund = verb + ___","opts":["-ed","-ing","-s","-en"],"ans":1,"exp":"Gerund: verb + -ing, used as a noun."},{"q":"\"___ is a great hobby.\" (gerund as subject)","opts":["Read","Reading","To read","Reads"],"ans":1,"exp":"\"Reading\" is a gerund acting as the subject of the sentence."},{"q":"\"I enjoy ___ movies.\" (gerund after verb)","opts":["watch","watching","to watch","watched"],"ans":1,"exp":"\"enjoy\" takes a gerund: \"enjoy watching\"."},{"q":"\"She is good at ___.\" (gerund after preposition)","opts":["sing","singing","to sing","sings"],"ans":1,"exp":"After prepositions (at, for, about) we use the gerund: \"at singing\"."},{"q":"Which is a gerund?","opts":["to run","running","ran","runs"],"ans":1,"exp":"\"running\" is the gerund form of the verb \"run\"."}]}'::jsonb, 0),
('l13b', 'u13', 'Infinitive: To + Verb', 'Infinitivo: To + Verbo', '🟢', 20, '{"learn":{"explanation":{"en":"The infinitive (to + base verb) is used after many verbs (want to, need to, decide to), after adjectives (happy to, easy to), and to express purpose (''I went to the shop to buy milk'').","pt":"O infinitivo (to + verbo base) é usado depois de muitos verbos (want to, need to, decide to), depois de adjectivos (happy to, easy to), e para expressar propósito (''I went to the shop to buy milk'')."},"examples":[{"en":"I want to learn English well.","pt":"Eu quero aprender inglês bem."},{"en":"She was happy to help me.","pt":"Ela ficou feliz em me ajudar."},{"en":"He went to the gym to exercise.","pt":"Ele foi ao ginásio para fazer exercício."}],"practice":[{"q":"''I decided ___ the job.'' (infinitive after verb)","opts":["accept","accepting","to accept","accepted"],"ans":2,"exp":"decide + to + infinitive."},{"q":"''She is easy ___ with.'' (infinitive after adjective)","opts":["work","working","to work","worked"],"ans":2,"exp":"adjective + to + infinitive: easy to work with."}]},"qs":[{"q":"Infinitive = ___ + verb","opts":["to","for","with","by"],"ans":0,"exp":"Infinitive: to + base verb, e.g., \"to study\"."},{"q":"\"I want ___ English.\" (infinitive after verb)","opts":["study","studying","to study","studied"],"ans":2,"exp":"\"want\" takes the infinitive: \"want to study\"."},{"q":"\"I went to the store ___ milk.\" (infinitive of purpose)","opts":["buy","buying","to buy","bought"],"ans":2,"exp":"Infinitive of purpose: \"to buy\" explains why I went to the store."},{"q":"\"She is happy ___ you.\" (infinitive after adjective)","opts":["see","seeing","to see","saw"],"ans":2,"exp":"\"happy to see\" — infinitive after adjectives describing emotions."},{"q":"Which is an infinitive?","opts":["running","to run","runs","ran"],"ans":1,"exp":"\"to run\" is the infinitive form."}]}'::jsonb, 1),
('l13c', 'u13', 'Verbs + Gerund vs Infinitive (Part 1)', 'Verbos + Gerúndio vs Infinitivo (Parte 1)', '⚖️', 25, '{"learn":{"explanation":{"en":"Some verbs ALWAYS take a gerund: enjoy, avoid, finish, mind, suggest, keep. Others ALWAYS take an infinitive: want, need, decide, hope, promise, plan. You simply have to learn which is which!","pt":"Alguns verbos SEMPRE levam gerúndio: enjoy, avoid, finish, mind, suggest, keep. Outros SEMPRE levam infinitivo: want, need, decide, hope, promise, plan. Simplesmente tens de aprender quais são quais!"},"examples":[{"en":"She finished reading the book.","pt":"Ela acabou de ler o livro."},{"en":"I need to go home now.","pt":"Eu preciso de ir para casa agora."},{"en":"He keeps making the same mistake.","pt":"Ele continua a cometer o mesmo erro."}],"practice":[{"q":"Which verb takes a GERUND?","opts":["want","need","avoid","promise"],"ans":2,"exp":"avoid + gerund: avoid doing."},{"q":"Which verb takes an INFINITIVE?","opts":["enjoy","finish","plan","keep"],"ans":2,"exp":"plan + infinitive: plan to do."}]},"qs":[{"q":"Which verb takes a gerund?","opts":["want","enjoy","need","decide"],"ans":1,"exp":"\"enjoy\" takes a gerund: \"enjoy doing\"."},{"q":"Which verb takes an infinitive?","opts":["enjoy","avoid","want","finish"],"ans":2,"exp":"\"want\" takes an infinitive: \"want to do\"."},{"q":"\"I hope ___ you soon.\"","opts":["see","to see","seeing","seen"],"ans":1,"exp":"\"hope\" takes the infinitive: \"hope to see\"."},{"q":"\"She avoids ___ in the rain.\"","opts":["walk","to walk","walking","walked"],"ans":2,"exp":"\"avoids\" takes a gerund: \"avoids walking\"."},{"q":"\"He agreed ___ me.\"","opts":["help","to help","helping","helped"],"ans":1,"exp":"\"agreed\" takes an infinitive: \"agreed to help\"."}]}'::jsonb, 2),
('l13d', 'u13', 'Verbs + Gerund vs Infinitive (Part 2)', 'Verbos + Gerúndio vs Infinitivo (Parte 2)', '⚖️', 25, '{"learn":{"explanation":{"en":"Some verbs change meaning with gerund vs infinitive! STOP + gerund = end a habit (''I stopped smoking''). STOP + infinitive = pause to do something (''I stopped to smoke''). Same with REMEMBER and TRY.","pt":"Alguns verbos mudam de significado com gerúndio vs infinitivo! STOP + gerúndio = terminar um hábito (''I stopped smoking''). STOP + infinitivo = pausar para fazer algo (''I stopped to smoke''). O mesmo com REMEMBER e TRY."},"examples":[{"en":"I stopped eating meat. (I no longer eat it)","pt":"Eu parei de comer carne. (já não como)"},{"en":"I stopped to eat. (I paused to eat)","pt":"Eu parei para comer. (parei para isso)"},{"en":"Remember to lock the door. (don''t forget)","pt":"Lembra-te de fechar a porta. (não esqueças)"}],"practice":[{"q":"''I stopped ___ (smoking = quit habit)''","opts":["to smoke","smoke","smoking","smoked"],"ans":2,"exp":"stop + gerund = end the habit."},{"q":"''I stopped ___ (in order to rest)''","opts":["resting","rest","to rest","rested"],"ans":2,"exp":"stop + infinitive = pause to do something else."}]},"qs":[{"q":"\"I love ___ English.\" (both gerund and infinitive possible)","opts":["studying","to study","both are correct","neither"],"ans":2,"exp":"\"love\" can take both: \"love studying\" and \"love to study\" have similar meanings."},{"q":"\"I stopped ___ coffee.\" (habit)","opts":["drink","to drink","drinking","drank"],"ans":2,"exp":"\"stopped drinking\" = I quit drinking coffee. Stop + gerund = end an action."},{"q":"\"I stopped ___ coffee.\" (to do something else)","opts":["drink","to drink","drinking","drank"],"ans":1,"exp":"\"stopped to drink\" = I stopped (something else) in order to drink. Stop + infinitive = purpose."},{"q":"\"I remember ___ the door.\" (past memory)","opts":["lock","to lock","locking","locked"],"ans":2,"exp":"\"remember locking\" = I have a memory of locking it. Remember + gerund = past memory."},{"q":"\"I remembered ___ the door.\" (required action)","opts":["lock","to lock","locking","locked"],"ans":1,"exp":"\"remembered to lock\" = I didn''t forget to do it. Remember + infinitive = a task to do."}]}'::jsonb, 3),
('l13e', 'u13', 'Gerund vs Infinitive with "Try"', 'Gerúndio vs Infinitivo com "Try"', '💪', 20, '{"learn":{"explanation":{"en":"\"Try + infinitive\" = make an effort to do something difficult: \"I tried to lift the box.\" \"Try + gerund\" = experiment with something as a solution: \"Try adding more salt.\" The difference is subtle but important!","pt":"\"Try + infinitivo\" = fazer um esforço para fazer algo difícil: \"I tried to lift the box.\" \"Try + gerúndio\" = experimentar algo como solução: \"Try adding more salt.\" A diferença é subtil mas importante!"},"examples":[{"en":"I tried to open the jar, but it was stuck.","pt":"Tentei abrir o frasco, mas estava preso."},{"en":"Try using a different password.","pt":"Experimenta usar uma senha diferente."},{"en":"She tried to explain, but nobody listened.","pt":"Ela tentou explicar, mas ninguém ouviu."}],"practice":[{"q":"\"Try ___ a different route.\" (experiment as solution)","opts":["to take","take","taking","taken"],"ans":2,"exp":"try + gerund = experiment with."},{"q":"\"I tried ___ the window, but it was locked.\" (attempt)","opts":["open","opening","to open","opened"],"ans":2,"exp":"try + infinitive = attempt (might not succeed)."}]},"qs":[{"q":"\"I tried ___ the box, but it was too heavy.\" (attempt)","opts":["lift","to lift","lifting","lifted"],"ans":1,"exp":"\"try to lift\" = attempt to do something (maybe impossible)."},{"q":"\"I tried ___ the door to get in.\" (experiment)","opts":["open","to open","opening","opened"],"ans":2,"exp":"\"try opening\" = experiment to see if it works."},{"q":"\"Try ___ your password again.\" (suggestion)","opts":["enter","to enter","entering","entered"],"ans":1,"exp":"\"try to enter\" = attempt to do something (usually as a suggestion)."},{"q":"\"I tried ___ the key, but it didn''t work.\" (experiment)","opts":["use","to use","using","used"],"ans":2,"exp":"\"try using\" = experiment with the key as a solution."},{"q":"What is the difference between \"try to do\" and \"try doing\"?","opts":["No difference","Try to do = attempt; Try doing = experiment","Try to do = experiment; Try doing = attempt","Try to do = past; Try doing = present"],"ans":1,"exp":"\"try to do\" = make an effort; \"try doing\" = experiment with an action."}]}'::jsonb, 4),
('l13f', 'u13', 'Gerund vs Infinitive with "Go"', 'Gerúndio vs Infinitivo com "Go"', '🏃', 20, '{"learn":{"explanation":{"en":"\"Go + gerund\" is used for recreational activities: \"go swimming\", \"go shopping\", \"go hiking\". \"Go + infinitive\" is used for purpose or destination: \"I went to the doctor\", \"I went to buy bread.\"","pt":"\"Go + gerúndio\" é usado para actividades recreativas: \"go swimming\", \"go shopping\", \"go hiking\". \"Go + infinitivo\" é usado para propósito ou destino: \"I went to the doctor\", \"I went to buy bread.\""},"examples":[{"en":"Let''s go swimming this afternoon!","pt":"Vamos nadar esta tarde!"},{"en":"I went to the market to buy fruit.","pt":"Fui ao mercado comprar fruta."},{"en":"She goes jogging every morning.","pt":"Ela vai correr todas as manhãs."}],"practice":[{"q":"\"Let''s go ___ at the weekend.\" (activity)","opts":["shop","to shop","shopping","shopped"],"ans":2,"exp":"go + gerund for recreational activities: go shopping."},{"q":"\"I went ___ my sister.\" (purpose)","opts":["see","seeing","to see","seen"],"ans":2,"exp":"go + infinitive for purpose: to see."}]},"qs":[{"q":"\"Let''s go ___ this weekend.\" (activity)","opts":["shop","to shop","shopping","shopped"],"ans":2,"exp":"\"go shopping\" — go + gerund for activities (usually recreational)."},{"q":"\"I need to go ___ some milk.\" (purpose)","opts":["buy","to buy","buying","bought"],"ans":1,"exp":"\"to buy\" — go + infinitive for purpose."},{"q":"\"She goes ___ every morning.\" (activity)","opts":["run","to run","running","ran"],"ans":2,"exp":"\"go running\" — go + gerund for activities."},{"q":"\"I went ___ the doctor.\" (purpose)","opts":["see","to see","seeing","saw"],"ans":1,"exp":"\"to see\" — go + infinitive for purpose."},{"q":"Which is correct for an activity?","opts":["go to swim","go swimming","go for swim","go swim"],"ans":1,"exp":"\"go swimming\" is correct for the activity. \"go to swim\" is for purpose."}]}'::jsonb, 5),
('l13g', 'u13', 'Review: Gerunds & Infinitives', 'Revisão: Gerúndios e Infinitivos', '🎯', 25, '{"learn":{"explanation":{"en":"Final review: Gerund (-ing) = subject, after prepositions, after certain verbs (enjoy, avoid, finish). Infinitive (to+verb) = after other verbs (want, need, decide), after adjectives, for purpose. Some verbs change meaning (stop, try, remember).","pt":"Revisão final: Gerúndio (-ing) = sujeito, depois de preposições, depois de certos verbos (enjoy, avoid, finish). Infinitivo (to+verbo) = depois de outros verbos (want, need, decide), depois de adjectivos, para propósito. Alguns verbos mudam de significado (stop, try, remember)."},"examples":[{"en":"Reading every day improves your English.","pt":"Ler todos os dias melhora o teu inglês."},{"en":"She decided to quit her job.","pt":"Ela decidiu abandonar o emprego."},{"en":"I''m interested in learning new things.","pt":"Estou interessado em aprender coisas novas."}],"practice":[{"q":"''I can''t stand ___ in traffic.'' (hate)","opts":["wait","to wait","waiting","waited"],"ans":2,"exp":"can''t stand + gerund."},{"q":"''She decided ___ abroad.'' (infinitive)","opts":["study","studying","to study","studied"],"ans":2,"exp":"decide + infinitive: to study."}]},"qs":[{"q":"\"___ is a good way to learn English.\" (subject)","opts":["Read","Reading","To read","Both B and C are correct"],"ans":3,"exp":"Both \"reading\" (gerund) and \"to read\" (infinitive) can be subjects."},{"q":"\"I can''t stand ___ in traffic.\" (gerund)","opts":["wait","to wait","waiting","waited"],"ans":2,"exp":"\"stand\" takes a gerund: \"can''t stand waiting\"."},{"q":"\"She decided ___ the job offer.\" (infinitive)","opts":["accept","to accept","accepting","accepted"],"ans":1,"exp":"\"decided\" takes an infinitive: \"decided to accept\"."},{"q":"\"I stopped ___ to the gym.\" (habit)","opts":["go","to go","going","went"],"ans":2,"exp":"\"stopped going\" = I no longer go to the gym."},{"q":"\"I stopped ___ to the gym.\" (purpose)","opts":["go","to go","going","went"],"ans":1,"exp":"\"stopped to go\" = I stopped (doing something else) to go to the gym."}]}'::jsonb, 6),
('l6h1', 'u6h', 'Professional Introductions', 'Apresentações Profissionais', '🤝', 25, '{"learn":{"explanation":{"en":"Professional introductions differ from casual ones. Use full names and job titles: \"Allow me to introduce myself — I''m [Name], [Job Title] at [Company].\" When meeting someone: \"It''s a pleasure to meet you.\" \"I''ve heard great things about your work.\"","pt":"As apresentações profissionais diferem das casuais. Usa nome completo e cargo: \"Allow me to introduce myself — I''m [Name], [Job Title] at [Company].\" Ao conhecer alguém: \"It''s a pleasure to meet you.\" \"I''ve heard great things about your work.\""},"examples":[{"en":"Allow me to introduce myself — I''m Ana Sitoe, Project Manager at TechMoz.","pt":"Permitam-me apresentar-me — sou a Ana Sitoe, Gestora de Projecto na TechMoz."},{"en":"It''s a pleasure to finally meet you in person.","pt":"É um prazer finalmente conhecê-la pessoalmente."},{"en":"I work in the finance department. What about you?","pt":"Trabalho no departamento financeiro. E você?"}],"practice":[{"q":"\"It''s a pleasure to meet you.\" A formal response is:","opts":["\"Me too.\"","\"Nice one.\"","\"The pleasure is mine.\"","\"Cool.\""],"ans":2,"exp":"\"The pleasure is mine.\" is the formal, polite response."},{"q":"\"What do you do?\" means:","opts":["What are you doing right now?","What is your job?","How are you?","Where are you from?"],"ans":1,"exp":"\"What do you do?\" = What is your job/profession?"}]},"qs":[{"q":"\"I am in charge of the sales team.\" This means:","opts":["I work with the sales team","I manage/lead the sales team","I am new to the sales team","I left the sales team"],"ans":1,"exp":"\"In charge of\" = responsible for, managing or leading."},{"q":"Professional greeting when meeting a new client:","opts":["Hey, what''s up?","Good morning, it''s a pleasure to meet you.","Yo! How are things?","Hi there!"],"ans":1,"exp":"\"Good morning, it''s a pleasure to meet you.\" — formal and professional."},{"q":"\"I report to the CEO.\" This means:","opts":["I write reports about the CEO","My manager is the CEO","I hired the CEO","I am the CEO"],"ans":1,"exp":"\"Report to\" = your direct boss/manager. \"I report to the CEO\" = the CEO is my manager."},{"q":"How do you ask about someone''s role professionally?","opts":["What are you?","What do you do?","Where do you work at?","What''s your thing?"],"ans":1,"exp":"\"What do you do?\" = professional way to ask about someone''s job."},{"q":"\"Based in Maputo\" means:","opts":["originally from Maputo","currently living/working in Maputo","travelling to Maputo","born in Maputo"],"ans":1,"exp":"\"Based in\" = where you are currently located and working."}]}'::jsonb, 0),
('l6h2', 'u6h', 'Emails — Formal Writing', 'Emails — Escrita Formal', '✉️', 30, '{"learn":{"explanation":{"en":"Professional emails have clear structure: Opening (Dear Mr/Ms [Name], / To Whom It May Concern,) → Purpose (I am writing to...) → Main message → Closing (Please do not hesitate to contact me. / I look forward to hearing from you.) → Sign-off (Yours sincerely / Kind regards / Best regards).","pt":"Os emails profissionais têm estrutura clara: Abertura (Dear Mr/Ms [Name], / To Whom It May Concern,) → Propósito (I am writing to...) → Mensagem principal → Fecho (Please do not hesitate to contact me.) → Despedida (Yours sincerely / Kind regards / Best regards)."},"examples":[{"en":"I am writing to enquire about the vacancy posted on your website.","pt":"Escrevo para me informar sobre a vaga publicada no vosso website."},{"en":"Please find attached my CV for your consideration.","pt":"Em anexo encontra o meu CV para a vossa consideração."},{"en":"I look forward to hearing from you at your earliest convenience.","pt":"Aguardo a vossa resposta quando vos for conveniente."}],"practice":[{"q":"Which is the correct formal email opening?","opts":["\"Hey John!\"","\"Dear Mr. Costa,\"","\"Hi there,\"","\"Yo, Mr Costa\""],"ans":1,"exp":"\"Dear Mr/Ms [Surname],\" is the standard formal email opening."},{"q":"\"Please find attached\" means:","opts":["I have lost the file","There is a file with this email","Please find me a file","I am searching for an attachment"],"ans":1,"exp":"\"Please find attached\" = a document is included with this email."}]},"qs":[{"q":"Which sign-off is MOST formal?","opts":["Cheers,","Love,","Yours sincerely,","Take care,"],"ans":2,"exp":"\"Yours sincerely\" is the most formal email sign-off. Use when you know the name of the recipient."},{"q":"\"I am writing to follow up on our meeting last week.\" This means:","opts":["I''m asking about something we discussed last week","I forgot about our meeting","I''m cancelling our meeting","I''m writing for the first time"],"ans":0,"exp":"\"Follow up\" = to check progress on something discussed previously."},{"q":"Which phrase asks someone to reply quickly?","opts":["\"Do not reply.\"","\"Reply when you want.\"","\"I look forward to your prompt response.\"","\"No need to reply.\""],"ans":2,"exp":"\"Prompt response\" = quick reply. Politely requesting a fast answer."},{"q":"\"To Whom It May Concern\" is used when:","opts":["you know the person well","you don''t know the recipient''s name","you are emailing a friend","you are angry"],"ans":1,"exp":"\"To Whom It May Concern\" — formal opening when you don''t know who will read the email."},{"q":"Which is a professional way to apologise in an email?","opts":["Sorry!!!","My bad.","I apologise for any inconvenience caused.","Oops!"],"ans":2,"exp":"\"I apologise for any inconvenience caused.\" — formal, professional apology."}]}'::jsonb, 1),
('l6h3', 'u6h', 'Meetings & Discussions', 'Reuniões e Discussões', '🗣️', 25, '{"learn":{"explanation":{"en":"Key meeting phrases: To start: \"Shall we get started?\" \"Let''s begin with item one.\" To contribute: \"I''d like to add...\" \"If I may...\" To agree: \"That''s a good point.\" \"I couldn''t agree more.\" To disagree: \"With respect, I think...\" \"I see it differently.\" To summarise: \"To sum up...\" \"In conclusion...\"","pt":"Expressões-chave para reuniões: Para começar: \"Shall we get started?\" Para contribuir: \"I''d like to add...\" Para concordar: \"That''s a good point.\" Para discordar: \"With respect, I think...\" Para resumir: \"To sum up...\""},"examples":[{"en":"Shall we get started? We have a lot to cover.","pt":"Podemos começar? Temos muito a tratar."},{"en":"With respect, I think we should reconsider that approach.","pt":"Com respeito, acho que devíamos reconsiderar essa abordagem."},{"en":"Could I just add something to that point?","pt":"Posso acrescentar algo a esse ponto?"}],"practice":[{"q":"\"With respect, I disagree.\" This phrase is:","opts":["rude","politely disagreeing","agreeing strongly","changing the subject"],"ans":1,"exp":"\"With respect\" softens a disagreement. It is POLITE."},{"q":"\"Let''s table this for now\" means:","opts":["discuss it later","agree with it","disagree with it","put it on the table"],"ans":0,"exp":"\"Table something\" (British) = postpone for later. Note: In American English, \"table\" means the opposite — to discuss it now!"}]},"qs":[{"q":"\"The floor is open for questions.\" This means:","opts":["The floor is broken","You can now ask questions","Questions are not allowed","Please sit on the floor"],"ans":1,"exp":"\"The floor is open\" = anyone can now speak or ask questions."},{"q":"How do you politely interrupt in a meeting?","opts":["\"STOP!\"","\"Excuse me, could I just add something?\"","\"Be quiet, I''m speaking.\"","\"Wait, no.\""],"ans":1,"exp":"\"Excuse me, could I just add something?\" — polite, professional interruption."},{"q":"\"Let''s take a five-minute break and reconvene.\" means:","opts":["End the meeting","Pause and come back together","Change the topic","Vote on something"],"ans":1,"exp":"\"Reconvene\" = come back together after a break."},{"q":"\"I move that we approve the proposal.\" This is used to:","opts":["ask a question","formally suggest a decision","disagree","summarise"],"ans":1,"exp":"\"I move that...\" = formally proposing a decision for the group to vote on or agree to."},{"q":"To summarise at the end of a meeting, you say:","opts":["\"I want to say something.\"","\"Are there any questions?\"","\"To sum up, we have agreed to...\"","\"Let''s start again.\""],"ans":2,"exp":"\"To sum up...\" = to give a brief summary of what was decided."}]}'::jsonb, 2),
('l6h4', 'u6h', 'Negotiations & Agreements', 'Negociações e Acordos', '🤝', 30, '{"learn":{"explanation":{"en":"Negotiation language: Making an offer: \"We could offer...\" \"How about...\" Making a counter-offer: \"What if we...?\" \"We''d be willing to... if you could...\" Accepting: \"That sounds reasonable.\" \"We have a deal.\" Rejecting: \"I''m afraid that''s not quite what we had in mind.\" \"We''d need you to...\"","pt":"Linguagem de negociação: Fazer uma oferta: \"We could offer...\" \"How about...\" Contra-proposta: \"What if we...?\" \"We''d be willing to... if you could...\" Aceitar: \"That sounds reasonable.\" \"We have a deal.\" Rejeitar: \"I''m afraid that''s not quite what we had in mind.\""},"examples":[{"en":"We could offer a 10% discount if you order 500 units.","pt":"Poderíamos oferecer um desconto de 10% se encomendar 500 unidades."},{"en":"That sounds reasonable. Let''s shake on it.","pt":"Parece razoável. Vamos selar o acordo."},{"en":"I''m afraid that''s not quite what we had in mind.","pt":"Receio que não é bem o que tínhamos em mente."}],"practice":[{"q":"\"We have a deal!\" means:","opts":["We disagree","We are still negotiating","We have reached an agreement","We need more time"],"ans":2,"exp":"\"We have a deal\" = we have agreed. The negotiation is complete!"},{"q":"\"What if we split the difference?\" means:","opts":["each side takes half the difference","we end the negotiation","we disagree","we repeat our offer"],"ans":0,"exp":"\"Split the difference\" = each party meets halfway between their positions."}]},"qs":[{"q":"\"We''d be open to negotiating the price.\" means:","opts":["The price is fixed","We refuse to change the price","We are willing to discuss the price","We have agreed on the price"],"ans":2,"exp":"\"Open to negotiating\" = willing to discuss and possibly change."},{"q":"\"That''s our final offer.\" means:","opts":["We will offer more later","We will not change this offer","We are still thinking","We are withdrawing the offer"],"ans":1,"exp":"\"Final offer\" = the last and non-negotiable offer. Take it or leave it."},{"q":"How do you politely reject a proposal?","opts":["\"No way!\"","\"That''s ridiculous.\"","\"I''m afraid that doesn''t quite work for us.\"","\"Rejected.\""],"ans":2,"exp":"\"I''m afraid that doesn''t quite work for us.\" — polite, professional rejection."},{"q":"\"Let''s find a middle ground.\" means:","opts":["Let''s disagree","Let''s find a compromise","Let''s end the negotiation","Let''s repeat our positions"],"ans":1,"exp":"\"Middle ground\" = a compromise position that both sides can accept."},{"q":"\"Could you go any lower on the price?\" means:","opts":["Can the price be higher?","Can you reduce the price?","Is the price fixed?","Can we talk later?"],"ans":1,"exp":"\"Go lower on the price\" = reduce the price. A request for a discount."}]}'::jsonb, 3),
('l6h5', 'u6h', 'Job Interviews', 'Entrevistas de Emprego', '👔', 30, '{"learn":{"explanation":{"en":"Job interview essentials: Opening: \"Thank you for the opportunity.\" Strength questions: \"I''d say my greatest strength is...\" Weakness questions: \"I''m working on improving my...\" Experience: \"In my previous role, I was responsible for...\" Closing: \"Do you have any questions for me?\" \"When can I expect to hear from you?\"","pt":"Essenciais para entrevistas: Abertura: \"Thank you for the opportunity.\" Pontos fortes: \"I''d say my greatest strength is...\" Fraquezas: \"I''m working on improving my...\" Experiência: \"In my previous role, I was responsible for...\" Fecho: \"Do you have any questions for me?\""},"examples":[{"en":"My greatest strength is my ability to work under pressure.","pt":"O meu maior ponto forte é a minha capacidade de trabalhar sob pressão."},{"en":"In my previous role, I managed a team of eight people.","pt":"No meu cargo anterior, geria uma equipa de oito pessoas."},{"en":"I''m a quick learner and I adapt well to new environments.","pt":"Aprendo rapidamente e adapto-me bem a novos ambientes."}],"practice":[{"q":"When asked \"What is your weakness?\", the best approach is:","opts":["Say you have no weaknesses","Name a real weakness and say how you''re improving it","Refuse to answer","Say the job description''s requirements"],"ans":1,"exp":"Be honest but show self-awareness: name a weakness AND how you''re working on it."},{"q":"\"In my previous role\" means:","opts":["in my current job","in my future job","in my last/former job","in my dream job"],"ans":2,"exp":"\"Previous role\" = former/last position. The job before the current one."}]},"qs":[{"q":"\"Tell me about yourself.\" Start your answer with:","opts":["My hobbies are...","I am [Name], currently working as... with experience in...","I was born in...","I don''t know what to say."],"ans":1,"exp":"Start with name, current/recent role, and key experience. Keep it professional and relevant."},{"q":"\"Why do you want to work here?\" The best answer focuses on:","opts":["The salary","How the role fits your career goals and what attracts you to the company","That you need a job","That it''s close to your home"],"ans":1,"exp":"Show genuine interest in the COMPANY and how the role matches your GOALS."},{"q":"\"Where do you see yourself in 5 years?\" is about:","opts":["your personal life","your career ambitions and goals","what you want to buy","where you want to live"],"ans":1,"exp":"This question is about CAREER AMBITIONS. Show ambition but also commitment to the role."},{"q":"\"I''m a team player.\" This means:","opts":["I prefer to work alone","I work well with others","I manage teams","I play sports"],"ans":1,"exp":"\"Team player\" = someone who works well with others and contributes to group goals."},{"q":"Which question is NOT appropriate to ask at an interview?","opts":["What does the role involve day-to-day?","What are the opportunities for growth?","How much is the salary? (first question)","What does the team culture look like?"],"ans":2,"exp":"Asking about salary as your FIRST question gives a bad impression. Research it before the interview."}]}'::jsonb, 4),
('l6h6', 'u6h', 'Presentations & Public Speaking', 'Apresentações e Oratória', '🎤', 35, '{"learn":{"explanation":{"en":"Structure your presentation: Opening (Good morning everyone. Today I''m going to talk about...) → Main points (First.../Moving on.../Furthermore...) → Visuals (As you can see from this chart.../This graph shows...) → Conclusion (To summarise.../In conclusion...) → Q&A (I''d be happy to answer any questions.)","pt":"Estrutura a tua apresentação: Abertura (Good morning everyone. Today I''m going to talk about...) → Pontos principais (First.../Moving on.../Furthermore...) → Visuais (As you can see from this chart...) → Conclusão (To summarise.../In conclusion...) → Q&A (I''d be happy to answer any questions.)"},"examples":[{"en":"Today I''m going to walk you through our Q3 results.","pt":"Hoje vou apresentar-vos os resultados do 3º trimestre."},{"en":"As you can see from this chart, sales have increased by 20%.","pt":"Como podem ver neste gráfico, as vendas aumentaram 20%."},{"en":"I''d now like to open the floor to questions.","pt":"Gostaria agora de abrir espaço para perguntas."}],"practice":[{"q":"\"I''d like to draw your attention to...\" means:","opts":["Please ignore this","Please look at / focus on this","Ask me a question","Skip this part"],"ans":1,"exp":"\"Draw your attention to\" = please focus on / look at this specific thing."},{"q":"\"To wrap up\" means:","opts":["to start a new topic","to end the presentation","to show a chart","to answer questions"],"ans":1,"exp":"\"To wrap up\" = to finish/conclude. \"Let me wrap up with one final point.\""}]},"qs":[{"q":"How do you start a presentation?","opts":["Let''s go.","Good morning. Today I''d like to talk to you about...","So... yeah...","OK here it is."],"ans":1,"exp":"\"Good morning. Today I''d like to talk to you about...\" — professional, confident opening."},{"q":"\"Let''s move on to the next point.\" is used to:","opts":["End the presentation","Transition to a new topic","Summarise","Ask a question"],"ans":1,"exp":"\"Move on to\" = transition smoothly to the next section or topic."},{"q":"\"As you can see from this graph...\" is used when:","opts":["you have no visuals","referring to a visual aid","asking a question","summarising"],"ans":1,"exp":"Used to draw attention to a VISUAL AID (chart, graph, image) in your presentation."},{"q":"What should you do if you don''t know an answer in Q&A?","opts":["Make something up","Say \"That''s a great question. Let me get back to you on that.\"","Say nothing","End the presentation"],"ans":1,"exp":"\"Let me get back to you on that.\" — honest and professional. Never guess or bluff!"},{"q":"\"In conclusion\" is used to:","opts":["introduce a new idea","begin the presentation","summarise and close","ask for questions"],"ans":2,"exp":"\"In conclusion\" = to signal you are SUMMARISING and ending the presentation."}]}'::jsonb, 5),
('l6i1', 'u6i', 'Describing Mozambique', 'Descrever Moçambique', '🗺️', 25, '{"learn":{"explanation":{"en":"Talking about your country in English is a powerful skill. Key vocabulary: natural resources (resources naturais), coastline (litoral), landlocked/coastal nation, province (província), ethnic diversity (diversidade étnica), official language (língua oficial), developing country, GDP, tourism.","pt":"Falar sobre o teu país em inglês é uma competência poderosa. Vocabulário-chave: natural resources (recursos naturais), coastline (litoral), province (província), ethnic diversity (diversidade étnica), official language (língua oficial), developing country, GDP, tourism."},"examples":[{"en":"Mozambique is a coastal nation in southeastern Africa.","pt":"Moçambique é uma nação costeira no sudeste de África."},{"en":"The country is rich in natural resources, including coal, gas, and minerals.","pt":"O país é rico em recursos naturais, incluindo carvão, gás e minerais."},{"en":"Maputo is the capital and the most populous city.","pt":"Maputo é a capital e a cidade mais populosa."}],"practice":[{"q":"\"Coastal\" means:","opts":["landlocked","near the ocean/sea","mountainous","rural"],"ans":1,"exp":"\"Coastal\" = near or along the coast/sea. Mozambique has a long Indian Ocean coastline."},{"q":"\"Natural resources\" are:","opts":["man-made things","materials from nature (minerals, gas, coal)","tourist attractions","cultural traditions"],"ans":1,"exp":"\"Natural resources\" = materials found in nature: coal, gas, minerals, water, timber."}]},"qs":[{"q":"How many provinces does Mozambique have?","opts":["8","10","11","13"],"ans":2,"exp":"Mozambique has 11 provinces. The capital Maputo is also a city-province."},{"q":"\"Mozambique borders ___ countries.\"","opts":["3","5","6","7"],"ans":2,"exp":"Mozambique borders 6 countries: Tanzania, Malawi, Zambia, Zimbabwe, South Africa, and Eswatini."},{"q":"\"Língua oficial\" in English is:","opts":["mother tongue","national language","official language","local language"],"ans":2,"exp":"\"Official language\" = língua oficial. Portuguese is the official language of Mozambique."},{"q":"\"The GDP of Mozambique is growing.\" GDP means:","opts":["government development plan","gross domestic product","general development policy","geographic distribution plan"],"ans":1,"exp":"\"GDP\" = Gross Domestic Product = the total value of goods and services produced."},{"q":"Mozambique is famous for its:","opts":["mountains and snow","Indian Ocean coastline and marine biodiversity","desert climate","cold winters"],"ans":1,"exp":"Mozambique is known for its stunning Indian Ocean coastline, beaches, and marine life."}]}'::jsonb, 0),
('l6i2', 'u6i', 'Talking About African Culture', 'Falar sobre a Cultura Africana', '🎭', 25, '{"learn":{"explanation":{"en":"Sharing your culture in English is valuable. Vocabulary: tradition (tradição), custom (costume), ceremony (cerimónia), ancestor (antepassado), community (comunidade), ubuntu (spirit of shared humanity), indigenous (indígena), oral tradition (tradição oral), folklore, lobolo (bride price), initiation rites.","pt":"Partilhar a tua cultura em inglês é valioso. Vocabulário: tradition, custom, ceremony, ancestor (antepassado), community, ubuntu (espírito de humanidade partilhada), indigenous (indígena), oral tradition (tradição oral), folklore, lobolo, initiation rites (ritos de iniciação)."},"examples":[{"en":"In many Mozambican cultures, the lobolo is an important tradition.","pt":"Em muitas culturas moçambicanas, o lobolo é uma tradição importante."},{"en":"Oral tradition was how stories and history were passed down before writing.","pt":"A tradição oral foi a forma como as histórias e a história foram transmitidas antes da escrita."},{"en":"The concept of ubuntu teaches that a person exists through others.","pt":"O conceito de ubuntu ensina que uma pessoa existe através dos outros."}],"practice":[{"q":"\"Oral tradition\" means:","opts":["written stories","passing knowledge through speech and storytelling","modern music","digital media"],"ans":1,"exp":"\"Oral tradition\" = knowledge, history, and stories passed verbally from generation to generation."},{"q":"\"Ancestor\" means:","opts":["a future descendant","a very old relative from past generations","a neighbour","a community leader"],"ans":1,"exp":"\"Ancestor\" = antepassado — a person from whom you are descended."}]},"qs":[{"q":"\"Ubuntu\" is best described as:","opts":["a type of food","a philosophy of shared humanity and community","a traditional dance","a language"],"ans":1,"exp":"\"Ubuntu\" = \"I am because we are\" — a southern African philosophy of community and shared humanity."},{"q":"\"Indigenous\" means:","opts":["foreign","modern","originating naturally from a place","recently arrived"],"ans":2,"exp":"\"Indigenous\" = originating naturally from a particular region. Indigenous cultures = culturas originárias."},{"q":"\"A coming-of-age ceremony\" is:","opts":["a birth celebration","an initiation/transition ritual marking the move from childhood to adulthood","a wedding","a funeral"],"ans":1,"exp":"\"Coming-of-age\" = transition to adulthood. Many Mozambican cultures have important initiation ceremonies."},{"q":"How do you describe a traditional dance in English?","opts":["We have a dance from our region called [name]. It is performed during [occasion] and represents [meaning].","Dancing.","It''s traditional.","We dance sometimes."],"ans":0,"exp":"A good description gives the NAME, OCCASION, and MEANING — this makes your answer rich and interesting!"},{"q":"\"Passed down through generations\" means:","opts":["destroyed by time","transmitted from parents/grandparents to children over many years","invented recently","forgotten"],"ans":1,"exp":"\"Passed down through generations\" = transmitted from older to younger family members across time."}]}'::jsonb, 1),
('l6i3', 'u6i', 'Formal Letter Writing', 'Escrita de Cartas Formais', '📄', 30, '{"learn":{"explanation":{"en":"Formal letter structure: Your address (top right) → Date → Recipient''s address (left) → Salutation (Dear Sir/Madam, / Dear Mr/Ms [Name],) → Opening paragraph (purpose) → Body paragraphs → Closing paragraph → Sign-off (Yours faithfully [if no name] / Yours sincerely [if name known]) → Signature.","pt":"Estrutura de carta formal: Seu endereço (canto superior direito) → Data → Endereço do destinatário (esquerda) → Saudação (Dear Sir/Madam, / Dear Mr/Ms [Name],) → Parágrafo de abertura (propósito) → Parágrafos do corpo → Parágrafo de fecho → Despedida (Yours faithfully / Yours sincerely) → Assinatura."},"examples":[{"en":"I am writing to formally apply for the position of...","pt":"Escrevo para me candidatar formalmente ao cargo de..."},{"en":"I would be grateful if you could provide further information regarding...","pt":"Ficaria grato se pudesse fornecer mais informações sobre..."},{"en":"I trust this matter will receive your prompt attention.","pt":"Confio que este assunto receberá a vossa atenção imediata."}],"practice":[{"q":"Use \"Yours faithfully\" when:","opts":["you know the person''s name","you don''t know the person''s name (Dear Sir/Madam)","emailing a friend","texting"],"ans":1,"exp":"\"Yours faithfully\" = Dear Sir/Madam (name unknown). \"Yours sincerely\" = Dear Mr/Ms [Name] (name known)."},{"q":"\"I would be grateful if...\" is used to:","opts":["complain","make a polite request","give information","apologise"],"ans":1,"exp":"\"I would be grateful if...\" = very polite way to make a formal request."}]},"qs":[{"q":"When you don''t know the recipient''s name, you write:","opts":["Dear Friend,","Dear Person,","Dear Sir/Madam,","Hello there,"],"ans":2,"exp":"\"Dear Sir/Madam,\" — standard formal opening when you don''t know the name."},{"q":"The sign-off for \"Dear Mr. Costa\" is:","opts":["Yours faithfully,","Best wishes,","Cheers,","Yours sincerely,"],"ans":3,"exp":"\"Yours sincerely\" when you know the name. \"Yours faithfully\" when you don''t."},{"q":"\"I am writing with reference to your advertisement dated...\" means:","opts":["I saw your ad and I''m responding to it","I am writing for no reason","I disagree with your advertisement","I am not interested"],"ans":0,"exp":"\"With reference to\" = about / regarding. Tells the reader why you are writing."},{"q":"Which paragraph states WHY you are writing?","opts":["The last paragraph","The opening paragraph","The sign-off","The address"],"ans":1,"exp":"The OPENING paragraph states your PURPOSE: \"I am writing to apply for / enquire about / complain about...\""},{"q":"Which is the most formal expression?","opts":["Can you help me?","Gimme the info.","I would appreciate your assistance in this matter.","Let me know."],"ans":2,"exp":"\"I would appreciate your assistance in this matter.\" — formal, polite, professional."}]}'::jsonb, 2),
('l6i4', 'u6i', 'CVs & Job Applications', 'CVs e Candidaturas a Emprego', '📋', 30, '{"learn":{"explanation":{"en":"A CV (Curriculum Vitae) should include: Personal details → Personal statement → Work experience (most recent first) → Education → Skills → References. Key phrases: \"I am currently working as...\" / \"My responsibilities include...\" / \"I have [X] years of experience in...\" / \"I am proficient in...\"","pt":"Um CV deve incluir: Dados pessoais → Declaração pessoal → Experiência profissional (mais recente primeiro) → Formação → Competências → Referências. Frases-chave: \"I am currently working as...\" / \"My responsibilities include...\" / \"I have [X] years of experience in...\""},"examples":[{"en":"I have five years of experience in project management.","pt":"Tenho cinco anos de experiência em gestão de projectos."},{"en":"I am proficient in Microsoft Office and data analysis.","pt":"Tenho domínio do Microsoft Office e análise de dados."},{"en":"My responsibilities include coordinating a team of ten people.","pt":"As minhas responsabilidades incluem coordenar uma equipa de dez pessoas."}],"practice":[{"q":"\"Proficient in\" means:","opts":["learning","very skilled at","interested in","studying"],"ans":1,"exp":"\"Proficient in\" = very skilled at, competent in. \"I am proficient in English and French.\""},{"q":"\"References available upon request\" means:","opts":["I have no references","I refuse to give references","I can provide references if asked","My references are included"],"ans":2,"exp":"It means: \"If you want references, ask me and I will provide them.\""}]},"qs":[{"q":"Work experience in a CV is listed:","opts":["oldest first","alphabetically","most recent first","randomly"],"ans":2,"exp":"Most recent FIRST — reverse chronological order is standard for CVs."},{"q":"\"I have a track record of...\" means:","opts":["I have no experience","I have a history of proven results","I am just starting","I have bad results"],"ans":1,"exp":"\"Track record\" = history of proven achievements or results."},{"q":"\"Seeking a challenging role in...\" means:","opts":["I want an easy job","I am looking for a demanding and stimulating position","I am not sure what I want","I want to retire"],"ans":1,"exp":"\"Challenging role\" = a demanding, stimulating position that will push you to grow."},{"q":"Which best describes a \"skill\" on a CV?","opts":["Team player, fluent in English, proficient in Excel","I am nice and friendly","I enjoy weekends","I have a family"],"ans":0,"exp":"Skills = specific abilities: languages, software, technical skills, soft skills (team player, communicator)."},{"q":"\"Coordinated cross-functional teams\" means:","opts":["worked alone","managed teams from different departments working together","played sport","travelled for work"],"ans":1,"exp":"\"Cross-functional teams\" = teams from different departments working together on a shared goal."}]}'::jsonb, 3),
('l6i5', 'u6i', 'Development & Environment', 'Desenvolvimento e Meio Ambiente', '🌱', 30, '{"learn":{"explanation":{"en":"Important global topics you may discuss in English: sustainable development (desenvolvimento sustentável), climate change (alterações climáticas), deforestation (desflorestação), renewable energy (energias renováveis), food security (segurança alimentar), infrastructure (infra-estrutura), NGO, foreign investment, poverty alleviation.","pt":"Tópicos globais que podes discutir em inglês: sustainable development, climate change (alterações climáticas), deforestation (desflorestação), renewable energy (energias renováveis), food security (segurança alimentar), infrastructure (infra-estrutura), NGO, foreign investment, poverty alleviation."},"examples":[{"en":"Climate change is affecting rainfall patterns across southern Africa.","pt":"As alterações climáticas estão a afectar os padrões de chuva em toda a África austral."},{"en":"Mozambique is investing in renewable energy such as solar power.","pt":"Moçambique está a investir em energias renováveis como a energia solar."},{"en":"Food security remains a challenge in rural areas.","pt":"A segurança alimentar continua a ser um desafio nas zonas rurais."}],"practice":[{"q":"\"Renewable energy\" is energy that:","opts":["runs out eventually","comes from sources that naturally replenish (sun, wind, water)","uses coal and gas","produces a lot of pollution"],"ans":1,"exp":"\"Renewable\" = naturally replenishes. Solar, wind, hydro = renewable. Coal, oil = non-renewable."},{"q":"\"Food security\" means:","opts":["having a food factory","reliable access to sufficient nutritious food","security guards in supermarkets","expensive food"],"ans":1,"exp":"\"Food security\" = everyone having reliable access to enough safe, nutritious food."}]},"qs":[{"q":"\"Deforestation\" means:","opts":["planting trees","cutting down large areas of forest","protecting the environment","water conservation"],"ans":1,"exp":"\"Deforestation\" = large-scale cutting/clearing of forests. A major environmental concern."},{"q":"\"Sustainable development\" means:","opts":["developing quickly at any cost","meeting current needs without harming future generations'' ability to meet theirs","only using fossil fuels","stopping all development"],"ans":1,"exp":"\"Sustainable development\" = growth that meets TODAY''S needs without harming FUTURE generations."},{"q":"\"NGO\" stands for:","opts":["National Government Organisation","Non-Governmental Organisation","Northern Global Office","Natural Gas Operation"],"ans":1,"exp":"\"NGO\" = Non-Governmental Organisation. Examples: Red Cross, Doctors Without Borders."},{"q":"\"Poverty alleviation\" means:","opts":["increasing poverty","ignoring poverty","reducing or eliminating poverty","studying poverty"],"ans":2,"exp":"\"Alleviation\" = reduction, relief. Poverty alleviation = efforts to reduce poverty."},{"q":"\"Foreign investment\" refers to:","opts":["money from local businesses","money from businesses/governments of other countries","investment in foreign cultures","tourism"],"ans":1,"exp":"\"Foreign investment\" = money invested in a country by foreign companies or governments."}]}'::jsonb, 4),
('l6i6', 'u6i', 'English in the SADC Region', 'Inglês na Região da SADC', '🌍', 25, '{"learn":{"explanation":{"en":"English is the working language of SADC (Southern African Development Community). Key benefits: trading with South Africa, Zimbabwe, Zambia, Tanzania; reading contracts and legal documents; working in regional organisations and NGOs; access to international education and scholarships.","pt":"O inglês é a língua de trabalho da SADC (Comunidade de Desenvolvimento da África Austral). Benefícios: comércio com África do Sul, Zimbabwe, Zâmbia, Tanzânia; leitura de contratos e documentos legais; trabalho em organizações regionais e ONGs; acesso a educação e bolsas internacionais."},"examples":[{"en":"The SADC region has a combined market of over 300 million people.","pt":"A região da SADC tem um mercado combinado de mais de 300 milhões de pessoas."},{"en":"English fluency opens doors to regional trade and investment.","pt":"A fluência em inglês abre portas ao comércio e investimento regional."},{"en":"Many international organisations in the region use English as their working language.","pt":"Muitas organizações internacionais na região usam o inglês como língua de trabalho."}],"practice":[{"q":"SADC stands for:","opts":["South Africa Development Council","Southern African Development Community","Southern African Democratic Countries","Sub-African Development Centre"],"ans":1,"exp":"SADC = Southern African Development Community — a regional economic community."},{"q":"\"Working language\" means:","opts":["a language for leisure","the language used officially for business and communication","a difficult language","a new language"],"ans":1,"exp":"\"Working language\" = the language officially used for business, meetings, and documents."}]},"qs":[{"q":"Which of these is NOT a SADC member?","opts":["Mozambique","South Africa","Nigeria","Tanzania"],"ans":2,"exp":"\"Nigeria\" is NOT a SADC member — it is part of ECOWAS (West Africa). SADC covers Southern Africa."},{"q":"One major benefit of English in the SADC region is:","opts":["watching Hollywood films","communicating in regional trade and business","speaking to tourists only","learning American culture"],"ans":1,"exp":"English is the WORKING language of SADC — essential for regional trade, business, and diplomacy."},{"q":"\"Cross-border trade\" means:","opts":["trading within one city","trading between different countries","online shopping","local markets"],"ans":1,"exp":"\"Cross-border trade\" = trade between different countries. Very important in the SADC region."},{"q":"To work for a SADC regional organisation, you need:","opts":["only Portuguese","only Swahili","English and often French or Portuguese","no specific language"],"ans":2,"exp":"SADC has 16 members with many official languages. English is key, and French/Portuguese are also important."},{"q":"Learning English helps a Mozambican worker to:","opts":["only speak to tourists","access regional and global opportunities, education, and careers","forget Portuguese","speak only to South Africans"],"ans":1,"exp":"English skills dramatically expand career, educational, and business opportunities both regionally and globally."}]}'::jsonb, 5)
